insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-09-04','(Pedro)llega a la Comisión, desde la Abogacía, solicitud de documentación para la revisión de la capacidad de D. Jesús. Se contacta para recabarla con Teofilo (T. Soc. del CRPS de Cáceres) y con Futuex. SE solcita la siguinte documentación: +++CRPS Cáceres: +++++Identificación de los familiares y dirección/contacto de los mismos. (Los nombres de la familia nuclear los tenemos en la Comisión, pero por si tuvierais conocimiento de algún otro). +++++Elaboración por tu parte de un Informe Social valorando la autonomía en los ámbitos personal y patrimonial que presenta D. Jesús. +++++Acudir como testigo a la vista judicial del procedimiento. Para ello sería necesario que nos indicases tu dirección y teléfono a efectos de notificación del Juzgado. En este caso, no sería necesaria la elaboración del citado informe Social. +++Se solicita todo ello al siguiente correo-e (tdearce.sanmiguel@hospitalarias.es) +++Teo no tiene inconveniente en asistir como testigo en el procedimiento. Considera que D. Jesús tiene asumida su situación y que ha decidido adaptarse a ella y a los ingresos que tiene, si bien se siente más segura si hay "alguien" pendiente de él, especialmente ante una posible recaída.++++++++++++++++++++++++++Contacto con Toni (FUTUEx): +++No tienen datos sobre los familiares de D. Jesús. +++remitirán nuevo informe ACTUALIZADO A ESTE VERANO con la correspondiente firma y sello. ++++++++++++++++++++++++++++++++Llamo a D. Jesús (633447172) para recabar información sobre su familia pero no coge el teléfono. +++Contacto con D. Jesús. +++Refiere, como había indicado Teo, tener asumida su situación y encontrarse mucho mejor: mantiene relación con sus amigos, reconoce la ayuda del CRPS, la importancia del deporte para él y ha vuelto a mantener relaciones con sus hermanos: +++++ D. Julián Romero Pérez reside en Plasencia y D. Zacarías Romero Pérez en Vitoria. Dada mi petición en cuanto a su dirección y contacto me dice que, si no me importa, primero hablará con ellos para ver si le dan permiso para ello. +++++Con su padre, D. Zacarías Romero Chamorro, prácticamente carece de relación. Comenta que, sin embargo, y lo dice con sorpresa, lollamó para su cumpleaños y su padre le agradeció la llmada. No osbtante, solamente sabe que vive en Benidorm +++Quedamos en que cuando lo tenga, se las pase a Teo para que nos las remita por correo-e . +++La converscaión ha sido tranquila, fluida y muy repetuosa, solcitando permiso para el tuteo al inicio de la misma. Al igual que la despedida, en un tono muy amable y cordial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-09-03','(Pedro)Conversación con Alberto, Técnico Dependencia I de Cáceres (927-270466). +++Precisamente en el momento de la llamada comenmta Alberto que la Jefa de Sección, Carmen Gallego, está tratando el tema con la Técnico. +++Ruego que, en la medida de lo posible, agilicen el trámite para remitir la solicitud all cadex dada la premura del tema los requerimientos del Juzgado. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de Mónica, Técnico dependencia(21842): +++Le están dando la máxima prioridad al caso, apesar de que ya en dos ocasiones el trámite no ha prosperado al no dar perfil de discapacidad. +++ENVIARÁ la revisión de gardo y el PIA para su firma y lo REMITITEMOS por CORREO CERTIFICADO a la dirección que nos envíe en el correo-e para darlE mayor rapidez a la gestión.','2');
