insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-09-05','TERESA:EMAIL DE FUTUEX estamos al tanto, en lo de la medicación almenos y está el salud mental también informada pero no se hace gran cosa.... a pesar de ser conocedores que no se toma la medicación, la psiquiatra planteo ir a verlo a casa hace meses, pero aun nada, te envio un informe con el seguimiento de hace un par de semanas y con lo que recabemos hoy mismo que iba a pasarse la compañera por alli.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2019-09-05','TERESA: EMAIL FUTUEX le diremos que no pida presupuesto para la casa y nos pondremos con el a mirar tema de pisos, que estará dificil pero bueno... ya que no quiere ir a domir también a los pisos tutelados donde come.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-09-05','(Pedro)Correo-e de Teófilo, T. Soc. del CRPS de Cáceres. +++Buenos tardes Pedro. Según quedamos por teléfono y solicitado por correo electrónico, te envío la información solicitada referida a D. Jesús Romero Pérez. Respecto al nombre y localización de familiares de Jesús, te recomiendo te pongas en contacto con él y sea él quien que detalle todos los datos. En cuanto a la elaboración del informe social, comentarte que opto por la asistencia a la vista, por lo que cuentas con mi disponibilidad y la de su buen amigo Pedro Pastor (me lo ha confirmado esta mañana). Para la remisión por parte del juzgado de la citación pertinente te remito la dirección de Pedro y mía: ++++++++++++++++++++++++++++++++++++++++++++++++++ Pedro Pastor Villegas. Av. Rodríguez de Ledesma, 2. 1º.C 10001.- Cáceres. +++++++++++++++++++++++++++++++++++++++++ Teófilo de Arce Escudero C/ Islas Azores, 9. 1º. A. 10001.- Cáceres. Sin otro particular, recibe un saludo. Gracias por los teléfonos.','2');
