insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2019-09-05','TERESA: RECIBO ESCRITO EN EL QUE SOLICITA SE REPAREN DAÑOS PRODUCIDOS EN UNA VIVIENDA PROPIEDAD DE JOSE FERNANDEZ CUBERO LA CUAL LINDA CON ESTE TUTELADO. INTETO PONERME EN CONTACTO CON EL TS 8924584084) PARA QUE VALORE EL DAÑO EL ARQUITECTO MUNICIPAL. QUEDO PENDIETE DE HABLAR CON EL TS EL CUAL VA LOS MARTES A CALERA Y AHORA SE ENCUENTRA DE VACACIONES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2019-09-05','TERESA: LLAMA LA TS DE LA PROVIDENCIA EN RIVERA DEL FRESNO PARA COMUNICARNOS QUE SE ENCUENTRA ALLI INGRESADA Y QUE ESTA PENDIENTE DE QUE TOMEMOSM POSESION PARA PODER GESTINOAR SUS CUENTAS. LE PIDO CERTIFICADO DE INGRESO Y QUEDAMOS A LA ESPERA DE TOMAR EL CARGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2019-09-05','Te escribo para contarte sobre Joaquín. Decirte antes de nada que va mejorando su actitud, parece estar madurando. ¿Recuerdas cuando te comentó que quería hacer un cambio de sexo?, bueno pues sigue con esa idea. Él por su cuenta se ha estado informando sobre el tema y contactó con la Fundación Triángulo. Un chico de esta Fundación se ha puesto en contacto con nosotras y hemos concertado una entrevista para este jueves, a las 11.30 horas. Vamos a crear un equipo de trabajo para tratar este asunto donde estarán Mª Ángeles como gerente, la coordinadora de vivienda, la psicóloga que lo trató cuando estaba en colegio y yo. Queremos ver bien este asunto para asegurarnos que no sea algún "capricho" pasajero de Joaquín. Nos ha comentado este chico que ya no es necesario que la persona pase por el psicólogo para que decida si es apta o no para el cambio, que la persona puede pedir cita con su médico de atención primaria y lo deriven al endocrino especializado en estos temas. Joaquín está muy animado, pero queremos asegurarnos bien antes de dar cualquier paso. Esto es lo que llevamos visto hasta el momento. Si desde la CTAEX consideráis otra cosa me lo comunicas y ya vamos viendo. Si tienes cualquier duda me lo dices. Un beso. -- Eva Álvarez Gallego Trabajadora Social Tfno. 924 454 727 Plena Inclusión Montijo','2');
