insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-09-05','-Amalia : procedimiento abierto desde el SAD Bjoz ( Manuela ) y C.salud Valdepasillas ( FEli ) . Tb el del marido Antonio Paredes Hernández , que es defensa judicial. Contactar con ellas cuando el expediente se resuelva. 924210243 Tf SAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-05','miguel, a petición de Teresa TS, llamo al Juzgado nº1 de Villafranca de los Barros donde me confirman que de los dos procedimientos judiciales que le hemos remitido está pendiente que le den número de procedimiento al de modificación de capacidad de curatela a tutela (les llegó a finales de Agosto vía Lexnet), mientras que el otro procedimiento nº 547/19, les llegó físicamente final de Julio aproximadamente, y consistente en solicitud de internamiento involuntario en centro de mayores. Según me indica Tere TS, desde la UHB de Llerena apremian a que le llevemos al centro de mayores porque allí ya ha superado el plazo máximo de estancia...El problema que al ser una curatela, no podemos ingresarlo ni por vía de urgencia ni esperar a la autorización de ingreso involuntario, porque previo será el procedimiento de modificación de capacidad de curatela a tutela. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Puerto, Enfermera del 112 (924-387669). +++Una vez enmarcada la situación, planteo la cuestión de si harían el traslado sin la autorización judicial. En principio la respuesta es que no...pero va a llamar al Juzgado para plantear el caso. +++Tras llamar al Juzgado, la Letrada le dice que el procedeimiento tiene que seguir su curso, si bien mañana el auto lo tendrta el juez en su mesa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-05','(Miguel)Conversación con Marta briosca, Letrada del Juzgado de nº 2 de Villafranca de los Barros (924-524013). +++El prcedimiento de autorización de ingreso ha entrado ya en el Juzgado y tiene número asignado, no así el de ampliación de la incapacidad. +++Se podría proceder al ingreso involuntario sin la autorización... ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Puerto, Enferm,era del 112 (924-387669). +++Una vez enmarcada la situación, planteo la cuestión de si harían el traslado sin la autorización judicial. En principio la respuesta es que no...pero va a llamar al Juzgado para plantear el caso. +++Tras llamar al Juzgado, la Letrada le dice que el procedeimiento tiene que seguir su curso, si bien mañana el auto lo tendrta el juez en su mesa.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-09-05','miguel, me pide Tere Ts hable con el Juzgado porque desde el mes de abril de 2019 que solicitamos la autorización para ingreso involuntario, y no han contestado. Llamo al Juzgado nº1 de Villanueva de la Serena y me confirman que está entre las notificaciones pendientes de que remitan, y que hasta octubre de 2019 no nos llegará la contestación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-09-05','-Se recibe llamada tf. de la madre de Rubén . Llama para informarnos de lo acontecido con la agresión, le indico que ya sabíamos lo sucedido porque estuvimos con las delegadas de Futuex en visita domiciliaria. Dice que eso es mentira pq ella no se mueve de su casa ,luego manifiesta que sale a la compra a Mérida. Le indico que llevábamos tiempo intentando contactar con ella por tf. para acordar día de la cita pero no nos fue posible. Responde que no coge el tf. si no conoce el número . Le pregunto por su estado de salud pero no me da respuesta . Le pregunto sobre cómo sucedió la agresión , me cuenta que fue de noche , que él estaba en su piso , que la llamó y cuando acudió él la agredió sin más . Está buscando culpables de la situación , no le doy más información, la remito al Jdo. ( Trabajadora Social )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-06','TERESA: ENVIO RESOLUCION DE PLAZA RESIDENCIAL AL DORTOR CATALAN Y A ISABEL LA TRABAJADORA SOCIAL. ISABEL DIRECTORA DE LA RESIDENCIA DE LOS SANTOS ME ENVIA REGLEMENTO ITERNO Y DOCUMENTO CON LO QUE VA A NECESITAR PARA EL INGRESO. QUEDO PENDIENTE DE HABLAR EL MARTES CON MAI PARA PEDIR QUE NOS RESERVE LA PLAZA UNOS DIAS MAS HASTA QUE TENGAMOS LA ORDEN DE INGRESO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FRANCISCO'and edp.apellido1='PATIÑO'and apellido2='COUCEIRO'),'2019-09-05','TERESA: ENVIO CONSENTIMIENTO INFORMADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTO'and edp.apellido1='DIAZ'and apellido2='BOZA'),'2019-09-06','TERESA: EMAIL DE LA TRABAJADORA SOCIAL DEL P.I ZAFRA CON LAS SALIDAS PROGRAMADAS AL DOMICILIO HASTA FINALES DE AÑO SEPTIEMBRE: del viernes 13 al lunes 16 OCTUBRE: del viernes 25 al lunes 28 NOVIEMBRE: DEL VIERNES 15 AL LUNES 18 DICIEMBRE: DEL VIERNES 20 AL LUNES 23','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANDREA'and edp.apellido1='DAZA'and apellido2='REGALADO'),'2019-09-06','-Autorizo a la TS de las Hermanitas de la Soledad para q la aux. acompañe a Andrea al hospital por cita medica. Lleva a 10€/h nos pasará la factura y Nº cta. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='GUERA'and apellido2='CASTAÑEDA'),'2019-09-06','(Pedro)Llamada de Dª Pilar Egea (651-473261), sobrina de D. Manuel. +++Ha fallecido la madre de D. Manuel y quiere agilizar los trámites de la herencia. +++Derivo a Ángel (Secc. Jurídica).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CARDOSO'and apellido2='SILVA'),'2019-09-06','-respuesta seccion eco al ayto: Buenos días, en relación a su escrito del día 16 de Agosto de 2019, y tras revisar las propiedades de Don Francisco Cardoso Silva, tutelado por esta Comisión Tutelar de Adultos, comprobamos que no existe ningún bien inmueble en el término de Barcarrota, según consta en el catastro como en el registro de la propiedad. Es por ello que les requerimos para que nos remitan cualquier tipo de información que obre en su poder y acredite que nuestro tutelado es titular del citado inmueble. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2019-09-06','(Pedro) Llamada de Sonia (698-742953), hija de Dª Concepción). +++Llama para que le demos el DNI de su madre hoy mismo porque van a vender una casa de la que ella es copropietaria y lo necesitan para llevar al notario la docuemntación. +++Le explico que no pueden vender la casa sin contar con la autorización judicial correspondiente a nuestra tutelada y que la notaría se ponga en contacto con la Comisión para habalr del tema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2019-09-06','-Pido a FUTUEX q en la proxima visita la semana q viene la acompañen a una sucursar de iberbank o liber y digitalicen el DNI . Nos avisarán para abrir nueva cuenta y quitar la del Santander. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2019-09-05','miguel, llama el cuñado y nos comenta que están pendientes de inscribir las herencias del padre y tío. Angel solicita a los juzgados la aprobación definitiva de las herencias para inscribirlas en el registro de la propiedad. Una vez que lleguen los oficios los mandaremos a los registros de la propiedad. Una vez inscritos comenzaremos a recabar con el cuñado la documentación para hacer la herencia de la hermana','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-09-06','(Pedro)Llamada de María Dolores y posteriormente de Gisela. +++Temas: +++++COLCHÓN: al parecer, a pesar de ser nuevo, es defectuoso, no aliviando en absoluto los dolores que Mariloli dcie tener por la noche. Si está en garantía, se pondrán encontacto con la tienda para solicitar el cambio. +++++FISIOTERAPIA: lo debe hablar con su médico y si lo considera necesario derivarla al Fisio. En este caso, si la consulta se retrasa, se podría considerar la posibilidad de acudir a uno privado valorando el número de sesiones y el coste de las mismas. El tema del sobrepeso es importante para los problemas de artrosis que dice tener Mariloli. +++++PISO de Almendralejo: ya se le ha insistido en que no le conviene ir por allí, por las escaleras, porque no tiene capacidad para atender las tareas, etc. ++++++++Se fue ayer a Almendralejo y ha regresado hoy al CRR: al parecer su hermano la ha tratado como una empleada y ha vuelto muy cansada. +++++PLAYA: creemos que es bueno que vaya a la playa con el centro y le animamos a ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-06','TERESA: ME COMUICA EL DOCTOR CATALAN QUE EL PROXIMO DIA ONCE SALE DE ALTA,SI PARA ESE DIA NO TENEMOS AUTORIZACION DE INGRESO VOLVERA A SU DOMICILIO LLAMO AL SSB DE LA FUENTE Y HABLO CON LUISA TRABAJADOR SOCIAL YA QUE ANTONIO ESTA DE VACACINES. LE COMENTO QUE POSIBLEMENTE VUELVA A CASA PARA QUE CONTEMPLEN LA POSIBILDAD DE QUE ASISTA A CENTRO DE DIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2019-09-06','-Pido a FUTUEX q en la proxima visita la semana q viene la acompañen a una sucursar de iberbank o liber y digitalicen el DNI . Nos avisarán para abrir nueva cuenta y quitar la del Santander. AD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2019-09-06','-Amalia : buenos días , acabo de preguntar en la sección correspondiente su situación en la lista , está el nº8 en lista ordinaria. Esto supone que se puede demorar mucho en el tiempo . Podríamos solicitar plaza por emergencia social en el caso de que en el recurso actual exista un límite máximo de tiempo de estancia y esté cerca de extinguirse. Anotamos la salida prevista para estos días . Un saludo De: MARIA MERCEDES CRUZ DUQUE >mcruz.cdmeba@caritas.es> Enviado: viernes, 6 de septiembre de 2019 13:43 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Asunto: Caso de Manuel Domínguez Buenas tardes Amalia Manuel se irá unos días al pueblo con la familia, se marchará el lunes día 9 y volverá el miércoles día 11 de septiembre. Quería preguntarte una duda, no hemos vuelto a saber nada del recurso residencial de salud mental que se le solicitó a Manuel, podrías informarme?? El próximo día 20 de septiembre hemos marcado cita con él para revisar los objetivos cumplidos y lo que nos quedaría por trabajar y obtener la plaza en ese recurso aparece en sus objetivos de vivienda, me gustaría poder decirle e informarle de cómo va en lista si sabemos tiempos de espera, etc. Una vez hagamos la revisión con él, te mandaré un mail informándote de cómo vamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-09-10','(Pedro) Se recibe el Informe de Futuex sobre D. Jesús para remitirlo a Escalona, guardado en expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-10','El Juzgado de Primera Instancia e Instrucción nº 2, de Trujillo, dicta Auto nº 51/2019, de fecha 1 de abril de 2019, denegando el internamiento involuntario de Felipe (ITR INTERNAMIENTO 78/2019).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-09-10','-Amalia : Envio email a la sección económica : -Buenos días , vamos a cambiar el pto. establecido para RAFAEL FAUS LEMUS , que se encuentra en Ctro. penitenciario de Badajoz. -Subimos cuenta peculio a 150€ -Hacemos transferencia a su tía de 150€ ASUNCION LEMUS , el nº cta. es el que tenéis de las ultimas transferencias , si queréis confirmarlo con ella , su tf es 924109808.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2019-09-10','TEREAS: EMAIL FUTUEX Informar, de que el pasado 4 de Septiembre, recibimos una llamada de Mari Cielo de CRPS de Zafra comentándonos que Beatriz estaba ingresada en la UHB de Llerena desde el día anterior. Lo sabían porque la mañana del 4 se había pasado por el CRPS, Toni, el novio de Beatriz para comentarlo.Últimamente Beatriz había tenido muchos cambios de medicación y aunque estaba más o menos estable, tenía pequeñas crisis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-09-10','TERESA: EMIAL FUTUEX Mari Cielo: ha ido María Helena a la oficina para hablar con ella y recoger el dinero semanal para la comida. Mientras Mari Cielo hablaba con ella, Maria Helena le ha contado que el pasado 1 de septiembre se tomó un blister de pastillas y su hijo la llevó a Llerena, donde estuvo en observación hasta el lunes 2 de septiembre. Mari Cielo nos contaba que esta mañana en el CRPS la había visto muy bien, como siempre y que es una persona muy impredecible y muy cambiante. Es muy complejo determinar como está a largo plazo. Iremos a visitarla en breve para comprobar su estado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2019-09-10','CORREO Se remite autorización para el programa de detección precoz de cáncer colorrectal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2019-09-10','CORREO Se remite Aceptación de PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2019-09-10','(Pedro)Paso a Alberto la gestión del IBI pendiente de pago segun nos comunica Pilar, la T. Soc. de la Residencia Ciudad jardín en corre-e del 06 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-09-10','(Pedro) Paso a alberto l situación de impago de plaza de las mensualidades de abril, junio y agosto, comunicadas por la T. Social de la residsencia menisnte correo del 6 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-09-10','TERESA: EMIAL DE CRPS ZAFRA (MARI CIELO) • Durante el fin de semana del 30 de agosto al 1 de septiembre nos hemos encontrado numerosas llamadas en el contestador del CRPS, el cual estaba cerrado. El lunes 2 de septiembre intentamos contactar con ella siendo imposible hasta el 3 de septiembre, que tiene que venir al CRPS pero no acude. El domingo 1 de septiembre tuvo una sobreingesta medicamentosa provocando un ingreso en la UHB de Llerena hasta el lunes por la tarde, por lo que no acude al crps. • El viernes 6 de septiembre acude al CRPS y le hago entrega de dinero, me comenta que ha estado muy nerviosa estos días y me entrega el informe del ingreso en la UHB, que adjunto. • El viernes 6 de septiembre a ultima hora nos llama para comunicar que no puede vivir en casa porque su hermano no la deja en paz; tanto la psicóloga como yo hablamos con el hijo para darle indicaciones de que hacer en caso de que este nerviosa; posibilidad de llamar al 112, pero no se muestra muy de acuerdo. Cuando hablamos con ella se muestra más tranquila y colaboradora. • Hoy, 10 de septiembre, acude al CRPS a por dinero y me pide por favor que la ayudemos a salir de su casa ya que se encuentra mal. Ha tenido un conflicto en su casa y ha agredido a su padre, provocando la intervención de la Guardia Civil y la Policía Local, además del 112. Su padre no ha puesto denuncia, pero el 112 ha tendido que comunicar el incidente ya que ha habido parte medico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-09-10','(Pedro)Llama Francisco reclamando con mucha urgencia un extra de 60 euros para "...pagar un atasco que tengo en la tubería y tengo que llamar hoy mismo a Acualia..." +++Le propongo que una vez que vaya el técnico que nos remita un presupuesto o factura sobre la reparación y nos otros lo abonamos desde aquí. Pero a ello contesta que "...de eso nada, que el dinero tiene que ser en metálico. Que él ya está viviendo de manrea independeinte con su novia y que necesitan el dinero. Que no tiene nadie que administrar su dinero porque para eso es suyo...". +++Acude a las dependencias de la Comisión con la misma reclamación pero sin cita. +++HOY MISMO HA SACADO LOS 60 euros QUE SEMANALMENTE TIENE ASIGNADOS.A FECHA DE HOY, TIENE UN SALDO de 454 euros. +++En conversación con Amalia me dice que está pendiente de reunirse con él en Badajoz, a donde le ha dicho que va a acudir porque quiere el dinero ya... +++++Le digo a Amalia que no lo atienda ella sola y que el Guarda de Seguridad esté avisado y próximo al lugar de la entrevista.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GALAN'and apellido2='FARRONA'),'2019-09-11','(Pedro)Acude D. Juan Galán Farrona, hermano de D. José María, a la Comisión con la documentación que ha enviado al Juzgado de 1ª Instancia e Instrucción nº 4 de Mérida ante el cual ha presentado la rendición de anual refereida a su hermano. +++El Juzgado le ha devuelto la documentación presentada indicándole que no es el tutor de su hermano y que es a la Comsión a la que le compete su presentación. Deja copia de toda la documentación. +++Insiste en qué tiene que hacer para ser tutor de su hermano. Le planteo que, siendo ya tutor de su otro hermano, si no cree que asumir ambas tutelas le va a suponer demasiado esfuerzo, a lo que responde: "...sí, puede ser, ¿verdad? Creo que tiene razón...? +++++++++La rendición de cuentas del hermano del que es tutor la debe dirigir al Juzgado nº 2 de Mérida: Nº procedeimineto de Incapcitación/tutela de Felipe Galán Farrona X08-197/2016. Instancia Nº 2','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2019-09-11','TERESA:TERESA: ARCHIVO RESOLUCION INCLUSION EN EL PROGRAMA PARA PAECIENTES CON NECESIDADES ASISTENCIALES ESPECIALES EN EL AMBITO DEL SISTEMA SANITARIO PUBLICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2019-09-11','TERESA: ARCHIVO INFORME SOCIAL QUE ENVIAN DESDE PLENA INCLUSION PARA RENDICION DE CUENTAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS MIGUEL'and edp.apellido1='MUÑOZ'and apellido2='SANCHO'),'2019-09-11','TERESA: RECIBO EMAIL DE MARGA LA TS DEL CENTRO PENITENCIARIO Luis Mi, tiene oportunidad de pasar a trabajar en el Servicio de Gestión de Residuos, creemos que es una buena oportunidad para él porque es otro destino con más responsabilidad, mayor contacto con otras personas, fuera del módulo con lo cual tiene oportunidad de salir más tiempo y cobraría en torno a 120 € y su actual puesto pasaría a estar cubierto por otro interno que está iniciando inserción laboral. SE AUTORIZA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-09-11','miguel, recibimos vía email auto del Jzdo de Cáceres nº1 indicando su incompetencia y remisión al Jzdo Decano de Plasencia (que es el competente por razón del domicilio del tutelado.. Tras llamar al Jzdo de Cáceres nº1 me indican que ellos remitirán en próximos días la documentación al Jzdo de Plasencia y que si pasados unos 20 días no recibimos nada del Jzdo de Plasencia, que volvamos a llamarles para cercionarnos que lo remitan a Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2019-09-11','miguel, recibimos Angel y yo a un familiar (sobrino de Alfonso Jimenez 667-78-11-97), resto de familiares todos vienen de Madrid, no los recibimos porque son muchos. Nos comenta el sobrino, que confirma con nosotros que somos los tutores de Angel Manuel Aguado Jimenez. Nos comenta que unas parientes cercanas (tías) pretende quedarse con el capital (inmuebles, y dinero) de la familia y que les denegaron una remoción de tutoria en el juzgado. Les damos nuestros datos de contacto para cualquier duda en un futuro. Al parecer las llaves de la casa sita en Avda. Ricardo Carapeto, nº 31, 5ºc, de Badajoz, las tienen esas tías y creen que pueden estar viviendo allí. Sería interesante que enviáramos allí a Futuex, a los efectos de lo comprobara para, en caso de estar vacía, cambiar la cerradura y así cerciorarnos que nadie pueda entrar y comenzar los trámites de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SAUL'and edp.apellido1='RODRIGUEZ'and apellido2='RAMOS'),'2019-09-11','TERESA: ENVIO CONSENTIMIENTO INFORMADO VIA FAX AL HOSPITAL MERIDA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-09-11','(Amalia y Pedro). Visita realizada a Andrés en el CSS de Mérida, junto a Carmen Franco (Directora) y María Barrasa (T. Soc.). +++SE informa a Andrés de su situación legal y de lo que ello significa, así como del papel de la Comisión Tutelar en cuanto a su atención. +++Pendientes de la revisión que el CADEX realizará mañana a Andrés para valorar perfil para centro de discapacidad. El determinar el recurso adecuado para Andrés y su acceso a él condiciona en estos momentos cualquier intervención ulterior. +++Dada la identidad sexual manifestada por Andrés (con absoluta firmeza) se plantea solicitar, una vez determinado el recurso anterior, la valoración para iniciar protocolo de un posible cambio de sexo. ---------------------------------------------------- Amalia: añadir algunos datos obtenidos en la reunión : -fugado varias veces del hospital . En alguna ocasión por la carretera Montijo . Consigo averiguar que su mejor amiga, Cristina , vive sola según Andrés , en Montijo . La conoce de su paso por centros de menores . Al cumplir los 18 años vive independiente . Se quiere ir a vivir con ella entre una de sus opciones. -Revisado su Grado de dependencia , se le inició expediente en Andalucia , se ha solicitado por PIA desde menores Ctro. discapacidad. -Fumador -Conflictos con la madre y su abuela pq no aceptan su homosexualidad. Quiere comprarse ropa y quiere que sea de chica . En el CSS no se lo han permitido para evitar conflictos se valorará en Ctro. discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='MENDO'and apellido2='RODRIGUEZ'),'2019-09-11','(Amalia y Pedro)Visita a D. Pedro en el CSS de Mérida, junto con Carmen Franco, Directora. +++Se plantea la posibilidad, deseada y solicitada por el propio Pedro, de acceder a un recurso residencial para personas mayores."...Me encuentro muy cansado ya de estar aquí, depués de 15 años ingresado. Además, considero que en un centro de mayores tendré más posibilidades de poner en práctica algunas de mis ilusiones: terminar la carrera de derecho que dejé en 3º, dedicarme a temas que me interesan como la religión, a escribir sobre la maldad y el respeto en el mundo..." +++Pedimos a Carmen que nos haga llegar los informes de la Psiquiatra de Pedro para inciar los trámites. +++En principio, para evitar mayores esperas, después de hablar sobre cuáles serían su preferencias y de explicarle y entender que si dejamos la zona abierta la espera será menor, decide que no solicitemos ninguna residencia en concreto. -------------------------------------------------------- Amalia : Me pongo en contacto con Blanca( CSS )para valorar el tema del cambio de PIA . Previamente confirmo con dependencia que tiene Grado II , tiene 64 años . Solicito informes psiquiatricos. Me indica Blanca que lo ha tratado con Isabel , la médico , y tiene dudas de que se pueda adaptar a R.Mayores. Actualmente está en crónicos. Si finalmente quieren " probar " , serán ellas desde el centro las que hagan la gestion con dependencia , lo enviarán para firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2019-09-11','miguel, mando de nuevo a Escalona con la modificaciones establecidas en el informe nuevo de futuex (que ya viene firmado)e indicandole los datos de los testigos y de la familia (hermanos y padre)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-09-11','miguel, llega aceptación por el Ayto de Coria de la solicitud de prorroga que hicimos en agosto de la Plusvalía','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-08-08','miguel, remito a la oficina liquidadora de Plasencia la solicitud de liquidación del impuesto de sucesiones (unicamente podemos aportar, hasta firmemos la herencia en notaria-previa autorización judicial, como digo aportamos sentencia de incapacitación y aceptación del cargo, y fotocopia de fallecimiento y de últimas voluntades y testamento de su fallecida hermana Cristina','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-09-11','En relación con el contrato de alquiler, enviamos requerimiento de pago al arrendatario, para que en 7 días naturales desde que reciba el mismo, regularice las rentas debidas. En caso contrario, iniciaremos acciones legales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2019-09-12','(Pedro)Llamada de Catalina (675-615145) +++"...tengo ganas de ir a veros, pero no tengo nada nuevo que contaros..." +++ALQUILER: "...estoy bien en el piso. La mujer me ha ofrecido renovar el contrato por 5 años pero yo le he dicho que eso lo tendrá que hablar con la Junta..." +++PSICOLOGÍA: "El día 17 de septiembre tengo cita con Asunción. Dice que me va a dar el alta pero yo creo que sigo necesitando esta consulta...porque si no, que Psicólogo voy a tener...Le dije que antes lo hablara con vosotros...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-12','(Pedro)Conversación con Juan Carlos Álvarez, Enfermero de la consulta de Anestesiología y reanimación del Hospital Universitario de Cáceres (927-153180). +++Solicito envíen el consentimiento informado para su firma y remisión a dicho servicio. Doy la dirección de la Comisión, el correo-e y el fax. +++Indico que la documentación relativa a la tutela la tienen en la consulta de Cirugía General, Servicio de Cirugía General y Digetsiva del Hospital "Nuestra Señora de La Montaña". ////////////////////////// Ana: Sólo recibimos por fax la primera página de ambos C.I. (Anestesia Loca y General). Llamo al Serv. de Anestesiología y Reanimación (56084), hablo con Natalia-Enfermera, hablará con el otro enfermero (Juan Carlos) y nos lo volverán a enviar./////// Recibo llamada de Maribel - Admón. de la HUC del Hptal. Universitario-CC (56148). Me comunican que la Consulta Preanestesia será el día 20/09/19 a las 11 h. El electro y radiografía el día 18/09/19. La intervención será a posteriori. ***Con respecto a los C.I. dice que hay que firmarlos allí el día de la consulta. Le explico que la Tutela de Antonia es administrativa y que el respresentante legal (cargo político) no acude a los hospitales. Le explico cómo solemos proceder con otros hospitales. Lo consultará y me llamará cuando le confirmen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-09-11','-Amalia : devuelvo la llamada perdida que tenía Pedro en su tf. a la UHB HMerida ( tf 81619) . Es la psiquiatra , Virginia , conoce perfectamente el caso , fue ella la que emitió los informes en el momento de su incapacitación. Nos pregunta si tenemos información de cómo está el caso a nivel judicial , no sabe si puede darle salidas terapeuticas de un par de horas por la tarde en Mérida . Le paso la consulta a Miguel ( sección jurídica ) para ver si puede hacer averiguaciones al respecto. Verifico si tienen allí el DNI de Rubén , lo solicita la sección economica para abrir nueva cta. bancaria en otra entidad .La Caixa no acaba de solucionar el problema con su cuenta.','1');
