insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-09-04','Ana: Se solicita mediante fax al E.S.M., Informe Médico en que se haga constar evolución, estado actual y cambio en la medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-09-12','-Amalia : se envia email al Ctro. penitenciario Buenos días , revisamos nuevamente el dinero que se le ingresa en cuenta peculio , se sube a 150€/ al mes , se intentará que sea quincenal para evitar que malgaste la totalidad del dinero . Se acuerda así con la colaboración de la tía , nos indica que ya no le dejan llevarle el tabaco. Se le enviará a su tía dinero para la compra de ropa , según manifiesta Rafael ha aumentado mucho de peso. Nos ha comentado que la TV ya la ha comprado ella ,no quiere que se le reintegre el dinero. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-09-12','Ana: Hemos recibido la RESOLUCIÓN de la REVISIÓN DEL GRADO DE DISCAPACIDAD de Mª Eugenia y el nuevo DICTAMEN TÉCNICO: 75% "Retraso Mental Moderado", ya NO aparecen "Alteración de la conducta" (Escaneo ambos documentos en su Expte). *Recibimos también la Tarjeta acreditativa de Grado de Discapacidad, que habrá que enviarla al centro en el que le asignen plaza ///////////////// La semana pasada Pedro (Jefe de Sección CTAEX) envió el PIA firmado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-09-06','(Pedro)Se recibe documento aceptación PIA para su firma y devolución a Dependencia I.','2');
