insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-09-12','miguel, me llama Belén Camisón tlfno 646951392 (cuñada de José Mª Guillen Roman)y me pregunta si ya tenemos la firmeza de la extinción de condominio y le comento que no nos lo ha remitido abogacía general (la vista estaba prevista para el 17-9-19). Me envía por email de ctutelar el auto y la firmeza aceptando la extinción de condominio. ******************************************************** Reenvío a José Luis (notaria de calle Romero Leal)dicha documentación para que nos indique si es necesario o no alguna otra documentación y caso contrario nos dé fecha de firma para dicha extinción de condominio.','2');
