insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-09-12','-Amalia : LLama Junajo , TS de la UHB HUB , le han dado el alta y vuelve a la RM. Escribo a la resi para ver cómo va todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-09-12','(Pedro) Visita de Emi y Gisela. Tema gafas y visita a hijos. +++GAFAS: Emi dió una entrada de 110 euros para la compra de las gafas que no se comunicó a la Comisión, por lo que esta pagó la factura completa (unos 400 euros). +++++General Ópticos les comunicó que habían abonado un exceso que debían reembolsarles (los 110 euros) pero han acudido tres veces a la óptica y no se lo han devuelto todavía. +++++Hoy les han dicho que quizá esta tarde pueda estar resuelto el tema. Esperaremos a ver si es así, y si no nos remitirán por corre-e copia de factura y del anticipo a cuenta para reclamar ese dinero. +++VISITA A LOS HIJOS (14 y 16 años): quedamos en que, como ahora se van a ir de vacaciones, planificarán esa visita a la vuelta. Entre otros temas que hemos hablado al respecto y que propongo se expongan en dicha visita, están los siguientes: +++++Aclarar que ella no abandonó a sus hijos como parece ser que a ellos les han contado. Ella querría escribirles una CARTA explicándo que ella no los abandonó, sino que por su enfermedad no pudo hacerse acrgo de ellos. Sobre esto le digo que la escriba, pero que no puede estar segura de que la reciban. Le propongo llevarla escrita en su próxima visita y si esta se "torciese" que la puediera entregar en mano a sus hijos. +++++Plantear la posibilidad de que también ellos puedan acudir a ver a su madre en Mérida. +++++Ver posibilidad de quedar en un punto equidistante de ambas localidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-09-12','(Pedro) Visita de Gisela.Sobre el colchón. +++ Es cierto todo lo que contó Mariloli. Le propongo pedir un presupuesto de otro somier, reforzado, dado su peso y quizá sobre él aprovechar el colchón si no está tan deformado que cause molestias. Si no, pedir presupuesto también para el colchón. +++ Como asignación tiene 50 euros semanales. 200 al mes que parece demasiado. Se le puede hacer ver que el coste del colchón corre de su cuenta retiran´dole semanalmente la cantidad que se considere oportuna de su asignación semanal. P.E. 10euros. +++Nos informarán de la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-09-12','(Pedro) Ildefonso ha acudio a la Comisión y ha pedido cita para mañana. +++Le llamo por teléfono para ver de qué se trata y si se puede resolver sin que tenga que venir. No coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2019-09-13','(Pedro) Llama María, de Novaforma. +++José Fermín ha sufido un accidente como paasajero del bus urbano, al frenar éste como consecuencia de un coche que ha abierto la puerta bruscamente. Consecuencia:traumatismo nasal. +++Envía informe de Urgencias y parte de lesiones para su firma y devolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2019-09-13','Ana: Se recibe en la noche de ayer un correo de la Guardia Civil solicitando datos de filiación y Tutela de Isbel: "Adjunto remito a Vd. documento-oficio solicitandole datos de filiación de una persona, en virtud de la instrucción de diligencias policiales de esta unidad.-" Respondo al correo remitiendo toda la documentación pertinente y solicitando se pongan en contacto con nosotros. /////////////////// Llamo a la Res. de Mayores de Jaraicejo (927 33 62 21), no hay ningún responsable, dejan nota al director para que me devuelva la llamada. ////////////////////// Llamo al puesto de la Guardia Civil de Deleitoa (927 54 00 23), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-13','-Amalia: Recibo email de Reme , TS del pueblo , hace días que no está en su domicilio y no saben su paradero . Los amigos q viven con él indican q se ha ido a algún centro. Se averigua que está ingresado en la UHB del H.U. H Hablo con el TS , le dieron alta ayer , ha regresado al domicilio. Contacto con Reme para comentárselo . Solicito tb informe policial de la incidencia que queda en enviarmelo ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-09-13','(Pedro)Visita de ILdefonso. +++Trae presupuesto de dos gafas (cerca y lejos). 210 euros. Paso a Alberto para autorizar. +++FIRMA EN JUZGADO Nº 2 DE MÉRIDA (924-284258). No ha frimado el pasado 1 de septiembre por ser domingo. Dice que fue el día 2 pero que no le dejaron firmar. +++++Llamo al juzgado referido explicando la situación: inoformo a Ildefonso de que la próxima vez que ocurra esto acuda al Juzgado de Guardia POR LA MAÑANA. +++++Pregunto al funcionario del Juzgado si es necesario que se pase por allí para recuperar la firma del día 1 y me dice que no, pero que procure que no vuelva a suceder lo mismo otra vez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-09-13','(Pedro)Llamo al Juzgado de Primera Instancia nº 4 de Badajoz (924-284255). +++La solicitud de ingreso involuntario ha entrado en este Juzgado con el nº de PROCEDIMIENTO 751/2019. +++ Me atiende Rosa: hoy mismo le ha pasado al Médico Forense el caso para que le haga una visita. +++++Comento la situación en la que se encuentra Dª Rosario y pido que, en la medida de lo posible, agilicen los trámites.','2');
