insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-09-13','Ana: Recibo mediante fax, Informe de Seguimiento de Psiquiatría (Dr. Miguel Medina Bermúdez) de Juan. No hay cambios con respecto a los anteriores informes. Escaneo y guardo en el expte. /////////// Recibo llamada de Juan, de nuevo se queja (como en anteriores llamadas en los meses de julio y agosto) de que "se violan sus derechos civiles", "vive por debajo del umbral de la pobreza", "los jurídicos no hacen nada y tiene que llamar a los bancos para solicitar los extractos bancarios de las administraciones de lotería" y además se queja de que ha ido a visitarle, Teresa, Delegada Tutelar y dice que ***no quiere que vaya nadie. Por último dice que necesita dinero para varias cosas y pide que se le autoricen 80€ para el lunes. ***Se lo paso a Alberto, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2019-09-12','Ana: Recibo llamada de Pilar Sánchez, Hogar S.Vicente de Paúl por varias cuestiones: 1- Marga quiere cursar estudios en la EPA, firmará ella misma la solicitud (preinscripción) si tiene plaza nos enviarán la matrícula para la firma del D.Gerente. 2- Van a solicitar una beca al SEXPE por el curso de formación de cocina que ha finalizado Margarita. Nos enviará el modelo de solicitud, una vez tenga la firma del D.Gerente se lo enviaré por correo certificado. // Una vez recibido el correo, cumplimento el documento y recabo la firma del D.Gerente, pongo el oficio para Registro de Salida y adelanto escaneada por mail la solicitud a Pilar.','2');
