insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-13','Ana: Carmen Ferrer, Secc.Prog.Asistenciales de Salud Mental, acude a comunicar que se le ha concedido plaza en el CRR de Plasencia a Mª Ángeles. //// Llamaré al CRR para organizar el día de la entrevista inicial que realizan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-13','Ana: Tras conversación mantenida entre Pedro, Jefe de Secc. CTAEX, y Miguel Ángel Santano Árias, Hpta. Universitario de CC (56014) acuerdan que volverán a llamarnos a lo largo de la mañanaa en relación a Intervención Quirúrgica pendiente de Antonia y los correspondientes C.I. //////////////// Al final de la mañana vuelvo a llamar al Hptal. Miguel Ángel me comunica que no nos ha llamado porque el Dr. Cano, Jefe de Serv. no le ha dicho nada todavía. En cuánto éste le comunique algo al respecto nos llamará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-09-13','Ana: Recibo llamada de Sonia Bernabé, ASINDI, como Justo está inscrito como Demandante de Empleo en el SEXPE, le han llamado de la Fundación Sorapan de Rieros (Entidad Colaboradora del SEXPE) para citar a Justo el día 16 a las 13 h. para una formación de 17 h, que engloba tanto sesiones individuales como grupales, en distintos días. El primer día al menos le acompañará Blanca, la Psicóloga de ASINDI. Le han explicado que tiene que aportar documentación, cuando se lo den nos lo harán llegar. Pregunta si hay problema para ello, le explico que a priori, siendo un organismo oficial no lo hay. En cuanto a las firmas, las de asistencia como tal (para justificación de la entidad ante el SEXPE) le digo que puede firmar Justo, en cuanto a otro tipo de documentos (p.ej. autorizaciones) deberán remitírnolos a la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-09-02','Ana: Recibo por mail del Ayto. de Romangordo, el Certificado de Ingreso en Residencia de Guillermo, que solicité previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-09-16','miguel, me llama Mely para preguntarme si ya tenemos el único documento que falta para la firma de la hermana del tutelado Pilar Serrano Palacios. Le digo que llamaré el lunes y la llamaré a ella con el resultado ******************************************************** Llamo al Jzdo 1º instancia nº4 de Plasencia (Matilde) me confirma que ya remitió al Rgtro de Albacete y ha comprobado que ya está inscrita nuestra tutela. Me indica que pidamos Certificado literal de inscripción de tutela (lo solicito hoy y una vez me llegue lo remitiré a la notaria) ***************************************************** Llamo a Mely comentandole que solicitamos hoy el certificado literal de tutela al registro civil de Albacete y envío email a notaria con copia a Mely, indicandoles que en cuanto nos lo envíen se lo remitiremos vía email. En principio a falta de verificar el borrador de herencia (con las modificaciones indicadas a la notaria)estaría todo para su firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-09-16','miguel, localizo qué Juzgado está llevando el caso. Confirmado que lo lleva el Juzgado de instrucción nº3 de Mérida, siendo las Diligencias Previas las nº 387/19. Conforme me indican Amalia y Pedro intento hablar sin éxito para informar de la localización de procedimiento y juzgado a la Psiquiatra Maria (ext 85825). Seguiré intentandolo ***************************************************** Pedro habla con la Guardia Civil de Valverde de Mérida (924-321831) y le confirman que ha habido diligencias previas de otros procedimientos que son conocidos por los juzgados de Mérida, aunque no le concretan cuales.Sí le confirman que ninguno de agresiones como este último cuyas diligencias previas son las 154.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2019-09-16','Ana: Envío por CORREO CERTIFICADO a Pilar Sánchez -Hogar S. Vicente de Paúl, la solicitud de BECA del SEXPE debidamente firmada y sellada por el D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-09-16','Ana: Llamo a Adela, PNC (924 00 59 95), me había dejado una nota en mis vacaciones, en relación a la PNC de Joaquina, pero tras varios intentos no consigo contactar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2019-09-16','Ana: Recibo llamada de Teresa, Novaforma (662 337 460), pregunta si se ha enviado ya los documentos firmados relativos al accidente de José Fermín./// ***Justo acaban de bajarlos de la Firma. Se lo adelanto escaneado por email. Le enviaremos el original por correo certificado./// Pongo oficio para registro de salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-09-17','(Pedro) Conversación con Mónica (21849). +++Ya ha tramitado el PIA a Gerencia y a Sección de Discapacidad de Mérida (ayer por correo-e y ordinario). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Converesación con Carmen Gallego, Jefa de Sección de Dependencia I (927-004339). +++Acudirán a hacer la valoración la semana que viene: +++++En cuanto a Dª Mª Eugenia M. C., la visita de Dependencia para su valoración va a ser en la siguiente fecha: MARTES, 24 de SEPTIEMBRE de 2019. Hora: 09:30 Lugar: Hostal La Rosa. C/. Sanguino Michel nº 8, de Cáceres. Teléfono: 927-215206 TÉCNICO PIA: ANABEL Teléfonos PIA: 927-006788 y 689-575711 +++Contacto con Toni (FUTUEX). Acudirá a la valoración PIA Virginia, Delegada Tutelar.','2');
