insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-09-10','-Amalia: Atiendo en el edificio SARA a Fco( tf . 643052527) y su novia , Laura ( 622546412,lauratorneiro23@gmail.com). Vuelve a solicitar su sentencia de incapacitación, lo hablo con Pedro , el día de la visita le entregué la sentencia inicial en la que nombraban a los padres. No ve mal que la tenga pero no sé para que la quieren y no le envio nada más . Quiere ir al jdo. para remover el cargo. Aqualia enviará la factura de 50€ para q lo abonemos via transferencia. Solicita otro extra de 50€ para taxi , no se le concede.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-17','Ana: Llamo al CRR-Plas. (927423978), Paula, T.O., me dice que tiene que cuadrar agenda con su compañera. Me llamarán o escribirán para concretar día de la primera entrevista con Mª Ángeles. //// Recibo correo de Paula, T.O., plantea mañana miércoles o pasado mañana a las 10:30 h. ///////////////// Llamo a Toni-Futuex (924 49 19 14) me informa de que precisamente en la última visita de Virgina el pasado día 4, Mª Ángeles manifestó que no quería irse a ningún centro, se notaba muy influenciada por el padre, que se niega rotundamente a que "se lleven" a su hija. ***Acordamos que mañana acudirán Virgina y Gloria a visitarles de nuevo y plantearles una visita al centro e intentar convencerles de la necesidad de que asista al mismo. Como último recurso habría que plantearles la realidad, si no ingresa en el CRR de forma voluntaria, habrá que proceder al ingreso involuntario en el CSS. ////////////*Llamo de nuevo a Paula (CRR) explicando la situación, se muestran flexible para que puedan visitar el centro en cualquier momento a lo largo de la mañana de mañana o pasado. ///////////// Acude Eva, de Salud Mental (Unidad de Progr. Asistenciales), para preguntar por el ingreso de Mª Ángeles, le explico cómo está la situación, en cuanto haya alguna novedad iré a comunicárselo. /////// Llamo a la hermana de Mª Ángeles - ROSARIO (648 644 520), atiende la llamada Josechu, amigo (ex-pareja) la tenía acogida en casa. Me explica que tiene el teléfon porque ella está ingresada en Psiquiatría del Hptal. Clínico de Salamanca por un brote de Esquizofrenia. *Le ha pedido piso tutelado y le ha apuntado a una Asociación de P. con Enfermedad Mental. Josechu me facilita su contacto:636097935 // *Dice que el padre tiene problemas con la bebida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-09-17','++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Converescaión con Carmen Gallego, Jefa de Sección de Dependencia I (927-004339). +++Acudirán a hacer la valoración la semana que viene: +++++En cuanto a Dª Mª Eugenia M. C., la visita de Dependencia para su valoración va a ser en la siguiente fecha: Martes 24 de septiembre de 2019 Hora: 09:30 Lugar: Hostal La Rosa. C/. Sanguino Michel nº 8, de Cáceres. Teléfono: 927-215206 TÉCNICO PIA: ANABEL Teléfonos PIA: 927-006788 y 689-575711 +++Contacto con Toni (FUTUEX). Acudirá a la valoración PIA Virginia, Delegada Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-09-17','(Pedro)Conversación con Soraya (CSS de Plasencia,24104). +++La alternativa que se planteó hace unos meses de un "alta parcial" no parece ya viable. +++En estos momentos, la opción que se está barajando, y con la que Soraya dice que Jairo está de acuerdo, es la de un piso supervisado. +++NECESIDAD DE subcomisión: va a hablar con su Psiquiatra para valorar la necesidad de la Subcomisión o bien plantearlo como una visita en la que el Psiquiatra quiere que estemos para partcicipar de la decisión.','2');
