insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-11','-Amalia: le dan el alta en la UHB , ha estado unos días ingresado .En su informe de alta hospitalaria ( guardado en su expediente ) se indica que fue un intento autolítico , solicita que se le ingrese en un centro inmediatamente o " me corto las venas " . Sin embargo , los amigos con los que convive en su casa manifestaron a la TS del pueblo ( Reme ) que se fumó un porro demasiado grande y se puso malo. Según refiere la auxiliar de SAD , en la casa hicieron una fiesta, la casa estaba en mal estado , con condones tirados por el suelo , restos de bebidas ...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-09-17','TERESA: LLAMO A COSTANZA PARA CONVOCAR SUBCOMISION Y ME COMENTA QUE HA ESTADO INGRESADA LA SEMANA PASADA, QUEDA EN CONOCARLA PARA EL MES DE OCTUBRRE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-09-17','TERESA: LLAMO A LA TS DE SALUD MENTAL DEL CENTRO DE SALUD PARA QUE HAGA INFORME SOCIAL Y ME COMENTA QUE NO TIENE INFORMACION PARA PODER HACERLO Y QUE ELLA NO PUEDE SALIR A DOMICILIO, LE PIDO QUE AL MENOS ME MANDE INFORME DEL PSIQUIATRA DE LA ULTIMA CONSULTA. ME INDICA QUE LO ENVIARA POR FAX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-09-17','-Amalia : Tras reunion con Inma TS del pueblo a finales de agosto se acuerda : -S.decesos: confirmado con Sta. Lucia. ( la madre no tiene seguro , al ser unico heredero tendria que abonar el sepelio él llegado el día. Madre en proceso de incapacitación) -Ingresos PFHC + P. ORFANDAD , total 530€ gastos de estanco, tienda , hipoteca al dia . Suministros de la casa , ctro de dia , OAR .. haydeudas pendientes. -Nivel juridico. Queremos solicitar ampliar la incapacit. a tutela , he pedido I.medicos y sociales a la TS . con el objvo de solicitar Ctro discapacidad , tiene 45 años . Solicito autorizacion de venta de las dos casas que tiene , se encargará Miguel , contactará con la inmobiliaria Colón.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-09-17','miguel, nos citaron para el día 17/9/2019 a comparecencia, que según nos comunicaron aye vía fax, queda suspendida por el traslado previo del expediente para su contestación al Ministerio Fiscal. Remito vía email a Curro para su constancia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2019-09-17','-Tiene un inmuble en avda. Ricardo Carapeto , 31 , hay que averiguar si está ocupado por alguien pq se ha puesto en venta. Se pido a los juridicos que lo pidan a la policia local de Badajoz. Tiene 70 años y está ingresado en un centor residencial con deterioro cognitivo , en " Los Olivos " en Mérida . Dirección : En la nota simple dice que tiene su acceso por el número 31, piso 5º, letra c, Avda. Ricardo Carapeto, de Badajoz.','2');
