insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-09-12','miguel, nos comunica Curro comunicación del Jzdo de Cáceres nº1 indicando que remitirán la solicitud de gastos extraordinarios al Juzgado de Plasencia (lugar de residencia de Ceferino). Solicito al Juzgado de Cáceres nº1 trasladen junto al expediente solicitud de videoconferencia cuando nos citen','2');
