insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2019-09-13','miguel, nos llegó a finales de Agosto Decreto del Juzgado de 1º instancia e instrucción nº5 de Badajoz, donde nos indicaban que nos daban un plazo de 10 días a partir del 2 de septiembre para contestar a un procedimiento de disolución de herencia. Envío fax hoy al Juzgado de 1º instancia e instrucción nº5 de Badajoz, indicando que no podemos contestar a la demanda porque carece de abogado y procurador, con lo que solicito nombren uno de oficio, al tiempo que solicito videoconferencia desde Mérida para cuando nos citen a comparecencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-17','miguel, a petición de Pedro JS comunico vía fax al Juzgado de 1º instancia e instrucción nº1 de Villafranca de los Barros a los efectos oportunos, certificación de la Residencia de Mayores Alcalde Antonio Zapata de los Santos de Maimona, lugar en el que Don Juan Antonio Sánchez Santiago ha ingresado de forma voluntaria. Quedamos pendiente del si el juzgado a parte del procedimiento de pasarlo de modificación de capacidad (curatela a tutela) resuelve si continúa o no el procedimiento de solicitud de ingreso involuntario nº 547/19.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-13','miguel, a petición de Pedro JS comunico vía fax al Juzgado de 1º instancia e instrucción nº1 de Villafranca de los Barros a los efectos oportunos, certificación de la Residencia de Mayores Alcalde Antonio Zapata de los Santos de Maimona, lugar en el que Don Juan Antonio Sánchez Santiago ha ingresado de forma voluntaria. Quedamos pendiente del si el juzgado a parte del procedimiento de pasarlo de modificación de capacidad (curatela a tutela) resuelve si continúa o no el procedimiento de solicitud de ingreso involuntario nº 547/19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2019-09-17','Ana: Recibimos por mail un comunicado de Mª Jesús Gómez, TS de la Mancomunidad Comarca de Trujillo. Informa de la denuncia que interpusieron ante Mª Isabel y el deseo de ésta de cambiar de Resid. a Plasencia (Guardo en el Expte.) //// Llamo a la Resid. de mayores de Jaraicejo, José Villegas, Supervisor, narra una versión de los hechos, dice que fue un enfrentamiento mutuo entre ambas señoras, según testigos, motivado e iniciado por la otra Sra. (la denunciante), al parecer Isabel mantiene una relación con el hermano de la primera y esta sra. no lo acepta. *"En el centro Isabel no presenta mal comportamiento. Sí que tiene mal carácter cuando se enfada, pero nunca hemos tenido ningún problema con ella" expresa. La denunciante alguna vez ha acusado a Isabel de acoso, pero José dice que no es real, que el hermano acude a buscarla a la residencia y la relación es buena, consentida por ambos. /// José me informa asimismo de que precisamente hoy ha ido a visitarla Gloria, Delegada Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-16','(Pedro)Conversación con Miguel Ángel Santano, Admvo.Consulta de anestesia del H. Universitario de Cáceres (56014). +++Tiene el consentimiento informado preparado para enviárnoslo, pero está a la espera de que el especilista le indique los pasos a seguir, porque cabe la posibilidad de que sea intervenida en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-09-17','-Amalia : Nos escriben desde la residencia , vuelve a fugarse : Buenas tardes, El residente continúa sin volver al centro. Esta mañana llaman desde un comedor social para comunicar que ha ido a desayunar allí y estando allí ha llegado su cuñada a recoger comida y han discutido, por lo que el residente se ha ido. Llamamos nuevamente al comedor social (924221773) por si está allí poder llamar a la policia o a un taxi para que se venga al centro pero nos comunican que se ha ido y no ha vuelto. Hablo con su cuñada Manoli y me dice que ella ha pedido al comedor social que no le den de comer, en tono muy enfadado. Le informo de la situación. No volvemos a tener noticias de donde puede encontrarse durante la mañana. Amalia, te he llamado pero no he conseguido contactar contigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-09-17','-Amalia : Nos escriben desde la residencia , vuelve a fugarse : Buenas tardes, El residente continúa sin volver al centro. Esta mañana llaman desde un comedor social para comunicar que ha ido a desayunar allí y estando allí ha llegado su cuñada a recoger comida y han discutido, por lo que el residente se ha ido. Llamamos nuevamente al comedor social (924221773) por si está allí poder llamar a la policia o a un taxi para que se venga al centro pero nos comunican que se ha ido y no ha vuelto. Hablo con su cuñada Manoli y me dice que ella ha pedido al comedor social que no le den de comer, en tono muy enfadado. Le informo de la situación. No volvemos a tener noticias de donde puede encontrarse durante la mañana. Amalia, te he llamado pero no he conseguido contactar contigo.','2');
