insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2019-09-17','Ana: Llamo a Toni-FUTUEX (924 49 19 14), ya hicieron la visita a Ceclavín, tienen pendiente enviarme informe al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2019-09-18','-Amalia : he solicitado a Futuex que quede con este señor para ver la casa . Hola Amalia, te cuento un asunto relativo a JUAN CARLOS RUBIO GALAN, y cuando tú puedas me llamas. Como recuerdas hablamos de poner la casa en alquiler hasta que te dieran la autorización judicial para la venta. Pues bien, hay una persona que vive aquí que me ha manifestado su intención de alquilar la casa con derecho a compra. Se trata de SAntiago Bravo Gago, su teléfono es 621012579. No ha podido ver la casa, pero ya te digo que está interesado. La semana pasada la auxiliar de tutela que vino, a instancias mía fue a ver la casa con Juan CArlos, pero no sé nada más. De cara a que no se fuera este "posible inquilino" es por lo que te he puesto el asunto como urgente, ya sabes que la situación económica de CArlos es muy precaria. Muchas gracias','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-09-18','(Pedro)Llamada de Teresa (618-819511), hermana de José María. +++Pregunta por cómo va el tema de la asignación del centro. Le informo de que sigue en la lista de espera de CRR. +++Hablar con Futuex para que lo visiten y valoren situación y compra de microondas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-09-17','Ana: Llamo a Adela, PNC (924 00 59 95), dado los problemas con el cambio de D.Gerente, como titular de la cuenta (Liberbank) para que Joaquina no deje de percibir la PNC, no introducirá en el sistema la datos de la tutela hasta que el D.Gerente conste ya como titular de la cuenta. ***Le avisarán a las compañeras de la Secc. Ecca. cuando el cambio sea efectivo. *El cierre de nóminas lo hace el día 5 de cada mes o antes (según cuadre en la semana)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-09-18','Ana: Recibo llamada de Lucía, Acompañante (605 15 13 70), me comunica que Consuelo ayer por la tarde "tuvo una crisis", no es la primera vez que le ocurre estando en la residencia. *Por otra parte, evoluciona bien, utiliza un andador que le han prestado en la Resid. Se lo indicó el traumatólogo en la última consulta. Éste se enfadó porque la habían puesto a caminar antes de que él lo dijera. **Consuelo se muestra un poco ansiosa porque no quiere seguir más tiempo en la residencia, explico a Lucía que la idea es que pueda volver al CRR, cuando ya le indiquen que necesita sólo las muletas, contando con su apoyo en algunos momentos del día para aseo, acompañamiento y otras ayudas que pueda necesitar. ///////// Llamo a Victoria Rajo, Directora CRR-CC. Tras valorarlo con la psicóloga del centro, me comunica que no hay ningún problema, que si se le pone acompañamiento unas horar al día (acordamos 4-5), Consuelo podría volver, eso sí, la persona que asista tendrá que firmar un acuerdo de confidencialidad. Enviarán un correo con la propuesta de horarios de acompañamiento y yo les confirmaré el día exacto del regreso (aproximadamente en 15 días, pues además hay que preavisarlo a la residencia).//////// Comunico esta decisión a Carmen y Eva, Ud. de Rec. Asistenciales- Salud Mental, a quienes también les parece bien. Toman nota. //////// Llamo a Pilar Cerrillo, TS - Res.San Jorge (618 908 506), tiene una reunión, acordamos volver a hablar mañana. // Llamo a Mariola, Res.San Jorge (927 62 80 10), comunica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JACINTA'and edp.apellido1='RUBIO'and apellido2='BRAVO'),'2019-09-18','Remitimos a Liberbank de Valdemoro (María Teresa, mtmorana@liberbank.es, 918083769), documentacion relacionada con la herencia de su hermano y a su sobrino Marcos (marcos.rubiog68@gmail.com), el número de cuenta para que le transfiera el importe que se le adjudica de esta herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-09-18','miguel, tras conversación con el Juzgado de 1º instancia e instrucción nº2 de Plasencia y tal como me confirmó Matilde, indicandome que el registro civil, donde debemos aparecer esta Comisión Tutelar de Adultos como tutores, es Albacete. Me confirma que ya ha comprobado ella que le han inscrito nuestra tutoria y portanto que ya podemos solicitar Certificado literal de nacimiento. ******************************************************** Remito al Registro Civil de Albacete Certificado literal de nacimiento. Cuando me llegue hay que remitirlo a la notaria de Villajososa, ya que es el último trámite para que se pueda firmar la herencia.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2019-09-18','-Amalia : nuevo ingreso en UHB por descompensación. Email de Ap3 : Buenos días. Envío email para informar de una incidencia grave de la usuaria de Residencia RAL, Felisa Bruno Saavedra. El pasado viernes, cuando llegó de Centro Ocupacional a Residencia a medio día, comenzó a ponerse agresiva tanto verbal como físicamente con los profesionales de residencia, llegando a agredir a una trabajadora, provocándole una distensión muscular en una muñeca y un derrame en una rodilla. Acudió el 112 y al final consiguió lo que quería, que era ingresar en el hospital, en la unidad de hospitalización breve. Está allí desde el viernes por la tarde. El sábado una trabajadora fue a llevarle ropa. Nos comunican por teléfono ayer, que se encuentra tranquila y que a lo largo del día de hoy se le asignará psiquiatra. Mencionar que ha estado de vacaciones junto con otros compañeros, en Chipiona del 2 al 8 de septiembre, empeorando su comportamiento , a medida que pasaban los días allí, insultando y amenazando tanto a compañeras como a las trabajadoras que acompañaron al viaje. Continuaremos informando. Saludos.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2019-09-18','-Amalia : Nos escribe la hna , dice que su hna se queja de que no la atendemos bien , q necesita que la vea un medico especialista. Le pregunto al director del CRR y no le da mucha credibilidad , aún así va a solicitar a su medico de cabecera una analítica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-09-18','miguel,llamo a la notaria de romero leal y ni Jose Luis ni Ana dicen tener la documentación para poder firmar la Extinción de Condominio que ya nos ha autorizado el juzgado. ******************************************************* Llamo a Belén Camisón para en cuanto pueda vaya a la notaria y hable con la persona a la que le dejó la documentación (comenta que fue a Ana) y que una vez lo tengan todo y pongan fecha de firma nos avise para asistir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-09-17','miguel, remito al Ayto de Plasencia, solicitud de prórroga del pago de Plusvalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-09-18','miguel, tras recibir vía email de Javier Leal de Liberbank para conocer el estado del procedimiento, le contesto que teníamos comparecencia ayer día 17/9/2019 que fue suspendida porque le iban a dar traslado al Ministerio Fiscal para que informe, una vez lo cual el juzgado resolverá lo que considere oportuno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANTONIO'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-09-18','CORREO Se remite autorizacion para dar el CCC en las farmacias que trabajan con Mensajeros de la Paz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-09-18','CORREO Se remite, al CADEX de Cáceres, solicitud de reconicimiento del grado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-09-18','Ana: Recibo llamada de Isabel Cuesta- Equipo de Menores de CC (927 00 43 60), llama porque su compañera, Raquel Galán (927 00 43 60) que es quién lleva el caso no está. Pregunta por el caso, dice que Santiago Eduardo ya ha cumplido la mayoría de edad y por tanto ya ellos no pueden hacer nada. Han recibido una carta diciendo que ya no cumple los requisitos para seguir percibiendo la pretación y por tanto se la rescindirán. **Reside en ASPACE. Están preocupados con el pago del centro y la falta de ingresos si no se le solicita la prestación correspondiente. **No cuenta con apoyos familiares de ningún tipo. **Pide que enviémos la Aceptación del cargo por fax a la A/A. de La Jefa de Sección de Menores: Emilia Paz Pérez Aparicio. ///////////// Hablo con Juan Pedro, Admtvo. CATEX, la aceptación es de hace 2 días (16 de septiembre), se la enviará por fax. Tiene ya preparados y registrados los oficios para solicitar la documentación pertinente. //////////////////////////////////// Llamo al CAIS-CC (927 62 00 00), me intentan pasar con 2 ext. diferentes, pero no obtengo respuesta. Llamo a Miguel Martín (927 62 10 12) varias veces, pero comunica. ///////////////// Llamo a ASPACE (927 23 47 68), me pasan con Amor - T.S., le comunico que el cargo ha sido aceptado hace 2 días (16/09/19), estamos en fase de inventario, no obstante vamos a intentar agilizar trámites (solicitud de prestaciones/pensiones). Le explico brevemente la estructura de la CTAEX y el modo de proceder, pues lo desconocía, y le facilito datos de contacto (direcciones de correo y algunos nº de telef.) Intentará facilitarme por mail toda la información/documentos de que disponga en el expte. Hablará con la Gerente de ASPACE al respecto. //////////////// Si conseguimos el nº de cuenta bancaria y podemos añadir como Titular al D.Gerente antes de que finalice este mes, le solicitaré PFHC, para que tenga efectos de 1 de octubre y que no pase mucho tiempo sin ingresos. A posteriori solicitaré la PNC-Invalidez, pues ésta puedes tardar hasta 3 meses en resolver. ***Le corresponde Complemento ATP (Tiene discapacidad y Grado III de Dependencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2019-09-11','TERESA: ENVIO PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2019-09-18','TERESA: ENVIO PFHC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-18','-Amalia: escribe Reme , TS de Puebla de la Calz. Ha estado en despacho Bartó y quiere ingresar en centro . La llamo pero está atendiendo , le escribo el siguiente email : Buenos días , Te he dejado nota , llámame cuando puedas . Te adelanto las gestiones que he realizado : -He consultado en dependencia y tiene un grado III , y por PIA tiene aprobado 70 horas de SAD . Por un lado , hay que solicitar revisión PIA ,indicando CRR , hay un modelo , sólo hay que marcar la opción y tendría que firmarlo él . -Por otro lado , hay que solicitar al Equipo de Salud Mental de Montijo (tf 924454950) que le den una cita y valoren la posibilidad de derivarlo a CRR ( Centro Residencial de Rehabilitación ) . Si lees su informe de alta hospitalaria, en el mismo indican que tiene que pasar por este equipo , ellos proponen derivación a CRPS , en este caso , estimo que el recurso es insuficiente y no es residencial , que es nuestro objetivo ahora mismo. -Por su edad , 55 años , podría cumplir requisito para acceder a Centro Residencial de Mayores , pero por su problemática conductual no lo van a admitir. -Centro de discapacidad no da a lugar , puesto que su discapacidad es por enfermedad mental ( esquizofrenia ) -Descarto también Comunidad Terapeútica por consumo de drogas , en su informe médico se indica que el consumo es sólo puntual. Todo ello partiendo de la base de su voluntariedad para el ingreso , no tenemos respuesta del juzgado con respecto a la solicitud que se presentó para ampliar su incapacidad. Además , aunque estuviese incapacitado totalmente ,en el CRR se exige igualmente la voluntariedad para el acceso , si él no quiere ni con una tutela absoluta podríamos solicitarlo . Dado que la sentencia actual es una curatela , exclusivamente en el ámbito de administración de su patrimonio , no podemos hacer estas gestiones desde la Comisión. Tendrías que ponerte en contacto con el ESM y solicitar la cita para Bartolomé y explicarle que valoren ingreso en centro residencial ó indicarle a él que se acerque . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2019-09-18','-Amalia : me llama la madre de J.Mª , Julia tf 688381229 , le comunican desde el CTro. penit. psiquiatrico que no está recibiendo dinero en peculio. Escribo email a sección eco para que abran cuenta y le ingresen dinero , ya se solicitó pero creo que no se ha gestionado.','2');
