insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2019-09-19','Ana: Recibo correo de Felisa Custodio, en salida a Cáceres a una actuación musical, Rosario chocó accidentalmente con la fachada de una vivienda provocando desperfectos, puesto que el CAMF no tiene seguro que cubra esto, nos enviarán la factura de la reparación que reclama la vecina de CC. //////// *Hablado con Alberto, Jefe Secc. Ecca. Rosario tiene dinero para afrontarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUILLERMO'and edp.apellido1='MUÑOZ'and apellido2='PALLERO'),'2019-09-19','miguel, Ana TS me da teléfonos de contacto de familiares para intentar localizar documentación a efectos de poder hacer Declaración de Herederos y posterior Herencia de la madre fallecida Doña Pilar Pallero Moreno. ******************************************************* Llamo sin éxito a la hermana Manuela Muñoz Pallero tlfno 916381597 (dejo mensaje en su contestador que nos llame) y a su cuñado Jose María Gutierrez Bustamante tlfno 618783686(que no oye). Del resto de hermnaos Jesús y Antonio Muñoz Pallero no tenemos teléfonos de contacto. Intentaré hablar con la hermana en posteriores días','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2019-09-19','(Pedro)Nueva llamada de Cándido (637-193320). +++Demandas: tejado, TV, puerta de la cocina. +++Le planteo la conveniencia de pensar en buscar piso de alquiler. Argumentos en contra de ello: le da pena dejar su casa y además tendría que pagar alquiler y casa. Le planteo la posibilidad de venderla una vez se haya trasalado. Se muestra reflexivo con la propuesta. +++En conversaciones anteriores también se le planteó la alternativa de un residencia, pero se negó rotundamente a esa posibilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='CABRERA'and apellido2='MUÑOZ TORRERO'),'2019-09-19','(Pedro). PENDIENTE DE RECIBIR LA FIRMEZA DE SENTENCIA, solcitada tanto por teléfono (numerosas llamadas), fax y mediante oficio. +++FAX: 12-06-2017///18-09-2017///23-01-2018///23-05-2018/// +++Último OFICIO: del 28 de mayo de 2019. +++LLAMADA DE HOY: hablo con Antonio, funcionario del Juzgado de 1ª Instancia e Instrucción nº 1 de Villanueva: "...LAS TENGO YA PREPARADAS. OS LAS ENVÍO YA MISMO..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2019-09-19','Ana: Respondo al correo de Mª Jesús, T.S. de la Mancomunidad de Trujillo (ssb32mancomunidadcomarcatrujillo@hotmail.com), le informo de las comuniciaciones/gestiones realizadas en relación a la denuncia que interpuso la vecina de Jaraicejo. *En cuanto a la demanda de cambio de centro de Isabel a la Res. San Fco. de Plas., le indico que ya hace meses que se envió una circular a los Centros sobre cómo proceder. No obstante, le informo que tras haberlo consultado (SIDEX) se hizo la solicitud (Revisión PIA) en 2016 y a día de hoy está en trámite. //*Por otra parte le solicito copia del DNI actual, pues la que tenemos en el expte. es de uno caducado //////////////////// NO TENEMOS EN EL EXPTE. LA RESOLUCIÓN DEL GRADO DE DEPENDENCIA. EN SIDEX: GRADO II, Fecha de Resolución: 07/10/14.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-09-19','Ana: Consulta en SIDEX: la Plaza en ASPACE de S. Eduardo la tiene concecida por Resolución de 13/05/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-09-19','-Amalia: email de Aprosuba 3 en respuesta a mi correo preguntado por el estado de Felisa que sigue ingresada en la UHB . Buenos días Amalia. Desde residencia han contactado con su psiquiatra. Le han asignado la misma doctora de la vez anterior , Doctora Gómez. Comenta que está mejor que la vez anterior, que sigue con las mismas llamadas de atención: Quejas somáticas continuas. Simulación de embarazo.(distorsión de la esfera sexual) Demanda continúa de actividades y de atención del personal. En definitiva , actitud caprichosa y egoísta. No quiere volver a residencia porque manifiesta que hay mucha gente mayor. Sospechamos que lo que le da miedo es regresar a residencia después de su conducta el viernes para no enfrentarse a las consecuencias. No le va a modificar la medicación, simplemente le va a adelantar el Xeplión a los 21 días en vez de a los 28, pues se ha detectado en residencia que se empieza a alterar dos o tres días antes de que le toque la inyección. Se ha quedado en hacer una visita desde residencia para que no tenga miedo a la vuelta, y de esta manera no rechace el volver. Se le va adelantar la visita que tiene con Leopoldo Elvira, se le ha solicitado que nos atienda en un espacio de tiempo sin que esté ella delante para que podamos verbalizar su conducta adecuadamente. AMALIA, SERÍA MUY CONVENIENTE UNA VISITA TANTO A FELISA COMO AL RESTO DE USUARIOS. A ANTONIA PÉREZ SE LE HA VISITADO YA? ESTAMOS PREOCUPADOS POR SU BIENESTA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-09-19','-Amalia : respuesta a su petición de visita : Buenos días , el día 26 de este mes viene Pedro , tenemos tres visitas a tutelados nuevos , entre ellos contamos con la de Antonia . El problema es que no sé si la familia va a colaborar . Te contaré después de la misma . No creo que ese día nos de tiempo pasar por residencia , si fuera posible acercarnos te avisaría en la misma mañana . Si no , quedaremos para otra fecha y me acerco a residencia para ver al resto de usuarios .','2');
