insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-19','-Amalia : ante la imposibilidad de contactar via tf. con Reme le escribo el ss email : Buenos días Reme , te he vuelto a llamar varias veces pero no es posible contactar . No sé si habrás podido leer mi email de ayer. Me indicabas en tu correo que Bartó tiene un amigo en Almendralejo y que podría querer ir allí , de qué tipo de recurso estamos hablando ?? Revisando todas las incidencias con Bartó , hay una de su Equipo de Salud Mental de 2017 , en ella indicaban que no veían factible la opción del CRR . Tendríanque volver a valorar esta opción. Solicité a la parte económica de la Comisión datos actualizados de sus cuentas. Sus ingresos son de 720€ ( P. orfandad ) +588 €( PFHC) . Ahorrado en cuenta tiene en Banco Santander 7000€ y en Banca Pueyo 4900€ . Para evitar que sus " acompañantes " le quiten el dinero no se le está dando mucho dinero. Otra opción que se podría valorar es ingreso voluntario en Residencia de Mayores a nivel privado . Alguna que ronde los 1000€/ mes y que lo aceptara,sería posible. Un saludo . La trabajadora Social de CTAEX','2');
