insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-19','-Amalia : ante la imposibilidad de contactar via tf. con Reme le escribo el ss email : Buenos días Reme , te he vuelto a llamar varias veces pero no es posible contactar . No sé si habrás podido leer mi email de ayer. Me indicabas en tu correo que Bartó tiene un amigo en Almendralejo y que podría querer ir allí , de qué tipo de recurso estamos hablando ?? Revisando todas las incidencias con Bartó , hay una de su Equipo de Salud Mental de 2017 , en ella indicaban que no veían factible la opción del CRR . Tendríanque volver a valorar esta opción. Solicité a la parte económica de la Comisión datos actualizados de sus cuentas. Sus ingresos son de 720€ ( P. orfandad ) +588 €( PFHC) . Ahorrado en cuenta tiene en Banco Santander 7000€ y en Banca Pueyo 4900€ . Para evitar que sus " acompañantes " le quiten el dinero no se le está dando mucho dinero. Otra opción que se podría valorar es ingreso voluntario en Residencia de Mayores a nivel privado . Alguna que ronde los 1000€/ mes y que lo aceptara,sería posible. Un saludo . La trabajadora Social de CTAEX','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-09-19','-Amalia: se pide a FUTUEX que le acompañe a comprar un microondas ante la insistencia de la hermana. Futuex nos contesta en el sentido que lleva meses sin querer que entren en su domicilio y que está gestionando muy mal el dinero. Se le subió recientemente su asignación económica. Él tiene capacidad para comprarlo solo y pagarlo de su asignación. email de FUTUEX : Hola al respecto de lo que me dices de Valle Simón del microondas, te cuento, justo ayer estuvo Sonia (está haciendo el seguimiento de algunos de Teresa, por compensar los seguimientos) y no nos deja entrar en la casa.. pero no solamente a ella, a Teresa, este verano tampoco le dejó ... cosa que nos escama un poco, podemos acompañarle a lo del micro pero intentando precisamente que nos deje subir y ver como está y si esta roto realmente o que.. entendemos que la casa debe esttar en unas condiciones imposibles y por eso no quiere que subamos. Si que nos consta que lo usaba, porque no cocina nada... porque no compra bombona, no ha accedido, y lo pco que coma será con microondas. Asique si te parece, en la proxima visita, la semana que viene intentamos utilizar eso como contigencia, que nos deje verlo para ver el tamaño del que se va comprar nuevo, tipo y todo esto... si te parece bien, y le acompañariamos a comprarlo en ese caso en la siguiente visita o en esa misma. Te adjunto el informe de tipo social, que ha hecho la compi, ya lo leeras, pero destacar la mala gestión del dinero. Retiró el día 16 de Septiembre 175€ y a fecha de ayer 17 de Septiembre decía tener solo 10€. Aún debe dinero en la carnicería en frente de su casa. Hemos pensado que para que no acumule deuda igual se podia pagar directamente a la carniceria si accedieran? podiamos hablarlo con la tienda si te parece.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2019-09-19','-Amalia: se pide a FUTUEX que le acompañe a comprar un microondas ante la insistencia de la hermana. Futuex nos contesta en el sentido que lleva meses sin querer que entren en su domicilio y que está gestionando muy mal el dinero. Se le subió recientemente su asignación económica. Él tiene capacidad para comprarlo solo y pagarlo de su asignación. email de FUTUEX : Hola al respecto de lo que me dices de Valle Simón del microondas, te cuento, justo ayer estuvo Sonia (está haciendo el seguimiento de algunos de Teresa, por compensar los seguimientos) y no nos deja entrar en la casa.. pero no solamente a ella, a Teresa, este verano tampoco le dejó ... cosa que nos escama un poco, podemos acompañarle a lo del micro pero intentando precisamente que nos deje subir y ver como está y si esta roto realmente o que.. entendemos que la casa debe esttar en unas condiciones imposibles y por eso no quiere que subamos. Si que nos consta que lo usaba, porque no cocina nada... porque no compra bombona, no ha accedido, y lo pco que coma será con microondas. Asique si te parece, en la proxima visita, la semana que viene intentamos utilizar eso como contigencia, que nos deje verlo para ver el tamaño del que se va comprar nuevo, tipo y todo esto... si te parece bien, y le acompañariamos a comprarlo en ese caso en la siguiente visita o en esa misma. Te adjunto el informe de tipo social, que ha hecho la compi, ya lo leeras, pero destacar la mala gestión del dinero. Retiró el día 16 de Septiembre 175€ y a fecha de ayer 17 de Septiembre decía tener solo 10€. Aún debe dinero en la carnicería en frente de su casa. Hemos pensado que para que no acumule deuda igual se podia pagar directamente a la carniceria si accedieran? podiamos hablarlo con la tienda si te parece.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2019-09-19','-Amalia , envio email a la TS de Caser en respuesta a su correo : Buenos días , como sabéis Pedro Sudón ( tenéis la sentencia en la residencia) es curatela para la administración del patrimonio . Desde la Comisión no tenemos capacidad jurídica para actuar en otra esfera , para todo lo demás no está incapacitado. Pero si te sirve mi orientación, sería conveniente que contactarais con su Equipo de Salud Mental y comentarais la situación con su psiquiatra. Ante cualquier incidencia o descompensación no dudéis en llamar al 112 . En mi opinión y conociendo la trayectoria de Pedro , creo que hubiese sido necesario un ingreso en psiquiatría más prolongado . Así se lo transmití también al trabajador social de la unidad de psiquiatría del Hospital pero finalmente le dieron el alta . Un saludo De: BELEN DIAZ SANCHEZ >BDIAZ@caseresidencial.es> Enviado: miércoles, 18 de septiembre de 2019 15:25 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es> Cc: MANUEL ISIDRO GUERRERO BLANCO >MGUERRERO@caseresidencial.es>; GLORIA CABANILLAS VIÑUELA >GCABANILLAS@caseresidencial.es>; RECEPCION OLIVENZA >ROLIVENZA@caseresidencial.es> Asunto: Re: Pedro Sudón Hernández Hola Amalia, Si, regresó ayer por la noche. Llamó la policia local de Badajoz para comunicar que lo mandaban al centro en taxi. Su conducta continúa igual, no sé como no lo consideran oportuno...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-19','Ana: Llamo al CRR-Plas. (927 42 39 78 / 927 42 33 37 / 682 704 401) múltiples veces en distinto horario, comunican todas las líneas. / Hablo con Mª Luz Madrigal, Jefa de Secc. de Salud Mental, se muestran flexibles en que Mª Ángeles se quede en el centro el mismo día que haga la entrevista, si la pasa, siempre y cuando en el CRR acepten esta excepción. Me facilita otro nº de contacto del CRR: 682 70 47 28. ///////// Llamo al CRR, hablo con Carolina, Psicóloga, se muestra inflexible con la propuesta, debe hacer la entrevista antes del ingreso. Finalmente se fija el lunes día 23 de septiembre entre las 11 y 12 h. Su padre irá a acompañarla. ///////////// *Llamo a Toni-Futuex, pedirá a las compañeras que cambien las agendas para poder acompañarla (al menos una de las dos delegadas) llamarán al padre para decirle que deben acudir en taxi (lo gestionará Gloria) y que allí les estará esperando al menos una de ella. *Si todo va bien propondrán el ingreso para el míercoles 25. //////////// Acudo a informar a Mª Luz Madrigal y Eva, de la Ud. de Rec. Asitenciales de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-09-19','TERESA: ME LLAMA PARA DECIRME QUE SE QUIERE IR DE CASA QUE LE DA IGUAL EL CENTRO, HABLO CON DISCAPACIDAD Y ME COMENTA QUE EN OCTUBRE SE ABRE LA RESIDENICA EN FUENTE DE CANTOS, LLAMO A ISABEL MESA 924010142 PARA PREGUNTAR COMO VA LA GESTION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2019-09-19','TERESA: LLAMA RAMON PARA MANDAR PRESUPUESTO DE UN CORDON Y UNA CADENA QUE SE QUIER COMPRAR, ADEMAS ME DICE QUE SE LE HA ESTROPEADO LA NEVERA Y QUE VA A IR UN TECNICO A VERLA. AMENAZA CON NO PONERSE EL INYECTABLE SI NO LE COMPRAMOS EL CORDON Y LA MEDALLA LAS CUALES VALEN 100 Y 40 EUROS RESPECTIVAMENTE.','2');
