insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-09-19','Ana: Hablo con Pilar Cerrillo (618 908 506), vuelve a preguntar por las deudas de Pedro y cómo va el rescate del Contrato de Valores. **Le paso nota a Alberto, Jefe de Secc. Ecca. // Por otra parte, dadas las necesitades econóicas, solicitaré la PFHC, pues sólo percibe la orfandad y no le da para pagar el recurso residencial privado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2019-09-19','TERESA: ME LLAMAN ISABEL DEL EQUIPO DE DEPENDENCIA DE JEREZ PARA INFORMARSE SOBRE ADRIAN YA QUE VA A IR A VALORARLO EL PROXIMO LUNES, ME LLAMARA PARA INFORMARME DEL RESULTADO DE LA VALORACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-19','-Hablo nuevamente con Reme , estaba en despacho Teresa de FUTUEX . Me va a enviar nuevo informe policial , hay un grupo de menores de 16 años que están cometiendo robos en la localidad y hay sospechas de que se están quedando en su casa . Valoramos todas las opciones posible. Reme considera que la más apropiada es la de Residencia de Mayores por via dependencia con revision PIA ( me indica que este verano tramitó una por emergencia social con Ana Moreno y le llegó resuelta en breve , creo que tb lo va a solicitar por esta via . Lo he comentado con dependencia y sólo por la via de depend es lo más rapido ) . Luego lo valoraría May y va a si pudiera ingresar .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-09-20','Ana: Llamo a Mª Jesús - Directora del CAM Isabel de Moctezuma ,Caminomisco (927 01 57 30 - cam.isabeldemoctezuma@salud-juntaex.es). Me facilitará el número de cuenta y me enviará los documentos que tengan en el expte. Así mismo hablará con las compañeras de menores de CC para que me envíen lo que tengan allí, vía fax o mail. //////////////////////////////////// Recibo llamada de José Acebedo-ASPACE, quiere qué le explique bien en qué consiste la Tutela y cómo proceder hasta ahora, la T.S. habitual está de excedencia y aunque yo haya estado en contacto con Amor, TS nueva, se queda más tranquilo hablando conmigo.','2');
