insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-20','Ana: Recibo llamada de María, Secretaria del Registro Civil de Miajadas (Nº del Juzgado 927 34 70 03) en relación a la solicitud de Certificados de Defunción de los padres de Felipe, necesita más información para poder buscar los mismos: Fecha de fallecimiento o DNI, al menos. Y estar seguros de que fallecieron en dicha localidad. ////////////////////////////////////////// Llamo a Isabel Pino, TS de Miajadas (927 34 70 00 ext. 3216). Del padre de Felipe no tiene más información en el expte. De la madre lo único que ha encontrado en un antiguo informe es que falleció en 1993. Me facilita el tlf. de contacto de Mª Carmen, hermana de Felipe que reside en Trujillo (608 86 75 46), por si ella pudiera aportar algo más.','2');
