insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-09-23','(Pedro)Llamada de Mª Carmen, Directora de la Residencia "La Coronada" (20212). +++Tienen ya preparado el Informe para la rendición anual. Lo enviarán a ctutelar y por correo ordinario. +++Paula está muy "pasota" y dejada de sí misma: no hace por levantarse de la cama -hay que obligarla- ni se asea. Hay que triturarale la comida. Hace unos días, perdió el equilibrio y se cayó, haciéndose un "chichón".SOLAMENTE SE PONE DE PUNTA EN BLANCO CUANDO VA AL MÉDICO. +++Ella quiere marcharse a al Hospital de Cáceres. +++TRASLADO DE CENTRO: la Terapéuta cree que sería bueno para ella trasladarla a un centroen Cáceres, donde ella tiene sus raíces y conoce a la gente. El traslado a la Coronada la ha descentrado y volver a Cáceres cree que la ayudaría. Desde la Comisión creemos que volver a Cáceres podría suponer el querer volver a su casa y dejar el centro; además, en Cáceres tampoco tiene una red de apoyo de garantías ni relaciones personales fuertes. Por otro lado, creemos que un nuevo traslado en apenas 4 meses podría ser contraproducente, más si cabe por cuanto, según la directora, Paula ha establecido un cierto vínculo con la Terapéuta que podría ser adecuado para una evoluci´çon positiva. Por lo tanto, y de acuedro con la Directora, acordamos dar algo más de tiempo a Paula en su proceso de adaptación. +++SIGNIFICATIVO: +++++RESPONDE AL NOMBRE DE PAULA, algo que no había ocurrido nunca antes en su relación con la Comisión, ni con Servicios Sociales y Sanitarios. +++++NO HA VUELTO A PREGUNTAR POR SU HERMANA MARTINA. +++++NO HA VUELTO A PREGUNTAR POR JORGE "SU DETECTIVE".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-09-23','TERESA: RECIBO LLAMADA DA ANA P.I. ZAFRA LA TRABAJADORA SOCIAL ME COMENTA QUE LA MADRE DE NATALIA LA LLAMA CON FRECUENCIA SIENDO UNA MALA INFLUENCIA PARA ELLA LE DICE QUE VA A SOLICITR LA REMOCION DE LA TUTELA, NATALIA SE HA ESCAPADADO DEL CENTRO ESTE FIN DE SEMANA. EL CONTACTO CON LA MADRE NO LE ES NADA BENEFICIOSO. LE COMENTO QUE NOSOTROS NO PODEMOS PROHIBIR QUE VEA A SU MADRE NI QUE MATENGA CONTACTO CON ELLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2019-09-23','Ana: El viernes recibí un correo de Pilar Sánchez - Hogar S.Vicente de Paúl (direccion.hgsvplasencia@gmail.com) "Buenos días, Ana, te envío, para su firma, la autorización para dos excursiones que realizará Margarita con el Centro FEAFES. Te informo, además, que, ayer, Marga vino diciendo que no se ve con fuerzas para realizar el curso de Competencias Básicas de Educación de Adultos, por lo que, al final, no sé qué decidirá. Se puede hacer la matrícula hasta el día 25, así que, si por fin se decide a hacerlo, te enviaré la documentación de la matrícula. Un saludo Pilar Sánchez" **Pongo las autorizaciones para la firma del D. Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-23','(Pedro)Recepción de correo-e de CRR: +++Buenos días, +En relación a la operación a la que se someterá la persona tutelada Antonia Canelada para la extracción de vesícula, decir que el pasado viernes acudió a consulta y resulta no ser apta por parte del especialista en anestesiología a someterse a las pruebas de anestesia, debido a que posee los niveles de hemoglobina alterados. Deberá pasa antes por hematología y posteriormente volverán a verla en anestesiología para iniciar las pruebas pertinentes. +Allí nos preguntan por los consentimientos informados y le indicamos al especialista en concreto, que esta persona está tutelada. La próxima cita con anestesiología nos llegará por correo, una vez que su tutor de la CTA se ponga en contacto con citaciones y anestesiología. +Adjunto los teléfonos de contacto para que se ponga en comunicación con ellos: 927256203 citaciones HSPA 927256858 anestesiología Un saludo, Victoria Rajo Dirección Técnica.- CRR y PS Salud Mental - FEAFES C/ Ana Mariscal Nº 4 10004 Cáceres Tel.: 927 18 11 09 - 687 487 908 +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++RESPUESTA AL CORREO ANTERIOR. +++Buenos días, Victoria. Gracias por la información sobre Dª Antonia. He llamado a Anestesiología (H.Universitario, Lista de Espera Quirúrgica, ext. 56005)y me han dicho que no la pueden citar en Anestesiología hasta que la vean primero en Hematología. Van a reclamar el volante para Hematología y remitirán esta cita al CRR. En cuanto a los consentimientos informados, la pasada semana nos enviaron el de Anestesiología pero incompleto. Llamamos a la Unidad para que nos lo enviaran completo pero estaban entonces pendientes de lo que al final pasase con la cita del anestesiólogo. He vuelto a llamar, y estoy a la espera de lo que me digan. ¿Cómo está Dª Antonia con tanto trajín? Seguimos en contacto.','2');
