insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2019-09-23','Buenas tardes Amalia. Te comento sobre Joaquín González Millón. Nos reunimos con la persona que vino de Fundación Triángulo y nos explicó todo el proceso que hay que seguir para el tema de cambio de sexo de Joaquín. Joaquín sigue decidido al cambio. Hemos pedido cita para un endocrino especializado en el tema y tiene la cita el martes día 24. Lo acompañaré yo. Quiere que nos dirijamos a el en femenino y que le llamemos Cristina que es como quiere llamarse cuando ya pueda cambiar de manera legal. Sus comaperos ya han empezado a hacerlo y, la semana que viene vendrá el chico de la Fundación Triángulo para dar una formación sobre el tema y q lo veamos de manera naturalizada. Si tienes alguna duda sobre el tema me lo dices. Besos. Eva Álvarez Gallego Trabajadora Social Tfno. 924 454 727','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='DIAZ'and apellido2='SEPULVEDA'),'2019-09-23','(Pedro)Llamada de Encarnación, T. Soc. SSB de Aceuchal (658909576), +++Pregunta por Dª Rosario D.S.No consta en nuestra base de datos ni siquiera como Defensa Judicial. +++A raíz de esta consulta, informa de que D. José Díaz Sepúlveda HA FALLECIDO. Pdte. de confirmación oficial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-23','(Pedro)Eva (Secc. Salud Mental) entrega en la Comisión Resolución de 17 de septiembre de 2019 adjudicando plaza en el CRR de Plasencia para Dª Mª Ángeles. ///////////////////////////////////////// Ana: Tras varios intentos de hablar con Marta- PNC CC (927005227): Hablo con Adela, PNC Mérida (924 00 59 95). Dice que Mª Ángeles sí está cobrando la PNC, no se ha devuelto ningún mes, desde diciembre en la cuenta nueva que se abrió con Consolación. ////////////// Se lo comunico a Coral y a Belén, volverán a contactar con el banco, debe haber habido algún error.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-23','(Pedro) Ana me comenta que ha recibido información de Isabel Pino, T. Soc. de Miajadas, de un nuevo episodio de agresividad de Francisco hacia Felipe, amenazándole nuevamente con un cuchillo. +++ Al parecer, sucedió ayer domingo 22 de septiembre sobre las 15h (la Guardia Civil de la localidad, con la que hablo posteriormente, refiere que no tiene cosntancia de esa incidencia pero sí de una similar que se produjo por la noche.) +++Parece ser que intentó poner dencuncia pero no le dejaron por estar incapacitado. +++CONVERSACIÓN CON LA GUARDIA CIVIL DE MIAJADAS. +++++Primero con el Guardia Otero y posteriormente con el Sargento Antonio (615-553788). +++++REfiere no tener conocimiento de las amanezas sufridas por Felipe el mes de agosto pasado (se denucnió a través del Juzgado con escrito del SSB) pero sí de otras sucedidas en OCTUBRE de 2012 (por lo que con éstas últimas ya son tres las incidencias de las que se tiene constancia. +++++Delegamos la presenbtación de la denuncia en Isabel Pino, acompañando a Felipe en representación de la Comisión. //////////////// Ana: Llamo a Pilar Martín, TS del Equipo de Salud Mental de Trujillo (54612) comunico el intento de agresión de Francisco hacia su hermano Felipe. Pide que lo comuniquemos por escrito a su correo-e: pilar.martinp@salud-juntaex.es **Envío dicho correo a Pilar con copia a Pedro Gracia (guardado en el Expediente, carpeta Juzgados).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-09-23','Ana: Recibo llamada de Raquel, Equipo de Menores de CC (927 00 43 60). Acordamos que me enviará la documentación que tengan en el expte. que considere necesaria para el correcto ejercicio de la Tutela. ***Recibo por mail (etaif.caceres@salud-juntaex.es): copias del DNI, Nº cuenta, Resolución Grado Dependencia, Certificado de Discapacidad y Dictamen Técnico del CADEX.','2');
