insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='DOMINGUEZ'and apellido2='IZQUIERDO'),'2019-09-23','miguel, desde secretaria general (María Guerrero)nos indica que necesitan la solicitud de intervención de abogacía general. Lo preparo junto la documentación que la complementa y se la envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-24','Ana: Ayer por la tarde recibí el siguiente correo de Paula, T.O. - CRR Plas. (tocupacional.crrplasencia@grupo5.net): "Buenas Ana, hemos entrevistado a Mª Angeles y hemos fijado fecha de ingreso para el miércoles día 25 de septiembre. Tenemos algunas dudas sobre el perfil de Mª Ángeles y las posibilidades de adaptación al recurso, observando que el paso supone un gran escalón por su situación previa y por lo poco que hemos podido observar, también por la dinámica de relación con su padre. Intentaremos adaptar todo lo posible para que pueda incorporarse y beneficiarse del recurso. Tenemos que coordinar el dinero que va a necesitar y si te parece podemos estimar unos 280 Euros iniciales y nos vamos ajustando. Mañana (martes) hablamos. Un saludo. Paula." /////// Llamo al CRR-Plas. (682 70 47 28) me dicen que tanto Paula como Carolina están ocuapadas. Me devolverán la llamada. /////////////////////////////////////// Llamo a Toni-Futuex (924 49 19 14): Ayer tuvo lugar la entrevista, en terminos generales fue bien. Aunque una de las delegadas tuvo que salirse fuera con el padre, pues mantenía una actitud controladora y "machista tradicional", queriendo influir sobre Mª Ángeles, pero por otra parte vino muy bien que le acompañara, pues el centro le gustó y le decía a su hija que allí iba a estar muy bien, que tiene cosas que ellos no tienen en casa. Se quedó más tranquilo. Le comunico que el ingreso tendrá lugar el míercoles, pues no les confirmaron nada a las delegadas. **En cuanto a la cuestión económica, el padre les dijo que él todos los días 25 acude al banco con el DNI de su hija y retira el dinero. /////////////// Hablaré con Alberto, Secc. Ecca. /////////////// *Toni Futuex, me confirma que ya han acordado el servicio con un taxista. Les recogerá a las 10:00 h en el pueblo. El precio total serán 88€ con IVA. (ida y vuelta). Le acompañarán a la entrevista las dos Delegadas, Virginia y Gloria, que le estarán esperando en el puerta del CRR. ////////////////////////// Convesación con Paula-CRR: Tras la entrevista, van a valorar en equipo si Mª Ángeles tiene capacidad y suficiente autonomía para adaptarse al Centro. La veían con "mucha perplejidad, le faltaba capacidad para responder y presentaba conducta infantilizada".','2');
