insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-09-24','TERESA. RECIBO EMAIL DEL CRPS Buenos días Teresa. Te comento lo que le hemos propuesto a Mª Elena y ella ha aceptado hasta que tenga plaza en residencia, ya que la situacion en su casa ya era insostenible y aprovechando que quería salir de allí. Le hemos propuesto quedarse en el Piso de Apoyo a la Rehabilitación que tenemos: este piso solo funciona de lunes a viernes y es para favorecer el acceso a la Rehabilitación. Ella se va a quedar en el piso de martes a viernes, por ahora vamos probar si funciona, ya que siempre ha sido muy inconstante con los recursos residenciales abandonándolos rápidamente. Os iremos informando de su funcionamiento en el mismo y si hay o no adherencia al piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-24','Ana: Recibimos por fax del Hptal S. Pedro de Alcántara - CC, 2 C.I.; para Anestesia General y Anestesia Loco-Regional. En los documentos no aparece el nº de fax para poder devolverlos por el mismo medio. Llamo a Miguel Ángel Santano, Admtivo (56014), no sabe el número de fax, me llamara en unos minutos para decírmelo. **Como no recibo llamada vuelvo a llamar más tarde, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2019-09-24','Ana: Llamo a Mª José Polo, TS de Zarza de Granadilla (664 01 82 09 / 927 48 60 04 ext.5 / ssbm@trasierratierrasdegranadilla.es ), me comunica que finalmente Francis (Aux.) no puede acompañar mañana a Florencia a renovar el DNI, además hoy Florencia está muy alterada. *Pedirán nueva cita ellas, para cuadrarlas con la agenda de Francis y con las citas médicas pendientes de Florencia. ////***Anulo la cita de mañana en la Web de la Policía Nacional. ////////////////////////// Recibimos un correo en el ctutelar@ de Mª José Polo, TS, comunicando que se va a *proceder a la reparación de la taza del sanitario de Florencia, ya han avisado al fontanero. Nos enviarán la factura.','2');
