insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-09-24','miguel, tras conversación telefónica con Belén Camisón, cuñada de nuestro tutelado, remito hoy email a Ana de la Notaria de Romero Leal de Mérida la documentación nuestra (que me indica Belén le ha dicho Ana que le falta) de sentencia de incapacitación, nombramiento, aceptación, testimonio y nota simple de la finca objeto de extinción de condominio. ******************************************* Llamará mañana a Ana de la notaria para confirmar con ella si le falta algo más e intentar ir poniendo fecha de firma de la extinción de condominio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='AREVALO'and apellido2='MORENO VAQUERIZO'),'2019-09-24','miguel, voy al juicio, por videoconferencia desde Mérida,para aceptación de la herencia y autoización de venta del inmueble y acepto en nombre de la comisión tutelar de adultos, quedando pendiente unicamente que aporten certificado de saldos de las cuentas bancarias que quedan vigentes, y que nos remitirá el juzgado de castuera nº2','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-09-24','(Amalia y Pedro). Visita a Pedro Tomás en el CSS de Mérida. Asisten Pedro Tomás y su pareja, Blanca (T. Soc.), María (Psiquiatra), Juan pedro (Psicólogo). +++La conversación con Pedro Tomás, es fluida, cordial y en momentos cuestionando la necesidad de estar tutelado, si bien durante la conversación paarece entender que se trata de una medida de protección que además no tiene por qué ser defionitiva. +++Llevan viviendo en un PISO de ALQUILER desde principios de agosto (no se envió a la Comisión Informe previo con la propuesta tal como se quedó en la incidencia anterior). El Psio está a nombre de la paraja ¿nombre? y pagan 320 euros de alquiler. +++Se explica a ambos la situación en la que se encuentra Pedro, lo que significa y la temporalidad de la misma si se dieran las circunsyancias para solcitar una ampliación de la capacidad o su restauración. +++Plantea la venta de la vivienda familiar que tiene en su pueblo. Se le ecplica que primero habría que hacer la herencia y luego solicitar autorización de venta al Juzgado.DICE COONOCER LAS FECHAS Y LOCALIDADES EN LAS QUE FALLECIERON SUS PADRES. +++Blanca está tramitando cambio de su pensión a PF y Orfandad Absoluta. +++Parecen tener prisa por comprarse un coche que ha visto por 1700 euros: PEDRO NO TIENE CARNET, PERO ELLA SÍ. Se trata de que entiendan que dada su situación y el tratamineto que sigue ella quizá no sea conveniente que conduzca un vehículo, auqnque según dice ya lo ha hecho en las últimas salidas... +++Se les pidse que hagan un presupeuystro de gastos para ajustar el dinero del que puerde disponer Pedro. +++Se les informa sobre las vistas de Futuex. +++ÚLTIMA CONSULTA de su pareja: "...Pedro, entonces ahora Pedro Tomás podría avalar a mi hija en la compra de un coche, porque tuvo un accidente y se quiere compar otro..." ¿SIGNIFICATIVO?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-25','Ana: Recibo llamada de Isabel Pino (927 34 70 00 Ext.3216) ayer había quedado con Felipe para poner la denuncia a las 11:30, pero a Felipe se le olvidó. Tuvo que volver a contactar con él. **La denuncia la pusieron finalmente a las 14:00 h. *A las 21:00 h la llamaron de la Guardia Civil para comunicarles que habían dado la orden de detención de Francisco y que hoy, día 25, se celebraría el juicio en Trujillo a las 11:00 h. /////////////////// Se recibe también llamada de Antonio, Sargento de la Guardia Civil de Miajadas (615 553 788), conversación con Pedro. El Juzgado es el de Violencia de Género, no está seguro si es el nº1 o el 2. /////////// Nueva conversación con Isabel Pino, ha llamado a Felipe, pero tiene el móvil desconectado. Solicitará a la policía municipal que acuda al domicilio para ver cómo está Felipe. Ayer por la tarde él ya decía que quería "retirar la denuncia", de nuevo le explicaron que no podía hacerlo. ////////////////// Llamada Isabel Pino: ha hablado con la Concejala, para ver si hay plazas en los Pisos Tutelados y plantear, que en ese caso, Felipe se quede allí unos días, por emergencia social. Aún está esperando respuesta por parte de la Concejala. Ha hablado también con USM, Pilar le dicen que a Francisco lo tienen que derivar desde el C. Salud. Aquí ha llamado y no ha obtenido respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2019-09-25','-Antonia llama por tf. , se le explica que ya está valorada por dependencia. Le solicito informes médicos actualizados para solicitar revisión de grado . Me los enviará con Teresa. Le han denegado la financición del tto. dental. esperaremos tener dinero ahorrado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2019-09-25','Ana: Envío por fax los C.I. para anestesia a Miguel Ángel Santano (56014), al número de fax que el mismo me facilita: 927 15 31 87.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2019-09-25','miguel, nos llega del centro de la luz de Badajoz, email indicando que nos pongamos en contacto con los primos de los hermanos LOPEZ CABRERA, así que mando email a su prima (anabcabam@gmail.com) para nos acredite si está o no ya vendido, caso contrario en qué estado se encuentra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-09-25','-Se recibe informes de las incidencias de Felisa ( archivados en su expediente ) : Buenas tardes, En adjunto te envío informe sobre el incidente grave perpetrado por la usuaria FBS, el pasado 23 de septiembre en nuestro centro ocupacional. Indicarte que ese mismo día fue ingresada en la unidad de agudos de psiquiatría del Hospital Infanta Cristina de Badajoz. Tengo que puntualizar que posteriormente nuestra directora del servicio de residencia RAL, Isabel Miranda, se pone en contacto con el psiquiatra asignado, concretamente con el Dr. Zamora, que comenta lo siguiente: “ explica que su actitud es delictiva, y que tras haber cometido dos incidentes graves en residencia, la envía directamente a la UDAD”. (Adjuntamos varias de los incidentes graves cometidos con anterioridad por esta usuaria). Por tanto, dado el semblante que está tomando la usuaria FBS (justificados en los informes adjuntos), de agresividad, intimidación y superioridad hacia usuarios y profesionales del centro ocupacional y de Residencia San Javier, donde reside, mantenerla aquí supone un grave riesgo para todos ya que pone en grave peligro la vida de los usuarios y de los profesionales de Aprosuba 3. Es por todo lo anterior, ruego encarecidamente en nombre de toda la Junta Directiva de Aprosuba 3 y de manera urgente se tomen medidas, sobre la búsqueda inminente de otro recurso adecuado a las necesidades de FBS, donde puedan atenderla de manera adecuada, dentro de la red de salud mental. Recibid un cordial y afectuoso saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-25','miguel, tras hablar con Pedro Gracia donde me indica que el Sargento de la Guardia Civil de Miajadas le comenta que le notifica verbalmente que tenemos vista en juzgado nº1 de Trujillo hoy a 11h. Con esos datos logro hablar con Juzgado nº1 de Trujillo, con la juez quien me comenta: -No es necesario nuestra asistencia por ser unicamente la toma de declaración a ambas partes. -Me confirman desde el juzgado que procederán a dictar Orden de Alejamiento. -Nos comentan desde el Juzgado que enviarán al final de la mañana por fax la documentación (denuncias, declaración, etc) ************************************************************ Pedro JS comenta con Ana TS que se intente la vía de buscar algo temporal (un piso tutelado...)sino lo logran, hablaríamos con el Juzgado,para que una vez nos remitan el fax, pedirles activen un internamiento de emergencia a uno de los dos, para evitar que estén juntos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-25','-Se recibe email de FUTUEX ( en su expediente su guardan fotos ) : Adjunto enviamos para conocimiento de la comisión tutelar, aunque me consta que por la ts estas informada del caso, de la grave incidencia ocurrida en la vivienda de Bartolomé Alba Gragera. en su ausencia de la seman que ha estado ingresado, su amigo Alonso , un nieto suyo, menor de edad y otros amigos y chicas, han estado entrando en su casa, no es la primera vez, dejando todo en un estado,más que fiesta, más bien un orgía. Se aprecia bien en las fotos adjuntas. estos chicos tiene antecedentes policiales y judiciales. Se ha citado a Bartolomé para firmar voluntariamente plaza en centro residencial, esperemos que acuda, es mañana miercoles 25 de Septiembre, acudirá Teresa, al despacho de Remedios Lozano, y a ver si finalmente accede voluntariamente.De no ser así, tendremos que planificar nueva visita la próxima semana para volver a intentarlo, o en el peor de los casos, quizás valorar otras opciones de ingreso. Te mantengo informada! Buena tarde!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-09-25','-Se recibe email de FUTUEX ( en su expediente su guardan fotos ) : Adjunto enviamos para conocimiento de la comisión tutelar, aunque me consta que por la ts estas informada del caso, de la grave incidencia ocurrida en la vivienda de Bartolomé Alba Gragera. en su ausencia de la seman que ha estado ingresado, su amigo Alonso , un nieto suyo, menor de edad y otros amigos y chicas, han estado entrando en su casa, no es la primera vez, dejando todo en un estado,más que fiesta, más bien un orgía. Se aprecia bien en las fotos adjuntas. estos chicos tiene antecedentes policiales y judiciales. Se ha citado a Bartolomé para firmar voluntariamente plaza en centro residencial, esperemos que acuda, es mañana miercoles 25 de Septiembre, acudirá Teresa, al despacho de Remedios Lozano, y a ver si finalmente accede voluntariamente.De no ser así, tendremos que planificar nueva visita la próxima semana para volver a intentarlo, o en el peor de los casos, quizás valorar otras opciones de ingreso. Te mantengo informada! Buena tarde!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2019-09-25','-Emial desde aprosuba : Buenas tardes Amalia. He ido con Joaquín/Cristina al hospital para valoración de endocrino. La endocrina ha preguntado quién la ha derivado a su consulta, le decimos que su médico de atención primaria y nos dice que la tiene que ver primero la psiquiatra del centro de salud Ciudad Jardín. Cris le comenta que Abel de Fundación Triángulo nos había comentado que hay un protocolo que dice que ya no es necesario pasar por psicólogo o psiquiatra, pero ella nos ha dicho que aunque exista ese protocolo manda a la gente a la psiquiatra porque lo considera importante. Le ha dado cita para el 23 de marzo de 2020. Nos ha mandado a Ciudad Jardín para pedir cita a la psiquiatra y nos han dado para el 7 de febrero de 2020, pero antes la llamará la trabajadora social para preguntarle algunas cosas. Le ha mandado a hacer una analítica para verle las hormonas, si tiene VIH y hepatitis. La analítica se la tiene que hacer a finales de febrero, en Badajoz también. Cuando vayamos sabiendo algo más te lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-09-25','Ana: Adelanto a Maite(927017281 Corto: 21661 // camp.plasencia@salud-juntaex.es)escaneado por mail el CI para Estirpación de la Paratiroides de Joaquina. // Se lo paso a Juan Pedro, Admtvo. para que envíe el original tal y como me han solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-09-25','(Pedro)Conversación con Mariví y con Soraya (T. Soc. Y Directora del CSS de Plasencia. +++Matrícula en la Uned y en la Escuela de Idiomas: +++++MARIVÍ: NO ve la matrícula en la UNED por los intentos que ha tenido y por su falta de capacidad (en la Comsiión pensamos los mismo). Respecto a la Escuela de Idiomas, cuya matr´ciula son 75 euros, puede ser una forma de mantener su interés por algo. +++++SORAYA: cree que SÍ debe matricularse en la UNED además de porque es gratuita, porque se han enterado que hay apoyos para personas con discapacidad que podrían ayudarle en su propósito. Y necesita matriculars ene Francés porque es un idioma que le pieden en la UNED. +++QUEDAMOS PENDIENTE LA CONVOCATORIA DE LA SUBCOMISIÓN. CONFIRMAR DÍA 16 DE OCTUBRE A LAS 10:00H. +++JAIRO ESTÁ EN LISTA DE ESPERA PARA EL CRR. le gestionó la solcitud Pedro, T. Soc. del CSS Plasencia antes de estar de baja.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2019-09-25','Ana: Llamo a Pilar Cerrillo, T.S. Res. Virgen de la Montaña-Casar de Cáceres (618 908 506), le informo de la solicitud de remoción de la tutela de Isidora que ha presentado su sobrina y de que en el escrito uno de los argumentos es: "...las atenciones que se le están dispensando en la residencia geriátrica dejan mucho que desear...". Pilar está en total desacuerdo con esta afirmación y expresa que la sobrina nunca ha mostrado el menor interés y que nunca la visita. **Le pido que nos envíen un informe para adjuntarlo al escrito de respuesta al Jgdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2019-09-26','Ana: Llamo a Cristina, Psicóloga, CRR-CC (927 18 11 09), en relación a la solicitud de remoción de tutela que ha presentado en el Jgdo. la hija de Agustín. Me informa de que Azucena, desde 2015 ha visitado a su padre 6 veces, nunca se ha llevado a casa a su padre ni has mostrado interés en hacerlo (a pesar de que su padre ha mostrado interés en irse con ella en fechas señaladas, como por ejemplo Navidades), las mayoría de veces que ha llamado al centro ha sido por motivos económicos, en Navidades exigió el "aguinaldo" y se enfadó porque no se lo dio. En el último año sí que ha intensificado las llamadas, lo cual a Agustín le está viniendo muy bien, puesto que no tiene más vínculos afectivos y se encuentra muy solo. Y le ha llevado un día ropa que le ha comprado. Pero ha realizado preguntas como "Si se muere mi padre qué vais a hacer con sus cosas". Cristina afirma que además Azucena presenta "labilidad emocional". **Pido a Cristina que nos envíen informe para aportarlo como Doc. en la respuesta al Jgdo. Intentarán enviarlo el lunes. **Ellos ya están haciendo la relación de visitas que le ha solicitado de oficio el Jgdo.','2');
