insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-09-26','REQUERIMIENTO Se reenvía requerimiento de pago a la dirección dada por José Luis: C/ Figueira da Foz, 4, 2º, Izq.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ZORAIDA'and edp.apellido1='AYUSO'and apellido2='PIÑERO'),'2019-09-26','miguel, llama Elena Sanchez Simón, me indica que tras la vista que tuvimos, hubo toma de declaración a Abraham, hermano de Zoraida Ayuso, y que en la misma éste aportó unos wasap donde la directora del Centro de la Luz " Doña Segunda Sánchez Martin" le escribió disculpandose por cuando le llamaron, asímismo dice que todos saben como es Zoraida y que no ha dicho la verdad. Posteriormente estos wasap los ha aportado documentalmente al procedimiento. El lunes día 30/9/2019 se tomará declaración a la directora Segunda Sánchez Martin. Elena (de abogacía general) está muy enfadada porque no sabía nada de estos wasap, y de hecho estuvo en el centro reunida con las trabajadoras que firmaron el documento que fue firmado por 5 personas para preparar el juicio en su día, y que saludó a Segunda y ésta no le comentó nada al respecto. Me confirma Elena que esto puede suponer un duro revés al procedimiento. Quedamos en que envía al email personal de Pedro Js los wasapa y que éste llame mañana día 27/9/2019 a Segunda y le pregunte al respecto de estos wasap. Con lo que nos informemos la llamaremos a ella para que el lunes acuda al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2019-09-26','Ana: Conversación con Paula, T.O. CRR-Plas. (682 704 401), las primeras 24 horas de Mª Ángeles en el CRR han transcurrido con normalidad, ella está contenta, presenta buena disposición. Pidió ducharse nada más llegar. Acudió con la ropa limpia, bien doblada y ordenada en la maleta, pero escasa, necesitará calzado, ropa interior y algo de ropa para el invierno. Así mismo necesitará Podólogo, crema para algunas excemas que le han visto y Dentista (no entra por el PADI, no presenta D.I.) ///// Como la plaza del CRR no hay que pagarla, tiene mayor solvencia económica, hablaré con Alberto, Secc. Ecca. la propuesta que enviaron al correo-e del día 25/09 (280 € la primera semana de cada mes) e ir ajustándolo si fuera necesario. Por otra parte, dadas la fechas y las necesidades iniciales se plantea aprobar un extra de 70 € para el día 25 de octubre. //// Se lo paso a Alberto. **Reajustará el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-09-26','Ana: Llamo a Isabel Pino (927 34 70 00 Ext.3216) Fco. ha pasado una noche en el Albergue de Transeúntes de Miajadas, va a contar con el apoyo de su hijo, que vive en Escurial. Tiene una pensión mínima (algo más de 600 €). De Felipe no ha vuelto a saber nada. Cuando le llamó la primera vez que volvía en el taxi de Trujillo, tras decirle quién era Felipe le colgó el teléfono. Cuando volvió a llamarle más tarde, varias veces, no volvió a coger el teléfono. ///// Me facilita un nuevo nº de Mª Carmen, hermana : 693 751 866 ///////***Por otra parte los suministros de la vivienda los estaba costeando Francisco, por lo que habrá que cambiarlos a nombre de Felipe. Isabel me llamará para facilitarme información de compañias, contrato y datos necesarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-09-27','Ana: Llamo a Mariola, Res.San Jorge (927 62 80 10), no está, me piden que vuelva a llamar más tarde. No obstante recuerdo que la he llamado en varias ocasiones, le han dejado nota pero no he obtenido respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2019-09-27','(Amalia y Pedro). Inspección del domicilio de D. Ángel, sito en Avda. Ricardo carapeto 27, 5ºC de Badajoz, acompañados por dos Agentes de la Policía Local. +++No había nadie en el domicilio. La Policía habló con un vecino del mismo rellano quien nos confirmó que allí no vivía nadie desder hace al meno dos años. No obsatnte, unode los agentes conocía a un sobrino de D. Ángel, subinspector de Policía, aquien localizó y le confirmó la desocupación de la vivienda. +++Llamamos a un cerrajero (Cerrajeros Badajoz. 633-267005) para poder entrar y pudimos comprobar que, efectivamente, no había nadie: la capa de polvo y suciedad denotaba el abandono del domicilio. Dejamos la bombana de gas desconectada (no estaba vacía, más bien parecía medio llena). Ver fotos en expediente. +++El cerrajero cambió la cerradura por una nueva. Las tres llaves están en la caja fuerte de la Comisión. +++Pedrimos a la Policía Local que nos enviase informe de las actuaciones realizadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2019-09-27','Ana: Llamo a Maica, TS de Torrecillas de los Ángeles (927 67 70 71), me dicen que hoy atiende en Eljas (927 14 21 59) o Vva. de la Sierra (927 44 50 02), en relación al email que recibimos del Ayto. de Torrecillas a fecha de 18/09/19, ella no ha enviado ningún correo electrónico. Que si en el Ayto. tampoco saben nada que pruebe a preguntar en el Jdo. ////// En cuanto a Alfonso, dice que sabe que ingresó en el CSS-Pla. en Agosto, pero poco tiempo porque la madre solicitó el alta. ¿? // Por otra parte añade literalmente: "Yo con Alfonso no trabajo, hago seguimiento indirecto con la madre, pues él se niega. Es una persona que tiene problemas para relacionarse, se encierra en su habitación y cuando he ido a su casa no se ha dejado ver" Por otra parte está dispuesta a colaborar. Había quedado con Gloria, delegada FUTUEX, para hacer una visita y comenzar a coordinarse, pero le llamó para anularla. Tienen pendiente volver a fijar fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2019-09-27','(Amalia y Pedro).Visita domiciliaria a Alberto. +++Estaba solo en el domicilio, con el orddenador que cerró cuando subimos al salón.Le comentamos la posibilidad de enseñarnos el resto del piso, a lo cual en un primer momento accedió, pero no dió pié a la visita una vez que dijimos de marcharnos. +++Poco comunicativo, parecía tener ganas de que nos fueramos lo antes posible. Refiere no tener prácticamente realciones de amistad y con la familia parcen haber mejorado algo. +++Está yendo al ESM y a CEDEx (dice no consumir nada en la actualidad). +++Quiere recuperar el carnet de conducir, que perdió -dijo- hace unos ocho años. Le indicamos que se informe en el Centro de Conductores sobre los tráites a realizar y que cosnulte con su Psiquiatra la posibilidadd de conducir en relación al tratamineto que está siguiendo. +++A los pocos minutos de salir de su casa vimos que se marchaba con la bicicleta (que tiene en mitad de la escalera, de una pendiente considerable y sin poder acceder por ella con la bicicleta en esa posición, lo que resulta pedligroso tabnto para subir como para bajar. le dimos varias opcionbes para cambiar su ubicación).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-09-27','(Amalia y Pedro)Visita domiciliaria a Antonia. +++Estaba en el docmicilio con su madre, Fernanda, y un hermano de ésta. La madre estaba recostada en el sofá, en un salón de pequeñas dimensiones y con varios perros en el domicilio alguno de los cuales tuvieron que encerrar. +++Al cabo de estar allí unos minutos llegaron sus tres hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-09-27','Ana: Recibo llamada de Carmen Jerez - Miembro permante de la Subcomisión sociosanitaria (74947). Dice que ha estado hablando con el Psiquiatra de Jairo, que ya NO es Daniel, ahora es Agapito Herrero, Coord. Área de Salud Mental de Plas., y no consideran que sea necesario ya convocar la subcomisión. Ellos quieren que se solicite plaza en Piso Supervisado. *Les comento que Pedro, TS del CSS, le solicitó hace unos meses CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-09-27','-TF DE ATI . 695893358','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2019-09-27','Ana: Recibo llamada de Pilar Cerrillo, TS Grupo Ciudad Jardín (618 908 506), me envirá Informe Social, Medidas Cautelares (previas a la aceptación de la tutela por la Comisión Tutelar) y registros de la resid. al mail. Y narra la historia: Isidora ingresó en la resid. del Casar en 2014. En 2015 le conceden la Ley de Dependencia (Grado III) momento en que ingresó también su marido, Juan Leo, pues con esa ayuda económica ya podía permitírselo. En este momento Juan solicita la Incapacitación de Isidora. Su vecino, Benito, taxista de profesión, es quién le ayuda, le lleva y le acompaña a todas las gestiones y los hospitales cuando es necesario. En un momento dado, invitan a Juan a la comunión de una nieta de Isidora (hasta ese momento apenas había habido relación con la familia extensa) y estnndo en la Iglesia a Juan le da un infarto y fallece. También ahí son los vecinos quienes van al hptal, se hacen cargo de de sus objetos personales y cartera y de todas las gestiones para el sepelio). La familia no se encargan de nada. La sobrina apareción justo después del fallecimiento de Juan, para la apertura del testamento. En una ocasión fue a otra de las residencias del grupo a pedir las facturas y preguntar por qué le hacen el cargo en una cuenta y no en otra. En la actualidad, acude 2-3 veces al mes a visitar a Isidora media hora (desde hace un año apróx.) Y son los vecinos quienes tienen las llaves de la casa y a quiene Juan ha dejado en testamento la mitad de todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-09-27','miguel, llama por tlfno el tutelado y comenta con Angel que está citado para comparecer en el juzgado de Villafranca en proximos días, pero no sabe indicarnos fecha, ni tiene citación... Hablo con el Juzgado nº1 de Villafranca quién me confirma que la que lo lleva está de baja y que la llame la semana que viene (Mercedes) Me toman nota por si tienen que notificarnos algo de nuestro fax y mi número de teléfono','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-09-27','Ana: Belén, Secc. Ecca., me da el Alta a Terceros que le había solicitado./// REGISTRO DE ENTRADA solicitud de PFHC, con toda la documentación pertinente. //////////////////////////// Recibo llamada de Amor- T.S. - ASPACE, Ha acudido al Ayto. le han informado de la documentación que tiene que presentar para empadronar a Santiago Eduardo en el Centro. Le haremos una autorización para que pueda firmar ella la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-09-27','-llama Feli , quiere saber cómo vamos a proceder. Le indico que pasen la herramienta para ver si da para plaza sociosanitaria . Solicito a dependencia ( Mª Duarte ) que prioricen expediente. Hay que reactivarlo . Se solicitó en 2018 pero no han podido hacer valoracion pq nadie cogia el tf. Quedo pte. de dependencia para solicitar la plaza lo antes posible , ya tenemos autorizacion judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-09-27','-llama Feli , quiere saber cómo vamos a proceder. Le indico que pasen la herramienta para ver si da para T2 . Solicito a dependencia ( Mª Duarte ) que prioricen expediente. Hay que reactivarlo . Se solicitó en 2018 pero no han podido hacer valoracion pq nadie cogia el tf. Quedo pte. de dependencia para solicitar la plaza lo antes posible , ya tenemos autorizacion judicial.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-09-26','-Visita domiciliaria : conviven en el mismo domicilio 5 hijos todos con discapacidad , la madre y un hno. de ésta de avanzada edad. La casa no reúne condiciones de habitabilidad ni de higiene. La madre percibe P. viudedad ( unos 700€) , 4 hermanos perciben pensiones de PFHC+ P. ORFNANDAD. El mayor es el único que no percibe ni el tío pq superan en ingresos económicos ( más de 2000€ en la U.C ) Quedamos con ellos en que de la pensión de Antonia ( pf+orfandad ) se le mandará un dinero a la cuenta de la madre y otra parte la administraremos nosotros. Estoy pte. que la parte económica me facilite nueva cuenta bancaria para solicitar cambio de titularidad de las pensiones. ( ya hay que dejarlo para noviembre para que no deje de percibir , se pidió hace meses )','1');
