insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2019-09-27','Ana: Recibo llamada de Carmen, pide 100 € para colaborar con la compra de ropa y libros de sus hijos. Dice que su madre es quien se encarga habitualmente de esos gastos. Consultaré con los compañeros del área ecca. y se lo confirmaré a Paula o Carolina.','2');
