insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-10-01','Ana: Recibo llamada de Jesús, pareja de Felisi, han recibido carta de Diputación, al parecer se deben recibos de la vivienda. *Les facilito el nº de móv. de la Secc. Ecca. y envía imagen del documento. Además dice que han visto que en abril se pasaron 2 recibos (los días 16 y 25) y el 20 de septiembre le han pasado otro recibo de 37,67€ y no saben de qué. **Le paso todo a Belén, Secc. Ecca. ///////////////// Por otra parte dicen que Virginia no ha vuelvo a ir a visitarlos. Y que siguen con la cisterna rota. Por último añade que la cocian huele mucho a gas, que es muy vieja y lo mejor sería cambiarla. **Hablaré co Futuex para que valoren estas cuestiones.','2');
