insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2019-10-01','Ana: En relación al presupuesto de 200€ para Dentista, por el que me pregunta Paula, TO CRR Plas., compruebo que se hizo una autorización para retirar el efectivo del 2-6 de septiembre. ***Llamo a Paula, como está en terapia, se lo comunico a Blanca.','2');
