insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-09-24','Ana: Recibo llamada de Pablo, nieto de Manuela (676 783 101), sigue con intención de denunciar a la empresa de SAD. Le digo que por nuestra parte no hay inconveniente en que lo haga. Lo único que tenga en cuenta que según Marco Antonio Lobo, Jefe Ud. Dependencia, dice que será difícil de demostrar. Quiere hablar con Pedro, Jefe de Secc., le paso nota a Pedro para que le llame cuando pueda, hoy etá en una reunión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-01','Ana: Recibo llamada de Mª José, TS del Hptal. Virgen de la Montaña de CC (56348). Mª Pilar se encuentra en la UHB del hptal por un brote de Esquizofrenia, pero en Psiquiatría le dicen a Mª José que no cumple criterios para ingreso hospitalario. Como le han dicho que es tutela nos llama. Tras revisar la Sentencia confirmo a Mª José que es una Curatela de tipo económico, por lo que en principio no tenemos potestad para intervenir en otras cuestiones. **Le envío a Mª José al email la sentencia (mariajose.lozanol@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-01','Ana: Llamo a Mariola, Directora Res.San Jorge (927 62 80 10), no está. Me dicen que llame mañana en horario de 9:15 a 13:45 h. No obstante les pido que vuelvan a dejarle nota y que me faciliten un correo. Dice que no tienen el de ella, pero me dan el de recepción: recepcionsanjorge@grupociudadjardin.com /////////////// Envío e-mail A/A de Mariola.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-10-01','Buenos días. Comunicaros que la usuaria de Residencia RAL Felisa Bruno Saavedra, será hoy dada de alta de UHB, regresando a Residencia San Javier a lo largo de la tarde de hoy. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-02','Ana: Habiendo recibido respuesta al mail de Mariola, directora Res. San Jorge, envío otro (recepcionsanjorge@grupociudadjardin.com) confirmando que Consuelo dejará su plaza en Res. y volverá al CRR el 17 de octubre. ///////////// Lo comunico también a través de e-mail a Victoria Rajo, Directora. CRR-Plas. (residenciadir@feafescaceres.com). Le solicito además que me confirme el horario en que consideran será necesario el apoyo de Lucía Peña (acompañante).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-10-02','(Pedro)Conversación con Raquel (Hogar de Nazaret). +++Ante los correos -e recibido de D. Francisco Villegas "denunciando" la entrada en el domicilio y la puesta a la venta de muebles por parte de D. Julián Villegas, me pongo en contacto con el hogar de Nazatret para saber si es posible que José Pedro haya podido dejar las llaves a su hermano. +++Las llaves están en Dirección y José Pedro no tiene acceso a ellas, ni se las han dejado ni lo harán a nadie sin autorización de esta Comisión. +++José Pedro se encuentra muy bien, no pregunta por la hermana. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni (Futuex). +++Virginia ha estado en ambos domicilios y no ha visto nada diferente de lo que había en anteriores visitas. Ha realizado fotografía que nos enviará y tratarán de confirmar en Facebook (si es posible) la existencia de los artículos que Francisco dice haber puesto a la venta su hermano.','2');
