insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-10-02','Ana: Ayer recibí correo de Sonia Bernabé - ASINDI : "Hola Ana, ayer me llamó la hermana de Roberto y Justo Hernández Castaño porque va a solicitar una beca y me dice que le piden los datos de la discapacidad de sus hermanos. Le informé que ellos no están empadronados en la unidad familiar, pero me insiste que únicamente le preguntan si tiene algún familiar con discapacidad y que ponga los datos del certificado de cada uno de ellos. Necesito que me digáis si se los puedo facilitar o no. Hoy os mandaré el 4º trimestre de las visitas al domicilio de estos hermanos. Estamos viendo fechas para que no vayan tanto tiempo en navidades y Roberto no tenga problemas en el regreso. Un saludo" /////////////////// Con respecto a la solicitud ue realiza la hermana, respondo al correo indicando que le pregunten el Organismo al que solicita la beca y las orden/bases de la convocatoria de la misma.','2');
