insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2019-10-02','-Hablo con Antoino ( INSS CC PFHC ) , han dado de baja el expediente de PFHC . No puedo activar uno nuevo pq no tenemos cta. bancaria nueva abierta , hay q llevar el DNI a escanear y hasta diciembre no tiene permiso de salida. Preguntaré a Manoli del Ctro. penit. si ellos lo pueden llevar. -Hago escrito al Inss , le pido a Pedro que lo firme y registre de entrada pidiendo reactivar el expediente. -Es perceptor de PFHC ( titularidad la madre y es quien lo coge y le manda al hijo en peculio ) +P. ORFANDAD. -Cuando tengamos cuenta abierta hay q hacer cambio titularidad y nº cuenta de la PFHC Y cambio cta. de P. orfandad.','2');
