insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2019-10-01','-Hablo con la madre , la llamo al móvil , el fijo no lo cogía . La mujer es una señora mayor , enferma , no quiere perjudicar a su hijo pero no puede hacerse cargo de él en los permisos penitenciarios . En Navidad será el siguiente y dice q le dan 45 dias , no puede estar con su madre tanto tiempo . comentarlo con Manoli , a ver si se le puede dividir o buscar algún otro recurso. Es ludópata , le llega a robar el dinero a la madre . Para volver a Sevilla la madre paga al marido de la sra. que va a su casa a limpiarle 200€ y le da al hijo 100 .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2019-10-01','-Hablo con la madre , la llamo al móvil , el fijo no lo cogía . La mujer es una señora mayor , enferma , no quiere perjudicar a su hijo pero no puede hacerse cargo de él en los permisos penitenciarios . En Navidad será el siguiente y dice q le dan 45 dias , no puede estar con su madre tanto tiempo . comentarlo con Manoli , a ver si se le puede dividir o buscar algún otro recurso. Es ludópata , le llega a robar el dinero a la madre . Para volver a Sevilla la madre paga al marido de la sra. que va a su casa a limpiarle 200€ y le da al hijo 100 .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-02','Ana: Llamo a Mª José, TS Hptal. Virgen de la Montaña (56348), me comunica que Pilar, a quién dieron ayer el alta, está de nuevo hoy en urgencias, la tienen en observación. Le transmito la informaicón que hemos obtenido a través de Futuex. /// Habló con el SSB y le dijeron que ya han comunicado la situación a Fiscalía, pero de momento no han obtenido respuesta. //// Llamó a Salud Mental y Pilar, TS, le dijo que hace muchos años que no intervienen con ella. //// Con quién no ha conseguido hablar aún ha sido con el C. Salud. ///// *Le pido que, si quiere que lo pongamos en conocimiento de Fiscalía, nos remita Informe Médico de ayer, Informe de Psiquiatría, Informe Social suyo y si se los hacen llegar del SSB y C. Salud. //////////////////////////////////////// Llamo a Pilar, ESM-CC (54612), dice que no hay constancia de atención desde el 2003. El Psiquiatra que le atendía ya no está. Tendremos que solicitar informe por escrito a la Coordinadora del Equipo, Dra. Julia García White, Coordinadora de la USM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-10-02','TERESA: RECIBO ULTIMO INFORME DE PSIQUIATRIA CON FECHA 21/11/18 DESD ENTONCES NO ACUDE A CONSULTA. QUEDO A LA ESPERA DEL INFORME DE LA TS DEL SSB PARA TRAMTAR INTERNAMIENTO INVOLUNTARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-03','Ana: Se envía por fax (927 21 36 74)solicitud de informe de actuación al ESM-CC. A/A: de la Coord. del equipo, Dra. Julia García White. /////////////////// Convesación con Mª José Lozano, T.S. HVM-CC. Ayer finalmente dejaron ingresada a Pilar en la UHB, pero el Psiquiatra tiene intención de darle pronto el alta, posiblemente el lunes próximo día 7/10/19. **Me enviará informes de Urgencia (día 1/10), Informe de Psiquiatría e Informe Soc. emitido por ella. /////**Recibmos fax con dichos documentos. /////////////////// Llamo a Mª Teresa Doncel, TS IMAS-CC (927 627 138 = Edif. Valhondo) pero no obtengo respuesta.','2');
