insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-10-03','TERESA: Te adjunto el documento que ha elaborado la logopeda del centro y que ha explicado a Genaro. Le han quitado los dos dientes de arriba que le quedaban por lo que puede tener problemas de deglución. La logopeda ha considerado que necesita una dieta adaptada y evitar así problemas de atragantamiento ARCHIVO DOCUMENTO Genaro lo ha entendido y ha aceptado este nuevo menú','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-10-03','Ana: Llamo a José Miguel Martín, Concejal de obras del Ayto. de Guadalupe (626 070 969), dice que para asegurarse y que Juan se quedara más tranquilo se destaparon las tuberías de la calle y el problema no es de fuera. La avería está en la vivienda de Juan. Le propongo que acuda el Técnico Municipal, emita informe y nos lo envíe. A posteriori, una vez constatado que la avería es de su vivienda, se llevará a cabo la reparación y se abonará la factura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-09-20','Ana: Recibimos un fax de Raquel Moreno, T.S. - SSB Villuercas I-Ayto. de Guadalupe (Telf. 927 36 70 06 Fax: 927 36 70 49) solicitando nos pongamos en contacto con el Concejal de Obras D. José Miguel Martín (626 070 969). *Llamo al Concejal, me comunica que hay una avería en las tuberías en casa de Juan que está afectando a la calle y a las viviendas colindantes. Está saliendo mucha agua. **Acordamos que se realice la reparación necesaria y se remita la factura al email ctutelar@ para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-09-25','Ana: Recibo llamada de Juan (625 895 394), dice que el Concejal, José Miguel, ha estadon en su casa y que la avería no es de allí, que es de la calle pues en su contador no hay movimiento. Añade que dicha avería le está ocasionando problemas de humedad dentro. // A parte dice que no le hace falta las visitas de Teresa (Delegada - Futuex). Que le ha salido una fístula en el ano y que ha ido al especialista del hpta. él solo. Le han dado cita para revisión para dentro de 6 meses. //////// Por otra parte dice que la medicación que le están poniendo "no le hace falta para nada", que se están violando sus derechos civiles, que sus pensamientos son de dominio público, que todo lo que piensa sale en antena... continúa con su discurso delirante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-09-26','Ana: recibo la llamada de Juan (625 895 394), solicita 80 € para unas zapatillas (expresa que tiene problemas con el carcaño y las necesita, cuestan 40 €), para comprar butano y detergente. Le indico que todos los lunes cobra su asignación semanal y estas 2 últimas cosas debe pagarla con la misma. Argumenta que "vive bajo el umbral de la pobreza" y comienza a reproducir su discurso habitual. ***Finalmente, tras valorarlo con Alberto, Jefe Secc. Ecca., de decide aprobar un extra de 55 € para retirar la próxima semana, para el calzado y butano. **Ya se le aprobaron 2 extras en agosto y otro en sept.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-10-03','miguel, dado salida en registro ayer, envío hoy a Oficina Liquidora de Cáceres el impuesto de sucesiones con toda la documentación necesaria (fotocopias), en contestación a la subsanación que nos concedieron de 10 días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-02','Ana: Recibo llamada de Fco.-Hostal La Rosa. Ha hablado con Virginia, esta tarde pasará ella por allí para hablar en persona de la situación. *Mª Eugenia en el hostal mantiene buen comportamiento, no ha surgido ningún problema, pero ya le han dado quejas de algunos establecimientos de la zona. ///***Dice que se deben dos recibos, y que ese no era el acuerdo. Que ha decidido dar de baja el servicio del restaurante, pues él lo paga por adelantado y está dispuesto a seguir adelantano más dinero cuando a él no se le abonan las facturas correspondientes.**Hoy le ha entregado a Mª Eugenia el último bono diario de comida. **Pide además que confirmemos mediante correo con 2 días de antelación la reserva de las semanas sucesivas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-03','Ana: Conversación con Toni-Futuex, acordamos que Virginia acudirá al Comedor Social de CC, para ver si Mª Eugenia puede ir a comer allí hasta que le den plaza en Centro. Si esto no fuera posible preguntarán en el Catering "Qué bueno", donde se trataría de llegar a un acuerdo de comidas semanales que se abonarían por transferencia y por adelantado. ///////////// Belé, Secc. Ecca. envía un email a Fco, Hostal La Rosa, explicando la situación (dificultades con el banco que se están tratando de solventar a la mayor celeridad) y disculpándonos por la demora en el abono de las 2 últimas facturas. //////////////////////////////////////////////// Recibo llamada de Mónica, Técnico PIA - Secc. Depend. Brozas (21842), dice que le ha llamado Maribel Ramos, Secc. Recc. Discapac. pidiendo que le envíe de nuevo el PIA original firmado porque marcó "Plaza Residencial" en lugar de "Promoción de la Autonomía". Me lo enviará por mail para que lo ponga a la firma del D. Gerente, se lo adelantaré por mail y despues se lo remitiremos por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-09-27','Ana: Recibimos desde el IMAS-CC; Informe Social, 2 Informe de la Policía Local y breve Informe Médico de Att. Primaria. ///////////// Intento ponerme en contacto con el IMAS (927 21 23 35 / 927 627 138), pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-10-03','-confirmo con pensiones , percibe PENSION INCAPACIDAD PTE. ABSOLUTA . No hay que hacer nada . Tendrán que poner al gernete en la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-09-27','Ana: Convesación con Paula, T.O. CRR-Plas. Continúa el periodo de prueba de Conchi en Piso supervisado. **Confirmo a Paula que Conchi pasa la pensión compensatoria a su expareja por su hija (100€/mes) desde Julio de 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2019-10-02','Ana: Recibimos por correo ordinario el documento original remitido previamente (el día 17/09/19) por mail por Mª Jesús Gómez, TS de la Mancomunidad Comarca de Trujillo (Comunicando la incidencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-10-04','TERESA:RECIBO EMAIL DE LA TS DEL CENTRO Hemos tenido episodio con Natalia muy grave, y un fin de semana más vuelve a quedarse en residencia y no va a casa de su abuela a Badajoz. La abuela ya lo sabe y está de acuerdo, y ella, aunque amenazó entre otras cosas, con escaparse otra vez, hoy no lo ha hecho. Está ya más tranquila pero preparando “la venganza”. Lo que ha ocurrido es que se han confirmado las sospechas que tenemos hace tiempo, de que agrede a una compañera con grandes necesidades de apoyo (autista e invidente). La monitora de referencia de esta usuaria (Manoli) ha sorprendido a Natalia en el baño dándole repetidos puñetazos en la cara. Aunque en un primer momento lo ha negado, después ha reconocido que se había vengado de ella porque Manoli ayer le dio unos golpes que le han provocado moratones (algo muy improbable o al menos intencionadamente- Manoli es autista, ciega, no tiene comunicación y suele deambular por el centro o permanecer en sitios tranquilos sentada sin interactuar con nadie) Creemos que es un episodio bastante grave y que viene ocurriendo hace bastante tiempo pero no ha sido descubierta hasta ahora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-04','Ana: Adelanto por mail la Aceptación PIA rectificada, debidamente firmada y sellada a Mónica Duque, Técnico PIA-EVD Sección Brozas (monica.duque@salud-juntaex.es / 927 27 04 66 / 21842) /////////// Se da registro de salida al oficio y se envía por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2019-10-18','-Hablo con Jaime de la Asociacion Oncologica ( 673925159/924207713) , desde dependencia piden el contrato con la firma original . Me dice que ellos tienen una copia, la que tiene el SEPAD es original el sello de Consoli pero no el suyo . Va a enviar por correo una copia con el original por su parte. -Hablo con Juani , auxiliar que los atiende, se coge unos dias de vacaciones , la van a sustituir. Este domingo ingresa Julio para operarse , vienen sus hnas de Madrid. No se sabe el tiempo que estará hospitalizado. Desde la parte eco hacen la gestion para que durante estas semanas saque el dinero Isabel. ( Amalia )','2');
