insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-10-04','TERESA:, HALBLO CON EL ANA LA TS ME COMENTA QUE LA HAS CASTIGADO NUEVAMENTE SIN SALIDA DEL FIN DE SEMANA, FINALMENTE HA RECONOCIDO QUE HA SIDO ELLA LA QUE LE HA PEGADO A LA COMPAÑERA. EL PROXIMO DIA 21 TIENE CITA EN PSIQUIATRIA Y LE VAN A COMENTAR PARA QUE REAJUSTE LA MEDICACION. TAMBIÉN SE PLANTEAN POSIBLE DERIVACION A AL UDHAC EN FUNCION DE COMO SIGA SU COMPORTAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-04','Ana: Comprobamos en SIDEX que Pilar NO ESTÁ VALORADA de dependencia ni se le ha solicitado valoración. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro) Conversación con Toni (FUTUEX). +++El Psiquiatra, Dr. ¿Ballesteros? ha llamado a Gloria (Delegada Tutelar) para inofrmarle de la situación: +++++INGRESO: la va a mantener al menos hasta mitad de semana que viene. +++++TRATAMIENTO: va a ver su evolcuión con un jarabe y posterioremente valorar posible inyectable. +++++CONFIRMAR DISAGNÓSTICO DE ENFERMEDAD MENTAL. +++++PROPUESTA DE INTERVENCIÓN: prescribir inyectable y supervisión personal y pormenorizda de dicho tratamineto por parte de Gloria (Delegada Tutelar) con la que parece haber establecido coierta relación de confianza. Sobre todo al principio, realizar visitas muy frecuentes. +++Minetras tanto, solicitaremos ampliación de la incapacidad con medida cautelar de internamiento involuntario.Toni enviará el último Informe debidamente firmado para su inclusión en la solcitud. +++Paso el expediente a Miguel para solicitar AMPLIACIÓN de la INCAPACIDAD: pendiente de diagnóstico final, Informe del ESM e Informe firmado de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-04','Ana: Convesación telefónica con Lucía Peña - Acompañante (605 151 370), confirmo que el día de regreso de Consuelo al CRR será el día 17 de octubre. Acordamos la llegada al centro entre 10:30 - 11:00 h. *El apoyo que necesitará será principalmente para el aseo, ducha, vestido, arreglo del dormitorio y acompañamiento incial a paseos. No está segura si necesitará apoyo para la noche, valorará con Consuelo y con la Residencia y me confirmará el lunes. ///////////// Envío un correo con esta información a Victoria Rajo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-04','(Pedro) Conversación con Toni (FUTUEX). +++El Psiquiatra, Dr. ¿Ballesteros? ha llamado a Gloria (Delegada Tutelar) para inofrmarle de la situación: +++++INGRESO: la va a mantener al menos hasta mitad de semana que viene. +++++TRATAMIENTO: va a ver su evolcuión con un jarabe y posterioremente valorar posible inyectable. +++++CONFIRMAR DISAGNÓSTICO DE ENFERMEDAD MENTAL. +++++PROPUESTA DE INTERVENCIÓN: prescribir inyectable y supervisión personal y pormenorizda de dicho tratamineto por parte de Gloria (Delegada Tutelar) con la que parece haber establecido coierta relación de confianza. Sobre todo al principio, realizar visitas muy frecuentes. +++Minetras tanto, solicitaremos ampliación de la incapacidad con medida cautelar de internamiento involuntario.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-10-04','TERESA: LLAMA CRISTINA ENFERMERA DE SIERRA PINAR PARA PREGUNTAR SI LE PUEDE FACILITAR AL HIJO DE JOSE CERTIFICADO DE INGRESO EN RESIDENCIA Y CERTIFICADO MEDICO, LE EXPLICO QUE AL ESTAR TUTELADO NO PUEDE FACILIAR INFORMACION SIN NUESTRO CONSENTIMIENTO. ME COMENTA QUE AL INGRESO NADIE LES COMUNICO QUE ESTABA TUTELADO. LA MANDO LA SENTENCIA Y EL AUTO DE NOMBRAMIENTO PARA QUE LO TENGAN EN SU EXPDIENTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-10-04','TERESA: HABLO CON DISCAPACIDAD Y ME COMUNICAN QUE EL PADRE DE PALOMA NO DA FERFIL PARA EL MODULO DE DISCAPACIDAD. LLAMO A MARIOLA Y SE LO COMENTO. VAMOS A SOLICITAR INGRESO INVOLUNTARIO EN CENTRO POR DEPENDENCIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-10-04','miguel, llega cedula de citación cambio de señalamiento de procedimiento de división de herencia 72/2018 del Jzdo de Coria nº2. Llamo al jzdo para interesarnos por esta citación ya que es la primera noticia que tenemos, y me indican que la citación es para hablar con el secretario de la división de herencia de los padres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-10-04','miguel, envío contestación a demanda a Escalona, del procedimiento de remoción solicitada por su hijo Raúl. ********************************************************* Asimismo envío por email a la Notaria de Villajoyosa,Certificado Literal de Nacimiento del Rgtro Civil de Albacete, que nos llegó ayer original por carta. Con este documento ya tendrán todo para firmar esa herencia, y una vez la firmen nos la envíen para su ratificación (tendremos que solicitar autorización judicial para la aprobación de esa herencia)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='VAZQUEZ'and apellido2='RODRIGUEZ'),'2019-10-04','miguel, llama la abogada Jacinta (669-478594), me pregunta qué fue del escrito que hizo el 19-3-19 donde nos reclamaban dos importes que se abonaron tras el fallecimiento de Pedro Vaquez Rodriguez (fallecido el 28-8-18). Dice se sacaron dos importes 1600 y 800 aproximadamente el 7-9-2018. ******************************************************* Tras revisar el expediente con Pedro Js, comprobamos que la rendición de cuentas final recoge los movimientos de cuentas y se presentó después de esa fecha y ya recogía esos cargos. Dichas cuentas estan aprobadas por el Juzgado. ****************************************************** Remito a la abogada Jacinta,a que llame el martes a Alberto Js Económico, para la informe sobre la contestación a su escrito o cualquier otra información.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-04','miguel, me da Pedro Js el expediente donde me pide tramitemos ampliación de incapacidad de Curatela a Tutela. Me pide que en Medidas cautelares solicitemos el Ingreso involuntario en Centro. *************************************************** Me indica que está pendiente de dos informes: -El del psiquiatra que tendrá que dictaminar enfermedad definitiva a efectos de poder solicitar centro de enfermedad mental o bien de discapacidad. -El informe de Futuex','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-10-04','Ana: Llamo a Pilar Cerrillo (618 908 506), dejo mensaje en el buzón de voz para que me devuelva la llamada cuando pueda. ///// Vuelvo a intentarlo más tarde, hoy tienen fiesta en la residencia y la pillo en mal momento, acordamos que me llamará el lunes 07.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2019-10-04','miguel, llama su hija Inmaculada para indicarme su situación. Dice ser la tutora de su tía. Me dice que los tutores de su madre somos nosotros. Comenta que ha pedido la remoción suya con su tía para que asumamos su tutela nosotros. A parte quiere que tramitemos la herencia de sus abuelos ya fallecidos y que tenían bienes por la zona de Zalamea. Comenta que la documentación la tiene un abogado a la que se la ha dejado hace más de 6 años y que no ha hecho nada ************************************************ La pido que tome nota de nuestro email y nos de los datos del abogado y de ella. Que le pida al abogado toda la documentación y que o bien la escane y nos la envíe o bien venga por aqui a dejarnosla y la vemos. Dice vendrá la próxima semana a dejarnosla','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2019-10-04','Ana: Llamo a Vanesa(622 699 668), atiende el teléfono su pareja, Javier, Vanesa está trabajando. Le pido que por favor me llame el lunes por la mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-09-20','Ana: Recibo llamada de Ceferino, al final concedieron plaza en el CRR-Plasencia a su pareja, Ramoni, ya lleva allí 10 días. Dice que no están agusto allí, quieren irse a vivir los dos juntos a Logrosán, a la casa familiar que tiene allí Ramoni. **Le recuero que ya probaron esta opción una vez y no funcionó. Él insiste en que quiere volver a intentarlo. Le pregunto qué le han dicho los profesionales del centro y dice que le han dicho que depende de la Comisión. *Le digo que de momento no es posible y que en todo caso tendría que valorarlo en equipo y con el CRR. Volverá a llamar la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-09-24','Ana: Conversación con Puala, TO CRR-Plas. Me informa de que "Ceferino se gastó todo el dinero de Ramoni nada más llegar esta al CRR. Además ella no quiere irse a vivir con él, pero está muy influenciada y no sabe decirle que no a Cefe. **En el CRR no están de acuerdo en que se vayan a vivir los dos solos. Acordamos plantearle a Cefe, por ambas parte, que hable con Ramoni y valoren si realmente ella quiere irse con él. Así mismo, explicarle que no está preparado para dar ese paso. En cuanto al aumento de la asignación diaria (percibe 3€/día) que ha planteado en varias ocasiones, decirle que no es posible en la medida en que no está cumpliendo sus compromisos del plan de intervención del CRR. *Por otra parte felicitarle por haber terminado "el libro" que comenzó a escribir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-09-27','Ana: Llamada de Ceferino; le argumento todo tal y como acordamos Paula y yo (Anotación del día 24/09). **Ceferino dice que va a cursar el curso de acceso a la Universidad en la EPA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-09-24','Ana: Conversación con Paula, T.O. CRR-Plas. Antonia hará una visita a casa. Ya lo han hablado con la familia. Será del 1 al 4 de octubre. Por otra parte, *va a inscribirse como Demandante de Empleo en el SEXPE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-09-24','Ana: Paula, TO CRR-Plas. Informa que Conchi continúa de prueba en el piso, no obstante plantean si es posible aumentar la asignación semanal, pues en el mismo tiene que aportar dinero para los gastos comunes. ***Paso la nota a Alberto, Jefe Secc. Ecca.','2');
