insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-07','Ana: Recibo llamada de Lucía Peña (605 151 370): la familia de Consuelo le ha llamado diciendo que prescinden de sus servicios de acompañamiento porque no pueden seguir pagándole. Hablaré mañana con Alberto, Jefe Secc. Ecca., para adelantar el acompañamiento (ibamos a empezar el día 17 cuando retorne al CRR), a ser posible comenzarán mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2019-10-07','MODIFIACION DE LA CAPACIDAD Mediante Sentencia 80/18, de 26 de noviembre, se amplia la incapacidad de Bartolomé. Pasa a ser tutela. Mediante fax, se pregunta al jzdo. (1 de montijo) si la sentencia es firme. Éste contesta que Bartolomé ha solicitado asistencia jurídica grauita para recurrir la sentencia arriba mencionada. Finalmente, el 2 de octubre de 2019, el jzdo. infica la firmeza de la sentencia de modificación de la capacidad y solicita a la CTAEx la aceptación del cargo de tutor. Se procede, pues, a realizar el acuerdo de aceptación de cargo de tutor de Bartolomé. Se modifica, así mismo, el número de expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-10-07','Ana: En respuesta al correo de Sonia Bernabé, preguntando si Justo podría participar en el casting de la Federación Plena Inclusión para un corto-documental LGTBI (tendría que enviar un video presentándose y explicando por qué quiere participar), le respondo que como ese primer video será para uso interno, en exclusiva para hacer el casting, sí puede grabarse y enviarlo, y en el caso de resultar seleccionado para el corto, sí tendrían que enviarnos la autorización para que la firme el D.Gerente y comunicarlo desde aquí a Fiscalía.','2');
