insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PEDRO'and edp.apellido1='SAHAGUN'and apellido2='CHAMORRO'),'2019-10-07','miguel, llama su ex mujer Pilar para preguntar por el estado de la liquidación de la sociedad conyugal. Me comenta que ha fallecido ayer Juan Pedro... La indico que mañana hablaré con Alberto de la parte económica para que indique el estado de todo. Belén me indica que vendrán facturas sin pagar (la pido que la manden las facturas pero no las pague hasta pidamos autorización judicial) Pido a Pilar (exmujer)que su abogado Martin, nos envíe un email comentandonos lo que ella dice que el procedimiento por alimentos está ya para ejecución de sentencia. ********************************** Ver todo esto con Alberto Js económica.','2');
