insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='ROLLAN'and apellido2='SUAREZ'),'2019-10-07','-( Amalia ) Después de numerosos intentos , consigo hablar con Nuria Ts de VPP8924332459).La vivienda ha etado ocupada por dos chicos de 20 años que venían del sistema de protección de menores. Nos comenta que esta situación había sido acordada con el tio y la madre de Jonathan. Pero a su vez , es la madre la que ha acudidio a VPP para denunciar la ocupación. Vivienda denunció a los chicos , ya han salido de la vivienda y las llaves la tienen ellos. -Cuando salga juicio y sepamos liquidación de la condena hay que informar a Nuria ( se lo pido a Miguel seccion juridica )','2');
