insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-10-07','miguel, nos llaman por teléfono del Centro (Mariví) que está con Miguel Santos Cordero para decirnos dos cuestiones: -Hay que arreglar el tejado de uno de sus viviendas para lo cual los vecinos se pondrán en contacto con nosotros. -Existe una cuenta de la cual es titular Miguel y autorizado su hijo, me comentan que por allí se cargan luz, iberdrola, pensión y la cuota de 60€ que se le da al tutelado. ******************************************************* Quedo en que veré el expte con Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO RAFAEL'and edp.apellido1='GUTIERREZ'and apellido2='GALLEGO'),'2019-10-07','TERESA: HABLO CON EL PADRE FERNANDO PARA COMUNICARLE QUE LA PF QUE ACTUALMENTE COBRA LA MADRE LA TENEMOS QUE PONER A NOMBRE DEL TUTOR LEGAL, LE PIDO EL TELEFONO PARA COMUNICARSELO A SU MADRE. ME FACILITA EL TELEFONO DE LA MADRE M CARMEN 654786109 PARA QUE LE COMUNIQUE EL CAMBIO. QUEDO EN LLAMARLE UNA VEZ ESTE RESULTA LA PF PARA CUADRAR CUENTAS YA QUE LA MADRE PAGA PARTE DE LA PLAZA PUESTO QUE CUESTA 1200 EUROS AL MES. ALVARO PERCIBE LA PF Y ORFANDAD CON ESO SOLO PAGA EL 50% DE LA PLAZA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-07','(Amalia y Pedro) Visita programada de Dª Mª Dolores. Temas recurrentes: +++Dinero. +++Colchón. +++Plaza residencial. Se le explica que tiene un Grado I, lo que implica que no puede tener acceso a plaza pública. +++++Acceso a PLAZA PRIVADA: requiere la venta de su piso para poder pagar la plaza. Para ello su hermano tiene que marcharse. Se le indica que hable con él para que antes de Navidad haya hablado con la T. Social de su localidad para que le tramite plaza residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-10-07','(Amalia y Pedro)Visita programada de D. pedro tomás a la Comisión. +++Comprar coche para su pareja:no viable ni judicial ni económicamente. Se valoran inconvenientes e imprevistos. +++VENTA DE LA VIVIENDA: está de ACUERDO con la venta. Se le esplican los trámites: declaración de hererderos, aceptación de herencvia y solcitar autorización judivcial para la venta. +++PRESUPUESTO DE GASTOS: de momento dispondrá, como hasata ahora, de toda la pensión en pago único, hasta que se vea la posibilidad de tener derecho a PF y Orfandad para ajustar dicho presupueesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-10-07','(Amalia y Pedro) Visita programada a la Comsión. +++Pendiente de cita en ESM el 25 de octubre: planteará al psiquiatra la solcicitud de ingreso en CRR. +++Alimentación: propondrá en el comedor social que le acepten para comer a cambio de pagar dicha comida. +++++Alternativa: buscar un restaurante en el que le pongan un menú diario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2019-10-07','Ana: Solicito a Vanesa(622 699 668) que me envíe a través de la T.S. del SSB, copia de su contrato de trabajo. *Pregunta por su cartilla del banco, pues ya tiene la Resolución de la Curatela. Le pido que me envíe copia también. *Dice que en lugar de acudir al despacho de la T.S. me lo enviará por fax. Le facilito el nº.','2');
