insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2019-10-08','- ( Amalia ) El Gerente ya está incluido en la cuenta de Ibercaja. Pido a la sección eco que autorice a sacar la pension integra al principio de mes . Este mes ya ha sacado 300€ desde el CSS , le queda el resto . Suministros de su casa se pagarán de ahorros . -Paso a la parte juridica que comience las gestiones para la venta de la casa .','2');
