insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-10-08','miguel, atiendo vía telefónica a Mercedes Ts Plena Inclusión de Llerena a petición de Teresa Ts, para informarla de los pasos dados en el Recurso de Apelación que hemos interpuesto al régimen de visitas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-10-08','TERESA: LLAMA MERCEDES DE PLENA INCLUSION PARA PREGUNTAR COMO VA EL PROCESO DEL REGIMEN DE VISITAS DE BEATRIZ, BEA SE ENCUENTRA MAL Y NO DEJA DE PEDIR QUE QUIERE VER A SU HIJA, LE PASO CON MIGUEL PARA QUE LE EXPLIQUE LA SITUACION TAMBIEN ME COMENTA QUE SE ESTAN PLANTEANDO LA POSIBILIDAD DE HACERLE LA LIGADURA DE TROMPAS YA QUE BEA NO QUIERE IR A PONERSE EL INYECTABLE. ME PIDEN AUTORIZACION PARA PASAR EL PUENTE DE NOVIEMBRE EN SU CASA, QUEDO PENDIENTE DE VALORAR PARA AUTORIZAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-10-08','De: Ana Delfa Cantero >adelfa.sanmiguel@hospitalarias.es> Enviado el: martes, 8 de octubre de 2019 9:45 Para: Amalia Diaz Gonzalez >amalia.diaz@salud-juntaex.es>; MARIA DEL MAR SANCHEZ GARCIA >mariadelmar.sanchez@salud-juntaex.es> Asunto: Mercedes P P Buenos días a ambas; Os comento que he atendido en varias ocasiones a Mercedes P. P., le hubiera tocado por lista de espera iniciar ya proceso, pero ella ha mantenido negativa para hacerlo. Ante esto he dado citas y la he llamado. La última cita que mantuvimos el 23/09 estaba mejor que en anteriores ocasiones, había retomado tratamiento aunque el seguimiento de inyectable se lo hacían a nivel privado. Mi idea era verla yo puntualmente para ir trabajando el que pudiera iniciar proceso, pero ayer me llamó y me dijo que no iba a venir a la cita de la próxima semana y que su problema era en relación a temas administrativos con la C tutelar que a mi entendía que no me iba a contar. Intente mantener contacto pero fue imposible, ante esto quedaré unos meses más en lista de espera por si hubiera cambios. Os traslado esto porque el hecho de que acuda a su Esm solo para citas con su psiquiatra y dado que estas suele ser muy espaciadas, puede ser un riesgo. Espero que vaya lo mejor posible y cualquier cosa que estiméis o volareis aquí estoy, un abrazo.','2');
