insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-09-24','Ana: Paula, T.O. del CRR, me comunica que Eugenia, ha regresado al CRR, del CSS (estaba a media estancia). Su pareja tiene una casa en Tejeda y plantean probar a vivir juntos en la misma. En el CRR no les parece una relación equilibrada, pero plantena hacer la prueba (máximo un mes). Proponen que tengan 150€ para comida, pero no lo solicitarán a no ser que sea extrictamente necesario. En este caso enviarán un mail al ctutelar@ con 2-3 días de antelación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-08','Ana: Recibo llamada del Padre de Consuelo (927 582 223), di que no está convencido de que Consuelo vuelva al CRR, tiene miedo de que vuelva a ocurrir y porque según dice hay un chico en el centro que consume y no quiere "que se junte con él". Había pensado en el centro de día de su pueblo, pero le explico que no es un centro adecuado a la patología de Consuelo y que en el CRR cuenta con profesionales que ella requiere. Parece quedarse más tranquilo. /////////////////////////////////// Acuerdo con Alberto, Jefe Secc. Ecca. aprobar el acompañamiento de 2h diarias de Consuelo desde mañana, si fuera posible.','2');
