insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-10-08','-Amalia : acude a cita en despacho. Tiene una citación judicial para el dia 3 de diciembre por violencia doméstica ( a su madre ,hermanos...) , teme que lo puedan ingresar en Ctro. penitenciario. -Sigue viviendo en la calle. Acude a las duchas de las Hermanas. Allí le dicen que no puede comer pq tiene ingresos eco. Le indico que pregunte si podría comer haciendo una aportación economica. Otra alternativa que le planteo es que se busque un bar donde le permitan la entrada y podamos ajustar un menú diario. Dice que come de bocadillos. Nos trae la factura de unas gafas , le doy el OK y se lo paso a la parte eco para que lo abone. Quier guardar sus casas en un guardamuebles ( Hidalgo Mañero) , va a preguntar . Acude al ESM el día 25/10/2019 para solicitar ingreso en CRR .','2');
