insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-10-09','-Amalia : ingresado en C.R. La Granadilla desde 2015. -Es a su vez tutor de un hermano que reside en un centro residencial de Coria , lo paso a la sección jurídica para que regularicen esta situación. -tiene un piso alquilado , el inquilino no abona desde hace años , está en trámite judicial. Posteriormente quiere venderlo. -Tiene dos hijos con discapacidad con los q no mantiene contacto.','2');
