insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-09','Ana: Llamo a Lucía Peña, Acompañante (605 15 13 70), confirmo que pueden retomar el acompañamiento de Consuelo (2 horas/día). No saben si podrán acudir hoy mismo, sino retomarán mañana. En cuanto al taxi para el traslado al CRR el día 17 se encargará de gestionarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-10-09','Ana: Conversación con Pilar Cerrillo, le informo de que la solicitud PFHC la registré en septiembre y de que ayer acordé con la Jefa de Sección la priorización de la valoración de dependencia. En cuanto al rescate del Contrato de Valores, los compañeros de las Secc. Ecca. y jurídica están en ello. **Acordamos que, por su parte, hablará con el Gerente para NEGOCIAR LA BAJADA DE PRECIO DE LA PLAZA en la residencia. Por último me comunica que un sobrino de Pedro Román, que le visita con asiduidad, le ha dicho que de vez en cuando le da dinero a Pedro R. Y sí que es verdad que esporádicamente él sale a tomar café o saca algún refresco de la máquina del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-09','(Pedro)Llamada de D. Pedro, hermano de Mª Dolores. +++"Deja de meterle pájaros en la cabeza a mi hermana porque la casa NO SE VENDE, porque es mía y de ella...Y yo la he pintado, la he picado y la he arreglado -¿con qué dinero?- y no se vende -¿y quién paga el IBI, la luz, el agua...?-','2');
