insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-10','Ana: Recibo llamada de Marisé, Gerente del Hostal La Rosa (678 615 089), se deben varias facturas por un importe total de 700€, expresa que es un negocio familiar, que tienen que hacer pagos y que tiene que comer. Quiere una explicación y saber si van a cobrar y cuándo. *Le explico el problema con el que nos encotramos con la entidad bancaria (la cuenta está bloqueada a raíz del cambio de Representante Legal de la CTAEX). **Pedro, Jefe de secc. CATEX le llamará. ///////////////////////////////////////// Llamo a Marisé, Hostal La Rosa (678 615 089), le pido disculpas de parte de Pedro pues no ha podido llamarle, le indico que hemos acordado una excepción con el banco, mientras se soluciona el problema, y que si todo va bien, mañana por la mañana la Virgina, Delegada Tutelar, acompañará a Mª Eugenia al banco a retirar el dinero y poder abonar las facturas pendientes en efectivo. ///////////////////////////////////////////////////////// *En cuanto a la comida, mediante conversación telefónica, Toni-Futuex, me confirma que la admitieron en el Comedor Social, pero creen que no está asistiendo con regularidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-10','Ana: Con anterioridad a a la Aceptación de la Tutela, a fecha de 3/06/19, la CTAEX aceptó el cargo de Defensor Judicial. En el expte. se encuentra la Carpeta "Defensa Judicial" con Informes: Social, 2 Médico-forense, varios de Psiquiatría (UHB y CSS) y otro Médico de las Hermanas Hospitalarias de Cataluña.','2');
