insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2019-10-10','TERESA: Beatriz ha sufrido una caída y debido a las lesiones tiene que guardar reposo, os remito el informe. En principio tiene que guardar reposo absoluto durante 3 días y después puede levantarse de la cama, pero hasta que no la vea el traumatologo no sabe exactamente cual va a ser el tratamiento. Le han dicho que la verán en 10 días aproximadamente. Mientras tanto su madre se ha trasladado al domicilio con ella y su pareja se encarga de hacerle los tramites burocráticos; van a pedir a la cruz roja unas muletas y tambien van a solicitar el traslado al hospital cuando la cite el especialista. Hoy le he realizado visita domiciliaria; estaba en la cama, tiene puesto pañales, aunque se ha levantado para ir al baño y dice que se ha lavado, no es capaz de hacerlo en condiciones y su madre no lo hace bien, además de que discuten por todo. Le he recomendado a su madre que se quede con Beatriz hasta que pueda levantarse y pueda por lo menos ir al baño sola y en principio será así. De todas formas, me gustaría plantearos: ¿Sería posible contratar a alguien un par de horas al día para que la ayudase en la higiene personal y ayudarla en las tareas más importante? No se si sería o no posible, pero os lo planteo para que habléis con ella la posibilidad, ya que la higiene no la tiene muy bien. Esta a la espera de servicio de ayuda a domicilio de Ayuntamiento, no se si ya se ha hecho los tramites para que este en lista de espera y si es así, no se si sería posible una ayuda puntual hasta que se encuentre bien. HABLO CON EL AYUBTAMIENTO DE ZAFRA A FECHA DE HOY SIGUE EN LISTA DE ESPERA Y NO HAY HUECO COMO ALTERNATIVA ME OFRECE LA AYUDA A DOMICILIO MUNICIPAL PERO ESTA SOLO PRESTA SERVICIO UN DIA A LA SEMANA UNA HORA. LE PLANTEO A ALBERTO A LA SITUACION PARA VER SI PODEMOS HACER FRENTE AL PAGO DE UNA CUIDADORA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2019-10-10','TERESA: como ya comentamos por teléfono, la delegada tutelar esta intentando que Paco se actualize un poco, una de las ideas que hemos tenido es comprarle un móvil, os paso un presupuesto, también en la misma tienda nos pueden contratar la línea por 12€ al mes con llamadas ilimitadas o le compramos una tarjeta de prepago como vosotros veáis un saludo José Julián Real Giraldo LO PASO A ALBERTO PARA QUE ME DE EL OK','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN ANTONIO'and edp.apellido1='EVERLISTA'and apellido2='LEONISA'),'2019-10-10','-Está muy mal , van a enviar de la residencia de el Valle de Montijo (21746)un pto. con funeraria para cuando se necesite. Se le dará el OK .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-10-10','-Amalia : respuesta desde el ESM a Ana , del CRPS donde no quiere acudir. MARIA DEL MAR SANCHEZ GARCIA Jue 10/10/2019 12:56 Buenas tardes, Te agradezco Ana que la mantengas en Lista. A Mercedes P.P. desde el ESM se le da cita más continuas, tanto con Psiq., Enfermería y TS. Ella no es que falta a las consultas, llama a administración antes de la fecha de cita, indica que no puede venir, que se encuentra bien y pide que le den cita para dentro de 6 meses o más porque ella está bien. Respecto a C. Enfermería, se ha insistido en que debe venir a seguimiento, ella dice que prefiere por lo privado. En cuanto a mi consulta, ella siempre dice que no tiene tiempo, ni dinero para venir (transporte en Taxi), le indico que venga andando, pero según ella tiene un problema en los pies. Hablo casi todas las semanas con ella por teléfono, animándola a venir, sin éxito. Seguimos llamándolo. Saludos. Mar Sánchez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2019-10-10','-Amalia : contacto con CSS Merida, Maribel , para que gestione el traslado al centro en Fuente de Cantos. Ella avisará a la familia . Lo harán la semana que viene con el coche del CSS.','2');
