insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2019-10-08','Ana: El día 8 recibí un correo de Sonia, ASINDI (trabajosocial@asindi.e.telefonica.net), "Hola Ana, quería comentarte dos temas: - Hermanos Rodriguez Alcántara. Tienen un hermano que vive con su mujer y su hija en Plasencia, hace tiempo que nos les ven y por ambas partes hay ganas de encontrarse. El hermano y la cuñada nos dicen que si podemos organizar el viaje para que vayan a pasar el día a Plasencia el próximo 27 de octubre (domingo). ¿Puedo organizar el viaje para que vayan en taxi?. La siguiente visita sería en diciembre a su casa para ver a sus padre un día durante las fiestas navideñas." Respuesta al correo: "...En cuanto a la visita de los hermanos Rodríguez Alcántara a Plasencia, en principio no hay problema, pero el Jefe de la Sección Económica me pide que enviéis un presupuesto del taxi al correo ctutelar@, indicando en el asunto “Secc. Ecca.”','2');
