insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2019-10-15','-Amalia : Llamo al Centro Fco. Asuar de Fuente de Cantos para ver cómo va el tema del traslado. Me dice la Dtra . ( Rosa , tf. 924500211( ayto ) 667693216 ( trabajo Rosa ) que nadie la ha llamado aún. Quedo pte. enviarle sentencia y documentación . ver temas economicos , pago d plaza , dinero bolsillo... ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con Maribel, T. Soc. del CSS de Mérida. +++Tiene pendiente hablar con Rosa hoy para realizar el traslado. +++Nos avisará cuando se vaya a realizar. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo-e de Maribel: ha hablado con Fuente de Cantos y han quedado en que seguramente el lunes 21 de octubre se pueda realizar el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2019-10-15','(Pedro)Conversación con Catalina. +++Quiere cambiar de piso porque en el que vive está muy lejos de su médico, del sepad, etc. +++Dice que alquilan un cuarto piso en el mismo bloque en el que estaba antes y se le dejan a mitad de precio (¿?). +++A pesar de que se quiso marchar de ahí por problemas con la vecina dice querer volkver porque ya no estará en la misma planta y el alquiler le sale más barato. +++Envío correo electyrónico a Futuex para que en próxima visita a Catalina hablen del tema, vayan a ver el piso y valoren lo oportuno del cambio propuesto por ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-10-15','(Pedro)Conversación con Inmaculada, T. Soc. de Guadiana. +++Estuvo tratando ayer de hablar con Amalia y Futuex sobre el acompañamineto al Juzgado. de hoy. +++Le informo que Dª Rosario no tiene que ir y que Amalia le ha enviado un correo-e al respecto (no lo había visto).','2');
