insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-10-10','Ana: Recibo correo de Paula, TO CRR-Plas.: "...• Conchi Fernández Muñoz: está ingresada desde ayer por la tarde en la UHB del Hospital Virgen del Puerto; como te comentamos en días anteriores estuvo unos días en el CRR para hacerle un mayor apoyo. Salió al domicilio de su hermana durante una noche, y tuvo que regresar por las conductas erráticas y conflictos que tuvo. A su vuelta, tras regresar presenta alteración en los ritmos vigilia-sueño, apareciendo la necesidad de salir durante la noche del piso para "despejarse" y constándose después un malestar general e irritación que nos llevan a apoyar una consulta a urgencias y el posterior ingreso. Os mantendremos informados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2019-10-10','Ana: Recibo correo de Puala, TO CRR-Plas.: "...• Julián Gutiérrez Roncero: estamos trabajando el aumento de autonomía en la toma de medicación, siendo responsable de la auto administración diaria (le facilitamos el blíster cada día y toma la medicación en contexto grupal en presencia de un profesional. Su labor es custodiar el blíster y responsabilizarse de tomar la medicación). Continúa con un buen manejo del dinero de forma semi-autónoma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-10-16','Ana: Recibo un correo de Paula, T.O. del CRR-Plas.: "...confirmarte el alta hospitalaria de Conchi Fernández. Vuelve al piso dónde se está articulando un apoyo intensivo...". Respondo que está bien que intensifiquen el apoyo, pero que quizá deben replantear el cambio de recurso de Conchi. Por otra parte, en cuanto al aumento de la asignación mensual, les digo que desde el área eco. no lo ven, pues haciendo media de los gastos de todo el año, la media del gasto mensual supera al ingreso que tiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2019-10-16','Enviamos al Abogado, Ángel García Calle, documentación para que inicie los expedientes de aceptación de herencia y de venta de fincas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-10-16','miguel, hablo con el Jzdo de Coria nº2 por el procedimiento división de herencia de los padres nº72/2018.El padre D.Julián Villegas Montes falleció 13-2-1984 sin otorgar testamento (tendrán que otorgar declaración de herederos), y la madre Elena Serrano Mendez Galan, falleció 18-1-2011, y otorgó testamento ante el notario de Coria D. José María Marín Vázquez, con protocolo nº 1990, el 13-11-1997 Abogacía general a través de María Guerrero en email de hoy ha dejado claro que no nos asistirá en este procedimiento. Al haber solicitado por fax representación procesal al juzgado de oficio (abogado y procurador), me confirman que ya lo han solicitado al colegio de abogados. Por otra parte nos deniegan la videoconferencia por motivos de imposibilidad de sala, con lo que asistiremos. ************************************************************ El jzdo nº2 de Coria nos remite la documentación que remitieron a abogacía general y que éstos no nos han remitido, y que está compuesta por la diligencia de ordenación citandonos el 20-11-19, junto con la demanda, que está acompañada por certificados de defunción y testamento de la madre y nota simple. En dicha demanda se reconoce se deja unicamente la legítima a los 5 hijos de la casa de coria, y a jose pedro y cristina les concede tercio de mejora y libre disposición de la vivienda. La legítima a todos los hijos. Y el crédito de 12.000.000 pts que debe Julian a sus hermanos a partes iguales, despues de descontar su parte. pero no se acompañan certificados de saldo de cuentas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2019-10-16','ICIAR: SE LE AUTORIZAN 80 € PARA IR A REHABILITACIÓN. LLAMA LA MADRE. CONFIRMO CON RITA (TRABAJADORA SOCIAL) QUE EFECTIVAMENTE ESTÁN YENDO Y QUE EL VIERNES TARDE NO HAY AUTOBÚS DESDE SEGURA DE LEÓN.','2');
