insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2019-10-16','miguel, Nos visita Camilo, y hablamos con él Alberto y yo. Nos dice que tendrá que demandarnos debido a que no le pagamos. Le volvemos a comentar que el problema de no hacerlo es estar a la espera de la resolución de la autorización de gastos extraordinarios por parte del juzgado de Don Benito. ********************************************************** Acuerdo con Alberto Jsec el envío de un fax notificando la visita de Camilo al Jzdo y así lo hacemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-10-17','Ana: Recibo correo de Toni-Futuex. "A continuación se adjunta nota explicativa, más facturas y prepuestos (para cama articulada) que solicita con la vehemencia que le caracteriza, el nieto de Dª Manuela Morato Picado. Insiste de igual modo, en la pertinencia de la obra, con la subvención para reformas, se le explica que se solicitó un informe técnico por parte de la comisión para la valoración del estado de la cubierta (tal y como hablamos en la última reunión de coordinación). Amenaza, como hace habitualmente, en acudir al juzgado, para que se atiendan según él ¨las necesdiades de su abuela". A pesar de todo, las visitas se desarrollan con normalidad, y consigue tranquilizarse. Muchas gracias!"','2');
