insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2019-10-17','miguel, nos llega del juzgado resolución Decreto y Comparencia donde se nos requiere del pago vía ejecutiva, con procedencia de un procedimiento monitorio por reclamación de cantidad. Tras llamar al Juzgado de Don Benito nº2 y hablar con ellos me confirman que nos notificaron este procedimiento 4-1-19 y que tras 20 días al no contestar la parte actora pudo solicitar la ejecución de pago por título ejecutivo. Me indican cómo proceder al pago. Veo el requerimiento de pago con Alberto Jsec y comprobamos que no tiene más bienes que una cuenta en la cual la ingresan unos 320€ por lo que la pensión sería inembargable. *********************************************************** Hablar con Tere Ts para que me entregue Certificado de Pensiones a efectos de acreditar la inembargabilidad de sueldo al juzgado de Don Benito nº2','2');
