insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2019-10-18','miguel, Ana Ts comprueba que falta el certificado de pensiones de la tutelada y lo solicita vía email al Inss. Una vez que nos llegue comunicaremos al juzgado de don benito que por insolvencia no se puede cumplir la sentencia de la reclamación de cantidad por la que fue condenada. ********************************************************** Llega el certificado de pensiones del Inss y vemos que tenemos controlada una de las pensiones: la PNC de la Junta de 306,17€,pero descubrimos que tiene una con el Inss por viudedad que desconociamos de 919,24€, esto significa que no es insolvente y que o paga o la acabarán embargando. Ver con Pedro Js para que hable con las Monjas a efectos de poder pagar la sentencia e informarnos de esa cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-17','Ana: Recibimos del Juzgado de 1ª Instancia nº1 de CC, el mimso Informe de Psiquiatría, de la Dra. María Ríos Muñoz, que nos remitió por fax Pilar Martín, TS del ESM-CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2019-10-18','miguel, tras revisar el borrador de la declaración de herederos para la firma de la herencia y del borrador de la compraventa, remito email confirmandoles que una vez lo firmen nos lo remitan para podamos ratificarla en Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-18','Ana: Recibo llamada del Psiquiatra Dr. David Gimeno, Juan Angel está ingresado desde ayer en la UHB. Dice que para este caso ya se han convocado numerosas Subcomisiones Sociosanitarias, que lo que no puede ser es que los pacientes tengan que adaptarse al Sistema, que es el Sistema el que debe adaptarse. Él mismo, a pesar de que considere que el CSS no es la mejor opción, pues expresa que es un "Psicópata", sabe que no hay otra alternativa posible. *Le informo que Pedro Gracia, Jefe de Secc., ya ha hablado con Soraya y le ha solicitado convocar una Subcomisión Sociosanitaria. Me pide el número directo de Soraya para hablar con ella y agilizar el paso al CSS. **Acordamos que le enviaré por mail la Sentencia y la Aceptación del cargo (david.gimeno@salud-juntaex.es) así lo hago. Le pido, en el mail, que nos remita informe para adjuntar a la solicitud de Ingreso/Mantenimiento de la Medida de Internamiento Involuntario. ///////////////////////////////////////// LLamo a PFHC-Ba (924 21 61 52) Gloria me informa que la madre de Juan Ángel percibe PFHC.**Puesto que tb percibe Orfandad, enviaré nuevo expte. de solicitud de PFHC a nombre del D. Gerente. **Juan Ángel tiene reconocido un 76% de Discapacidad y Grado I de Dependencia. De momento no le voy a solicitar Complemento ATP. ////////////////////////////////////// /////////// **Conversación con manos libres entre Miguel-Asesor Jurídico, La Letrada y yo y a posteriori con la Jueza también. Se le explica las acciones llevadas a cabo hasta el momento y que no cumple requisitos para ningún centro (detallando cada tipo de recurso), La Jueza dijo que en 72 tenía que acudir a ratificar el ingreso involuntario por 112, en UHB. La idea es que pase a UME (CSS). Acordamos que en el momento en que sea ingresado en UME lo notificaremos al Jgdo. En caso de que a posteriori le den el alta en el CSS, tendremos que solicitar al Jgdo. Ingreso Involuntario, para lo cual necesitaremos el Informe de Psiquiatría.','2');
