insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-18','-Amalia : emil del CRR : Ayer por al tarde Mª Dolores, le dice a los compañeros que ha tomado una caja de Ibuprofeno y alguna otra pastilla, ante esto activamos el protocolo, llamando al 112. en el hospital por por precaución se ponen en contacto conmigo solicitando el ingreso e UCI de la misma, aunque se encontraba bien, querían hacerle un seguimiento, por lo que me solicitan el consentimiento de que se quede ingresada. Por el momento sigue ingresada y no tenemos noticias nuevas.','2');
