insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2019-10-18','Iciar: llama Pilar MAteos T.S. de ssb Badajoz 924 47 87 77. Ha estado visitando a Carmen. La vivienda no se encuentra en buen estado aunque Carmen está aseada. Dice tener un piso en alquiler del que no está ingresando ninguna mensualidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2019-10-18','Ana: Realizo llamada a Maite, TS C. Penitenciario de CC (927 18 14 07) varias veces para conocer a qué centro trasladaron finalmente a Antonio, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-18','miguel, Maria Guerrero me pide llamemos al Jzdo a la letrada. Hablamos con ella y la Juez Ana Ts y yo, nos dicen que no les hemos notificado el ingreso en la UHB de este tutelado pese a que en sentencia nos lo pedían. Ana les explica los trámites que se estan realizando por parte de la Ctaex (solicitud de Subcomisión, hablado con Soraya por Pedro y Ana para la asignación de Centro, etc) Aun así dicen que ven una dejadez desde hace mucho por parte de todos los que rodean al tutelado. La juez confirma que irá a la UHB y que solamente ratificará el mantenimiento de la medida de internamiento del tutelado si así lo confirma el psiquiatra. En cuyo caso posteriormente se intentará su internamiento en centro socio sanitario de Mérida. Caso contrario, que no haya mantenimiento de la medida (según la juez depende su decisión de lo que diga el psiquiatra) y por tanto le dieran el alta, tendríamos desde la Ctaex inmediatamente solicitar autorización de ingreso involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-10-18','miguel, remito al Jzdo nº1 de Zafra solicitud de videoconferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-21','Correo del 19 de octubre del CRR de Mérida. +++Buenas tardes, El jueves por la tarde ingresaron a María Dolores Fernández Báez en UCI por ingesta de medicamentos. Nos comentan que entre hoy y el lunes decidirán si la pasan a planta o a UHB. Le han hecho un lavado de estómago. Seguimos en contacto,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-10-21','Correo-e del CRR de Mérida del 19 de octubre. +++...Ángel Pinilla se encuentra en el CRR desde ayer por la tarde y, de momento, nos cuentan los compañeros que está de buen humor y el recibimiento del resto de usuarios ha sido muy positivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2019-10-21','TERESA;: Buenas tardes. Me pongo en contacto para comunicarles la sanción impuesta a Libertad García por parte de la Comisión Técnica de Observación de los Servicios de Centro Ocupacional y de Residenciaambos dependientes de PLENA INCLUSION LLERENA a los cuales pertenece la citada usuaria. Le adjunto la sanción para que les conste y les comunico la salida a su casa desde hoy viernes dia 18 hasta el sábado día 26 de octubre de 2019. El traslado lo ha hecho en autobús. Lamentamos mucho tener que tomar esta medida, pero Libertad incumple reiteradamente las normas mínimas y básicas de convivencia en el Centro considerándose faltas graves.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SARA'and edp.apellido1='VAZQUEZ'and apellido2='GILES'),'2019-10-21','TERESA: ENVIO AUTORIZACION EXCURSION PLAYA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-17','Ana: Consuelo vuelve al CRR, a priori todo va sin incidencias. Lucía Peña, dice que la taxista no quiere enviar factura, por lo que lo ha abonado ella (5€) y nos remitirá lluego la factura para justificar el gasto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-15','(Pedro)Visita de Dª isabel, madre de Juan Ángel. +++Tras exponer la situación "desesperada" de su hijo y a mi pregunta responde que él está deseando ingresar en el Centro y se compromete a llevarlo a la UHB, donde ya están avisados de qué hacer cuando ingrese.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-18','Ana: Tras intercambio de e-mail con Vicotira Rajo, se mantiene también conversación telefónica con ella. Se acuerda un acompañamiento de 3 horas en horario de mañana (8:15 - 11:15), desde el CRR también plantean una hora de acompañamiento por la tarde-noche, pero Lucía dice que ella no puede. **Aunque en el CRR son reticentes a que haya más de 2 personas externas realizando este apoyo, dada la situación finalmente acceden. *Pediré a Lucía el número de Ana (la otra persona que ha realizado el acompañamiento a Consuelo en la Res. de Mayores) para que acuda el lunes por la mañana a hablar con Victoria Rajo y a firmar el documento de confidencialidad. //////////// *Llamo a Lucía (605 151 370), pero no consigo contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-21','Ana: Hablo con Lucia (605 151 370) me facilita el nº de Ana: 678 39 78 25. La llamo, dice que hoy no puede pasarse, pero se podrá pasar mañana. /////////////// Habo con Victoria, dice que tras haberlo valorado estas primeras tardes, han confirmado que Consuelo no necesita ningún apoyo externo por las noches. Avisaré a Ana. ***En cuanto al regreso de Consuelo al CRR, de momento se está readaptando muy bien. //////////////////////////// *LLamo de nuevo a Ana-Acompañante (678 39 78 25) y le informo que ya no son necesarios sus servicios.','2');
