insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-21','(Ana y Pedro) Visita a Juan Ángel en la UHB de Mérida, junto con David, su Psiquiatra. +++SE le explica cuál es su situación legal, cuáles son las funciones de la CTAEx y qué pued eesperar de ella, así como qué puede esperar la Ctaex de él en su proceso de recuperación de su autonomía. +++Buen comportamiento desde el ingreso, refiere querer seguir estando tutelado siempre. +++Su Psiquiatra ha enviado la petición de derivación a UME, considerando que en función de la evolución pueda ser candidato a los demás recursos de la red.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-10-21','Ana: Correo de Paula, T.O.-CRR, dice que el periodo de prueba de Conchi ya finalizó, que ahora su plaza está en el Piso Supervisado y que ella misma no quiere ni oir hablar de volver al CRR, siente que su paso por allí ya terminó. Además cuenta con buenas habiliades funcionales para permanecer en el piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-10-22','- Amalia: me llama Emi por tf, su discurso no es muy coherente y aviso al CRR . Me comunican que quedó ingresada ayer por la tarde en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-22','María Dolores ha pasado a planta esta mañana y está en medicina interna. Esta tarde va una trabajadora de la empresa TENTUAYUDA para acompañarla en el Hospital de 17:30H a 20:30H. Ayer fue una compañera del CRR a visitarla y María Dolores se siente avergonzada y no quiere que nadie se entere de lo que ha hecho, se muestra arrepentida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-10-22','(Pedro) Coreo-e del CRR de Mérida. +++Buenos días, Tras valoración psiquiátrica en el Hospital de Mérida, Emilia Morales se encuentra ingresada en UHB desde ayer. Por la tarde le llevaron ropa y enseres personales que necesitaba. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-05-18','-Visitamos la casa de Adrián , Pedro y Amalia de CTAEX .Nos atiende su padre pero fuera de la casa a la que no podemos acceder . Nos comenta un poco sobre su sitación familiar . A Adrián no pudimos verle , su padre nos indica que está por los campos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-09-18','Amalia : nuevo ingreso en UHB por descompensación. Email de Ap3 : Buenos días. Envío email para informar de una incidencia grave de la usuaria de Residencia RAL, Felisa Bruno Saavedra. El pasado viernes, cuando llegó de Centro Ocupacional a Residencia a medio día, comenzó a ponerse agresiva tanto verbal como físicamente con los profesionales de residencia, llegando a agredir a una trabajadora, provocándole una distensión muscular en una muñeca y un derrame en una rodilla. Acudió el 112 y al final consiguió lo que quería, que era ingresar en el hospital, en la unidad de hospitalización breve. Está allí desde el viernes por la tarde. El sábado una trabajadora fue a llevarle ropa. Nos comunican por teléfono ayer, que se encuentra tranquila y que a lo largo del día de hoy se le asignará psiquiatra. Mencionar que ha estado de vacaciones junto con otros compañeros, en Chipiona del 2 al 8 de septiembre, empeorando su comportamiento , a medida que pasaban los días allí, insultando y amenazando tanto a compañeras como a las trabajadoras que acompañaron al viaje. Continuaremos informando. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-22','Ana: Recibo un correo de Teresa Doncel, T.S. IMAS-CC (teresa.doncel@ayto-caceres.es): "Buenos días Ana. Te reenvío el correo que me ha enviado la policía municipal. Me dicen que casi a diario tienen intervenciones de este tipo. Yo cada vez que me envíen uno te lo haré llegar por si esto sirve para agilizar los trámites de la incapacitación Un saludo. Teresa Doncel" Adjunta 2 informes que guardo en su expte. y pasamos a Miguel, Asesor Jurídico, para que los adjunte al escrito al Jgdo. ///////////////////////////////////////////////////////////////// Recibo llamada de Mª Isabel, hermana de Pilar (695 967 774), cree que tenemos la Tutela y no entiende que no ingresemos a su hermana ni hagamos nada. La ve en las calles cada vez peor, "descalza, cagada y meada" repite varias veces. **Le aclaro que se trata de una incapacitación parcial, que la Comisión sólo tiene la Curatela Económica, y le explico lo que quiere decir y las competencias que tenemos atribuidas en estos momentos. A pesar de ello estamos al tanto de todo, coordinados con los distintos recursos y llevando a cabo diversas acciones. Le explico que la T.S. del IMAS ya lo ha puesto en manos de Fiscalía, ha solicitado la ampliación de la Incapacidad. **Inteto dejarle muy claro así mismo, que aunque tuvieramos la Tutela, si no nos dan autorización judicial de igreso tampoco podemos ingresarla contra su voluntad. ***Expresa que si esta situación no se soluciona en unos días acudirá a hablarlo al Jgdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-10-22','Ana: Recibimos escrito del INSS, han resuelto denegar la PFHC a Pedro Román por "NO ESTAR INCAPACITADO JUDICIALMENTE". Llamo a Gloria - PFHC Ba, revisa el expte., comprueba que ha sido un error. Nos enviarán nueva carta con resolución aprobatoria. ////////////////////////////////////////////////// Llamo a Pilar Cerrillo, le comunico que el último recibo de la residencia casi con toda seguridad, se lo devolverán también, pues a día de hoy Pedro R. no tienen saldo suficiente en la cuenta. Le confirmo, que a pesar del error, le han aprobado la PFHC. ***Ella me comunica que este jueves día 24 acudirán a valorarlo de Dependencia. -**En cuanto a la bajada de precio de la plaza, dice que lo ha hablado con el Gerente, que ya de por sí tiene el precio ajustado, pues está en habitación individual pagando precio de habitación doble y que además no podrían pasarle a habitación compartida, pues dada la insuficiente higiene de Pedro (a pesar de que le obligan a ducharse) el olor en la habitación es muy fuerte. Por otra parte es un señor corpulento y un tanto agresivo y no quieren problemas con otros residentes. **Una vez le valoren de dependencia y recibamos el PIA, volveremos a valorar la posibilidad de una bajada de precio, el Gerente no está cerrado a ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2019-10-22','Enviamos al Colegio de Abogados de Badajoz, solicitud de asistencia jurídica gratuita, para solicitar autorización judicial de venta de inmuebles.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-10-22','Ana: Llamo a Adela, PNC (924 00 59 95) varias veces, pero no consigo contactar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-10-23','Ana: Llamo a Adela, PNC (924 00 59 95), no obtengo respuesta. ////////////////////////////////////////////////////////// Llamo a la Residencia San Fco.-Plas. (927 01 73 40), Maite Cañadas-Directora no está, me pasan con Ana-Administrativo, le facilito los telefonos de Juana y Belén, Secc. Ecca. y la dirección de email de la CTAEX. Le informo que ya pueden cobrar lo que se debe de la plaza de Joaquina, cree que lo harán mediante el Modelo 50, no obstante lo consultará con Maite y ya nos confirmarán. **Le solicito además que hagan y nos envíen un presupuesto de gastos de bolsillo. ////////////// Recibo llamada de Maite Cañadas. Me informa de que Joaquina está bien, tranquila. De vez en cuando pregunta por el hermano. Con el hijo se va distanciando poco a poco, la visitas cada vez se espacian más. En relación a la cuestión económica, le confirmo el número de cuenta. Pasarán el Mod.50 con lo que se debe y a posteriori periódicamente las mensualidades. ***Pide se le haga una Autorización para retirar el efectivo para gastos de bolsillo de Joaquina. //////////////// ***Se lo paso a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-10-23','Enviamos al abogado el acuse de recibo devuelto por correos, en reclamación al inquilino de requerimiento de pago del alquiler, a los efectos de que presente demanda ante el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2019-10-21','-Amalia: El traslado al centro Fco. Asuar en Fuente de Cantos se produjo el lunes. Tf. de Rosa , Dtra. : 667693216 , cofa@fuentedecantos.es. -Le pido a Julio que envie autorización gnral de salidas, saldrá algún fin de semana a su casa. -Parte eco: lleva para este mes unos 200€ desde CSS , le van a comprar un aparato de musica que quiere con parte de ese dinero . Cargarán en su cuenta el 75% de la PNC , 294€. El dinero de bolsillo hay q gestionar cómo se le va a dar , su cta. es de liberbank y en el pueblo hay ibercaja. -Le paso el caso a Teresa para seguimiento. -Le facilito a la Dtra. todos los contactos de CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-23','miguel y Pedro Js redactamos el oficio comunicando al Jzdo nº1 de Mérida, la visita realizada por Ana Ts y Pedro Js a la UHB donde se reunieron con el tutelado y el psiquiatra (David Gimeno), y acuerdan su derivación a la UME. Dicha derivación está a expensas de la reunión de mañana de la Comisión de Valoracion.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-23','Ana: Recibo llamada de Eva-TS Arroyo de la Luz (927 64 00 19), me comunica que una vecina del pueblo, que también es Técnica de la Mancomunidad, fue a verla ayer a última hora al despacho a informarle que había visto a Mª Eugenia, en CC, en la C/ León Leal, "rebuscando en la basura y con una pinta deplorable".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2019-10-23','Ana: Recibo llamada de Paula, T.O. - CRR-Plas. (682 704 401) Conchi está mejor, más estable. Intentarán ajustar al máximo el presupuesto con el que cuentan, y del extra anual intentarán sufragar los gastos para ir de visita puntualmente con la hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2019-10-23','Enviamos al Juzgado de Instrucción nº 2, de Badajoz (924284257/58-Isabel), solicitud de excusa de tutor con respecto a su hermano Florentino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL MANUEL'and edp.apellido1='AGUADO'and apellido2='JIMENEZ'),'2019-10-23','miguel, NOS LLAMA UN FAMILIAR DEL TITULADO (667-781197)INDICANDO QUE EL DÍA QUE FALLEZCA EL TUTELADO SE LE INCINERE Y SE ENTIERRE JUNTO A SUS HERMANOS FALLECIDOS EN BADAJOZ. HABLAN DE LA IMPOSIBILIDAD DE LA FAMILIA DE VENIR A EXTREMADURA DESDE MADRID (DONDE RESIDEN) DEBIDO A QUE SON PERSONAS MAYORES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-10-23','Ana: Conversación telefónica con Paula, TO-CRR Plas. Me comunica, sólamente para que estemos informados, que Toñi está haciendo consultas a abogados para solicitar la revisión de su incapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-10-23','Ana: Conversación telefónica con Paula, T.O. CRR-Plas.: La prueba de convivencia con la pareja NO funcionó, por lo que regresó al CRR. Por otra parte Eugenia está volviendo a jugar a las máquinas y a pedir dinero en la calle. Y retiró dineo (algo más de 100€)del banco sin el apoyo del CRR. ****Hay planteado un POSIBLE TRASLADO al CRR del CC. Van a tratar que lo acepte y SI NO LO ACEPTA TENDRÁ LUGAR LA EXPULSIÓN DEL CRR (Uno de los principales motivos es la LUDOPATÍA). ** No cuenta con apoyo de familiares fuera con los que pudiera irse a vivir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-23','Ana: Recibo llamada de Teresa Doncel, TS IMAS (670 011 027). Ayer a última hora le pusieron en contacto con Fidel, Coordinador de Fiscalía. Le han dicho que nos han solicitado desde Fiscalía el día 17 de octubre un Informe para valorar la ampliación de la Incapacidad de Mª Pilar. //////**Se lo comunico a Miguel, Asesor Jurídico y a Pedro, Jefe de Secc. *Aquí no hemos recibido nada. No obstante Miguel tiene pendiente enviar escrito al Jgdo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2019-10-23','miguel, remito al vecino Jose Fdez Cubero, contestación adjuntando informe del arquitecto del ayto denegando cualquier tipo de deficiencia que suponga obligación de reparación de nuestro tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRIADO'and apellido2='RODRIGUEZ'),'2019-10-23','Ana: Recibo llamada de José Aº Pulido, T.S. de Almoharín (L-M y J: 654 222 195 // X - Arroyomolinos 927 385 002). Le ha llamado Raquel, Administradora de Fincas - Gestoría Parra. Tienen que hacer obras en el bloque en el que Mª Jesús tiene su vivienda (Avda. de la Hispanidad, 10 - 4º D - Cáceres) y necesitan entrar en todas las casas. Él tiene las llaves de la vivienda **Por otra parte comunica que Gloria-Futuex ha ido a visitar a Mª Jesús en 2 ocasiones. ////////// Llamo a Raquel, Administraciones Parra (927 233 112 / 658 205 216) Me explica que "hay que cambiar la montante entera de las 4 plantas". El gasto corresponde a la Comunidad de Vecinos, que a día de hoy tiene fondo para la reparación. *La empresa reparadora es Global Service. //////////////// Llamo a Toni-Futuex: El jueves Gloria iba a acompañar a Mª Jesús a renovarse el DNI. Le facilito los números de tlf. tanto del TS como de la Administradora, se pondrán en contacto para que Gloria pueda recoger las llaves y estar el día que la empresa acuda a realizar las reparaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-10-23','-Amalia : me reúno con su tía Asunción en el Edif. SARA , tuvo que estar cerca el vigilante , actitud agresiva y amenazante. No volveré a reunirme con ella en Badajoz , si reitera visita , será en Mérida. Me entrega mucha documentación juridíca y multas en sobres sin abrir, muchas por tenencia de drogas. Me cuenta que en su casa la han tiroteado , con su hija y su nieta dentro , por temas relacionados con las drogas. Nos echa toda la culpa de lo que le pasa a su sobrino , a la Junta , la CTAEX , la jueza , la policia , los funcionarios ... y nos amenaza . Pido a sección eco , que suba cta peculio a 50€ semanales y extra a la tía para ropa . No quiere que paguemos ninguna de las multas. Exige que le pidamos pensión de orfandad , entrega cdo. de registros. Tiene muchísimas causa ptes a nivel judicial .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-10-23','-Amalia : me reúno con su tía Asunción en el Edif. SARA , tuvo que estar cerca el vigilante , actitud agresiva y amenazante. No volveré a reunirme con ella en Badajoz , si reitera visita , será en Mérida. Me entrega mucha documentación juridíca y multas en sobres sin abrir, muchas por tenencia de drogas. Me cuenta que en su casa la han tiroteado , con su hija y su nieta dentro , por temas relacionados con las drogas. Nos echa toda la culpa de lo que le pasa a su sobrino , a la Junta , la CTAEX , la jueza , la policia , los funcionarios ... y nos amenaza . Pido a sección eco , que suba cta peculio a 50€ semanales y extra a la tía para ropa . No quiere que paguemos ninguna de las multas. Exige que le pidamos pensión de orfandad , entrega cdo. de registros. Tiene muchísimas causa ptes a nivel judicial .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-24','orreo-e del CRR de Mérida de ayer, 23 de octubre. +++Buenas tardes, Comentarles que esta tarde ha venido María Dolores Fernández de alta en ambulancia. Cuando llega nos damos cuenta que le han dejado la sonda puesta. Le hemos explicado al personal de la ambulancia que en este recurso no hay personal sanitario por lo que no podemos aceptar que la dejen aquí con la sonda puesta. Me indican que no es responsabilidad suya puesto que ellos ya han realizado su labor. Llamo a la planta de medicina interna y le comento lo sucedido a la Enfermera que me atiende telefónicamente. Me explica que en el informe de alta no hacen alusión a que deba tener la sonda puesta por lo que me da varias alternativas: que llame al 112 y venga la ambulancia para trasladarla al hospital nuevamente y que se la retiren, que le pida el favor a la enfermera de Rosalba para que se lo quite ella o que nos acerquemos al Centro de Salud. Llamo al 112 y vuelvo a comentar lo ocurrido, la Doctora que me atiende acuerda mandar al personal de urgencia que hay en el hospital para que vengan a retirársela. Efectivamente pasado un corto periodo de tiempo se personan los técnicos en el CRR y le retiran la sonda. Los mismos técnicos que vienen nos comentan que ahora debemos supervisar si orina o no y que existe un riesgo alto de que se caiga al haber estado en cama mucho tiempo sin levantarse. Volvemos a explicar que en este recurso NO HAY PERSONAL SANITARIO. Hemos contactado con la persona que ha estado en el hospital acompañándola de la empresa "tentuayuda" para que le asista durante la ducha... Por otro lado, Juana Rivas se ha caído en la terraza. Se ha dado un golpe en la cabeza y tiene la boca ensangrentada fruto de la caída. Se la han llevado al Hospital para valorar la posible repercusión que pudiese tener el golpe. Seguiremos en contacto.+++++++++++++++++++++++++++++++++++++++++++++++++++++++++++SEGUNDO CORREO-e DEL CRR de MÉRIDA. +++Buenos días, María Dolores esta mañana ha hecho su cama perfectamente y se ha desplazado sola sin incidencias, está desayunando con normalidad. Hemos pedido cita para que el lunes le haga el seguimiento MAP tal y como nos han recomendado. Le hemos preguntado a ella si necesita el apoyo de la señora que ha estado viniendo para la ducha y comenta que no. TO va a avisarle ahora que no hace falta que venga y, si os parece bien, que os haga llegar la factura. Muchas gracias, Saludos.','2');
