insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2019-10-23','JUAN PEDRO: Tras recibir escrito de subsanación de solicitud de prestaciones sanitarias, solicitando que se aporte factura original y documentación que justifique la tutela. Puesto que desconociamos el asunto, llamo al centro y la directora me comunica que le han solicitado dicha prestación para una silla de ruedas y que ella misma se encarga de tramitar la subsanación.','2');
