insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-24','Ana: Recibo nueva llamada de Eva Luz, TS Arroyo de la Luz (927 640 019 // Personal: 655 093 822), me informa de que un Policía Municial le ha comunicado que vio a Mª Eugenia en CC, en la Avda. de España, a la altura de la tienda Pto. Roma, ejerciendo la mendicidad. ///////////////////////////////////////////// Hablo con Manuela, Jefa de Secc. Discap. Dice que finalmente han cambiado de idea, le van a asignar plaza en la nueva Resid. de Discap. municipal de Fuente de Cantos, lo han elegido porque, a parte de ser un centro nuevo "sin vicios" a la hora de trabajar, cuenta con buena infraestructura, bien preparado, bonito, con jardín y con vistas a la Dehesa, el equipo del C. Día y del C.O. trabaja muy bien y la Alcaldesa está muy implicada. Además el pueblo es accesible y muy integrador. //////// *Llamo a Eva, TS Arroyo Luz, y le transmito esta información. Se queda más tranquila. ///////////////////////////// Llamo a Toni-Futuex, le informo de los últimos incidentes. **Al comedor sigue sin querer ir y la asignación económica semanal que retira los lunes no saben en qué se lo gasta. *Le pido que itenten intensificar el seguimiento y aborden con ella las cuestiones de la mendicidad y de rebuscar en la basura. *Le informo tb de la próxima asignación de plaza para que puedan trabajarlo con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2019-10-24','Ana: Recibo email de María García, Dirctora del Centro Fco. de Asís (centrofranciscodeasis@gmail.com // 927 194 889): "Buenos días Ana Le dieron el alata ayer por la tarde, tiene el brazo inmovilizado con cabestrillo y nos pìden que no lo mueva ni se lo quite bajo ningún concepto. Lo que haremos es asistirle en todo y desplazarla en su silla de ruedas para evitar que haga cualquier esfuerzo. Le han mandado radiología y consulta de traumatología el 18 de noviembre, esperemos que evolucione bien. Gracias por lo de la ropa y el acompañamiento, lo mando todo a la otra dirección como me dices. Cualquier cosa, no dudes en ponerte en contacto conmigo. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2019-10-23','Ana: en relación al correo remitido por María García (centrofranciscodeasis@gmail.com) solicitando ropa, contesto al correo diciendo que no hay problema, pueden comprarle la ropa que necesita. Le indico que envíen la factura y nº de cuenta para hacer transferencia a la tienda al ctutelar@. // En relación a la caída de Inés que le ha comentado por teléfono a Icíar, Secc. Ecca., le pido me mantengan informada. **Del acompañamiento que le pusieron con carácter de urgencias en el hptal. también remitirán la factura al ctutelar@.','2');
