insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-24','Ana: Recibo llamada de Victoria Rajo, Directora-CRR (687 487 908), el próximo sábado libra Lucía Peña, acompañante, por lo que necesitarían que Ana realizara el apoyo a Consuelo (de 8:30 - 11:30). Le gustaría que acudiera mañana por la mañana de forma previa a firmar el documento de confidencialidad y para explicarle algunas cosas. ///////////// Llamo a Ana, acompañante (678 397 825), el sábado sí que puede realizar el acompañamiento, pero no podrá acudir mañana por la mañana, sólo podría por la tarde. Le digo que en ese caso acuda el sábado 5-10 minutos antes. *No obstante me da su consentimiento para facilitarle su nº a Victoria Rajo y así lo hago.','2');
