insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-10-24','(Ana y Pedro)Asistencia a la Comisión de Valoración para ingreso en UME de Mérida. +++Conclusión: se acepta la derivación y se plantea posibilidad de itinereraio hacia URH una vez alta en UME. +++Desde la Comisión se insiste en que la posibilidad de desinstitucionalización no es viable por la imposibilidad de seguimiento em medio abierto por falta de medios para garantizar aspectos fundamentales como la adherencia al tratamiento, la asistencia aconsulta, el acompñamineto a cedex, control del consumo, etc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2019-10-22','(Amalia y Pedro) Reunión con Aprosuba 3, Unidad de Programas y CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-10-25','Ana: Ayer por la tarde recibí correo de Pilar Cerrillo (calidad@grupociudadjardin.com): "Buenas tardes Ana, esta mañana han venido a valorar a Pedro Román, Alberto, técnico del equipo de valoración de Brozas. Te llamará para informarte de todo y negociar el Pia contigo, está entre un GRADO II o III, dependiendo de ello será la cuantía, o 426€ o 715€. Me ha dicho que también se priorizan los pagos, así que no cree que tarde mucho en cobrar. Y a partir del mes de noviembre ya ira un descuento en la factura del 6%. De todas maneras, mañana hablamos y te explico. Un saludo" //*Me llama en relación a lo ya explicado en el correo. El descuento corresponde a 88€/mes. No pueden bajarlme más el precio pues es imposible ponerle compañero en la habitación. **Lleva desde 2005 en la Res. y le han consentido muchas cosas: realiza todas las comidas del día en la habitación, a penas se asea (porque dice que "a Dios no le gusta que se toque"), se ducha una vez a la semana medio obligado y no se lava bien. A penas entran en la habitación para hacer limpieza y cuando le quitan ropa de cama u otras prendas suele ser para tirarlas. El olor, tanto corporal como de la habitación es muy intenso y desagradable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2019-10-21','Ana: Recibimos comunicado de Infancia y Familia; han iniciado procedimiento de incapacitación de su hijo Aitor Moreno Felipe y han propuesto que sea la Comisión Tutelar quien ejerza la tutela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2019-10-17','Ana: Recibimos comunicado de Felisa Custodio, TS del CAMF Alcuescar, con todas las salidas organizadas por el centro en las que ha participaco Rosario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2019-10-22','Ana: Envío un correo a Toni-Futuex, pidiendo que soliciten al nieto de Manuela Morato que nos hagan llegar Informe Médico que justifique la necesidad de la cama articulada. ///////// En cuanto a la factura de farmacia pendiente, se lo paso a Alberto, Jefe de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-10-25','Ana: Recibo llamada de Maite, T.S. C. Penitenciario-CC (927 18 14 07) Pregunta dónde irá a vivir Jose Manuel cuando salga de prisión el día 4. Le digo que al único sitio que puede ir es a su casa. **Al parecer ha expresado que QUIERE ir a CRR, pero no sabe si mantendrá esa idea pues cambia constantemente de parecer. Le dirá qué acuda a hablar con Pilar, T.S. del ESM cuando salga de prisión y si fuera necesario al C.Salud para que le deriven a Salud Mental.////////////////////////// Llamo a Pilar Martín, TS ESM-CC, pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-10-25','(Pedro)Conversación con Juan Carlos, solcitada por las T. Sociales del Psiq. Penit. de Sevilla. +++Juan Carlos sigue teniendo un importante sentimiento de soledad y una de sus peticiones es que vayamos a verlo +++Sigue jugando al fútbol, de portero y cultivando el huerto +++Tiene de vez en cuando alguna pelea con los compañeros, comennta Patricia, la T. Social, pero normalmente se porta bien. Le digo que cunado se empiece a poner nervioso se lo diga a los cuidadores para que le atiendan. Dice que lo hará. +++Quiere comprarse ropa deportiva y calzado. +++Nos enviará una carta con una fotografía. +++Manoli, la T.Social, plantea un extra de 200€ para comprar esas cosas. Lo paso a Alberto para que lo tramite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-10-23','(Pedro)Conversación con la Médico del CAM Plasencia, Esther (927-017307) +++No considera adecuado someter a Dª Joaquina a la colonoscopia diagnóstica y terapéutica, no aconsejando la misma en el inofrme que al respecto le pido y envía por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-10-25','(Pedro)Conversación con la Dra. Elena Abadía, especialista de Digestivo del H. Virgen del Puerto.(927-458000). +++No les consta petición alguna de la prueba diagnóstica y terapéutaica para Dª Joaquina. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a hablar con maite, T. Social del CAM. +++La prueba se solcita desde el programa de detección precoz de cáncer colorrectal en población de riesgo medio, por lo que parte del Csalud sin pasar pore el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-10-25','Ana: Recibo llamada de Lucia Peña (605 151 370), Consuelo tiene cita en Traumatología el día 6 de noviembre. Dice que está evolucionando muy bien y que se dan unos paseos muy largos, (1 hora aprox.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2019-10-25','miguel, me llama Francisco el hermano mayor de los Lopez Cabrera (Tlfno 603474861)y me indica que la gestoría donde están los papeles no ha hecho nada y le ha comentado que la Junta tardaría con las autorizaciones que se requieren para la venta. Le comento que por parte de la Ctaex tenemos en principio todo correcto (autorizaciones de venta, etc). Que desde marzo no sé de su prima Ana quien me comentó que estaba pendiente de la parte compradora. ****************************************** Quedo con Francisco Lopez Cabrera que me llamará o enviará emil indicandonos la notaria y persona que llevará la venta para que le remitamos la documentación que nos requieran.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-10-25','miguel, ayer fue la compañera Belen a notaria y le recordó a Ana que me llame o envíe un email confirmandome que está todo bien para la firma de la extinción del condominio(es la 2º vez que va a hablar con ella, porque es imposible hablar por teléfono y no contesta a los emails) ******************************************** Me llama Belén Camisón (la cuñada) y me comenta que si no hay novedades se firmará la extinción de condominio el viernes día 8 de noviembre a las 12h. Me dice que harán la transferencia a la cuenta del tutelado el día antes. La pido que envíe un email describiendo a qué cuenta harán la transferencia e importe para pasarlo a la parte económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-10-25','TERESA: PONGO A FIRMA ELECCION DE RESIDENCIA. RECIGO EMIAL DE ANA LA TS EN EL QUE ME COMUNICA QUE LA PRIMA DE M ANTONIA SE ENCUENTRA GRAVE EN EL HOSPITAL CON LO CUAL SI FALLECE ELLA TENDIRA QUE ABANDONAR EL DOMICILIO ACTUAL. SOLICITO VARIOS CENTROS ANTE LA SITUACION AUNQUE ELLA QUIERE IR A ZAFRA QUE ES DONDE ES USUARIO DE CENTRO OCUPACIONAL. PIDO INGRESO INVOLUNTARIO TAMBIEN POR SI LLEGADO EL MOMENTONO QUIER IRSE A RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-10-25','Ana: Recibimos correo de Estrella, T.S. CSS-Plas.: "Buenos días. Por el presente se solicita autorización para que su tutelada Josefa Domínguez Blánco con DNI: 44407988w pueda pasar unos días en su domicilio, debido a que su madre está gravemente enferma. Saludos" ///// Tras valorarlo con Pedro, Jefe Secc. y Teresa - TS, llamo a Estrella (24146), solicito nos indiquen por escrito que esta salida se estima favorable dentro de su plan de intervención, las fechas en las que se plantea, que indiquen que es con pernocta, cómo se realizará el traslado al domicilio familiar y quién se encargará de supervisar la toma de medicación. *Se lo comunicará a Mª Paz, Psicóloga y Coordinadora de la UHDAC.','2');
