insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2019-10-28','CAMBIO DE CENTRO Reside ahora en el C. R. Discapacitados Fco. Asuar, de Fte. de Cantos. Tfnos.: 924 50 02 11; 667 69 32 16. @: cofa@fuentedecantos.es. La directora atiende al nombre de Rosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-10-28','Ana: Recibo correo de Amor Lopez, TS - ASPACE-CC (amor.lopez@aspacecaceres.es): "... El próximo día 11 tenemos cita en el servicio de Salud mentalmental ( la cita anterior nos la cambiaron porque nos indicaba al servicio infantil y ya no nos correspondía ese, como tu bien sabes)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-10-28','(Pedro)Carmen, Directora de la Residencia "La Coronada", comunica el falleciemiento de Dª Paula en el día de ayer, 27 de octubre, sobre las 12:30h, como consecuencia de un infarto. Descanse en Paz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2019-10-28','(Pedro) El viernes de la semana pasada se remitió desde la Gerencia del Sepad escrito dirigido al Consejero de Sanidad en relación a una petición que por escrito foermuló Dª Estefanía, hermana de Dª Luisa. +++Se pidió información al CRR sobre algunas de las cuestiones planteadas y estamos a la espera de respuesta para informar a la Gerencia. +++HOY, nuevamente desde Gerencia se pide a la comisión que contactemos con Dª Estefanía (673-273863) por teléfono dada su insistencia. Nos ponemos en contacto con ella y se le insiste en que los temas que formula en su escrito están siendo gestionados desde la Comisión Tutelar de la forma que esta considera más beneficiosa para su hermana, y que las necesidades que esta pueda tener nos son comunicadas por el CRR y cubiertas en la medida de lo posible y según lo convenientes que esta Comisión entienda que son para su tutelada. En cuanto a las necesisdades sanitarias, es un médico el que las tiene que determinar, para lo cual ya hemos pedido dicha consulta al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2019-10-28','(Pedro)Dª Mª Dolores tenía CITA PROGRAMADA para HOY a las 12:30H pero NO VINO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-11-01','-Amalia: Desde el dia 1/11/2019 empezará a ingresar las pensiones en el nuevo nº cta. La PFHC , la retirará la familia íntegra. La orfandad de 207€ se le irá ahorrando , para pagar sus gastos , necesita unas gafas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2019-10-28','TERESA: PASO A ALBERTO PARA ABRIR CUENTA PECULIO PERCIBE UNA PNC Y TIENE UNA DEUDA CON LA SEG SOCIAL. SALE DE LA CARCEL EL DIA 27 DE NOVIEMBRE Y TIENE UN JUICIO EL 31 DE NOVIEMBRE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-10-27','EXITUS. Comunica la directora del centro que Paula ha fallecido el dia 27/10/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-29','Ana: Recibo llamada de Rosa Mª de Tena, Directora del C. R. para pers. con discapacidad Fco. Asuar, de Fte. de Cantos (667 693 216 // Nº del centro: 924 50 02 11 // 667 69 32 16 // cofa@fuentedecantos.es). Ha recibido la resolución de plaza de Mª Eugenia, para esta semana parece muy precipidado el ingreso y como el viernes es festivo y el lunes tiene otro ingreso, acordamos que se realice el martes día 5/11/19. /////////////////////////// Llamo a Toni-Futuex (600 56 42 15), al parecer Mª Eugenia ayer decía que sí quería ir a un centro, pero que si era después del puente mejor. **Acordamos que le acompañarán Virginia y Gloria, Delegadas, en el coche de una de ellas. En ppio. no activaré el 112, si el lunes Mª Eugenia cambiara de actitud, lo activaría. // Llegarán a la Res. entre 10:00 - 10:30 h. //// *Le confirmo a Rosa el día y la hora. //////////////////////////// Llamo a Eva Luz, TS Arroyo de la Luz (927 640 019 // Personal: 655 093 822) informo del proximo ingreso de Mª Eugenia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-10-29','-Amalia : Llamo a Fernanda, han estado el lunes en el SEPAD ella y dos de los hijos preguntando por nosotros. No han podido sacar la PFHC , les comento que ya la tienen disponible en el banco y que mañana pueden ir a retirarla. la Orfandad se la guardaremos para Antonia. Me dice que no tiene para coger la bombona ni para comida . Que los hijos no le dan dinero de la pensión que cogen. Que Manuel se la gasta en prostitutas y el mayor no tiene pensión. No puede pedir a los hijos pq teme las consecuencias , no la tratan bien. Otra alternativa que le doy , es que sea ella la que acuda al banco y se lo autorizamos a su nombre. Me indica que no es posible , por su problema de movilidad. Dice que compra en un ultramarinos de la zona , le propongo pagar allí los 400€ y al menos garantizar la comida. No lo ve claro , se lo va a pensar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-10-29','-Amalia : Llamo a Fernanda, han estado el lunes en el SEPAD ella y dos de los hijos preguntando por nosotros. No han podido sacar la PFHC , les comento que ya la tienen disponible en el banco y que mañana pueden ir a retirarla. la Orfandad se la guardaremos para Antonia. Me dice que no tiene para coger la bombona ni para comida . Que los hijos no le dan dinero de la pensión que cogen. Que Manuel se la gasta en prostitutas y el mayor no tiene pensión. No puede pedir a los hijos pq teme las consecuencias , no la tratan bien. Otra alternativa que le doy , es que sea ella la que acuda al banco y se lo autorizamos a su nombre. Me indica que no es posible , por su problema de movilidad. Dice que compra en un ultramarinos de la zona , le propongo pagar allí los 400€ y al menos garantizar la comida. No lo ve claro , se lo va a pensar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-10-29','miguel, llamo al Jzdo de Cáceres nº1 para que nos informen sobre el procedimiento que tenemos el día 6/11/2019 y nos cuelgan. Tenemos solicitada videoconferencia desde los juzgados de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-10-29','miguel, remito por correo certificado al Jzdo Decano de Cáceres solicitud de desbloqueo de la cuenta de depósito. También remito hoy por correo certificado al Colegio de Abogados de Cáceres para asignen abogado de oficio a este expte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-10-29','Ana: Recibo correo de Sonia Bernabé - ASINDI: "Hola Ana, únicamente comentarte que a la familia del residente que rompió las gafas le informamos y, aunque no es agradable el tema, lo entiende ya que sabe que atendemos a personas que pueden tener alteración de conducta y, en cualquier caso intentamos prevenir o evitar cualquier situación de peligro para ellos. Por todo esto te digo que no se ha puesto denuncia. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-10-29','Ana: Recibo correo de Amor,TS - ASPACE: "Buenos días Ana: Perdona que te moleste, acaban de llamar para cancelar la cita de santi para el día 11 nos mandarán una nueva(la enfermera no estará, no me dieron más información) saludos" ///////////////////// *Recibimos escrito de PNC (Serv. Terr. CC - Consej.Sanidad y Pªs Soc.) solicitando documentación: Certificado de Empadronamiento, Alta a terceros y modelo optando por una prestación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-10-29','Ana: Recibo correo de Sonia Bernabé - ASINDI: "Hola, en relación a la actividad que os comenté de Justo Hernández, (participación en un documental sobre LGTBI) ha sido seleccionado para poder participar. Hasta el momento ha participado en una formación y ha presentado un video casero grabado en ASINDI. El compañero que lleva este tema ha solicitado más información sobre cómo sería la participación de Justo en el documental y nos indican desde la Federación que en breve podrán darnos el guión oficial elaborado del video para que os lo pasemos y de vosotros a fiscalía para que nos digan si autorizan o no que Justo participe en este documental. En cuanto lo tengamos os lo hago llegar. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-10-29','-Amalia : mañana voy a visitarla a domilio con Teresa ( FUTUEX ) , he quedado con José a la 13.00 que es cuando acude al domicilio a darle de comer. -dirección : C/ Vicente Delgado Algaba ( xona estacion autobuses ) nº 62 . -La Sra. sale en silla de ruedas una vez al mes acompñada del auxiliar para ir al banco y sacar 600€ .El auxiliar acude de L a V desde SAD municipal y el fin de semana de manera privada que paga ella. Él se encarga de comprarle la ropa , la comida ... -Tf del auxiliar Jose Delgado 617245828.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-10-29','Ana: Llamo a Valentín, Admtvo. C. Salud Vca. Barros (85048), consulta el Jara y dice que hubo una cita en Psiquiatría el día 10/05/19 con la Dra. Mª Rosa Gómez Soler, pero ahora hay otra psiquiatra. El informe tendríamos que pedirlo por escrito, en original. Acordamos que se lo adelantaremos por fax: 924 52 43 43 y depués se lo enviaremos por correo certificado. *En cuanto a la pregunta de si se ha planteado el ingreso a través de ESM, dice que eso habrá que consultarlo a la T.S. ///////////////// Llamo a Esperanza, TS (85057), dice que ella no conoce al paciente y que ha habido varios cambios de Psiquiatra, por lo que no se ha planteado ingreso desde el equipo. Además a la cita del 10 de mayo no acudión Adolfo, según le dijo la Piquiatra acudió algún familiar. **Ella ya le pidió a la Dra. Rosa Informe de adherencia a las consultas, pero no le ha enviado nada. Dicha Dra. está ahora en la UHB-Mérida (por si la queremos llamar).','2');
