insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-10-25','Buenas tardes, : email del CRR .El viernes le dieron de alta a Emilia Morales. Está en el CRR, ayer pese a nuestras recomendaciones no vino a la residencia hasta las 2 de la madrugada. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-10-29','miguel, asisto vía videoconferencia a la vista de reclamación de gastos extraordinarios de mejora de los antiguos arrendatarios con opción de compra que se fueron. Se acordó con ellos solicitar 3000€ pero tras comprobar las facturas la juez estima que las mismas ascienden a unos 4.700€ y que al ser titular Ceferirino y su hermano Luis Miguel, les corresponden afrontar dichos gastos a partes iguales, por lo que sólo autorizará unos 2.300€. Quedamos a la espera de la resolución judicial para proceder al abono de la cantidad que finalmente corresponda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2019-10-29','TERESA: RECIBO EMIAL DEL CAMP la salida de Hermenegildo estaría prevista desde el jueves 31 por la mañana hasta el lunes 4 por la mañana. El residente va y viene en taxi a la localidad de Cabeza del Buey. Desconozco el importe de la salida, desde aquí se le facilitará el dinero de bolsillo para esos días y se abonára la factura de transporte a parte. Dicho esto, solicito vuestra autorización para que el residente pueda realizar este viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2019-10-28','TERESA;: RECIBO EMAIL DE PLENA INCLUSION , comentarte que aún no ha regresado al Centro. Ayer nos pusimos en contacto telefónico con ella y nos dijo que estaba bien y que quizás se quedara en su casa también esta semana. Tiene intenciones de esperar a que su hermano la pueda traer en coche hasta Llerena. Sirva el presente email como comunicación de que Libertad se encuentra en casa de su familia. Cuando nos informe del día de regreso te lo hago saber','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2019-10-28','miguel, Amalia Ts me deja cartas y notificaciones sin abrir de este tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-10-29','Ana: Recibo llamada de Maite, T.S. C. Penitenciario-CC. Vuelve a preguntar dónde irá José María cuando salga del Penitenciario el día 4, vuelvo a decirle que tendrá que ir a su casa. **Pide que le enviemos un escrito en que digamos que tenemos conocimiento de que finaliza medida y sale del C.P. el día 4 de forma definitiva y que irá a su vivienda, sita en la dirección correspondiente de CC. //*Por otra parte dice que necesita un extra, para cuando salga, pues no tiene dinero. ***Hablo con Alberto, Jefe Secc. Ecca. mirará cómo está su situación económica para hacerle un ingreso en su cuenta peculio y establecer una asignación mensual. ////// Convesación con José Luis, hermano de José Manuel, Dice que no hay inconveniente en que José Manuel vaya a vivir a la casa que tienen en propiedad todos los hermanos, los suministros siguen dados de alta (él se ha encargado de pagar el mantenimiento). **Seguramente el hijo de José Manuel (19-20 años), vaya una temporada a vivir con él (es lo habitual en él), refiere que sólo acude por interés ecómico. Es consumidor de porros. *José Manuel tiene otra hija, de 23 años apróx. que está trabajando en "La cervecería 100 montaditos", vive con su novio. **Habría que revisar la manuntención que le pasa José Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-10-29','(Pedro)Acude Emi a la Comisión. +++No se le puede atender en este momento porque estamos reunidos. Le pide el teléfono la Vigilante de Seguridad pero s elo da mal. +++Llamo al CRR y me da el teléfono correcto (633-501059). +++Hablo con Emi: está muy a disgusto con Gisela. Quiere cambiar de tutora. +++Seguidamente pide dinero para regalos: abrigo, balón para sus hijos, etc. +++No me quiere decir dónde está porque "se lo vas a decir a Gisela..." +++Se muestra disgustada pero la conversación transcurre con normalidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-10-30','TERESA: NOTA DE FUTUEX Se acude al domicilio de Paula para realizar un inventario detallado de todos sus bienes, mobiliario, indumentaria, objetos personales y de valor… Se realiza una lista detallada y se fotografía toda la vivienda. En el armario de su habitación se encuentra una pequeña caja fuerte, está cerrada, se busca la llave, pero no se consigue localizar por ningún lado; al moverla se aprecia que puede tener dentro documentación y/o dinero. Los muebles que encontramos están en buen estado y todo bastante cuidado, con posibilidad de llegar a venderse muchas cosas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-10-30','Ana: Llamo a Pilar Martín, TS ESM-CC (54612): Pilar va a intentar que José Manuel tenga cita en Salud Mental antes de salir. Contactará con el penitenciario y me mantendrá informada. //////////////////////////// Llamo a Maite, TS-Penitenciario CC (927 18 14 07) no está, le dejan nota para que me devuelva la llamada. ////////////////////////////////////////// Llamo a Jose Luis, hermano de José Manuel (687 58 10 61), está al corriente de que Jose Manuel sale el día 4, él está trabajando por la mañana y no puede ir a recogerlo. Este sábado día 2 tiene una comunicación con él. Dice que en la casa (que pertenece a 7 hermanos) estgá dada de alta la luz y el agua, lo ha mantenido él, el resto de hermanos no quiere pagarlo. //////// Llamo a Toni-Futuex: Dice que las delegadas no han intervenido nunca con él, que no lo conocen y por tanto no consideran que tengan que ir a esperarlo al C.P. Acordamos que le enviaré un mail con los datos y dirección para hacerles la derivación y el contacto del hermano para que vayan con él un día a conocerlo y comenzar a intervenir y hacer el seguimiento. (Previo consentimiento del hermano) //////////////////////// Llamo de nuevo a Jose Mª, hermano: Dice que el sábado en al comunicación no puede llevarle dinero. /// **Se hará transferencia y se intentará gestionar el taxi desde aquí. ///////////////////////////////////////////////// *Recibimos por fax COMUNICADO de la puesta en libertad definitiva de José Manuel el próximo día 4/11/19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-10-30','Enviamos al Juzgado de Primera Instancia e Instrucción nº 1, de Zafra, solicitud de internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTINA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-10-30','TERESA: HABLO CON VIVIENDA PARA COMUNICAR EL FALLECIMIENTO DE PAULA, ME SOLICITAN CERTIFICADO DE DEFUNCIÓN. QUEDO PENDIENTE COMUNICARLE EL DIA DE LA ENTREGA DE LLAVES LE SOLICITO ESCRITO EN EL QUE INDIQUE QUE ERA LA USUARIA DE LA VIVIENDA Y POR ENDE LA NECESIDAD DE VACIARLA PARA QUE LA PUEDA OCUPAR OTRA FAMILIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2019-10-30','TERESA: ENVIO ESCRITO AL CADEX PARA SOLICITAR NUEVA CITA YA QUE ESTA PENDIENTE DE QUE LA VEAN PARA PERFIL. LA CITARON Y NO SE PRESENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2019-10-29','-Email de Miryam , hay q agilizar la orden de internamiento. En la oportunidad de saludarle a la espera de qué este bien, le hago llegar la siguiente información. Rosario tiene más de un mes con infección de orina que parece estar controlada al frente a de hoy, se ha caido dos veces y se lastimó la verruga de la pierna. Esto ha mejorado pero hubo que llevarla constantemente a la vita en el entró de salud. Además persiste su problema de valores alta s de glucemia y tensión alta, lo que también ha requerido su chequeo casi que diario. En este sentido, su médico de cabecera la ha estado controlado prácticamente todas la semanas. De igual manera, le informo que ya tenido de nuevo alucinaciones, nerviosismo e inquietud y poco apetito. Presenta náuseas en horas de la mañana cuándo está en el centro. Dice quése siente muy agitada y agotada y algunos días no quiere ir al centro de día. Más o menos es el estado de Rosario actualmente. Tiene pendiente una cita al dermatólogo por el asunto de las verrugas para el mes de noviembre. No le había escrito porque he tenido problemas con mi correo y aún no lo puedo recuperar. También quiero hacerle saber que he decidido retomar mi tratamiento odontológico que quedó pendiente el año pasado. En este sentido tengo cita el 7 de noviembre y allí se decidirá fecha de la cirugía para implantar hueso artificial. En consecuencia estare fuera del trabajo me mínim 15 dias, podría ser incluso un mes. Ya se qué ese mes no es remunerado,pero necesito proceder lo antes posible. Ya hablé con Sully la señora que se quedó el año pasado conn Rosario pero no puede. Por favor, le agradezco su diligencia, seguiré buscando otra mujer en el pueblo. Sería para salir entre el 22 de noviembre al 22 de diciembre si es el mes completo, en su defecto según evolucione en mi tratamiento. Luego le hago llegar mis relación de horas pendientes. Sin otro particular por los momentos y en espera de su receptividad. Miryam Ramírez','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2019-10-30','TERESA: RECIBO EMAIL DE FUTUEX Van a visitiarla Gloria y Teresa, que les ha hecho seguimientos habitualmente.. la idea de que vayan las dos es enfatizar en la idea, de implicarse en "empezar de cero" o cambiar la situación que tiene, antes de que el juzgado determine que tenga que irse involuntariamente.. porque en realidad tiene una mala gestión ecónomica y la casa en condiciones lamentables, pero es una persona autonoma en el funcionamiento, y entendiamos que ahora con la opción de la compañera que es terapueta ocupacional, podriamos intentar trabajar con ella cuestiones relativas al funcionamiento y manejo del hogar, siempre y cuando esté ella sola y no tenga que ocuparse también de sus hermanos.. que está claro q lo hace mal y que no se encarga de la casa, pero está en está circunstancia machista en el fondo.. en el que se supne que ella es la que debe hacer la comida y las gestiones del hogar. La idea tal y como hablamos sería que ella se comprometiera en que para buscar algún alquiler, tendría que sacrificar parte de su asignación semanal y en lugar de 100 tendrá que coger menos dinero semanal, para poder ocuparse de los gastos de alquiler, comida y suministros. Hemos hecho una breve búsqueda en internet, de pequeños apartamentos, en un rango de 230 a 285 euros, por ahora, cual sería la cantidad maxima en la que se podría considerar un alquiler para ella?? entendemos que no más de 250 euros no? Nos ocupamos de ir al juzgado e indicar que os notifiquen todo, el juicio en teoria, sería para el internamiento involuntario, que nosotras sepamos no tiene más cuestiones judiciales pendientes, pero ella piensa que esto es para la remoción de la tutela... de ahi que para que la intervención pueda seguir haciendose con ella hemos entendido que habria que quemar este ultimo carchuto, de sacarla de su vivienda e intentar que se gestionara con apoyos, antes de la opción de centro. Te informaría del resultado del seguimiento de mñana. Y cualquier cosa que consideres me dices,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2019-10-30','TERESA: ENVIO SOLICITUD DE ELECCION DE CENTROS A PERSONAS CON DISCAPACIDAD. PEDIMOS ZAFRA, FUENTE DE CANTOS, LLERENA Y ALMENDRALEJO','2');
