insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2019-10-30','TERESA:SE PLANTEA SERVICIO DE AYDA A DOMICILIO DE FORMA PRIVADA A LA SECCION ECO A PROPOSICION DESDE FUTUEX. PODEMOS HACER FRENE A UN PAGO 70 EUROS AL MES PARA DOS HORAS Y MEDIAS SEMANALES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2019-10-30','TERESA LLAMA ANA TS DE ZAFRA, ME COMENTA QUE NATALIA HA COMENAZADO DE NUEVO CON EL INYECTABLE. SIGUE LA COSA TENSA PORQUE LE ESTAN RESTRINGIENDO LAS LLAMADAS CON LA MADRE PUESTO QUE LE ESTA MAL METIENDO. TAMBIEN HA RECIBIDO LLAMADAS POR PARTE DE LA ABUELA PATERNA. ANA ME PREGUNTA SI TIENE QUE DAR EXPLICACIONES A LA FAMILIA Y SI SE PUEDE NEGAR A RECIBIR LLAMADAS DE LA FAMILIA. LE HE COMENTADO QUE NO TIENEN PORQUE DAR EXPLICACIONES PUESTO QUE ESTA TUTELADA QUE SI LAS QUIEREN QUE SE LAS PIDA AL JUEZ, QUE ANTE CUALQUIER PROBLEMA LLAMEN A LA GUARDIA CIVIL. LE PIDO INFORME DE LA SITUACION PARA COMUNICARLA AL JUZGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-29','Ana: Recibimos escrito de PNC (Serv. Terr. CC - Consej.Sanidad y Pªs Soc.) solicitando documentación: Certificado de Empadronamiento, Alta a terceros y modelo optando por una prestación.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-10-30','Ana: Envío correo-e al Hostal la Rosa comunicando que esta semana será la última que Mª Eugenia pernoctará en su alojamiento (está abonado hasta el día 6 de noviembre).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-10-30','Ana: Recibo llamada de Pilar, TS - ESM-CC (54612), Pilar no ha acudido a ninguna de sus citas programadas para hoy. **Me envia por fax Nota de Enfermería y Comunicado de T.S. //////// *Se lo paso a Miguel, Asesor Jurídico, para que lo pueda comunicar también a Fiscalía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2019-10-29','Ana: Toni-Futuex, me pasa nota de Esteve y Presupuesto para comprarle zapatillas y un chandal. ////// Esteve recibe un dinero semanal en el C.O. acorde al trabajo realizado, con el cambio de medicación se encuentra más débil y produce menos, como consecuencia le dan menos dinero y él se altera más. **La Psiquiatra plantea que se le asigne una cuantía semanal desde la CTAEX. **Se comprueba que Esteve sólo percibe una PFHC y paga el PP.TT., en la cuenta tiene poco dinero. //////// *Le paso a Alberto, Jefe Secc.Ecca. el presupuesto para ropa. Lo de la asignación de momento no es viable. **Estudiaremos si tiene derecho a alguna otra prestación/pensión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-10-30','Ana: Llamo a Adela, PNC (924 00 59 95) varias veces pero no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2019-10-31','Ana: El lunes en la reunión Toni-Futuex me pasó nota de José con Presupuesto para viaje en el Puente de Diciembre. **Se lo paso a Alberto, Jefe de Secc. Ecca. para valorar si se le puede autorizar un extra.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-10-31','Ana: Llamo a Maite, T.S. C. Penitenciario-CC (927 18 14 07), le informo de que ayer mismo se le hizo una transferencia a la Cuenta Peculio, creen que el lunes tendrá el dinero en la cuenta. *Maite dice que "es mucho suponer" y que a las 8:30 sale José Manuel. Le comunico que ayer intentamos que el hermano le llevara el dinero, pero no es posible y la compañera llamó a Radiotaxi para solicitar el taxi y pagarlo por transferencia, pero tampoco es viable. **Sigue sin saber cuánto dinero debe José Manuel, hablará con él y con su compañero de Peculio, para ver si hay opciones. //////////// A última hora vuelve a llamarme Maite, T.S., finalmente el hijo de José Manuel irá a buscarlo el lunes (en autobús). Y han hecho una diligencia, para que el sábado, cuando acuda a la comunicación su hermano, un funcinario pueda darle a éste el equipaje de Manuel para que se lo lleve al piso en su coche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2019-10-31','TERESA:INFORME FUTUEX ESTA BIEN ADAPTADO AL CENTRO SU MAYOR PREOCUPACION ES VER A SU MADRE LA CUAL ESTA INGRESADA EN UNA REDISENCIA DE MAYORES EN MEDINA. HA IDO A SU CASA PARA RECOGER ALGUNAS COSAS Y TAMBIEN DINERO QUE TENIA GUARDADO. MANUEL SE MUESTRA CONTENTO Y COMENTA QUE LE GUSTARIA VER MA A SU MADRE Y MAS TIEMPO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2019-10-31','TERESA: INFORME FUTUEX FRANCISCO VIVE SOLO EN UNA VIVIENDA QUE ESTA BIEN CONSERVADA, MANIFIESTA QUE NO QUIERE SEGUIR VIVIENDO EN CALERA DE LEON, TIENE POCA RELACION CON LOS VECINOS PERO SI BUEN CON EL TS Y LA AUXILIAR DE AYUDA A DOMICILIO. INSISTE EN IRSE A UN PISO A ZAFRA EL QUIERE VIVIR SOLO RECHAZA LA OPCION DE PISO SUPERVISADO O DE RESIDENCIA. FRANCISCO TIENE 60 AÑOS Y NO POSEE HABILIDADES SOCIALES NINGUNA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2019-10-31','Ana: Llamo a la Residencia S.Pedro de Alcántara (927580624), en relación al extra que necesita para ropa Rosa y al dinero que debe a la Directora por la renovación del DNI: me dicen que Ivonne, Directora, está hoy en la Res. Buenos Aires (927 58 24 22), llamo, me dicen que vuelva a llamar más tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2019-10-31','TERESA: INFORME FUTUEX DIEGO RESIDE EN LA CASA QUE ERA DE SUS PADRES, AHORA VIVE SOLO YA QUE SU HERMANO INGRESO EN CENTRO RESIDENCIAL HACE POCO. TIENE UNA LIMPIADORA PILAR QUE SE ENCARGA DE TODO. DIEGO ES QUERIDO Y CONOCIDO EN EL PUEBLO. HABLAN CON PILAR Y NOS COMENTA QUE GASTA MUCHO DINERO EN LOS BARES Y QUE NO HACE NADA EN CASA Y DEJA TODO POR LOS MEDIOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-10-28','Ana: Toni- Futuex, me pasa nota de Felipe, por un lado pide extra para máquina cortapelo y de afeitar (como su hermano ya no vive con él, no tiene y la necesita), por otra parte tiene una cuenta en Santander (donde cobraba la contraprestación del C.O.) con un descubierto de 24 €, convendría cerrarla. **A parte, ha recibido notificación del banco y la ITV en relación a un vehículo que al parecer tiene la hermana a su nombre. ///// **Paso a Alberto, Jefe de la Secc. Ecca. todas estas cuestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='HIDALGO'and apellido2='ROMO'),'2019-10-31','Ana: Conversación con Maite, TS C.Penitenciario-CC (927 18 14 07): Antonio finaliza su medida y sale en libertad el día 12/12/19. Pregunta qué vamos a hacer cuando salga, le explico que la Comisión tiene sólo Curatela Económica, por lo que no es competencia nuestra. *Llamará a Pilar Martín, T.S. del ESM-CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2019-10-30','miguel, me llaman de la notaria de Badajoz de D. Antonio Jesus (Marco)y me pide autorizaciones de venta de los hermanos Lopez Cabrera, sentencias de incapacitación y testimonio de nombramiento a la Comisión Tutelar de Adultos, le remito todo vía email, para próxima firma de la venta de la casa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2019-10-31','Ana: Tras hablar con Alberto, Jefe de la Secc. Ecca., llamo a Toni-FUTUEX, en relación a las facturas pendientes de pago que tienen los hermanos. Virgina ya habló con algunos establecimientos de Ceclavín en que los hermanos tienen deuda para decirles que dejen de fiarles. **Planteo que ella y la T.O. trabajen con los hermanos el aprendizaje y la capacidad para administrarse mejor. ////////////////// Llamo a Marta, pero hoy no atiende en Ceclavín, llamaré de nuevo el lunes. //////////////////////////// Llamo a Juana Mª Mirón, dueña de la tienda de alimentación "Mirón rodríguez" (653 307 936), hace muchos años que tiene a los dos hermanos como clientes. Se implica bastante con ellos. Se le hará una transferencia para abonar la deuda pendiente. Acordamos que se establecerá una cuantía como depósito en su tienda para que puedan adquirir alimentos. (Planteamos 200 € en principio, si es necesario se reajustará a posteriori). **Dice que ella intenta ayudarles, con Manuel se puede hablar pero Juan Mª tiende a ponerse agresivo. **Como el Pub La Pista, donde hay otra factura pendiente, tienen horario de noche, ella se ofrece a hablar con el dueño que es amigo suyo, para decirle que se le abonará lo que se debe pero que no le fíen más, pues desde aquí no se les va a pagar, ellos ya tienen su asignación semanal. /////////////////// Llamo a Víctor Módenes - Panadería (927 393 373), pero no obtengo respuesta. Volveré a llamar el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2019-10-31','Ana: Tras hablar con Alberto, Jefe de la Secc. Ecca., llamo a Toni-FUTUEX, en relación a las facturas pendientes de pago que tienen los hermanos. Virgina ya habló con algunos establecimientos de Ceclavín en que los hermanos tienen deuda para decirles que dejen de fiarles. **Planteo que ella y la T.O. trabajen con los hermanos el aprendizaje y la capacidad para administrarse mejor. ////////////////// Llamo a Marta, pero hoy no atiende en Ceclavín, llamaré de nuevo el lunes. //////////////////////////// Llamo a Juana Mª Mirón, dueña de la tienda de alimentación "Mirón rodríguez" (653 307 936), hace muchos años que tiene a los dos hermanos como clientes. Se implica bastante con ellos. Se le hará una transferencia para abonar la deuda pendiente. Acordamos que se establecerá una cuantía como depósito en su tienda para que puedan adquirir alimentos. (Planteamos 200 € en principio, si es necesario se reajustará a posteriori). **Dice que ella intenta ayudarles, con Manuel se puede hablar pero Juan Mª tiende a ponerse agresivo. **Como el Pub La Pista, donde hay otra factura pendiente, tienen horario de noche, ella se ofrece a hablar con el dueño que es amigo suyo, para decirle que se le abonará lo que se debe pero que no le fíen más, pues desde aquí no se les va a pagar, ellos ya tienen su asignación semanal. /////////////////// Llamo a Víctor Módenes - Panadería (927 393 373), pero no obtengo respuesta. Volveré a llamar el lunes.','2');
