insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-11-04','TERESA: Buenos días: Os comunicamos que hoy día 4 hemos llevado a Genaro a Monterrubio con su prima. Pasará el día con ella y luego se vendrá en nuestro transporte a las cinco de la tarde. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2019-11-04','Ana: Recibo llamada de Raquel, T.S.-Hptal. de Coria (77227). Me comunica que ayer por la mañana falleción Mª Teresa en el Hptal. /////// Conversación con Ana, T.S.- Res. Virgen de la Asunción (Torre de D. Miguel): Teresa no tiene Seguro de Deceso, pero decía que tenía un nicho en Zafra, que es donde quería ser enterrada. **Pedirán a la funeraria con la que suelen trabajar el presupuesto más económico posible para su entierro allí y otro con traslado a Zafra. **Recibo el correo. **Las compañeras de la secc. ecca. aún están pendiente de la respuesta de los bancos, no sabemos qué dinero tiene en la cuenta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2019-11-04','Ana: Llamo a Víctor Módenes - Panadería (927 393 373), le explico que la deuda que han contraído los hermanos (Juan Mª y Manuel) se le abonará mediante transferencia cuando sea posible, pero se le pide que no les fíe más, pues no se van a abonar más facturas que no hayan sido autorizadas previamente. ///////////////////// Llamo a Marta Hdez., TS de la Mancomunidad Rivera de Fresnedosa (927 30 33 66 // Ayto. Ceclavín: 927 39 33 38); Marta me comunica que justo iba a llamarme ahora, pues Juan Mª ha roto el Cajero Automático de Liberbank a martillazos. Los hermanos no dejan de generar deudas en el pueblo. Le han facilitado dos facturas más pendientes de pago del estando y de una multitienda, me envía las facturas por email. Le comunico que ya he hablado con varios de los establecimientos, que llamaré a los otros dos y el mensaje será el mismo, se abonará lo que se deba pero de ahora en adelante no deben fiarles más pues desde la CTAEX no se van a abonar más facturas sin una autorización previa (con presupuesto). **Acordamos que la asignación de 50€ semanales se le distribuirán en 10€/día. Se modificará la Autorización del banco. *A Marta le parece bien el depósito de los 200€ en la tienda de Juana Mª. ///// Llamo a Liberbank (927 39 30 20), hablo con Carolina, Directora Oficina (Nº Directo: 679 95 31 62) de momento está abierta la investigación, la denuncia está puesta.','2');
