insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-11-04','Ana: Recibo de la Seg. Soc. Resolución Aprobatoria de PFHC: 392€ x 12. Con fecha de efectos 01/10/2019. ////////////////////////////////////////////// Conversación con Alberto Arias Bueso, T.O. del EVD Zona Brozas (927 270 466). Pedro ha obtenido Grado II. En la Negociación se plantean las dos opciones: Solicitud de Plaza Pública y Prestación Vinculada. **Se solicitarán ambas cosas. Me envía los documentos por email. //**Pongo para la firma del D.Gerente el Alta de Terceros y las 2 Aceptaciones de PIA: Prestación Vinculada y Solicitud de Serv. Residencia.','2');
