insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2019-10-29','Ana: Recibo llamada de Guadalupe, Directora de los PP.TT. de Madrigalejo (672 614 683): Han operado a la pareja sentimental de Anita y ésta quiere ir a visitarlo, la familia propone que vaya a verlo y comer a casa los días 1, 2 y 3. La recogería a media mañana en el centro y la llevaría de vuelta por la tarde un familiar. Le pido que nos lo ponga por escrito en un correo. Si desde el centro lo ven positivo, por nuestra parte no hay ningún problema.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-10-29','Ana: Recibo llamada de Teresa- Novaforma (662 337 460): Felipe se ha convencido de vender la casa y el corralón (éste último es de todos los hermanos). **Los gastos de mantenimiento de todo este tiempo los ha asumido Felipe y quiere que le devuelvan la parte proporcional de este gasto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-11-05','Ana: Recibo llamada de Teresa, T.S.- Novaforma (662 337 460), le han comunicado el nombre del Procurador que lleva la venta de las propiedades: José Luis de la Serna, es de Vva. de la Serena. No tiene teléfono de contacto. ///// *****Comunico a Ángel, Asesor Jurídico. Éste me informa de que FELIPE NO PUEDE VENDER, no es el único propietario de dichos inmuebles, la difunta madre, al parecer, según éstas manifiestan, desheredó a 2 de las hijas, pero en principio el difunto padre no (pueden tener una parte en propiedad), asemás las dos sobrinas, hijas del difunto hermano, también tienen su parte de la propiedad. //////////////// Llamo a Teresa-Novaforma y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-11-05','Enviamos al Colegio de Abogados de Cáceres, queja por la designación del Abogado de oficio para el procedimiento modificacion de medidas, debido a que a día de hoy no ha iniciado el procedimiento y para que designen un nuevo abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2019-11-05','TERESA: ENVIO POR EMAIL A PLENA INCLUSION RESOLUCIONT TRATAMIENTO PSICOLOGICO, LA ARCHIVO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2019-11-05','Ana: Hablo con Ana, TS de la Res. Virgen de la Asunción (927 44 10 97), comunico que ya tenemos los movimientos y el saldo de Liberbank. **Se pondrá en contacto con la funeraria para que realicen el traslado y entierro en Zafra. **Le solicito el Certificado Actualizado de Deuda. Lo pedirá al Ayto. /////////////// Llamo de Raquel, T.S.-Hptal. de Coria (77227) Comunico que hoy mismo irán de la Funeraria a recoger el cuerpo y trasladarlo a Zafra. **Solicito Certificado Médico de Defunción. Me lo enviará por emial. ////////////////// Recibo llamada de Amaya, Ayto. Torre de D. Miguel (927 441 032), la Secretaria no está, le dejará una nota para que mañana nos envíe el Certificado de Deuda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-11-05','Nos dirigimos al Excmo. Ayuntamiento de La Haba,en relación con la vivienda/almacén que tiene Felipe, junto con sus hermanos y sobrinos, al ser necesaria su reparación. Disponemos de un presupuesto de una empresa de albañilería. Tras conversación telefónica con el número 924 82 31 61, nos indican que es necesario cumplimentar un modelo de permiso de obra, el cuál no puede ser remitido vía e-mail, para cumplimentarlo y devolverlo firmado. Por ese motivo, les indicamos la dirección física de nuestras oficinas, a los efectos que nos sea remitido el mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TERESA'and edp.apellido1='MANGAS'and apellido2='DE LA CRUZ'),'2019-11-03','EXITUS. Comunica la T.S. del hospital de Coria el fallecimientto de Teresa Mangas de la Cruz el 03/11/19.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2019-11-05','En relación con la ejecución de título judicial en el que reclaman 2400 euros, más intereses y costas, contacta con nosotros el nuevo abogado de la parte ejecutante, Marcos M. Nieto Álvarez 610447054 (marcosnietocc@hotmail.com). Nos indica que va a preguntar a procuradora y juzgado qué cantidades se han pagado ya de este procedimiento, que nosotros sabemos porque nos la ha dicho el Juzgado (272,93 euros). Restan por calcular los intereses, que en principio son el 30% del principal (720 euros), pero que podemos negociar llegado el momento del pago. Hemos solicitado al Juzgado el número de cuenta. De momento no pagar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-11-05','Ana: Recibo llamada de Pilar Martín (54612), ha estado en su despacho José Manuel, quiere ir a CRR. *El Psiquiatra considera que no está para estar en su domicilio y tampoco lo ve para Crónicos en el CSS. Considera que la mejor opción es para CRR, pero con la condición de que no se firme Alta Voluntaria. Dice que si su firma no vale, no podría pedir el alta. **Le explico que el CRR tiene requisito de voluntariedad y que al igual que en las comunidades terapéuticas no se le puede retener allí contra su voluntad, aún habiendo una Autorización Judicial de Ingreso Involuntario. Pide que entonces firmemos desde la CTAEX, la Solicitud de plaza en CRR, le indico que no es necesario, que quién tiene que firmarlo es él. Insiste, y tras consultarlo con Pedro, de forma excepcional, se firmará por las tres partes, CTAEX, Salud Mental y el propio José Manuel. Pedirá a Eva, Secc. Salud Mental, que me traiga la hoja para firmarla y se la devolvamos firmada por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='RODRIGUEZ'and apellido2='MARTIN'),'2019-11-04','Ana: Llamo a Víctor Módenes - Panadería (927 393 373), le explico que la deuda que han contraído los hermanos (Juan Mª y Manuel) se le abonará mediante transferencia cuando sea posible, pero se le pide que no les fíe más, pues no se van a abonar más facturas que no hayan sido autorizadas previamente. ///////////////////// Llamo a Marta Hdez., TS de la Mancomunidad Rivera de Fresnedosa (927 30 33 66 // Ayto. Ceclavín: 927 39 33 38); Marta me comunica que justo iba a llamarme ahora, pues Juan Mª ha roto el Cajero Automático de Liberbank a martillazos. Los hermanos no dejan de generar deudas en el pueblo. Le han facilitado dos facturas más pendientes de pago del estando y de una multitienda, me envía las facturas por email. Le comunico que ya he hablado con varios de los establecimientos, que llamaré a los otros dos y el mensaje será el mismo, se abonará lo que se deba pero de ahora en adelante no deben fiarles más pues desde la CTAEX no se van a abonar más facturas sin una autorización previa (con presupuesto). **Acordamos que la asignación de 50€ semanales se le distribuirán en 10€/día. Se modificará la Autorización del banco. *A Marta le parece bien el depósito de los 200€ en la tienda de Juana Mª. ///// Llamo a Liberbank (927 39 30 20), hablo con Carolina, Directora Oficina (Nº Directo: 679 95 31 62) de momento está abierta la investigación, la denuncia está puesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MARTINEZ'),'2019-11-05','Ana: Convesación telefónica, con Antonio Rodríguez Monroy (660 695 939). Le explico la situación y le transmito el mimso mensaje que al resto de negocios en que los hermanos han generado deuda. Me facilita el nº de cuenta para que se le haga una tranferencia cuando sea posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2019-11-05','Ana: *En SIDEX no aparece la solicitud que registramos el 5/06/19. *Llamo al EVD-Plas., Gloria-T.O. (24111), me comunica que la solicitud deben tenerla en papel, pues aún no está gravada. Lo comprobará y me devolverá la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-11-05','miguel, remito a abogacía y secretaria general solicitud de intervención para actuar abogacía en procedimiento de revisión de capacidad de cambio de curatela a tutela. Remito al Juzgado Decano de Cáceres solicitud de internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2019-11-06','TERESA: ARCHIVO ACTA DE LA SUBCOMISION MANTENIDA EL 20 DE SEPTBIEMBRE. SE LLEGA A LA CONCLUSION DE QUE EL ENTORNO EN EL QUE VIVE ADRIAN NO ES EL MAS ADECUADO PARA EL (VIVE CON SUS PADRES EN UNA VIVIENDA SOCIAL CON MAS HERMANOS) LA FAMILIA NO APORTA EL SOPORTE REAL A LAS DIFICULTADES QUE TIENE ADRIAN Y EL MISMO RECONOCE SENTIRSE ABURRIDO Y CON POCO AUTOCUIDADO, NO PARTICIPA EN LA VIDA SOCIAL DEL PUEBLO EN EL QUE RESIDE NI TIENE GRUPO DE AMIGOS DEFINIDOS. LLEVA UN AÑO TRANQUILO CON UNA VIDA RUTINARIA Y DE POCA ACTIVIDAD. SE ACUERDA SOLICITAR DE NUEVO PERFIL AL CADEX PARA QUE REVISE LA SITUACION ACTUAL DE ADRIAN POR LOS CAMBIOS QUE SE HAN PRODUCIDO DESDE LA ULTIMA VEZ QUE FUE VALORADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2019-11-06','miguel, Alberto y yo vamos a la videoconferencia de la vista del juicio del proced Tutela 395/2016. Curro es quién representa a la Comisión Tutelar de Adultos. ********************************************************* Vamos al juicio sin saber bien si lo que allí se tratará es una reclamación de cantidad (subir su asignación mensual) o un procedimiento de revisión de la capacidad a tutela ya que no nos han remitido ni el juzgado ni desde abogacía general nada más que poderes apud acta de representación procesal y providencia del Jzdo nº1 de Cáceres de citación a esta Ctaex hoy. El 8/5/2019 con carácter previo a la aprobación de las cuentas nos requirió el Ministerio Fiscal "Mª del Carmen Barquilla Bermejo" a fin de que informaramos de modo de admiistrar la cuantía mensual a esta curatelada, así como el trámite establecido para la entrega de gastos extraordinarios, para viajes u otros. Dicha infomación decía la fiscal era necesaria por cuanto, por el IMAS se hace constar las dificultades para la recepción de dinero. *********************************************************** Finalmente el procedimiento es únicamente reclamando subida de la asignación económica mensual','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2019-11-06','-Nos informa Cati , TS de Aprosuba3 , que Antonia se ha autolesionado , con dos cortes de cuchillo en la cara . He guardado en su expediente la foto. Ha estado unos dias en casa y ya ha regresado , está tranquila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FERNANDA'and edp.apellido1='MARQUEZ'and apellido2='GARCIA'),'2019-11-04','TERESA: EMAIL DE LS TS CASA HOSPITAL SANTIAGO soy Susana, trabajadora social de casa Hospital de Santiago, con respecto a la pensión de Mª Fernanda Marquez te informo que abonó el mes de enero un total de 493,90€ y el mes de febrero pagó sólo la mitad, 200€. Por lo tanto tendría pendiente que abonar el 75% del total de ingreso/s de prestación/ es desde el mes de marzo de 2019. Respecto a los gastos de bolsillo, decirte que con las familias de las residentes estipulamos una cuantia de 500€ anuales que nos entregan en el mes de enero de cada año en mano, sin transferencias, y en el mes de diciembre de ese mismo año entregamos la relación de gastos con sus respectivos tickets y/ o facturas. En este año tampoco se hizo entrega de ese dinero de Mª Fernanda por lo que estaría pendiente. Para cualquier duda puedes ponerte en contacto conmigo al teléfono 607.331.963 Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2019-11-07','(Pedro) Correo-e de CRR de Mérida de ayer. +++Buenas tardes, Esta mañana han ingresado a Ángel Pinilla en UHB, no ha sido voluntario y hemos tenido que solicitar presencia policial. Cuando tengamos más información os comentamos. Muchas gracias, Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2019-11-06','miguel, envío al jzdo de cáceres nº4 comunicando que mañana se retiraran de la vivienda los enseres personales de Paula y se llevarán al CSS donde quedaran depositados hasta que los herederos los reclamen','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA EUGENIA'and edp.apellido1='MOLANO'and apellido2='CAMBERO'),'2019-11-05','Recibimos correo de Toni-FUTUEX: "Buenas tardes, pues finalizado el ingreso de Maria Eugenia, las compañeras ya están de vuelta en Cáceres, alli se han encontrado con Susana, que será la que hará el seguimiento, en Fuente de Cantos, han estado reunidas con las profesionales del centro que les han enseñado las instalaciones. Se han reunido con la directora, la psicóloga y la enfermera. Y María Eugenia se ha quedado muy impresionada con lo nueva que es la residencia y las instalaciones que tiene. Hay taller de huerto, de reparacion de zapatos, de manualidades, de cocina,...etc. Han quedado con la enfermera del centro que se va a poner en contacto con el PADI de llerena para saber cuándo puede ir María Eugenia a que le revisen la boca y nos avisará por si la podemos acompañar, como se hacía en Cáceres.para decirme la fecha. Trataremos de cubrir sus citas de salud mental y del PADI, en la medida que podamos, e intensificaremos las visitas para facilitar su adaptación. La veremos semanalmente, por ahora. ..." /////////////////// Llamo de Rosa Mª de Tena, Directora del C. R. para pers. con discapacidad Fco. Asuar, de Fte. de Cantos (667 693 216). Mª Eugenia en principio está contenta y se está adaptando muy bien, se han dado cuenta de que "lo que más necesita y apoyo y carió y allí lo va a tener", expresa. Le facilito el nº de cuenta para que puedan pasar el pago de la plaza. **Me enviará el Certificado de Ingreso en la Residencia. *En cuanto a la asignación económica le explicarán que ya no puede disponer de la misma cuantía semanal pues tiene que pagar la plaza. Hablaré con Alberto, Jefe de la Secc. Ecca. para fijar una nueva asignación semanal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2019-11-07','(Ana y Pedro) Visita a Jairo en el CSS de Plasencia. Reunidos también con Soraya (Directora) y Emilia (T. Social). +++PLANES DE JAIRO: +++++Ya matriculado para acceso a la Universidad (no han empezado las clases). +++++Ya matriculado en EOI en francés: A pesar de que ya han comenzado las clases no ha asistido a ninguna "...esperando a tener estar reunión para decidir que puedo irme a un piso de estudiantes..." SE le aclara que una cosa no tiene que ver con la otra. +++++Quiere COMPARTIR PISO DE ESTUDIANTES, "...porque así me integro en ese ambiente y poco a poco me iré adaptando..." +++++NIEGA LA POSIBILIDAD QUE SE LE OFRECE DE DERIVAR A CRR:"...no, eso no contéis con ello de ninguna manera..." +++PLANTEAMIENTO DE LA COMISIÓN: +++++Se le trata de hacer entender que lo que pide es un salto muy brusco entre la vida en el centro y una autonomía absoluta fuera de él para la que condieramos no está preparado. +++++Se le propone que plantee como primer objetivo el aprobar el acceso a la Universidad, para lo cual esl estar en el CSS o en un CRR le dan más posibilidades de centrarse en ello. Otro objetivo puede ser el acceso al CRR y posteriormenete a Piso Supervisado, con la posibilidad no descartable de que finalmente pueda hacer realidad sus objetivos. +++REACCIÓN de JAIRO. Alterado, pero dentro de unos límites aceptables, se niega a plantearse siquiera una mínima reflexión sobre ello. +++++Amenaza con denunciarnos a todos en el Juzgado, ante lo cual, apoyo su decisión y le paso los datos del Juzgadoa ante el que tiene que plantear dicha dencuncia, indicando también teléfono: "Sí, os voy a denucniar. Pero yo no voy a llamar al Juzgado, eso lo tendréis que hacer vosotros...". Aprovechamos esta circusntancia para tratar de hacerle consiente de su limitaciones. +++++SE MARCHA MUY MOLESTO, pero al cabo de unos minutos regresa piediendo disculpas por ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-11-06','Ana: Con Nota Interior, nos comunican desde la Ud. de Gestión de Prog. Asisteciales, que el día 28/10/2019, Eugenia fue trasladada al CRR de Cáceres. Nos adjuntan documentación relativa a la Revisión PIA y Autorización para el estudio económico actualizado *se ponen a la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='RODRIGUEZ'and apellido2='SOLIS'),'2019-11-05','Ana: Recibo llamada de Isabel Pino, T.S. - Ayto. de Miajadas.: Felipe necesita reactivar la tarjeta de transporte subvencionada. *La descargo de la web: http://ws-satedni.gobex.es/Cliente_SATE/ y **la pongo para la firma del D.Gerente. **Hay que adjuntar compulsadas las fotocopias de la Sentencia, Aceptación del Cargo y DNI del Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='SIMON'and apellido2='MARTIN'),'2019-11-04','Ana: Recibo correo de Mª José, T.S. Trasierra de Granadilla: "Buenos dias te remito el DNI de Florencia. TENEMOS UN POBLEMA, LA PRESTACION FAMILIAR POR HIJO A CARGO QUE VENIA PERCIBIENDO LA MADRE DE FLORENCIA, SE LE HA DEJADO DE INGRESAR PERO TAMPOCO SE LE ESTA INGRESANDO EN LA CUENTA DE FLORENCIA. HEMOS INTENTADO CONTACTAR CON LA SEGURIDAD SOCIAL SIN EXITO." ***Guardo el DNI en su expte. Intentaré averiguar y solventar lo ocurrido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-11-07','(Pedro)Conversación con Javier Pecero ( Director CRR de Mérida). +++Comunica el fallecimineto de un sobrino de José Mª en accidente de tráfico. Está muy afectado y esta tarde acudirá con su familia. +++Ruego le transmita las condolencias de parte de la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-11-07','Ana: Recibo un correo de Estrella, T.S. - CSS Plas. (estrella.duranc@salud-juntaex.es) "Buenos días, por el presente se solicita otorguen autorización para que la paciente Josefa Domínguez Blanco, tutelada por esa Comisión, pueda salir unas horas en el día de hoy, a visitar en el Hospital Virgen del Puerto de Plasencia, a su madre, la cual está enferma de mucha gravedad y con una avanzada edad (más de 90 años) y vuelve al centro, hoy mismo. Saludos." Hablo con Estrella, dado que en el CSS lo ven oportuno y la Psiquiatra le va a hacer el Pase de Salidas, respondo que por nuestra parte no hay ningún problema. Envío correo al respecto.','2');
