insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-11-11','(Pedro)Conversación con la Secretaría del Servicio de Cirugía General del Hospital "Virgen del Rocío" de Sevilla (955-012313). La Dra. Verónica Pino Díaz está operando. Dejo teléfonos de contacto de la Comisión. +++Quedamos en que llamarán a lo l,argo de la mañana. En caso contrario, llamra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-11-11','miguel, nos envía liberbank email interesandose por el estado del procedimiento. Llamo al jzdo de 1º instancia e instrucción nº2 de Plasencia donde me indican que estan pendientes de un requerimiento (oficio) que desde hace más de 1 mes han requerido a la central de Liberbank, sin que ésta les conteste (tanto en papel como vía lexnet). Le comento al jzdo que lo notifiquen a la oficina de Plasencia, dirigido a la persona que lleva dicha dación por parte del banco. Contesto al email y les indico que les llegará el requerimiento a la oficina de Plasencia. ////////////////////////////////////////////////////////////////////////////////////////////////////////////// Ana: Recibo llamada de Mariví Clemente, T.S.- CSS -Plas., dice que nos ha enviado un correo al ctutelar para que autoricemos la salida con su familia, la familia lo ha pedido por escrito, el psiquiatra está de acuerdo y como es tutela y Miguel es paciente judicial, tienen que enviar nuestra autorización al Jgdo. **Miguel tiene una MEDIDA DE INTERNAMIENTO (del 27/10/2017 al 25/10/2020). Tiene varias medidas. *Ingresó en el CSS con una medida judicial el 10/01/2017, antes de tener la tutela la CTAEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2019-11-11','miguel, nos llega la resolución que tenía la monja en relación con el procedimiento declarativo monitorio que confirma lo que sabíamos, es decir, que se archivo el mismo dando vía libre al procedimiento de ejecución, el cual como sabemos está finalizado y reclaman unos 760€+ intereses y pronto recargo. ************************************************ En su momento cuando nos llegó dicha resolución por el jzdo, y al requerir a TGSS a través de Ana Ts descubrimos que no sòlo tenía la pensión de unos 300€ nuestra tutelada, sino que había otra de unos 900€ que tenían controlada las monjas donde reside, esto es "Hogar Sta Teresa Jornet (Don Benito)". Tras hablar Pedro Js con ellas, la monja ha remitido este documento donde queda acreditado que no estaba exento del pago y por tanto Pedro Js la llamará para indicarles que o pagan o les embargarán la cuenta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Converdsación con Ana T. Soc. +++Se informa de que ya los plazos para tratar de evitar el pago de la deuda sehan cumplido, por lo que deberán abonar el importe. Se propone que solicten el fraccionamiento del pago, pero dice que lo abonarán íntegro. +++Al parecer esta circunstancia, que la hija haya sacado a la madre de la residencia y le haya hecho firmar "algo", no es la primera vez que ocurre. De hecho, ya la trabajadora social les envío un escrito advirtiéndoles de que no dejaran salir a Dª Rosario, pero "...por caridad humana...". Le explico que aquí ya no se trata de caridad, sino de legalidad. Y ahora Dª Rosdario está bajo la tutela de la Adminmistración. +++En relación a lo anterior, pido a Ana que nos envíe el escrito quye remitió a las monjas, nos indique las cirsunstancias que mortivaron esta deuda y la Comisión enviará a la Residencia escrito indicando que bajo ningún concepoto se permita la salida de Dª Rosario del centro sin la autorización de esta Comisión y que las visitas que se le hagan sean siempre supervisadas.','2');
