insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2019-11-11','Ana: Respondo al correo-e remitido por Victoria Rajo, Directora del CRR-CC, a fecha de 29/10/19, en relación a la situación económica de Eugenia. Informo de la situación y de la Autorización de retirada de efectivo que tenía en el otro CRR, se puede mantener la misma cantidad. Cuando nos comuniquen la sucursal y los datos de la/s persona/s que acompañarán a Eugenia al banco se hará nueva autorización. *Le envío la copia de la Sentencia de Incapacitación y nombramiento que solicitan.','2');
