insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2019-11-08','Ana: El pasado viernes 8 recibimos correo de Victoria Rajo, CRR-CC (residenciadir@feafescaceres.com): "Buenos días, Les escribo en relación al usuario Felix F. M. para informarles que la semana pasada falleció su padre y me plantea la cuestión relativa a la pensión de orfandad. El desea que se le tramite dado que sus ingresos mensuales son muy ajustados y le ayudaría de cara a afrontar gastos. Quedo a la espera de saber si se iniciarán los trámites al respecto. Reciban un cordial saludo, Victoria Rajo". Respondo al correo informando que la PNC que percibe es incopatible con la P.Orfandad, por lo que habría que solicitarle PFHC y Orfandad, pero para ésta última necesito los datos del padre fallecido y el Certificado de Defunción. **Cuando me lo faciliten comenzaré los trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='MARTINEZ'and apellido2='VAZQUEZ'),'2019-11-11','TERESA: RECIBO EMAIL DE LA PROVIDENCIA Buenos días, Informamos que la familia de la tutelada Concepción Martínez Vázquez necesitan una autorización judicial para poder vender la vivienda familiar. Envío el número de teléfono de una de las hijas de la tutelada: Purificación: 687168578 HABLO CON ANGEL Y ME DICE QUE NUESTRA TUTELADA ES USUFRUCTUARIA DE LA VIVIENDA, QUE EL PROPIETARIO ES PEDRO PECOS Y DEBEN DE HACER LA HERENCIA. BUENAS TARDES, NO SE TRATA DE LA VIVIENDA DE LA PAREJA QUE ES A LA QUE HACÉIS REFERENCIA. SE TRATA DE LA VIVIENDA DE SUS PADRES. ACABO DE HABLAR CON UNA DE LAS HEREDERAS Y ME COMENTAN QUE TIENEN EL TESTAMENTO Y LA DECLARACIÓN DE HEREDEROS. ENVÍO EL TELEFONO DE LA GESTORÍA QUE LO ESTÁ TRAMITANDO: 615 98 77 23 PREGUNTAR POR EMILIO. ES EL ENCARGADO DE LAS GESTIONES.','2');
