insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-10-31','Ana: Recibo email de Paula, T.O.-CRR Plas. (tocupacional.crrplasencia@grupo5.net): "Informaros de que ayer por la noche ingresó en el Hospital Virgen del Puerto Ceferino Mariscal. Verbalizaba ideas autolíticas y consideraron oportuno su ingreso. En los días previos ha reconocido haber entrado en la habitación de un compañero y haber robado 20 Euros que éste tenía en una mesa. Así mismo vamos a investigar su participación en un robo en un comercio de Plasencia (Carrefour) que él mismo cuenta situándose como acompañante de la persona que roba unas deportivas. Además de devolver los 20 Euros al compañero de su asignación diaria (durante el tiempo equivalente no ha recibido la asignación) vamos a valorar otras medidas, tanto de reparación del daño como una posible expulsión del recurso (posiblemente temporal). Hablaremos de esta situación durante la reunión del día 6, si os parece."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-11-06','Ana: En reunión mantenida en el CRR-Plas., nos comunican que Ceferino fue dado de alta a la mañana siguiente de su ingreso en el hptal. Fue una clara llamada de atención. *En relación a los robos, además de devolver el dinero, se acuerda tomar la medida de expulsarlo unos días del CRR, el nº de días dependerá de las disponibilidad del CAT (Centro de Acogida Temporal) de Cáritas, con el que ya han contactado y al que irá durante su expulsión. ///////// Por otra parte, le acompañarán a los establecimientos en los que suelen fiarle, para que él mismo pida que dejen de hacerlo, pues tienen deudas en varios de ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2019-11-06','Ana: En reunión mantenida en el CRR-Plas. acordamos, que si en la Revisión de Grado de Dependencia Guadalupe obtuviese Grado I, intentaremos solicitar Plaza en Residenca de Mayores vía Decreto por Emergencia Social, por haber superado la edad para residir en el CRR.','2');
