insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-11-13','(Pedro)Rosa (Admón. CSS de Plasencia.)Envía Correo-e con solcitud adjunta del hermano (ver expediente scaneado) +++Correo-e: +++++Buenos días Pedro: En relación con el paciente incapacitado y tutelado por esa Comisión, MIGUEL SANTOS CORDERO, se ha planificado una salida al domicilio familiar en compañía de su hermano, al encontrarse psicopatológicamente estable, según la información de la Médico Psiquiatra encargada de su seguimiento, Dra. Fernández. Al estar sometido a medida de seguridad, se ha enviado al Juzgado la solicitud del hermano, estando en espera de la contestación. Informaremos de la misma así como de cualquier incidencia. Adjuntamos copia de la solicitud del hermano. Un saludo. Rosa Bravo. CSS. Plasencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-11-13','TERESA: ARCHIVO RESOLUCION REGIMEN DE VISITAS DE SU HIJA. DESESTIMAN NUESTRA PROPUESTA CON LO CUAL LA VISITA TIENE QUE HACERSE EN CASA DE LA ABUELA PATERNA. LLAMO AL CENTO PARA COMUNICAR LA RESOLUCION Y PLANIFICAR LA VISITA DE BEA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-11-13','-Amalia: el traslado de Maria no se ha hecho según lo previsto. Todo estaba coordinado para que con el 112 se hiciese el traslado . Cuando el auxiliar SAD ha llegado al domicilio a las 10.00 de la mañana estaban alli , su cuñado Juan y la mujer , buscando las joyas , el dinero ... Maria se ha empezado a poner muy nerviosa y ha tirado objetos por la sala . El 112 , se ha presentado sin médicos , solo dos tecnicos y han tenido q llamar al medico de Valdepasillas q se ha presentado con Feli la TS y le ha puesto un valium para tranquilizarla. Desde Futuex , me cuentan lo sucedido. Llamo a la residencia y hablo con el Dtor , me dice q ahora está tranquila y que ha comido bien.','2');
