insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2019-11-13','Ana: Recibo email de Victoria, Directora CRR-CC: "Buenos días Ana, Hemos valorado que dispondremos de los servicios de Lucía hasta el domingo de la semana que viene, se lo comunicaremos a principios de semana. Consuelo ya ha comenzado a practicar con las muletas y está recuperándose bastante bien. Queremos que estar totalmente seguros de que Lucía ya no será imprescindible, para ello queremos estar con ella una semana más." /// Lo comunico a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='ORTIZ'and apellido2='GORDILLO'),'2019-11-14','Buenos días, Amalia. Yo no veo buena idea solicitar el traslado por cómo es él y cómo es su situación familiar pero insiste en que no quiere estar aquí toda la vida . Sabes que le cuesta asumir normas , trabajar en el taller, etc . Si quieres, puedes leer el informe que el pasado 25/10/19 la Comisión Técnica de este Centro dirigimos a Soraya Masa Moreno en respuesta a una queja telefónica que Miguel realizó con respecto a nosotros. Miguel piensa que en otro Centro su vida va a ser mejor. Habría que solicitarlo vía dependencia. Ya tiene el perfil modificado de RAL a VT por lo que habría que solicitar sólo los centros que disponen de servicio de vivienda tutelada que él ya los sabe porque lo hablamos una y otra vez. Si realizarais el trámite vía dependencia, por favor, enviame una copia. Pasa por el despacho para hablar conmigo TODOS los días.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2019-11-14','Ana: Paso a Juan Pedro, Admtvo. CTAEX, la solicitud de Revisión del CADEX, debidamente firmada y sellada, para que la remita por correo certificado a NOVAFORMA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2019-11-14','(Pedro)Llamada de D. José Vicente Vicente. +++"En el banco me dicen que no me dan dienro porque lo ha dicho un juez..." . Le explico los términos de la sentencia de incapacitación: curatela en la esfera sanitaria y para actos patrimoniales de cierta trascendencia y que excedan la gestión ordinaria de cantidades económicas de escasa cuantía... +++Cuando ingreso en prisión él mismo hacía la trasferencia a la cuenta peculio...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2019-11-14','(Pedro)Hablo con Reme, de la Secretaría de Cirugía General (955-012313). +++Explico nuevamente que la persona que figura como tutora de D. Juan Carlos es el Gerente del sepad y que él no se desplaz para estos asuntos. ++++No existe posibilidad de que la firma del consentimineto se pueda enviar por correo previa información con la Cirujana: "Aquí los médicos son muy estrictos con ello y tiene que ser la persona que figura como tutor el que venga a la consulta. +++ Planteo al alternativa de FIRMA DELEGADA. No sabe si eso va a ser factible por lo mencionado anteriormente. Lo comunicará a la Cirujana y lo pasarán a a la asesoría jurídica del hospital en espera de su respuesta. +++Además de los teléfonos indicados, dejo también mi correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2019-11-14','Ana: Recibo del CAMF Alcuescar, solicitud de material ortoprotésico del SES junto a la documentación que hay que aportar. Pongo la solicitud para la firma del D.Gerente. ///// Llamo a Felisa Custodio - T.S. (927 38 41 25) Acordamos que lo registraré yo y le enviaré copia escaneada a su email (trabajador_social_alcuescar@imserso.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALERIANO'and edp.apellido1='POZON'and apellido2='CORDON'),'2019-11-14','El procedimiento nº 772/2017 seguido en el juzgado de nº 2 zafra se encuenta en suspenso, según nos informa Escalona. Se abre nuevo procedimiento nº 51/2019 en el juzgado nº 4 de mérida, por lo cual se abre nuevo expediente en la intranet en 2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALERIANO'and edp.apellido1='POZON'and apellido2='CORDON'),'2019-11-14','SE ABRE NUEVO EXPEDIENTE EN INTRANET. PUESTO QUE, EL ANTERIOR PROCEDIMIENTO SEGUIDO EN EL JUZGADO Nº 2 DE ZAFRA ENCUENTRA EN SUSPENSO Y SE INICIA UNO NUEVO EN EL JUZGADO Nº 4 DE MERIDA.','2');
