insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-11-14','Ana: Recibo llamada de Juan Chamorro (625 89 53 94), de nuevo dice que necesita dinero, ha dejado a deber en el estando y en otro establecimiento. Pide que se le autoricen 80€ para Ocio. Le repito, como en la última llamada, que no se le pueden dar extras todos los meses. *Le recuerdo que tiene cita en Salud Mental el día 22, **dice que "NO PIENSA IR", que irá a hablar con la Dr. Consolación al C. Salud para pedir que allí le ponga el enfermero el inyectable, pero que a Salud Mental no pues el Psiquiatra tambien esta "en el complot".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2019-11-15','Ana: Recibo un correo de Paula, T.O. CRR-Plas.(tocupacional.crrplasencia@grupo5.net): "Buenas Ana, informaros de que ante las situaciones que comentamos de "gastos" impulsivos de Félix Franco en apuestas, hemos acordado que comience a acudir a la asociación AJER (Asociación de Jugadores) por lo que deberá aportar 20 Euros mensuales a la misma. Creemos importante en este momento que ese dinero pueda ser del presupuesto mensual o los ahorrillos de un mes a otro. También comentaros que desde esta asociación se le ha facilitado un documento para que rellene y así no pueda estar en los establecimientos de apuestas si piden el DNI. De esta forma le apoyamos para que pueda trabajar esta situación y pueda tener herramientas para seguir con su vida en el Piso Supervisado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2019-11-14','Ana: Recibo correo de Paula, T.O. CRR-Plas. ( ): "...Toñi Bernardo ha comenzado a realizar un voluntariado en la perrera municipal, con una valoración muy positiva y satisfactoria por su parte. Acude caminando (está a unos 45-50 min andando) y realiza labores de limpieza. Va de lunes a viernes un par 2-3 horas. Se muestra dispuesta a respetar horarios de citas y no ha dejado de realizar actividades o tareas comunes en el centro. Así mismo dice haberse apuntado al SEXPE. En próximas citas seguiremos explorando pero nos parecía importante transmitiros este paso a la acción de Toñi, como un cambio que trataremos de apoyar para que sea positivo en su vida."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-11-15','Ana: Recibo correo de Teresa Doncel, T.S. IMAS-CC, adjuntando nuevo informe de la Policía con otra incidencia de Pilar: Esta vez estuvo sacando garrafas de aceite usado del contenedor correspondiente y arrojándolos a la vía pública. /// Se lo comunico a Miguel, Asesor Jurídico CTAEX, de momento no lo comunicará a Fiscalía, lo aportará llegado el momento. *Guardo el informe en el expte. (PC y papel)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2019-11-15','Ana: Paso a Juan Pedro, Adtvo. CTAEX, C.I. y Solicitud de Inclusión en Lista de Espera para C.M.A. de Cataratas para que lo remita por correo certificado al CRR-CC. /////// En cuanto a los acompañamientos que se solicitan en la documentación médica para el día de la intervención, acuerdo con Victoria Rajo, Direct.CRR, que si es posible le acompañara al hptal. una de las Delegadas Tutelares y durante la noche se contratará una empresa para que haga el acompañamiento en el CRR. (*Ver correos del 14 y 15 noviembre)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-11-07','Ana: Recibo llamada de José Manuel (667 38 48 17), dice que se lo ha pensado mejor y que prefiere quedarse en su casa. Sólo aceptaría CRR si fuera el de Mérida. También quiere que le solicitemos SAD. En cuanto a la Asignación Económica, se acuerda con Alberto, Jefe Secc. Ecca., que podrá retirar 60€/semana todos los lunes (tirando un poco de las pagas extras).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-10-29','Ana: Recibo llamada de Carolina, hermana de Mª Luisa (696 281 560). Dice que la hija de Mª Luisa sigue viviendo en la casa y que los vecinos le han comunicado que está haciendo trapicheos y acuden a la vivienda personas con "mala pinta". Además le han visto sacar la lavadora y el frigorífico de la vivienda y llevárselos en una furgoneta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-10-21','Ana: Recibo llamada de Toni- Futuex: Al parecer, en relación a la compra de vivienda, Ana Pérez Tejeda, Psiquiatra de Ángel, marido, tiene un criterio distinto al de Rosa Mª Fdez. Barrera, Psiquiatra de Desideria y al de Mariví Clemente, T.S. *Toni nos pasará informe. **Las Delegadas acompañarán al matrimonio a inmobililarias y a ver viviendas de alquiler (como mucho con opción a compra).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='RETAMAL'and apellido2='GONZALEZ'),'2019-11-14','TERESA VISITO A CANDIDO EN SU CASA EN LA CALLE VELAQUEZ N 70 PARA ACOMPAÑARLO JUNTO CON SUSADA LA DELEGADA TUTELAR A SU NUEVO PISO EN CALLE LOPEZ DE AYALA N 19A 3 I. LE INDICAMOS QUE HAGA SU MALETA PARA IRSE HOY YA AL PISO. NOS ENSEÑA EL ARMARI Y LO TIENE LLENO DE ROPA QUE HA IDO ACUMULANDO, ROPA QUE NO USA Y QUE ADEMAS NO LE SIRVE PORQUE ES MUY GRANDE. HACE LA MALETA CON LA ROPA QUE MEJOR TIENE, INCLUSO ALGUNA SIN ESTRENAR CON LA ETIQUETA PUESTA. LA CASA ESTA UN POCO DESORDENADA LLENA DE BOLSAS CON COSAS POR TODOS LADOS, PERIODICOS ETC. LE ACOMPAÑAMOS AL PISO Y LE INDICAMOS LAS DIFERESTES ESTANCIAS Y LE COLOCAMOS UN POCO LO QUE NOS HEMOS TRAIDO DE SU CASA. CANDIDO FIRMA UN CONTRATO DE COMPROMISO EN EL QUE SE COMPROMENTE A CUIDADAR EL PISO Y NO LLEVAR ANIMALES. CANDIDO ES UNA CURATELA EXCLUSIVAMENTE ECONOMICA CON LO CUAL DESDE LA COMISION NO PODEMOS TRABAJAR NINGUN ASPECTO MAS QUE EL PURAMENTE ECONOMICO, SE INTETARA A TRAVES DE LOS SERVICIOS SOCIALES UNA SUPERVISION PARA QUE HAGA USO DEL PISO Y POCO A POCO VAYA DEJANDO SU CASA. TELEFONO PRPIETARIA RAMONA: 619752537','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-11-15','TERESA: ARCHIVO DNI','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-11-14','Ana: Recibimos correo de Toni-Futuex, con documento adjunto de alquieler de vivienda firamdo por Ángel, han encontrado un segundo piso con ascensor por 350€/mes. Lo ha firmado él sólo por miedo a perder la oportunidad de alquilarlo si tenía que esperar una respuesta de la CTAEX. Desde Futuex consideran "...relevante que se le asigne una cantidad mensual o quincenal a Desideria para que pueda aportar o sufragar otros gastos, de la pareja." Proponen 250/300€ mensuales. **Valoramos en equipo en la CTAEX (Alberto, Pedro y yo. A posteriori también Miguel): El matrimonio tiene Regimen de Bienes Gananciales y Desideria no tiene ingresos propios, si se le ha abierto una cuenta a parte para ingresar la mitad de la venta de la vivienda del pueblo ha sido por protección de Desideria. **Por lo pronto le solicitaré PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FERNANDO'and edp.apellido1='MARTINEZ'and apellido2='MARTIN'),'2019-11-15','TERESA: RECIBO EMAIL DE TS Buenos días Teresa, ya está encargada la SR de Fernando, y tambien se le ha pedido un cojín antiescaras y empapaderas para el cojín, por su incontinencia urinaria, para que si se produce, pueda lavarse el cojín y no empape todo el conjunto de la silla. Os haré llegar dos facturas, la de la silla para enviar la original al servicio de prestaciones y la del cojín y empapadera aparte. Me gustaría que me confirmaras si la otra silla que se solicito en marzo del 2018 se le ha abonado en cuenta, porque sé que va con demora, pero no con exactitud. muchas gracias, un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-10-23','Ana: Toni-Futuex, envía a Pedro un email con informe de actuaciones llevadas a cabo con Desideria. **Guardado en el expte. PC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2019-11-14','Ana: Recibo correo de Cristina Castro Mora, Ed. Soc. de Asoc. Vera (educadorasocial@asociacionvera.com): "Buenas tardes, Adjunto envío Consentimiento informado para tratamiento odontológico bajo anestesia local para extracción de muela del juicio de Dña. Mª del Carmen Mellado Guardabrazos. Solicito la aceptación mediante firma del consentimiento informado que adjunto envío. Saludos" // *Pongo el CI para la firma del D.Gerente.','2');
