insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-11-15','TERESA: ARCHIVO SENTENCIA REGIMEN DE VISITAS. HABLO CON EL CENTRO PARA COMUNICARLE LA SENTENCIA Y ORGANIZAR LA VISITA. DESDE EL CENTRO VAN A BUSCAR UN CUIDADOR QUE LA ACOMPAÑE Y SUPERVISE LA VISITA. LA COMISION TUTELAR VA A PONERSE EN CONTACTO CON LA ABUELA PARA ACORDAR DIA Y HORA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2019-10-29','Ana: Recibo llamada de Maite Cañadas, CR Conventual S.Fco.-Plas. (21860). Es una Sra. que está acostumbrada a manejar mucho dinero. Desde que se le han limitado las cuentas Joaquina está más inquieta. Dice que el viernes le dio 40€ y ayer lunes ya no le quedaba nada. Le ha dado hoy otros 20€. **Tras hablarlo también con Alberto, Jefe secc. ecca., acordamos una asignación semanal de 80€ que ella le administrará (a razón de 40 los lunes y 40 los viernes).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-10-10','Ana: Recibo llamada de Juan, die que fue al médico a Trujillo el miércoles por el carcaño y aprovechó para ir a ver al Psiquiatra. Le pidió algún medicamento para el ánimo, pero éste "ha intentado asesinarlo", "están en complot todos los médicos, lo tengo averiguado" refiere. Cree que el inyectable le está haciendo daño, "me está produciendo muchos dolores".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-11-15','Ana: Llamo a Nuria, Enfermera E.S.M.- Trujillo (54508). Le informo del contenido de las últimas convesaciones con Juan, me llama todas las semanas, el delirio parece estar activo y la última vez ha verbalizado no querer ir a la cita del día 22. *Le recuerdo que en el informe del Psiquiatra especifica que si no se pone el inyectable habría que ingresarlo. ***Hablará el lunes con el Psiquiatra y el martes con la T.S. y se pondrán en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-10-02','Ana: Recibo llamada de Cefe, desde un móvil que le han prestado. Dice tener una deuda de 30€ en una librería. Ayer en la farmacia se gastó 10€. Expresa sentirse apurado económicamente. Quiere que se le aumente la asignación diaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-11-18','Ana: recibimos mediante fax, comunicados del CSS-Mérida: El viernes 15 a las 18 h Juan Ángel se fugó del CSS. Regresó el a las 3:00 a.m. del día 16. El mismo 16 le trasladaron al Hptal. de Mérida. //////////////////////////////////////////// **Aún no he solicitado PFHC porque no tenemos nº de cuenta, ni en la misma está puesto como titular el D.Gerente.','2');
