insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2019-11-19','Ana: Recibo llamada de Juan Carlos Serrano, Director del C.Residencial Los Pinos-Plas. (21911), necesita saber, qué cantidad, además de la extra, se podrá pasar este mes para seguir abonando la deuda que queda pendiente. A día de hoy debe 967,18€. **Se lo paso a Alberto, Jefe de la secc. ecca. /// *Eduvigis está muy bien y perfectamente adaptada. La visten con ropa del ropero común, para no gastar en ropa, pero las aux. excogen la mejor ropa para ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2019-11-18','Ana: En relación al correo enviado por Victoria Rajo el viernes 15, en que decía que Feliciano muestra mucha preoucpación por la herencia familiar, "...le gustaría saber qué parte de la herencia le pertenece...", tras hablarlo con los Asesores Jurídicos, CTAEX, respondo al correo diciendo que los compañeros están en ello, que han solicitado al Jgdo. la aprobación definitiva de las herencias para inscribirlas en el registro de la propiedad, y que aún están a la espera de respuesta. Les mantendremos informados. /////////// También pregunta si se están gestinando desde aquí los pagos de los suministros de la casa hererdada. *Lo mirará Alberto, Jefe secc. ecca. *Confirma que no consta en las cuentas que se estén pagando esas facturas. Se lo comunico a Victoria.','2');
