insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2019-11-19','(Pedro) Llamada realizada a D. Juan Paredes Hernández, cuñado de Dª María. +++SE le informa sobre la tutelada de su cuñada, si bien no parece estar demasiado interesado en los detalles. +++Pide que acerquemos a su cuñada a badajoz, porque les supone un inconveniente el desplazarse para verla. Se le explica que, dado el poco tiempo que hace que ingresó en la Residencia de "El Torno", la Comisión no considera conveniente solicitar un traslado en estos momentos, a la esperea de ver cómo evoluciona Dª María en dicha residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2019-11-19','Ana: Me devuelven de REGISTRO las solicitudes de PFHC y Orfandad de Félix registrada a fecha de hoy. Archivo copias registradas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-11-19','(Pedro)Visita de Dª Isabel, madre de Juan Ángel. +++Acude porque había pensado ir a ver a su hijo, pero al ir a sacar dinero de la cartilla en la que figura como cotitular con su hijo le han dicho que no podía sacar nada de ella. le explico el motivo, que parece comprender. +++Aunque dice serle muy costoso el pedir un taxi para acudir a la visita si no paga su hijo al taxi, reconoce que tampoco ella tiene muchas ganas de acudir porque cada vez es más mayor y le cuesta más. +++Entiende que su hijo dispone de muy poco dinero y que el que tiene lo tiene que destinar a sus gastos ("...Yo antes, de su cartilla, sacaba el dinero para tabaco, ropa, etc...pero ahora ya no puedo y con mi pensión me llega para pagar la residencia y poco más...").La tranquilizo en el sentido de que las necesidades que su hijo tenga en la UME nos las comunicarán desde la Unidad, y la Comisión las tratará de satisfacer en función de la conveniencia que considere tanto técnica como humanamente, y de los recursos ecocnómicos que su hijo tenga en ese momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-11-19','Ana: Recibo llamada de Amor, T.S. -Aspace (690 791 638): Santi necesita ropa, al menos un par de sudaderas y camisetas. *Lo comprarán y enviarán la factura al ctutelar@ para que se abone a la tienda mediante transferencia. *Se lo comunico a Alberto, Jefe de la Secc. Ecca. ////////////////////////// Me informa también que las prendas que le van a comprar no pueden ser de algodón, porque se las come. **Y ha mordido ya a distintos profesionales (cuidadores). Tienen mucha fuerza, refiere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-11-20','miguel, tras conversación con el juzgado decano de Cáceres, me confirman que ha sido designado el jzdo nº1 de Cáceres para tramitar el procedimiento de internamiento involuntario. ************************************ Tras conversación telefónica con el nº1 de Cáceres me confirman que aunque han dado traslado al Ministerio Fiscal les remita físicamente la modificación al escrito inicial consistente que se le designe un centro socio sanitario, previo UHB Cáceres, en vez centro de Mayores (como se solicitó inicialmente, y al que no tendría derecho por edad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-11-20','miguel, conforme me requirió Escalona de Abogacía General, le remito hoy para modificación a la contestación a la demanda, ya que quería un informe firmado por un técnico, que tras conversación con Pedro Js, me confirmó que este tipo de escrito han de seguir firmandose por nuestro Director Gerente José Vicente Granado Granado','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='BORREGUERO'and apellido2='CAMBERO'),'2019-11-20','Ana: Llamo a Victoria Rajo (687 487 908), me facilita el nº del cuñado de Feliciano: Antolín 600 818 400. Éste se negó a seguir abonando las facturas de la vivienda heredada. **Victoria planteará a Feliciano la posibilidad de dar de baja los suministros, argumentando que sería una preocupación menos para él y que tanto su cuañado como él se ahorrarían un gasto innecesario, pues nadie hace uso de la casa. Me enviará un correo para confirmar.','2');
