insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-11-20','Ana: Recibo llamada de Mª Carmen, Residencia de Mayores de Guadalupe (667 891 640), María está muy débil y requiere silla del ruedas. El médico hará la prescripción. ***Remitirán 2 presupuestos al correo ctutelar@. Una vez aprobado y comprada la silla de ruedas, me **envirán la documentación para tramitar la Solicitud de Material Ortoprotésico del SES. // Cumplió 100 años en verano y le hicieron una fiesta en la residencia. Presenta hipoacusia y problemas de visión, pero mantiene plenas facultades mentales. Lee mucho. **No echa de menos su casa ni expresa ningún tipo de apego hacia la misma. Sólo recibe visitas de una vecina. *No tienen descendientes y los sobrinos ni la visitan ni la llaman.','2');
