insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2019-11-20','Ana: Recibo llamada de Noelia, T.S. C.Res. Cervantes (22237) pregunta cómo van los trámites del cambio de cuenta de Mª Luisa, pues ésta reclama poder retirar efectivo. **Se lo paso a Alberto, Jefe secc. ecca. /// Por otro lado me comunica que Mª Luisa lleva una temporada que no echa la ropa a lavar. Me pregunta si puede trabajar este aspecto la Delegada Tutelar en las próximas visitas. **Escribo un email a Toni-Futuex solicitándoselo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-11-20','Ana: Llamo a Nuria, Enfermera del ESM-Trujillo (54508), no obtengo respuesta. Llamo a Raquel, T.S. ESM (54509), pero tampoco responde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2019-11-21','(MIguel y Pedro). +++Asistimos al Juzgado de 1ª Instancia nº 2 de Coria para realizar el inventario de bienes de la madre de D. José Pedro para posteriormente llevar a cabo la repartición de herencia. ************************************************************ Renunciamos junto al resto de hnos a la supuesta deuda de Julian. Aceptamos la deuda de agua, y la de vecinos (que ya dijimos en jzdo que entendemos prescrita) La parte actora (abogado de Francisco) nos aporta toda la documentación, incluida unas pólizas con Alianza consistente en dos Fondos de Inversiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ROMAN'and edp.apellido1='GARCIA'and apellido2='GARCIA'),'2019-11-21','Ana: Llamo a Alberto Arias Bueso, T.O. del EVD Zona Brozas (927 270 466), le indico que la Orden de que me habló no tiene carácter retroactivo, me traerán el contrato original, para compulsar una copia y se la enviaré junto a la Tarifa Visada actualizada y el resto de documentos. //////////// **Acude Daniel, Coordinador Grupo Residencias Ciudad Jardín, trae orinal y copias del Contrato y de las Tarifas de Precio Visadas. Se compulsan las copias para adjuntarlas al PIA. Escaneo el contrato original y lo guardo en el expte. PC. ////////*Paso a Juan Pedro, Admvo., las aceptaciones PIA con toda la documentación requerida para que lo remita al EVD de Brozas, A/A de Alberto Arias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-11-21','Ana: Llamo a Nuria, Enfermera del ESM-Trujillo (54508), me atiende Germán, Enfermero, dice que Nuria ya no está, le estaba sustituyendo. Explico la situación actual de Juan y que dijo que no acudiría a su cita de mañana. Le recuerdo que en el Informe de Psiquiatría dice que de no ponerse el inyectable habría que ingresarlo. **Hablará con el Psiquiatra. //// Llamo a Clara, TS del C.Salud de Guadalupe (53107), no obtengo respuesta. Llamo al C.Salud (927 15 43 05 = 53103), le pasarán nota a la Dra. Consolación para que me devuelva la llamada cuando pueda. //////// Recibo llamada de la Dra. Consolación Sánchez (53100), Juan fue la semana pasada a su consulta, le metió en la tarjeta sanitaria la receta para retirar el inyectable y le consta que lo ha retirado de la farmacia. Le dijo que acudiera hoy para que se la ponga Reyes, Enfermera. *Acordamos que le llamaré yo ahora para recordárselo. **De todas formas ella llamará ahora al Psiquiatra, Dr. Medina, para ponerle en alerta por si tuvieran que activar el protocolo de ingreso. //// Llamo a Juan, vuelve a pedir dinero, ha dejado a deber en varios sitios. *Le recuerdo que tiene cita de mañana, dice que irá mañana a ponerse el inyectable al C.Salud, a Salud Mental no. Le digo que tiene que acudir hoy por el C.Salud pues mañana no estará el enfermero, que he hablado con la Dra. Consolación. Dice que sí, que acudirá esta mañana. /// Recibo llamada de Cristina, T.S. ESM, ahora está ella, ya no es Raquel. Ya ha hablado con el Psiquiatra. ////// **Recibo llamada de Dra. Consolación JUAN HA IDO A PONERSE EL INYECTABLE, ella no estaba pues había salido a un domicilio, pero Reyes le ha confirmado que se lo ha puesto. **Hablará con el Psiquiatra, que antes no lo consiguió y le pedirá que le cambie la cita de Psiquiatría de mañana a otro día, pues mañana se negará a acudir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='SANCHEZ'and apellido2='PANIAGUA TRENADO'),'2019-11-21','Llamo al Juzgado de Herrera del Duque (924650036), para preguntar por la autorización de la herencia que se presentó por el abogado de oficio, Miguel Ángel Asensio, el año pasado. Hablo con Juan, me dice que el expediente, debido a la pendencia de procedimientos que tienen en el Juzgado, está parado. Que va a impulsarlo. Llamó el marido de la tía de Tomás, José Antonio (659644804), para informarse.','2');
