insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-11-21','Ana: Recibo llamada de José Miguel Martín, Empresa de Construcciones El Abuelo Máximo y CONCEJAL del Ayto. de Guadalupe (626 070 969). Pregunta por el presupuesto de obras de mantenimiento mínimo de la vivienda de María que nos hizo llegar a través de Futuex. Le digo que estamos estudiando el caso. Aprovecho para preguntarle si la vivienda se puede demoler, pues es otra de las opciones que contemplamos. Dice que a priori está en zona protegida, pero que han tenido otro caso en el que Patrimonio les ha dado autorización. **Habría que enviar nueva solicitud al Ayto. para que nos envíen INFORME TÉCNICO MUNICIPAL del estado de la vivienda explicando la intención de demolición por el riesgo que supone para las viviendas colindantes.','2');
