insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2019-11-26','miguel, hablo con el Jzdo nº1 de Coria para que nos remita la firmeza del nombramiento y me comenta que es imposible porque se inhibieron y lo remitieron al Jzdo de Villanueva de la Serena el 4-7-2013 expediente completo, sin que dicho Juzgado de Villanueva le haya remitido justificante de su entrega. Julio me confirma que han requerido dicha firmeza en multiples ocasiones al Jzdo de de Villanueva de la Serena sin que nos haya remitido nada hasta la fecha. Necesitamos dicha firmeza para poder ratificar la herencia que se encuentra en notaria de c/ romero leal. Tras comentarlo con Pedro Js, me insta a que lo solicitemos de nuevo con firma del Director Gerente D.José Vicente Granado.','2');
