insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-11-26','Ana: Recibo llamada de Teresa Noguera, TS Novaforma: Les ha llamado la abuela de Álvaro, quiere llevarselo a su casa en Navidad. Desde la entidad no ven claro que pase allí muchos días, pero sí que pase algunas noches puntuales. Acordamos que vaya las noches del 24 y 31 de diciembre y la del 5 de enero. Así mismo, como en ocasiones anteriores podrá ir y venir (sin pernocta) algunos días.','2');
