insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2019-11-27','En relación con el PA 194/19, del Juzgado de lo Penal nº 1, de Mérida, se ha citado a Jonathan para el día 12/12. Hablo con el abogado, José María Delgado Temprano (607924597) y le envío documentación a su correo electrónico (2507@icaba.com). Ha propuesto que le reconozca el forense, pero Jonathan no se ha presentado. Va a insistir para que sea reconocido. Este procedimiento tiene su origen en el PA 460/2017, del Juzgado de Primera Instancia e Instrucción, nº 4, de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2019-11-27','miguel, llega ayer solicitud de Escalona de Informe técnico del equipo social para la contestación a la demanda por procedimiento de remociónde tutela. Hablo con Pedro Js y se lo remito a Amalia para lo redacte.','2');
