insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2019-11-27','Ana: Recibo llamada de Pilar Martín, TS ESM-CC (54612): nos va a enviar Informe de la Psiquiatra y próximas citas de Saturnino.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2019-11-27','(Pedro)Conversación con Felipe (927-269021)sobre la reapación y venta de la casa de la calle Barrio. +++SE le explica que para vender, primero hay que hacer la herencia para ponerla a su nombre y al de sus hermanas y sobrinos. Según contesta, todos ellos están de acuerdo en vender la vivienda. Es más, Felipe propone ceder su parte de la hernecia a sus hermanas, a lo cual le hago ver lo negativo que ello puede ser para sus intereses, dado que en algún momento pued erequerir ese dinero para cubrir sus nevcesidades. Entiende el argumento y lo acepta. +++Reparación de la vivienda: se le excplica que, en caso de que los más de 3000 euros los tenga que pagar él, después se reclamará la resto de los propietarios la parte que corresponda. También acepta sin dudar este punto. +++La conversación transcurre en todo meomto con la cordialidad habitual. +++Comenta que él ya no quiere ir para nada a su pueblo y pregunta si se puede empadronar en Cáceres. "Ya me están preparando los papeles". +++Finalmente, pongo a Teresa (Diretota Novaforma)al corriente de la conversación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2019-11-27','Ana: Conversación con Mariví Clemente, TS CSS (24142): Desideria no aportará ninguna cuantía económica al gasto familiar mensual hasta que tenga aprobada la PFHC y la esté percibiendo. Dado que se trata de un matrimonio con régimen de bienes gananciales, siguen conviviendo juntos y su situación económica no ha variado, seguirán viviendo como hasta el momento, con los ingresos de la unidad familiar, que en este caso es la pensión contributiva por incapacidad permanente absoluta que percibe Ángel, marido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2019-11-27','TELÉFONOS A través de IS del SSB se obtienen los siguientes tfnos. de María Isabel (Macarena): 615875445///629202607.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-11-25','Ana: Llamo a María Barrasa, T.S. CSS Mérida (24005), no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2019-11-27','Ana: Llamo a María Barrasa, T.S. CSS Mérida (24005), no obtengo respuesta. Llamo a la UME (24066), me dicen que está reunida, le darán nota cuando salga. //// Me devuelve la llamada: ya ha hablado con Amalia y le ha explicado la situación. Le indico que he vuelto a hablar con Alberto, Jefe de Secc. Ecca. Los compañerose están realizando las gestiones oportunas. María dice que Juan Ángel es conflictivo, como no tiene tabaco sale a pedir a otros pacientes. En un intento de fuga se cayó de la tapia y se ropió un dedo del pie, lo tiene escayolado. Aunque le han dicho que no apoye el pie y le han llevado una silla de ruedas, no quiere usarla, se levanta y anda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2019-11-27','Ana: Recibo llamada de Mariví Clemente, CSS Plas.: La transferencia que se hacía periódica del Santander al Liberbank para que puedan retirar efectivo para gasto de bolsillo no se estará haciendo efectiva, pues sólo le queda 70€ en la cuenta. *Se lo paso a Alberto, jefe secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-11-27','Ana: Recibo llamada de Juan (625 895 394), dice que "...los médicos están tramando deshacerse de él" porque, añade, sabe todo el entramado del C. Salud, lo de las inyecciones que se trajeron de Alemania, que se las pusieron a tu madre, que asesinaron a su tía, que todo el mundo está en el complot, que le robaron dinero... /////////////////////*Llamo a la Dra. Consolación Sánchez (53100), desde el ESM le van a citar el día 2 febrero con el Dr. Medina, Psiquiatra. Comprueba si retira la medicación de la farmacia: lleva desde el 30 de septiembre sin retirar el Rivotril de 0,5. El resto de medicación sí la está retirando. **No considera que tenga que ir a visitarlo ni activar nada a día de hoy pues dice que esos discursos y delirios son lo habitual en él. "Mientras no haya más alertas en el pueblo ni se muestre agresivo por la calle es que todo va bien"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2019-11-27','Ana: Recibo llamada de Ceferino, dice que está muy preocupado, ha hablado con Javier, Director del CRR, le ha dicho que le "...van a expulsar como transeúnte y le ha dicho que después lo mismo va a la cárcel por estafa a un compañero y él no quiere ir a la cárcel..." le indico que en al reunión mantenida cuando estuvimos allí Pedro y yo, se planteó la posibiliad de ser expulsado unos días por su comportamiento (hurtos a compañeros, en el Carrefour...) y que hablaré con el CRR al respecto.','2');
