insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2019-11-29','TERESA: RECIBO EMAIL DE LA CRISTINA TS CENTRO PENITENCIARIO. Buenos días. Os escribo ante la insistencia de José Vicente Vicente, curatelado por vosotros, sobre las transferencias económicas a la cuenta del Peculio. Amalia me informó hace algo más de un mes que en primer lugar se haría inventario de sus bienes, pero al no haber recibido aún ningún ingreso, quería información sobre cómo va ese proceso y así poder tranquilizar al interno. LE LLAMO POR TELEFONO PARA INFORMAR SOBRE SU SITUACION, ACABA DE CUMPLIR CONDENA DE NUEVES MESES POR PRIVACION DE LIBERTAR Y AHORA COMIENZA OTROS 9 MESES POR MEDIDA DE SEGURIDAD. TIENE OTRA CONDENA DE 3 AÑOS PENDIENTE. LE PASO EMAIL A PEDRO PARA QUE LE CONTESTE AL EMAIL Y ESTABLEZCA LA CANTIDAD QUE SE LE VA A PASAR A CUENTA PELCULIO MENSUALMENTE POR TRANSFERENCIA DESDE LA CUENTA QUE LE HEMOS ABIERTO CON JOSE VICENTE GRANADO','2');
