insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2019-12-02','Ana: Recibo correo de Sonia Bernabé, ASINDI: "Hola Ana, no sé si recordarás que hace un tiempo te comenté que Justo estaba interesado en participar en un video de sensibilización sobre el colectivo LGTBI que grabará la Federación. Nos acaban de mandar la documentación relativa a este proyecto y, nos informan que se grabaría en Mérida el día 4 de diciembre. Adjunto os remito toda la documentación que tenemos al respecto (autorizaciones, guión,...) Necesito que la reviséis y nos digáis, mañana, si puede o no participar porque, si autorizáis a que participe, tiene que llevar la documentación firmada el día de la grabación, es decir, el 4 de Diciembre. Un saludo" /// *Lo paso a Miguel, Asesor Jurídico. Éste da el ok, enviará todo junto a un escrito a Fiscalía. **Imprimo, cumplimento y pondo los documentos para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-12-03','Ana: Llamo a Urgencias del C. Salud de Pza. de Argel (53046), me pasan con la Dr. Mª Soledad Turégano Albarrán. Le informo sobre el AUTO de nombramiento de TUTORA PROVISIONAL a la CTAEX y la Medida Cautelar de Internamiento. Emitirá un informe proponiendo ingreso en Psiquiatría (UHB) para que la diagnostiquen. **Activaré el 112, para que la vayan a buscar mañana. //////// Llamo al 112 (924 31 02 04), hablo con la Jefa de Sala y expongo la situación. Me pasa con la enfermera que organiza los traslados. **Preparo y envío el FAX (924 31 14 87) ///////////////// Llamo a Toni-Futuex: Gloria Sampedro, Delegada, estará pendiente por la zona que suele frecuentar Mª Pilar. **sobre 9 - 9:30 h.','2');
