insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2019-12-04','TERESA: RECIBO LLAMADA DE M JOSE TS DEL CENTRO PARA COMENTARME EL ESTADO DE SALUD DE PABLO. LE HAN DETECTADO TUMOR EN UN RIÑON Y TIENE QUE SER OPERADO PERO AL TENER UN ANAURISMA LA OPERACION SUPONE UN ALTO RIESGO DE MUERTE. ME CITAN PARA QUE ASISTA MAÑANA A LAS 12 AL HOSPITAL VIREN DEL PUERTO DE PLASENCIA PARA QUE ME EXPLIQUEN LA OPERACION Y TOMAR LA DECISION DE OPERAR O NO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='CABEZAS'and apellido2='MAZON'),'2019-12-04','TERESA: LLAMO A SU HIJA YA QUE QUIERE HABLAR CON LA COMSION, ME COMENTA QUE HA IDO A VISITAR A SU MADRE EL DIA 24 DE NOVIEMBRE Y QUERIA SASCARLA A COMER PORQUE ERA SU CUMPLEAÑOS Y NO LA DEJARON SALIR DESDE EL CENTRO. HABLO CON ANA LA TS Y ME COMENTA QUE NO AUTORIZARON LA SALIDA PUESTO QUE DEBIDO A LOS ATECEDENTES QUE TIENE LA HIJA CON RESPECTO A SU MADRE (LA JUNTA LE QUITO LA TUTELA) LAS VISITAS CON LA HIJA DEBEN SER SUPERVISADAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-12-03','miguel, asisto al juicio del tutelado por 4 procedimientos por amenazas y coacción a la madre y por coacción leve e injurias al hermano. Se llega a un acuerdo con la fiscalia y basado en la voluntad del tutelado, consistente en el pago de una multa de 150€+150€ a pagar en 3 veces, y en 56 días +56 días de trabajo a la comunidad (lo cual nos notificarán más adelante las opciones para elegir el sitio donde prestará dichos trabajos sociales)','2');
