insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-12-04','Ana: Tras contactos varios con la Jefa de Sala del 112 y Toni-Futuex (las delegadas y la policía local están esperando desde las 9:00h y la ambulancia y policía nacional no ha llegado), se dan cuenta, de que aunque se pidió que el Ingreso se hiciera hoy, el 112 realizó el traslado al Hptal. San Pedro de Alcántara ayer. ///////////// Llamo a Mª José, TS HSPA, le informo de la situación acutal, hablará con Psiquiatría para recordar que no pueden darle el "alta voluntaria" y pedirles que elaboren un diagnóstico para que podamos solicitar recurso. A día de hoy no da perfil para ninguno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2019-11-21','remitimos al juzgado nº1 de Zafra solicitud para que solicite abogado de oficio a la tutelada, para el procedimieto en la que se encuentra en calidad de testigo DPA 475/2019','2');
