insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-12-04','Ana: llamo a Menores (927 00 43 60), Raquel, dice que lo habló con la Jefa de Secc, ésta pensaba que la CTAEX asumía el coste de la silla de ruedas y/o la plaza de residencia, le explicó que no es así, que en la CTAEX NO hay partida presupuestaria alguna y que lo que se hace es gestinar lo que cada persona tutelada tiene. **Santiago no tiene dinero para la silla de ruedas. **La jefa le dijo que retomaría el tema. Ya nos darán respuesta. ****Me vuelve a llamar Raquel, ha hablado de nuevo con la Jefa y le han dicho que con los presupuestos que tenían en Menores (les habían enviado 3) y el informe retomarán todo para gestionarsela, pero ya será para enero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2019-12-11','Ana: Llamo a Amor, T.S. -Aspace (690 791 638), le comunico lo hablado con Raquel-Menores, que retomarán los trámites para la silla de ruedas en enero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2019-12-04','-LLamo por tf a Angel , que ha acudido a la oficina. El tema es economico ha hablado con Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2019-12-04','-Amalia : confirmo con Sección depend. que tiene un Grado 1.2. valorado en el País Vasco. Está pendiente que vayan a su domicilio para elegir PIA .Con Grado 1 no podría acceder a recurso residencial de mayores , tiene 57 años . Podria entrar por promocion de la autonomia en centro de salud mental ( CRR ) . Se puede pedir por PIA y la tienen q valorar tb desde el ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2019-12-04','-Amalia : confirmo con Sección depend. que tiene un Grado 1.2. valorado en el País Vasco. Está pendiente que vayan a su domicilio para elegir PIA .Con Grado 1 no podría acceder a recurso residencial de mayores , tiene 57 años . Podria entrar por promocion de la autonomia en centro de salud mental ( CRR ) . Se puede pedir por PIA y la tienen q valorar tb desde el ESM.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-12-04','miguel, envío fax al Jzdo 1º instancia e instrucción nº2 de Don Benito solicitando nos comuniquen por escrito el problema de la dilación en la resolución. ****************************************************** Adjunto les remito la reclamación de cantidad dineraria y facturas que envía el perito que ha arreglado la vivienda Camilo. ******************************************************** Paralelamente resuelvo negativamente el escrito de reclamación de cantidad hasta que el juzgado resuelva, y que le enviaremos en próximos días. ********************************************************* Hablo con la persona del Jzdo de Don Benito que lleva el procedimiento y me confirma que el motivo es porque todavía el Colegio de Abogados no ha nombrado un abogado de oficio. Me dice que remitirá el expediente al Ministerio Fiscal y paralelamente enviará un nuevo oficio al colegio de abogados solicitandole abogado de oficio.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-12-05','Buenas tardes Amalia. Me pongo en contacto contigo para comentarte sobre Francisco Pinilla Baena. Ha causado baja en el centro porque dejó de venir y no hemos podido por ningún medio volver a hacer que viniera, por lo que se le propuso que tenía que causar baja. Dicha baja la ha firmado él, puesto que al tener sólo curatela económica y de salud, por lo que consideramos que podía hacerlo él. La situación personal de este hombre sigue siendo la misma. Sigue con Laura y su relación es muy tóxica. En estos momentos ella está viviendo en Badajoz porque está trabajando allí y Francisco se ha quedado en Lobón en la casa en la que vive con Laura. La casa es de una tía y de la madre de Laura y, como ya sabes, se encuentra en muy malas condiciones. No hay un mínimo de limpieza y las ratas campan a sus anchas por allí. Nos han comentado que le han dicho que ya no puede estar viviendo allí porque ha habido una queja vecinal. Ayer me comentó que se fue con Laura a Badajoz y que tuvieron una fuerte discusión por lo que los vecinos llamaron a la policía que se personó con una ambulancia. No me ha dicho nada más, por lo que entiendo que no ha cursado denuncia alguna. Sus padres han biscado una nave para alquilar donde pueda llevar a los perros y demás animales que tiene, pero quieren que sea Francisco quien pague el alquiler de dicha nave, para que asuma alguna responsabilidad. Este caso nos está resultando muy complicado la verdad. A ver si entre todos se nos ocurre alguna idea. Besos. -- Eva Álvarez Gallego Trabajadora Social Tfno. 924 454 727 Plena Inclusión Montijo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2019-12-05','-escrito de FUTUEX Se envía adjunto los siguientes documentos que ha solicitado la Comisión, de Antonia Hernánde Sánchez (talavera la Real) Al no poder desplazarse por el cansancio y fatiga, ha tenido un ingreso por agudización de su EPOC, ha solicitado al area económica de la Comisión (Juana), que su asignación semanal pueda ser ingresada en la cuenta de su madre, para que una de sus hermanas, autorizadas en dicha cuenta, retire su cantidad y se la controle como de costumbre. Juana, le ha dado el visto bueno y que, desde aquí, se le haga llegar dicho nº. También expediente de baja de dependencia en el pais Vasco que necesitan para la solicitud aqui en Extremadura. Y el informe de urgencias.( eso no viene )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2019-12-05','-escrito de FUTUEX Se envía adjunto los siguientes documentos que ha solicitado la Comisión, de Antonia Hernánde Sánchez (talavera la Real) Al no poder desplazarse por el cansancio y fatiga, ha tenido un ingreso por agudización de su EPOC, ha solicitado al area económica de la Comisión (Juana), que su asignación semanal pueda ser ingresada en la cuenta de su madre, para que una de sus hermanas, autorizadas en dicha cuenta, retire su cantidad y se la controle como de costumbre. Juana, le ha dado el visto bueno y que, desde aquí, se le haga llegar dicho nº. También expediente de baja de dependencia en el pais Vasco que necesitan para la solicitud aqui en Extremadura. Y el informe de urgencias.( eso no viene )','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-12-05','-Amalia : escrito que me envia Laura: Buenas noches Amalia, Me pongo en contacto contigo por qué quería comentarte que quería reunirme contigo para hablar sobre Francisco Javier Pinilla Baena de un tema delicado. Es algo que hemos echo los dos y me gustaría hablarlo contigo para que entiendas que yo no puedo llevar todos los gastos del alquiler sola. Y eso cuenta luz y agua. Y también quería comentarte otras cosas a parte de lo que quiero hablar personalmente con usted. A parte también quería pedirte la resolución del juzgado completo para entregárselo a mí abogado para coger toda la tutelación de Francisco. Espero que podamos reunirnos a partir de las 11 cualquier día de la semana de lunes a viernes. Ya que me urge hablar y comentarte unas cosas urgentes. Recibe un cordial saludo Laura','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-12-05','Buenas tardes Amalia. Me pongo en contacto contigo para comentarte sobre Francisco Pinilla Baena. Ha causado baja en el centro porque dejó de venir y no hemos podido por ningún medio volver a hacer que viniera, por lo que se le propuso que tenía que causar baja. Dicha baja la ha firmado él, puesto que al tener sólo curatela económica y de salud, por lo que consideramos que podía hacerlo él. La situación personal de este hombre sigue siendo la misma. Sigue con Laura y su relación es muy tóxica. En estos momentos ella está viviendo en Badajoz porque está trabajando allí y Francisco se ha quedado en Lobón en la casa en la que vive con Laura. La casa es de una tía y de la madre de Laura y, como ya sabes, se encuentra en muy malas condiciones. No hay un mínimo de limpieza y las ratas campan a sus anchas por allí. Nos han comentado que le han dicho que ya no puede estar viviendo allí porque ha habido una queja vecinal. Ayer me comentó que se fue con Laura a Badajoz y que tuvieron una fuerte discusión por lo que los vecinos llamaron a la policía que se personó con una ambulancia. No me ha dicho nada más, por lo que entiendo que no ha cursado denuncia alguna. Sus padres han biscado una nave para alquilar donde pueda llevar a los perros y demás animales que tiene, pero quieren que sea Francisco quien pague el alquiler de dicha nave, para que asuma alguna responsabilidad. Este caso nos está resultando muy complicado la verdad. A ver si entre todos se nos ocurre alguna idea. Besos. -- Eva Álvarez Gallego Trabajadora Social Tfno. 924 454 727 Plena Inclusión Montijo','1');
