insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-12-05','-Amalia : Luisa Paredes acudió ayer a SEPAD Badajoz, deja su tf para que la llamemos . En la llamada que acabo de recialir me indica que ayer Mercedes la despidió , no estaba conforme con el trabajo que habia realizado. Exige que se le paguen los 4 días correspondientes a este mes que le debe .','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2019-12-05','-Amalia : Luisa Paredes acudió ayer a SEPAD Badajoz, deja su tf para que la llamemos . En la llamada que acabo de recialir me indica que ayer Mercedes la despidió , no estaba conforme con el trabajo que habia realizado. Exige que se le paguen los 4 días correspondientes a este mes que le debe .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2019-12-05','miguel, llega la citación para toma de declaración del tutelado el 19-2-2020, a la cual no nos exigen asistir pero sí que vaya acompañado de abogado. Solicito a secretaría general (Mª Guerrero)nos indique si al estar afectada la administración es un procedimiento en el que asistirá abogacía general, o le buscamos un abogado de oficio','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-12-05','TERESA:RECIBO EMAIL DE LA TS DEL SSB DE VILLAFRACA Buenos días, me pongo en contacto con Uds. a fin de informarles que la madre de Adolfo García Cruz se encuentra hospitalizada en Tierra de Barros y por la información facilitada desde el ámbito sanitario, dicha señora se encuentra muy mal. Así mismo se informa respecto al hermano que vivía solo, Antonio, que mediante orden judicial se accedió a su domicilio para proceder a vaciarlo de basura (se sacaron 4 camiones), siendo ingresado en la unidad de salud mental del hospital y hoy se ha producido el alta. Teniendo en cuenta que hace más de 4 años que ambos hermanos no tiene relación, la enfermedad de ambos, que la casa de Antonio no está en condiciones para que vuelva ya que no dispone de agua ni enseres por lo que seguramente se irá a casa de la madre y de Adolfo y sobre todo la fijación que tiene Adolfo de que su madre es eterna, que va a vivir siempre y no va a faltar, todo ello consideramos que afectará gravemente a la situación de Adolfo y que surgirán lo más probable graves problemas de convivencia. saludos Marisa Álvarez Trabajadora Social SSASB','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2019-12-11','TERESA: RECIBO EMAIL DEL SSB Buenos días, contacto con Uds ya que he recibido llamada de la compañera del Centro de Salud para informar que durante este fin de semana contactaron con ella telefónicamente desde el Hospital Tierra de Barros ya que Adolfo estaba intentando localizar a un taxista a fin de irse a Sevilla a ver a una persona que había conocido por internet. Desde el personal del centro hospitalario pudieron convencerlo y por el momento desistió de la idea, aunque está obsesionado con buscar y tener novia. Se pone en su conocimiento ya que como se envió, en su día ya se trasladó a Sevilla recientemente y fue a través de la policía que se gestionó la vuelta a Villafranca Desde los servicios de salud comentan que la madre sigue mal y están pendientes de que exista plaza en el Hospital San Juan de Dios de Almendralejo para hacer el traslado desde el hospital Tierra de Barros de Almendralejo. según nos informan, el tlf corporativo, extensión, de la compañera del hospital Tierra de Barros es 89325 espero tengan en cuenta esta información y la facilitada recientemente a la hora de buscar la alternativa de ingreso de Adolfo en algún centro. Saludos Marisa Álvarez Tello Trabajadora Social SSASB Vfca. Barros','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CAMPA'and apellido2='SILGUERO'),'2019-12-11','TERESA: Buenos días: Os informamos que Dña. Antonia Campa Silguero, con DNI; 15.057.435-W, y residente de este Centro, se marchará de vacaciones a Cilleros, con su hijo Juan Carlos, el día 23 de Diciembre, regresando a la Residencia el 7 de Enero . Un saludo Mª Montaña García Fdez Trabajadora Social Centro Residencial El Cuartillo. CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='CUESTA'),'2019-12-11','Ana: Recibo correo de Emilia, TS CSS-Plas.: "BUENOS DIAS ANA. ADJUNTO LOS DOS PRESUPUESTOS DE LA SILLA DE RUEDA QUE NECESITA MARIA RODRIGUEZ CUESTA, Y PROCEDER A LA ADQUISICION DE LA MISMA SI NECESITAS EL INFORME MEDICO TE LO ENVIO. PROCEDEMOS A COMPRAR LA SILLA CON EL PRSUPUESTO MAS ECONOMICO. GRACIAS UN SALUDO." *Se lo paso a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2019-12-11','TERESA: Buenas tardes Teresa. Ya me he incorporado hoy al trabajo recuperada del todo .Me pongo en contacto para comunicarte que Beatriz asistirá al I Encuentro Internacional de Extremadura de Deporte sin Adjetivos que se celebrará en Cáceres durante los días 14 y 15 junto con más compañeros/as y dos monitores del Centro. La actividad es gratuita. Sirva el email para informar de la salida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2019-12-11','Ana: Recibo llamada de Juan Carlos, Director del C.R. Los Pinos - Plas. Eduvigis está ingresada desde el fin de semana en el hptal. Le están haciendo pruebas, pero necesitan C.I. para continuar. Me facilita un contacto. /// Llamo a Vanesa, Admvo. (78022), le pasará nota a la Médica que me llamará cuando pueda. // Recibo llamada de Estela Villalba, Médica Internista (78142), informa que ayer hicieron un TAC a Eduvigis, y creen que puede tener un Ampuloma (Tumor que obstruye las vías biliares), Eduvigis no tiene Vesícula. Habría que hacerle una CPRE, pero es una prueba bastante agresiva y dado el Deterioro Cognitivo Severo que presenta no está segura de que sea lo mejor. Como quiere saber más acerca del día a día de Eduvigis, hablará con Juan Carlos, Director de la Res. como Guardadores de hecho, pues en el centro es donde mejor la conocen. *Si finalmente fuera necesario el C.I. nos lo remitirán por fax. /// Llamo a Juan Carlos y le facilito el teléfono de la Doctora, pues al final no podrá acudir hoy al hptal. como era su intención incial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2019-12-04','Ana: recibo llamada de Vanesa (654 04 65 68), ya no está trabajando en el hotel, estuvo 2 meses y medio. Me vuelve a preguntar por su cartilla del banco. Le digo que el Jgdo. no nos ha enviado nada y como ella dice que tiene la Resolución Judicial, que no nos ha llegado a enviar, que acuda a la T.S. para que ella nos la remita escaneada o por fax. Afirma que lo hará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2019-12-04','Ana: Recibo llamada de Pilar Cerrillo, T.S., han recibido en la residencia una Fe de Vida de Isidora, para la hija de la misma. Lo cumplimentará y firmará ella como T.S. y lo enviará a Suiza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2019-12-11','Ana: Recibo llamada de Vanesa, dice que el mismo día que hablamos (4/12/19) acudió a llevarle a Ana, T.S. Miajadas, la documentación para que nos la enviara. Como no hemos recibido nada llamaré al Ayto. e intentaré hablar con ella. ///// Llamo a Anabel, TS (927 90 12 15) está atendiendo, me devolverá la llamada más tarde. **Me devuelve la llamada más tarde, dice que efectivamente Vanesa acudió a su despacho el día 4. Nos ha remitido copia de la Sentencia por correo ordinario (aún no ha llegado), es la nº 77/2019 del Juzgado de 1ª Instancia e Instrucción nº2 de Trujillo. **Se lo comunico a Ángel, Asesor Jurídico, llamará al Jgdo.','2');
