insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2019-12-12','Ana: Recibo llamada de Juan (625895394), parece alterado, con el delirio muy activo, pide que hable con la Juez, para que no le obliguen a ponerse el inyectable, que le está haciendo mucho daño, que no quiere acudir con el Dr. Medina, que está en el Complot y la Dra. Consolación también, que se "lo quieren quitar del medio", continúa con el discurso de anteriores conversaciones, sobre los robos, las inyecciones nacis traídas de Alemania... //////// Llamo a Germán, Enfermero del ESM de Trujillo (54508), hablará mañana con el Psiquiatra, pues ahora no está. Me mantendrán informada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-12-12','miguel, llama la madre de la tutelada, Marisol (646266658), para informarse del procedimiento penal nº2 de Badajoz cuya cita la tenemos el día 18-12-2019, sobre Delito de Daños y Delito de hurto leve, por los acontecimientos producidos en carrefour express, y Teresa Ts tras conversación con ella me la pasa para concretar en qué consiste el procedimiento y si hay algún otro vigente. Me comenta que hay otros procedimientos judiciales que no han saltado y que puede ser que más adelante salten. Le comento el juicio del que ha resultado absuelta en juzgado de Cáceres nº3, se muestra sorprendida pues comenta que su hija le comenta todo e ignoraba este procedimiento. Me indica su impotencia para ayudar a su hija y comenta que la van a hacer una exploración (hace 3 años tenían que verla la vesícula y no fue a la cita) y ahora ha perdido unos 15 kilos. Se muestra preocupada ya que todo lo que ingiere su cuerpo lo expulsa. En este puente ha estado visitando a su hija y dice que aquella casa desprende mucho olor a alcohol. La indico que al juicio del día 18-12-2019 irá Pedro Js por ser quién conoce más el caso, y me dice que posiblemente ella no vaya ya que la otra hija (que desconoce todo lo que va sucediendo) está apunto de presentarse al 2º examen de judicatura. Se muestra colaboradora y agradable, y en cierto modo resignada ya que coincide con lo que le decimos de que podría ser diferente si María se dejara ayudar. Se encuentra bastante preocupada ya que según dice cada día es un sobresalto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2019-12-12','-Anulo la cita para mañana con Laura para la proxima semana . Ha llegado I.Social de Montijo ,conflicto con los padres , ha vuelto de nuevo con la novia.','2');
