insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2019-12-13','Ana: Recibo llamada de Estela Villalba, Médica Internista (78142): Dada la alta sospecha de ampuloma (Tumor cancerígeno) y la situación de Eduvigis con una Demencia GDS6, no saben hasta que punto es beneficioso para ella somerterla a una prueba tan agresiva y cruenta, con la misma lo único que conseguirían sería poner una prótesis que le alargaría la vida unos meses. Consideran que lo único que pueden hacer es aportarle MEDIDAS PALIATIVAS llegado el momento. *Nos enviará un borrador del Informe por fax.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2019-12-13','Ana: Cumplimento y pongo para la firma del D.Gerente la Solicitud de Atención preferente en el SES remitida por NOVAFORMA. /////////////////////////////////// Convesación con Teresa, TS Novaforma, como en la vez anterior plantean que Alvaro acuda a su domicilio en estas fechas, pero tendría que ir y volver en taxi los días que se concreten (supone 4 viajes al día, pues su madre es quién tendrá que ir a recogerlo y llevarlo de vuelta). Sólo pernoctará las 3 noches más señaladas: 24 y 31 de diciembre y 5 de enero. Los otros días propuestos volvería el mismo día. ***Se lo paso a Alberto, Jefe de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='BLAZQUEZ'and apellido2='SANDOVAL'),'2019-12-13','Ana: Cumplimento y pongo para la firma del D.Gerente la Solicitud de Atención preferente en el SES remitida por NOVAFORMA. //////////////////// *Conversación con Teresa, TS Novaforma: *Acordamos que recortarán en las vaciones de Juan Manuel para que siga participando en las actividades de ocio de ASPAINCA, mucho más beneficiosas para él. *Está pendiente de Domiciliación Bancaria, y ya se deben 2 mensualidades. *Se lo paso a Alberto, Jefe de la Secc. Ecca.','2');
