insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2019-12-13','miguel, llama Camilo (albañil) a Juana preguntando quién lleva el procedimiento en el juzgado para ir a hablar con él. Le pedimos espere hablemos con el Colegio de Abogados a ver si desde aqui logramos que nos den solución a la asignación de abogado que solicitó hace meses el juzgado, aunque no logramos hablar con la sede de Don Benito ni la de Badajoz. ********************************************************* Le indicamos que vaya a la sede de colegio de abogados de Don Benito y le damos los datos de localización del colegio de abogados y con lo que le digan vaya al juzgado nº2 de Don Benito y pregunte por el procedimiento pendiente de resolución de gastos extraordinarios consitentes en la reparación de la vivienda','2');
