insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2019-12-13','Ana: Llamo a la Residencia Ntra. Sra. de Sopetrán de Jarandilla de la Vera (927 56 03 93), hablo con Maria, Directora. Dice que Juan José ingresó hace año y medio en la residencia, llegó muy mal, lo habían encontrado tirado en el suelo en una finca, pero se recuperó muy bien. Es muy autónomo. Mantiene buena relación tanto con el resto de residentes como con el personal del centro. *No tiene valoración de dependencia. Su plaza es privada (950€/mes - Habitación individual), la paga con sus ahorros, al parecer tiene al menos una cuenta bancaria más de lo que nos constaba a la CTAEX (Inventario), por la que le pasan el recibo mensual (Caja Duero), tiene dinero para seguir abonando la plaza, según María. *Se lo comunico a Iciar y Alberto, Secc. Ecca. // Por otra parte, María me informa de que Juan José se administra económicamente muy bien, a penas gasta dinero, nos planteamos no limitar las cuentas. // En cuanto a relaciones familiares, cuando llegó a la Res. no se hablaba con el hermano, ahora se cartean. *Tiene un amigo que le acompaña y le apoya cuando tiene que hacer alguna gestión. *Tiene una casa en Cuacos de Yuste (debe ser herencia, pues no aparecía nada a su nombre en el Certif. Catastral).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2019-12-13','Ana: Recibo un correo de Estrella, T.S. - CSS Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Te escribo para comunicarte que Josefa Domínguez Blanco se irá de vacaciones navideñas a su casa de Valedobispo. Vendrá su hermano Rafael a por ella el día 21 a mediodía y la traerá el día 27. Gracias. Saludos."','2');
