insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2019-12-16','Ana: Entrego a Alberto, Jefe de la Secc. Ecca., el recibo de luz que nos envió por correo José Luis, hermano de José Manuel para que se le abone. ////////////////////////////////////////// Conversación con José Manuel (667 38 48 17), dice que está pendiente de que se le apruebe el presupuesto para comprar el teléfono, el que está usando es de su hijo y éste ya se lo está reclamando. También dice que necesita dinero para ropa (pantalones, camisetas y zapatillas) *Se lo paso a Alberto, Jefe Secc. Ecca. /////////////// *Pregunta que por qué se le sigue pasando la manutención a su hija. Le explico que los compañeros Asesores Jurídicos, ya solicitaron abogado de oficio para que solicitara la modificación de la medida, pero mientras no haya otra resolución tiene que seguir pagándosela.','2');
