insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='BARROSO'and apellido2='DORADO'),'2019-12-16','TERESA: HABLO CON RITA PARA COMUNICARLE QUE LA PF YA ESTA A NOMBRE DEL TUTOT LEGAL. ME PIDE QUE SE LO COMUNIQUEMOS POR ESCRITO A ROSARIO Y QUE ESTABLEZCAMOS LA CUANTIA QUE SE LE VA A DAR A PARTIR DEL 15 DE CADA MES PARA INTENTAR ASI QEU LLEGUEN CON DINERO A FIN DE MES. LE PREGUNTO POR EL FISIO Y ME DICE QUE AUN SIGUE LLENDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2019-12-16','TERESA: TRAS HABLAR CON OLGA LA TS DEL CENTRO DE SALUD DE PLASENCIA Y LA TS DE LA RESIDENCIA IBARRA CONCLUIMOS NO AUTORIZAR LA SALIDA DE LA LOCALIDAD DE VILLFRANCA DE LOS BARROS EN BASE A QUE LAS VISITAS Y LLAMADAS DE JESUS A SU MADRE SON CASI NULAS Y QUE ELLA SE ENCUENTRA BIEN ADAPTADA EN LA RESIDENCIA SIENDO UN RIESGO EL QUE SE VAYA CON SU HIJO PUESTO QUE PARTIMOS QUE FUE UN INFGRESO INVOLUNTARIO LE COMUNICO A JESUS LA DECICION Y LA ACEPTA SIN PONER MUCHA OPOSICIÓN. NOS PROPONE QUE CONTRATEOS A ALGUIEN PARA QUE LA SAQUE A PASEAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='HORNERO'and apellido2='RODRIGUEZ'),'2019-12-16','Iciar: HAblo con María, directora de la Residencia. Juan José debido a un embargo que tuvo en su día puso de titular a su hermano Lorenzo en su cuenta de Unicaja y él se puso de autorizado, con lo cual no tenemos acceso a esa cuenta. Según María en esa cuenta habría cerca de 30.000€. El cargo del centro se seguirá pasando a esa cuenta. En Liberbank solo hay una cuenta que es la que nosostros le hemos abierto para pasarle allí la pensión.','2');
