insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-12-18','miguel, teníamos cita para la vista del procedimiento por hurto leve en el jzdo de lo penal 2. Futuex no puede llevar desde Monesterio a Maria, ni su madre tampoco. La tutelada dice estar enferma y tras hablar con el médico que hablaba de remitirnos a parte del informe de asistencia al médico de cabecera, nos iba a remitir un informe de la enfermedad de Maria que la imposibilite asistir al juicio. *********************************************** Llama su madre Marisol y nos indica que ya ha llegado a un acuerdo su abogado con el fiscal para que quede todo en una multa de 60€ que dice haber pagado ya. Por tanto que no solicitemos la suspensión del juicio por enfermedad y dejemos que se realice. Por nuestra parte remitimos a dicho juzgado vía fax el único documento que nos remiten que es el informe de asistencia del médico de cabecera a los efectos oportunos (no solicitamos la suspensión), no pudiendo remitir el informe que nos solicitó el juzgado (vía tfno)a efectos de acreditar el impedimento de asistencia a la vista de hoy de la tutelada consistente en el informe descriptivo de la enfermedad que debía enviar su médico (a lo que se comprometió tras conversación tlfno esta mañana con Pedro Js)','2');
