insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2019-12-19','(Pedro)Entrevista con Ildefonso (visita programada). +++Trae un presupuesto de ropa de trabajo para cumplir con los trabajos comunitarios impuestos por el Juzgado. +++Quiere realizarlos en jardinería, como en una ocasión anterior. Se le plantea que espere a ver qué trabajos se le proponen pero está seguro de que trabajará en jardinería. +++Dejo presupuesto a Alberto. +++SE vuelve a insistir en la asistencia a Salud Mental (para control de tratamineto)y a CEDEx. +++FUTURO: refiere que está planteándos la vuelta de JOAQUINA desde Barcelona y han hablado de irse a vivir juntos a San Pedro de Mérida. Cuestionado por el momento en que eso pueda suceder contesta que no lo sabe pero que ella está muy cansada de vivir con sus padres.','2');
