insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2019-12-20','(Ana y Pedro)Conversación con Mª José, T.Soc. del HSPA. +++Solicitamos nos envíen urgente el informe de ingreso en UHB y la comunicación del mismo al Juzgado nº 3 de Cáceres, para desde la Comisión remitir al Juzgado de 1ª Instancia Nº 1 de Cáceres comunicación del ingreso y previsión de alta. +++Se le pide que plantee nuevemnete a Jesús, psiquiatra, la posibilidad de derivar a Dª Pilar a URA como él mismo planteó como última opción, en espera de las indicaciones del Juzgadp nº 1.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2019-12-19','miguel, tras conversación con Belén Camisón (cuñada del tutelado) Hablo con la notaria Ana (quién dejará la escritura a Jose Luis) para sea firmada el día 2 de enero por los interesados y el 3 ratificaremos nosotros, así se lo hago saber a Ana y Jose Luis. No obstante Ana me pide le envíe email para recordarselo, y así lo haré. Por otra parte al día siguiente Belén Camisón me llama para ratificar que se pueda firmar y me confirma que harán transferencia el 26 o 27 de diciembre, lo cual se lo comunico a la parte económica para tengamos cuidado de que el tutelado no disponga de ese dinero.','1');
