insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2019-12-20','ICIAR: Llama Toñi (T.S. El Prado- 20877. El hijo de Dolores (Guillermo 667 63 21 67) se encuentra en el centro pues ha ido al banco a pagar el recibo de la contribución de la casa de la madre y en el banco no le han dejado hacerlo. Toñi nos manda el recibo escaneado para que demos orden al banco para pagar, el periodo voluntario termina en un día. Además comenta que los hijos no tienen constanacia de que la madre esté tutelada, la tutela es de 2014. Los hijos, son cuatro, quieren pedir la remoción de la tutela, se les facilita el nº de JUzgado y procedimiento de incapacitación. También comenta que están tramitando la herencia del padre y que les gustaría hablar con la Comisión para ver cómo tiene que hacer. Hace unos días también había llamado una de ls hijas preguntando en qué consistía la tutela pues no sabía que su madre estuviera tutelada, también nos dice que la relación entre los hermanos tamoco era demasiado buena. Nuera de Dolores- Carnmen t/c 693 78 99 65','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2019-12-20','BELEN, HABLO CON ELENA924485603 CLINICA DENTAL LOS MILAGROS PARA EFECTUAR EL PAGO DEL RESTO DEL PRESUPUESTO DE 975€, NOS INDICA QUE EMILIA LE DICE QUE EL APARATO LO HA TIRADO AL CONTENEDOR POR UN ATAQUE DE RABIA Y QUE NO COMENTE NADA AL CENTRO. ELENA NOS INDICA QUE HACE UNOS DIEZ DÍAS LE TERMINARON EL ESQUELÉTICO, Y QUE AYER NO LO LLEVABA PUESTO. LES PIDIÓ UN NUEVO PRESUPUESTO, Y LES DIJO QUE HABÍA PEDIDO OTRO EN CLINICA DIANA. AL PRESUPUESTO DE 975€ HAY QUE SUMAR 60€ DE UN AÑADIDO DE ROTURA.','2');
