insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2019-12-23','miguel, el viernes 20/12/2019 me llega fax recibido de la hermana del tutelado donde hace mención nos pongamos en contacto con ella (tlfno 674586675), y donde indica que quieren vender la casa de la c/ Andalucía nº19. Tras hablarlo con Pedro Js me indica que él le ha pedido el testamento (que es lo que nos remiten vía fax) ***************************************************** Reviso el testamento y figura el usufructo a favor de un tal Jose Maria con lo cual no se podría vender. Se lo comunico a Pedro quien me pide que la llame. La llamo y no me lo coge.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-12-26','TERESA: Buenas tardes, informaros que vuestro tutelado Andrés Silva en el día de hoy (25 diciembre) ha sido trasladado a la unidad de psiquiatría de merida por agredir a 4 cuidadoras. Se llamo al 112 y recibimos asistencia del centro de salud de la localidad y guardia civil. La médico decidio el traslado a Mérida. Asimismo me informa la médico del pac de cabeza del buey que hará un parte de lesiones puesto que una de las cuidadoras ha tenido que recibir asistencia médica. La guardia civil también ha recogido los datos de dicha cuidadora. Los hechos sucedieron está mañana sobre las 10.30. Sobre las 14.30 me llama la psiquiatra de Mérida para informar que Andrés se encuentra tranquilo y que le darán el alta. Le pautan un inyectable de rescate. A estas horas todavía no ha llegado al centro. Os mantendremos informados. HE LLAMADO AL CENTRO PERO SOLO ESTA LA ADMINISTRATIVO, ME INFORMA QUE YA SE ENCUETRA EN EL CENTRO Y QUE UNA DE LAS CUIDADORAS ESTA EN LA MUTUA YA QUE LA AGRESION HA SIDO BASTANTE FUERTE. ANOTA MI TELEFONO POR SI TIENEN QUE COMUNICAR ALGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-12-26','TERESA: RECIBO FAX DE M CARMEN DIRECTORA DE LA RM DE GUADALUPE EN LA QUE INFORMA QUE HA SUFRIDO UNA CAIDA Y ESTA EN EL HOSPITAL UNIVERSITARIO, NECESITAN CONSENTIMIENTO INFORMADO. ME PONGO EN CONTACTO CON LA TS DEL HOSPITALB 56823. TIENE ACOMPAÑAMIENTO MAÑANA Y TARDE','2');
