insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2019-12-23','TERESA: ACUDO A LA UHB DEL HOSPITAL DE MERIDA A PETICICION DE DTRA GAGARDO PSIQUIATRA DE LA UNIDAD. ME EXPLICA QUE RUBEN ESTA AMENZANDO A LAS ENFERMERAS CON HACER LO MISMO QUE LE HIZO A SU MADRE. NO RESPONDE A LA MEDICACION QUE SE LE PONE Y ES POR ELLO QUE NOS PIDEN FIRMEMOS CONSENTIMIENTO PARA TERAPIA ELECTROCONVULSIVA YA QUE TRAS VALORAR EL CASO CONSIDERAN QUE ES LO MAS ADECUADO. ENTREGO LOS CONSENTIMIENTOS FIRMADOS EN EL DESPACHO DE LA PSQUIATRA PARA QUE HOY MISMO EMPIECEN CON LA TERAPIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-12-27','TERESA: RECIBO EMAIL DE LA TS DE LA RESIDENCIA Hola Tere, queriamos comunicarte que el dia 30 de diciembre, vamos hacer una visita por Zafra; desayunaremos y haremos una visita a los belenes de la localidad. Queremos llevarnos a José Lara, con vuestra previa autorización.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2019-12-27','TERESA: RECIBO EMAIL DE LA DIRECTORA DEL CENTRO Buenos días, informaros que en el día de ayer, Andrés Silva se escapó 3 veces. La primera lo encontró la guardia civil (se encontraba en el centro de salud), la segunda la policía local (estaba en un bar pidiendo dinero) y la tercera lo encontró la policía que estaba a punto de montarse en un tren que salía hacia Villanueva de la serena (tenía el billete comprado, porque otro ciudadano se lo compró). Desde las 20.00 de la tarde estuvo la policía en nuestras instalaciones para que no se volviese a fugar y porque estaba agresivo con las cuidadoras. Finalmente tuvieron que activar el 112, puesto que la policía no puede pasar la tarde con nosotros. Se activo el 112 llegó guardia civil y servicios sanitarios. Le pusieron un inyectable, escupió varias veces una pastilla y pego a la médica que lo atendía. Por tanto, lo volvieron a derivar a Mérida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='SANCHEZ'and apellido2='BELLO'),'2019-12-27','TERESA: ENVIO CONSENTIMIENTO INFORMADO VIA FAX TRAS HABLAR CON LA TRABAJADORA SOCIAL (56781), LA VAN A INTERVENIR ESTA TARDE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RODRIGUEZ'and apellido2='OLMO'),'2019-12-27','miguel, viene a la oficina su hijo y nuera (Guillermo Sancho 667-632167 y Carmen 693-789965). Me confirman lo mismo que comentaron el viernes 20-12-19 donde ya indicaron a la parte económica que desconocian esta tutela y a ninguno de los 4 hijos les habían citado en el juicio de tutela del 2014. Que van a pedir la remoción de tutela entre otras razones porque son los que están siempre con ella en la Residencia del Prado y porque su madre tiene 90 años. Paralelamente están tramitando de una hermana del padre una herencia y me preguntan cómo proceder hasta tengan la remoción. Les digo que si la firman fuera luego pueden pedir la aprobación de herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2019-12-27','miguel, llega por carta remitido por el primo de la tutelada Manuel Garcia Alías: libro de familia, certificado catastral, 3 escrituras fincas rústicas, 1 escritura de donación, 1 contrato de venta de ovejas de Miguel Muñoz Alias, 1 inscripción Rgtro civil de Mª Ines, 1 resolución recurso de reposición, 3 libretas de ahorro(una de ellas abierta por el que suscribe para ingreso de liquidacioes de Don Miguel Muñoz Alias, 1libreta de pazo fijo con certificación de saldo a 10-2-2011, llave de domicilio de inés calle las Artes 25, pta principal, Monroy ******************************************************* llamar al primo para pedirle el resto de documentación, y me confirme si quieren firmar la herenci','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2019-12-27','miguel, tras conversación con Manuel (primo de la tutelada) me confirma que no quedan familiares vivos. Por tanto, tendremos que en base al libro de familia solicitar al Juzgado de Paz de Monroy nos remitan certificado de defunción de todos los hermanos y padres de la tutelada. ************************************************* Asimismo, me confirma que las cuentas que me remite en unas aparece él con la tutelada y en otras el hermano fallecido (Miguel), y todas ellas en Liberbank, donde se ven cantidades importantes y las cuales habremos de rescatarlas una vez tramitada las diversas herencias.','2');
