insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2019-12-04','Ana: Recibo informe de psiquiatría de la Dra. Guadalupe Espárrago. La última consulta tuvo lugar el día 8/11/19, en ella "...se hizo más evidente la expansividad e irritabilidad (junto con verborrea), llegando a apreciarse hipomanía leve, que se debía a haber abandonado temporalmente uno de los tratamientos: el litio... el paciente aceptó retomarlo y realizarse los controles analíticos... No aprecié síntomas psicóticos" el inyectable se le ha administrado de forma adecuada. *Se mantiene el tratamiento pautado. **Tras el alta en UME en 2017, ha acudido a todas las citas correspondientes salvo a la del día 14/08/19. **Próxima cita el 23 de enero de 2020.','2');
