insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-01-04','Ana: Llegó por fax comunicado del CSS-Mérida: se trasladó al hptal de Mérida a Juan Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='PECO'and apellido2='CARRANZA'),'2020-01-07','Ana: Recibo por correo interno escrito de Clara Isabel Gómez Nestares: "INFORMA... Isabel Peco... no es solicitante del reconocimiento de la situación de dependencia..." *Se lo adelanto escaneado a Longina, TS SSAB de Madrigalejo (ssbmadrigalejo@hotmail.com) y le paso compia compulsada a Juan Pedro, Admvo. CTAEX, para que la remita por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-01-07','Ana: Recibo llamada de Juan (625 895 394), de nuevo con el delirio muy activo, vuelve a hablar de las inyecciones nacis, de delitos y atrocidades, del complot, de que él lo sabe todo, que el gobierno utiliza sus pensamientos... dice que no piensa volver a ponerse la inyección, me pide que llame a la jueza para decírselo. ///// Llamo a Germán, Enfermero del ESM de Trujillo (54508), para preguntarle si llegó a hablar con el Dr. Medina, pero comunica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-01-07','Ana: Recibo llamada de Cristina, Ed. Soc. Asoc. Vera (681 143 911). Esta semana estaba previsto su ingreso en la residencia, pero dado que tiene pendiente una analíca el día 8 de enero y Cita con el Endocrino el día 17, viernes, en Badajoz, proponen posponer el ingreo al lunes 20 de enero. Le digo que en principio no hay ningún problema, no obstante mañana lo hablaré con Teresa, TS CTAEX, pues es ella quien lo ha organizado todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-03','Ana: Entrego a Alberto, Jefe de la Secc. Ecca., los recibos de luz y agua que nos envió por correo José Luis, hermano de José Manuel para que se le abonen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-07','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), dice que su hermano lleva 2 días ingresado en la UCI del hptal. S Pedro de Alcántara por ingesta de pastillas, lo encontró él en su casa. ///////////////////////////// *Llamo al hptal S. Pedro Alcántara, a Juani, TS (56341) y a Mª José, TS (56348) pero no obtengo respuesta. Llamo a Centralita (927 25 62 00) me pasan con la Médica de Guardia de UCI. Debido a una ingesta de pastillas (sobredosis) se quedó en coma y tuvieron que intubarlo, pero ya está estable, le han quitado los tubos y hoy mismo le darán el alta en el servicio. Lo pasarán a planta, pero no sabe si a Psiquiatría o a Medicina Interna, aún no está decidido. *El informe de alta sí habría que pedirlo por escrito. /////////////////// Llamo a Isabel, Documentación Médica (51365), enviaremos la solicitud de informe de alta por escrito al fax: 927 25 62 53.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2020-01-08','Ana: Envío correo a Felisa Custodio: "Buenos días Felisa, Me comunica el Jefe del Área Económica que a Fernando se le puede aumentar la asignación entre 5-10 € sin problema, de modo que podrá retirar entre 80 – 85 € mensuales. Un saludo."','2');
