insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2020-01-08','Ana: Recibo llamada de Ángel, Director del CAMP Mª Jesús López Herrero - Plas. (21653). Joaquina sigue ingresada, está muy grave. **Ahora han ingresado también a su hermana Ángela. Han conseguido que las pongan a las 2 en la misma habitación, de modo que el acompañamiento vale para ambas. **Nos enviarán al ctutelar@ facturas pendientes del acompañamiento hospitalario 24 h (13€/h durante el día y 15€/h por la noche) para que se abone desde aquí. *De momento tienen bastante dinero en la cuenta. **Hablado con Alberto, Jefe Secc. Ecca.','2');
