insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-01-08','miguel, a petición de Teresa llamo al Jzdo de 1º instancia nº1 de Zafra donde me indican que hay un procedimiento ITR 526/19 donde fue admitido a trámite el internamiento involuntario solicitado ( lo cual nos indican nos notificaron vía lexnet y nunca nos llegó a la Ctaex), y tras ser informado por el Ministerio Fiscal, éste requiere la revisión por el Forense y la citación de los familiares más cercanos. Nos comentan que remitamos un oficio vía fax señalando los familiares más cercanos, lo cual será remitido hoy por Teresa Ts.','2');
