insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-01-08','Ana: Llamo a Mª José, TS del Hptal. SPA (56348), Pilar sigue ingresada en UHB, en principio no hay novedad. Pido que nos mantengan informados. ///////////////////////////////////////// Recibimos fax escrito del Jgdo de 1ª Instancia e Instrucción nº1 de CC: Requerieren que comuniquemos el Centro o Residencia en que ha sido ingresada Pilar. **LLamo de nuevo a Mª José, TS del Hptal. SPA: nos enviarán entre hoy y mañana informe de ingreso en UHB. **Envío escaneado al mail de Mª José, el requerimiento recibido y le solicito hable con el Psiquiatra de Referencia para comunicar que acudirán a examinar a Mª Pilar con motivo de la modificación de la incapacidad.','2');
