insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-01-08','Ana: Llamo al INSS - Orfandad (927 62 00 56) no obtengo respuesta. Pruebo en otro nº (927 620 057), la solicitud de Orfandad está pendiente de resolve porque al parecer tiene que pasar revisión médica de Incapacidad Laboral. *Me indican que llame a PFHC. **Hablo con Antonio Ballesteros, Jefe de Secc (927 62 00 23): Esperaremos a agotar el plazo de respuesta (10 días hábiles desde hoy = Hasta el 21/01) y volveré a llamar a Orfandad. En función de si han resuelto ya o no volveré a llamar a Antonio Ballesteros.','2');
