insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-01-09','Ana: Recibo llamada de Aida, ha acudido a una "óptica-farmacia", está contenta con el servicio y la atención que le han dado. Ha enviado imagen del nuevo presupuesto por WhatsApp al móvil de la parte económica. *Se lo digo a Juana para que lo descargue.','2');
