insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-01-03','Ana: Recibo llamada de Aída (671 507 221), ha acudido a una óptica para que le gradúen y hagan revisión pues ha perdido visión. Le han detectado también principio de cataratas. **Necesita unas gafas nuevas. Hace unos días que desde la ótica Perfect Visión nos han enviado por mail un presupuesto al ctutelar@, localizo el mismo y se lo paso a Alberto, Jefe de la Secc. Ecca. *Vuelvo a hablar con Aida y le indico que debe enviar al menos otro presupuesto más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS ALBERTO'and edp.apellido1='MARIN'and apellido2='IGLESIAS'),'2020-01-09','-AMALIA : Respuesta a Eva TS : te reenviaré la solicitud firmada de Habilitacion Funcional para que adjuntéis los informes pertinentes y lo enviéis desde allí al CADEX .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-01-09','Ana: llamo a Guadalupe, Directora de los PP.TT. de Madrigalejo (672 614 683), al preguntarle por la relación sentimiental de Anita Priscila, expresa que "ella sólo ve por los ojos de él, hace todo lo que él dice. Ha dejado de participar en actividades que le gusta desde que está con él (gira, carnavales...), y cuando va a visitarla, se quita adornos del pelo (lazos) que le gusta ponerse. No hace nada ni toma decisiones sin el visto bueno de él", es una relación de dominio-sumisión. Guadalupe no aprecia que haya un interés económico por parte de él, de hecho suele comprarle y llevarle cosas a Anita. Desde su pueblo, Guadalperales, hay 15 min. apróx. a los pisos. Él acude a diario por las tardes a buscarla en su moto. Si algún día acude a Madrigalejo por la mañana a hacer gestiones también va a verla. Por otra parte, "Anita se muestra contenta con su relación", no ve que no es una relación saludable. *En navidad finalmente no ha ido ningún día a comer ni a cenar con él, en los pisos creen que será porque ha ido familiares a estar con él (vive solo), pues inicialmente ella dijo que quería ir. Desde los pisos le invitaron a él, para que acudiera a comer/cenar allí con ella, pero no quiso. ////////////////////////////////// En cuanto a la relación de convivencia en los pisos, Guadalupe manifiesta que Anita trata con desprecio a los/as compañeros/as, dice que son "viejos" y cuando acudía al C.O., hablaba de los/as compañeros/as como "tontos". A las auxiliares y demás personal de los pisos los trata como si fueran "sus criadas", dice que para eso ella les paga. ////////////////////////////////////// *Acordamos que la visita se llevará miércoles o jueves (para que pueda asistir también Longina-TS, a partir del día 20, pues es cuando Pedro, Jefe de Secc., regresa vacaciones. Volveré a llamarle para confirmar fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-01-09','Ana: Recibo llamada de Mª José, TS del Hptal. SPA (56348), dice que le ha llevado el Requerimiento del Juzgado al Psiquiatra y éste le ha dicho que va a hablar con UME para ver si la aceptan, en ese caso iniciaría el trámite y si le dicen que no, les pasará el caso a las trabajadoras sociales.','2');
