insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-01-10','Ana: Llamo a Germán, Enfermero del ESM de Trujillo (54508), para preguntarle si llegó a hablar con el Dr. Medina, está con un paciente, me devolverá la llamada a lo largo de la mañana. ////// Recibo llamada del Dr. Miguel Medina, Psiquiatra ESM Trujillo (54507): la próxima cita de Juan con él es el día 6 de febrero a las 10:00 h. Antes, a las 9:40 tiene cita en enfermería para ponerse el inyectable. **Dice que el discurso de Juan es el habitual, pero sí que puede ser que esté algo más excitado de lo normal y con mayor verborrea. El inyectable se lo tiene que poner sí o sí, pues sino tendría que derivarlo al Psiquiátrico. Dice conocer bien a Juan y que él no va a ceder.','2');
