insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-01-10','Ana: Llamo a Adela, PNC (924 00 59 95) pero no obtengo respuesta. Llamo a Marina Carmen Cintas, Jefa de Secc. (924 00 59 22), tampoco obtengo respueata. ////////////////////////////////////////////////// Llamo a Maite Cañadas, CR Conventual S.Fco.-Plas.(21860) en relación al borrador del Convenio Regulador de Separación que nos ha remitido por mail la abogada del marido de Joaquina: Maite cree que a Joaquina no le importa el hecho de separarse y además, dado su deterioro cognitivo, no considera ni siquiera oportuno el explicárselo. *En estos momenos en cuanto a la cuestión económica se muestra más tranquila y está más adaptada al centro. //////////// *Hablo con Ángel, Asesor Jurídico CTAEX, con respecto a la Separación. Se buscará y contratará un abogado para que reprente a Joaquina.','2');
