insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-10','Ana: Correo de Toni-FUTUEX: "Buenas, estos son todos los informes de la hospitalización de José Manuel alta UCi interconsulta psiquiatría y alta de la planta están todos en un mismo doc para q se pueda leer de seguido, te he llamdo antes pero estarias ocupada. Nada que como le han ofrecido la hospitalizacion en unidad voluntaria y no ha querido por lo tanto según el criterio de los médicos no podian hacer nada.. aluciante todo, pero no podemos hacer nada.. dicen que debe tratamitarse con la subdireccion de salud mental direcctametne para que le den un recurso. Hoy a llamado también a Virginia,.. el cura de la parroquia de su barrio..para ver si podia ir algun centro, decia que iba a llamar a Pedro El lunes si te parece lo hablamos. Virginia lo visita de neuvo el lunes 20 que la semana proxima esta de vacaciones" *Guardo los informes en el expte PC. Imprimo también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-01-13','Ana: Recibo llamada de Cristina, Ed. Soc. Asociac. Vera - Plena Inclusión (681 143 911), con respecto al ingreso de Adrián, me enviarán por mail la documentación necesaria al ingreso para que la firme el D.Gerente. Se la devolveremos firmada por mail y correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-01-13','Ana: Recibo llamada de María Barrasa, TS CSS-Mérida (24005): Juan Ángel regresó a UME del hptal. el día 6 de enero. *Le dieron cita de revisión en consultas externas para el día 20 de enero, pero ahora le dicen que **NO APARECE EN CÍVITAS y por tanto no aparece en las citas del hptal. Juan Ángel dice que perdión hace tiempo la tarjeta sanitaria, habrá que pedir duplicado y solucionar el problema de Cívitas. ***El DNI sí lo tiene, pero lo tiene picado. Desde el CSS pedirán cita para hacérselo de nuevo. ////////////////////////////////////////////// *Compruebo con Julio Admvo. CTAEX, en CÍVITAS, y aparece en alta. **Se lo comunico a María Barrasa, debe haber sido un error de Admisión del hptal. Llamará de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-13','Ana: Llamo a Pilar, TS ESM-CC: no obtengo respuesta. //////////////////////// Llamo a Toni-Futuex (600 56 42 15, Virginia, Delegada Tutelar, visitará a José Manuel el lunes 20/01.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-01-13','Ana:Recibo llamada de Gema, TS del SSB de la mancomunidad de la Vera (me facilita su nº personal: 617 24 00 51). Eugenia ha acudido a su despacho con su pareja, Pedro (compañero del CRRP-Plas. durante 8 años). Hace unas semanas se ha marchado a vivir con él. Ha pedido el Alta Voluntaria en el CRR-CC. *Necesita que se le autorice a retirar dinero en alguna oficina bancaria de Plas (Avda. Alfonso VIII). /////////////////////////////////////// Llamo al Cristina, Psicóloga del CRR-CC: Eugenia se marchó el día 22/12/19 a vivir con su pareja. Acordaron con ella que debía volver el día 10 de enero para que la acompañaran a retirar efectivo del banco y ratificara su deseo de dejar su plaza en el CRR. **Desde el centro consideran un error el que se haya marchado, pues en las semanas que ha pasado allí ha habido una mejoría. *Pero el día 10 llegó tan tande al CRR que ya no pudieron acudir al banco a retirar el dinero. **Firmó la ratificación. Me enviarán ambos documentos. ////////////////////// Nº de contacto: Eugenia 691 26 19 43 // Pedro-Pareja 697 85 27 24. ////////// Llamo a Eugenia: El nuevo domicilio es C/Enrique Alonso, nº 8, puerta 4 de Tejeda de Tietar. Le indico que le hará seguimiento alguna Delegada Tutelar de Futuex y que será ella quién vaya a acompañarla al banco para retirar el efectivo. *Les facilitaré sus nº de contacto. //////////////////////////////// *Llamo a Toni, como salta el buzón de voz, le envío un correo para derivar el caso para que inicien seguimiento y me confirmen fecha y quién le acompañará al banco. /////// *Pendiente hablar con Alberto, Jefe del Área Ecca, para que revisen la asignación y le autoricen a retirar el efectivo en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-01-14','Ana: Dado que aún no hemos tendio respuesta de la Policía Local de Valencia de Alcántara, realizo llamada (927 580 121) Me comunican que no me han contestado que el Oficial no está y que hasta el jueve-viernes que vuelve no nos podrán contestar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-01-14','TERESA: Buenos días TEresa. Informarte de que Beatriz esta ahora mismo en Llerena, valorando el ingreso en la Unidad de Hospitalización Breve (Psiquiatría). No he podido hablar aún con la psiquiatra, pero seguramente la ingresen, debido a posibles ideas delirantes que han podido aparecer. La familia me ha llamada para comentarme que necesitan dinero para tabaco y productos de higiene personal para el hospital. Te envio el telefono de su hermana Rosa para que puedas ponerte en contacto con ellos: 696 337732. En cuanto sepa algo mas te comento. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2020-01-14','TERESA: HABLO CON CLARA PARA AVERIGUAL EL INGRESO DE 105 ERUOS DE LA VINCULADA, ME COMENTA QUE YA ESTA DADO DE BAJA Y QUE HAY QUE DEVOLER UN MES,.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-01-09','Ana: Recibo llamada de Juan, sigue con su discurso de los últimos días. Pide que le cambien al ESM de Cáceres, no quierie seguir acudiendo con el Dr. Medina porque "está en el complot". Añade que la medicación le está haciendo mucho daño y que le tiene "castrating, me está afectando a mis partes íntimas también" expresa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-14','Ana: Llamo a Pilar, TS ESM-CC (54612): en diciembre, antes de de sus vacaciones, dejó preparada la solicitud por emergencia social de plaza en CRR (abierto a todo, especificando la medida de alejamiento que tiene hacia Consuelo Nevado, por tanto todo excepto Cáceres). Le dejó todo a Juan Pedro Jiménez Cano, Psiquiatra, pues faltaba la parte de éste. No sabe sí él finalizó el trámite. Le preguntará y me confirmará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-01-14','Ana: Llamada a Juan (625 895 394), tras haberme informado le comunico que si quiere cambiar de ESM tiene que acudir a Trujillo a solicitar el cambio por escrito. De momento, mientras no le concedan el cambio el que le corresponde por su lugar de residencia es el equipo de Trujillo y allí es donde tiene que acudir el día 6 a su próxima cita. Responde muy enfadado y un tanto alterado que no piensa ir a ver a Medina ni a ningún psiquiatra, qué él no lo necesita y añade una vez más "que además Medina ha intentado matarme".','2');
