insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2020-01-16','TERESA: ENVIO ESCRITO A LA GERENCIA DEL SEPAD PARA QUE HAGAN REVISION PRECIO PUBLICO DE LA PLAZA, VA A PAGAR POR LA PLAZA 438.53 EUROS. DECRETO PUBLICADO EN DOE 11 FEB 2020 QUE ESTABLECE LOS PRECIO PUBLICO PARA PLAZA SOCIOSANITARIA ENVIO CORREO A LA TS DE COMSER PARA QUE CALCULE DEUDAS Y PONERNOS AL DIA DE PAGOS Y PODER VER SI HACEMOS FRENTE AL PAGO DE LA SILLA RUEDA QUE NOS DEMANDAN ARCHIVO RESOLUCION DE PNC EFECTO ECO DESDE 1/10/19 ABONO PRIMER PAGO 1306,67 EUROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2020-01-17','Ana: Conversación telefónica de Javier, Director CRR-Plas (677 40 76 40). Finalmente intervinieron a Julián en Badajoz y parece ser que la necrosia no era tal, creen que puede ser funcional. Ahora tendrá que pasar en torno a 5 días en recuperación en UCI y aunque su estado aún reviste mucha gravedad hay esperanza. Los sobrinos han acudido al hospital desde el primer momento. Ahora en Ba se turnarán entre las hermanas y los sobrinos. Teresa, una de las hermanas parece ser muy demandante y exigente, cuando lo habitual es que no demuestre mucho interés y preocupación por él. Javier nos mantendrá al corriente de la evolución. ///////////////////// A media mañana recibo nueva llamada de Javier, Julián ha sufrido un infarto y se ha quedado en coma, le van a desconectar. Nos confirmarán llegado el momento. ////// Recibo nueva llamada, Julián acaba de fallecer.','2');
