insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2020-01-03','FAX: Comunicado del CSS - Miguel sale del centro desde las 10:00 hasta las 20:30 acompañado de su hermano con autorización de su psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2020-01-17','-Amalia : ayer recibí la llamada de Antonia , está ingresada en en H.Perpetuo Socorro por EPOC , muy alterada por otra discusión con las hnas , no tenia ropa interior ni sus cosas de aseo. Contacto con una hna. pero no recibo respuesta. Contacto con Futuex , ese dia iba por la zona , se acercó a su casa a por las cosas y por la tarde se las llevó al Hospital . Contacto hoy con ella para ver cómo sigue , ha pasado mala noche y reclama que la vea un psiquiatra. Contacto con la TS del Perpetuo ( Victoria ) se va a encargar de intentar una interconsulta con psiquiatria. Contacto con Carmen , TS del ESM Valdepasillas sin éxito. Próxima cita con el ESM para abril 2020. Quiero comentarles la posibilidad de derivarla a CRR . Tiene un Grado I , podria ingresar en CRR por promocion de la autonomia ( cuidados personales , atencion y cuidados en alojamiento de soporte a la inclusión comunitaria . ) Con un G.I no puede acceder a Residencia de mayores , tiene 57 años . Voy a solicitar tb revisión de grado. Comunico a MariLuz ( PIA gerencia Bjoz ) que contacten conmigo para negociar el PIA , lo tienen pte. y se hará en breve.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-17','Ana: Recibo llamada de Pilar, TS ESM CC (54612): José Manuel está de nuevo ingresado en el hptal. por ideación autolítica, desde el día 15. Nos remitirá solicitud de CRR (finalmente no registraron la solicitud en diciembre) para que la firme el D.Gerente, pues a pesar de que le digo que desde aquí no hay que firmar el documento pues el recurso requiere de la voluntariedad de la persona, dice que en la solicitud pone: "firma del interesado/TUTOR". *Hablaré con Eva de Salud Mental y con Pedro, Jefe de Secc.','2');
