insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2020-01-17','Buenas tardes, os comunico que Sol ha sido seleccionada para trabajar en una empresa que realiza trabajos de limpieza. Según nos han indicado trabajará en las instalaciones de la Clínica oftalmológica Sánchez Trancón y en una óptica que está al lado que también es de ellos. Mañana irá ya para tener una primera toma de contacto. Comienza a trabajar en esta semana, no sé la fecha de alta en el contrato. Tan pronto como tengamos el contrato os lo envío para que procedáis a su firma y nos lo reenviéis lo antes posible. Ella está muy contenta, es una gran oportunidad de normalización en su vida . Un saludo. Soledad Olmos Olmos - Trabajadora Socia','1');
