insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-01-21','TERESA: RECIBO EMAIL DE PLENA INCLUSION Te informo sobre Josefa Domínguez Blanco, que como sabes está desde el pasado mes de agosto en la UDAC de Plasencia y mañana vamos a por ella para hacer de nuevo su regreso a nuestro centro de forma progresiva, y así favorecer su adaptación de nuevo. Estará con nosotros una semana, el próximo martes 28, se iría (esperemos que no muestre resistencia) otra vez a UDAC , no sabemos por cuanto tiempo, mañana se concretará allí con los profesionales responsables. Por otra parte, la psiquiatra de referencia de Josefa, está al corriente, y está dispuesta a recibirla lo antes posible e iniciar trámites, si es posible, para recurso residencial de salud mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-01-17','Ana: Correo de Emilia, TS del CSS-Plas. (emilia.almodovar@salud-juntaex.es): "Buenos días Ana. Quería comentaros varias cosas sobre Jairo Puertas. Su actitud de reclamar dinero y cosas materiales. Me trae facturas de ropa 300e factura de unas gafas nuevas 150. esta visitando dentistas par ortodoncia. y libros para una universidad a la cual no va. Os comento todo esto,porque él insiste en que os llame para darle el visto bueno a todas sus exigencia. Tal vez le podríais llamar o poneros en contacto con el. Desde Dirección me cometan si seguimos intentando que acceda a un CRR. Gracias Ana un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-01-21','Ana: Correo de Emilia, TS del CSS-Plas. (emilia.almodovar@salud-juntaex.es): "Hola Buenos dias Ana. son presupuestos de las tienda los que esta presentando. Sobre elgastode ropa consideramos que no es necesario, pues hace relativamente muy poco tiempo ha comprado ropa. sobre las gafas; las patillas estan un poco mordidas por y tal vez sean antiguas, pero de cristales estan bien. Su comportamiento esta siendo complicado, debemos valorar como realizar las acciones sin que sean premios. Aun asi lo hablare con el Psiquiatra y el psicologo y te voy comentando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-01-21','Ana: Llamo a P.Orfandad - Toni (927 62 00 56), tras revisar el expte. me confirma que aún sigue pendiente de resolver. Indagará la situación y me devolverá la llamada a la lo largo del día. ////// Recibo llamada de Toni; desde el E.V.I. (Equipo de Valoración de Incapacidad) ni siquiera le han citado para la valoración. /////////////////////////// Llamo a Antonio Ballesteros - Jefe de Secc. PFHC (927 62 00 23) como no obtengo respuesta llamo a otros nº (927 62 08 27 / 927 62 08 28 / 927 62 08 29). No obtengo respuesta en ninguno. Vuelvo a intentarlo en distintos horarios sin éxito. /////////////////////////////////////// REGISTRO DE ENTRADA escrito solicitando amplíen el plazo para optar entre PNC Y PFHC por no haber recibido resolución de P. Orfandad (pendiente de cita con el Equipo de Valoración de Incapacidad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2020-01-21','TERESA: RECIBO LLAMADA DE TONI FUTUEX Y ME COMENTA QUE MARIA SE HA NEGADO A ASISTIR A LA CITA DEL DIGESTIVO PORQUE LA VUELTA LA TENIA QUE HACER EN BUS Y ELLA QUIERE QUE LA TRAJERA SUSANA. LE VAN A VOLVER A PEDIR LA CITA Y PLANIFICAREMOS IDA Y VUELTA PARA QUE ASISTA, TENEMOS SOSPECHA DE QUE REALMENTE NO LE PASA NADA Y PUSO ESTO COMO EXCUSA PARA NO ASISTIR AL JUICIO. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada de Marisol, madre de María (696-266658)+++Como siempre, muy preocupada. Planteando iniciar proceso de desintoxicación...pero no existe voluntariedad. +++Comento que estamos pendientes de la respuesta del Juzgado a nuestra exposición de la situación y petición de valoración forense. +++Ya se ha comprado el agaporni.','2');
