insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-01-21','Ana: Llamo a Mª José, TS del Hptal. SPA-CC (56348) para interesarme por Pilar, pero no obtengo respuesta. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Pedro)Llamada del Dr.Jesús Derecho, Psiquiatra del al UHB del H.San Pedro de Alcántara" (56881). +++DERIVACIÓN a UME: NO CUMPLE CRITERIOS. Ante esta situación: +++DERIVACIÓN A UHDAC: se ha realizado la misma pero en estos momentos NO HAY CAMA LIBRE. +++++Nos llama para que en la medida de lo posible podamos agilizar dicho traslado, dado que las condicones en las que se encuentra en la UHB ya no son para estar allí. También considera que no cumple criterio, realmente, para la UME. +++Comenta que el Forense has estado hace unos días valorando su estado. +++Jesús va a estar la semana que viene fuera, pero podemos contactar con los demás Psiquiatras: Dr.Juanjo Molina (Coordinador), el Dr. Enrique Daniel y el Dr. José Cerezo.','2');
