insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-01-22','Ana: Recibo llamada de María - Programa de familia Mancom. Tajo Salor. Me comunia que Felisa tiene contraida una deuda de en torno a 1000€ con el SAD municipal (Enviaron un correo a la parte económica hace ya un año: 02/01/2019) y tampoco ha pagado a día de hoy las entradas para los toros que adquirió este verano y que se comprometió a ir a abonar con uno de los extras que se le dió. /////////////////////////// Lo comunico a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-22','(Pedro)Llamada de D. José Luis, hermano de D.José Manuel. +++Preocupado por la situación de su hermano, pregunta para cunándo será posible que esté en un centro. Le explico que la derivación la tienen que hacer desde el ESM y que su hermano, una vez en el centro, tiene que aceptar las normas de convivencia en el mismo para que no vuelva a suceder de nuevo lo mismo. En cuanto al plazo, depende también de la existencia de plaza. ///////////////////////////////////// Acudo a hablar con Eva, Psicóloga - Secc. Salud Mental: No han recibido aún la solicitud de plaza en CRR de José Manuel. No obstante dice que éste es un caso que irá a la Comisión, no cree que resulte fácil que le concedan plaza. /////////////////// Llamo a Pilar, TS ESM-CC (54612): A su cita programada con el Dr. Juan Pedro Jiménez Cano, Psiquiatra, el día 20/01 sí ha acudido. No presentaba ideas autolíticas. Tendrá que acudir a seguimiento dentro de un mes. El día 31/01/2020 tiene programada cita con la enfermera para el inyectable.','2');
