insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-01-21','Ana: Recibo llamada de Vanesa, tiene que pagar la minuta de la abogada (Juicio sobre Reintegro de Capacidad) pero aún no tiene acceso a su cuenta bancaria. Como aún no hemos recibido la firmeza que los compañeros han reclamado varias veces al Jdo, me enviará la factura a través de la T.S. para que se autorice y se abone desde aquí.','2');
