insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2020-01-22','Ana: llamo a Guadalupe, Directora de los PP.TT. de Madrigalejo (672 614 683). Como en las últimas semanas Anita no ha vuelto a manifestar su deseo de irse a vivir con su pareja, acordamos no hacer la visita de momento para no remover nada. Me informa del nombre de la pareja; Gregorio (de edad similar a Anita) y del nombre del Juez de Paz; José Joaquín. *Pendiente llamar al Ayto. para hablar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRIGIDA'and edp.apellido1='MURILLO'and apellido2='ALVAREZ'),'2020-01-23','Recibimos Sentencia, NO FIRME, dictada por el Juzgado de lo Penal nº 2, de Badajoz, en relación con el PA 79/2019, por la que condenan a María, por un delito leve de hurto en grado de tentativa (Carrefour), al pago de una multa de 20 días con una cuota diaria de tres euros.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-01-23','TERESA: RECIBO EMAIL DEL SSB Buenos días, os informo que con fecha 03/01/2020 falleció la madre de Adolfo García Cruz (quedó Susana en que ella os informaba), en la actualidad están en el domicilio familiar Adolfo y su hermano Antonio. La comida se la lleva su hermano Lorenzo, que vive en otro domicilio. Lorenzo se irá como años anteriores a últimos de abril. Antonio venía con medicación del hospital psiquiatrico, pero según comenta su hermano Lorenzo, no se la está tomando y está consumiendo alcohol. tiene una revisión proximamente en salud mental del centro de salud y se duda que asista. Os pongo en conocimiento de estas circunstancias por la repercusión que sobre el tutelado tiene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-01-21','TEREASA: RECIBO A LORENZO HERMANO DE ADOLFO EN EL DESPACHO. ME COMENTA LA SITUACION ACTUAL LA CUAL YA ANTERIORMENTE NOS HA COMUNICADO EL SSB. ACORDAMOS EN QUE VA A INTENTAR QUE SU HERMANO ACUDA A LA CITA DE SALUD MENTAL PARA QUE LO PUEDAN VALORAR ASI COMO INTENTAR CONVENCERLO DE QUE ASISTA AL CRPS DE ZAFRA YA QEU EL EN ABRIL SE MARCHA COMO TODOS LOS AÑOS A TRABAJAR Y NO PODRA HACERSE CARGO DE SUS HERMANOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-01-23','TERESA: Tal y como hablamos por teléfono, te detallo a continuación los familiares de Mª Antonia con los que tenemos contacto y sabemos que actualmente guardan cierta relación, para que traslades información al Juzgado. - Natividad Fernández Salguero, hermana de Mª Antonia, reside en Madrid, y sus números de teléfono son : 916 75 58 17/ 607 72 48 50. La relación con su hermana es muy difícil y casi inexistente por las conductas y el carácter tan problemático de María Antonia (Ejemplo: en alguna ocasión ha denunciado falsamente (demostrado) al cuñado por mal trato). Desistió del intento de “cuidar de ella” por todo esto pero a menudo llama aquí al centro y se preocupa por el estado y el futuro de su hermana. - Tía Manuela González(91 años), con la que actualmente reside en el domicilio de esta en Zafra. No tenemos su teléfono. El parentesco les viene de lejos, Manuela era prima del padre de Mª Antonia, no habían tenido una relación muy cercana, apenas se conocían, hasta la fecha de entrar Mª Antonia en el centro ocupacional, dónde una de las hijas de Manuela (Loli) trabajaba como cocinera y otra hija (Águeda) de limpiadora. - Loli Álvarez González, hija de Manuela. Reside en Zafra. Jubilada (trabajaba hasta Mayo de 2019, como cocinera de Plena Inclusión Zafra). Teléfono de contacto: 679 84 33 58 - Águeda Álvarez González, hija de Manuela. Reside en Zafra (trabaja actualmente en Plena Inclusión Zafra como limpiadora). Teléfono de contacto: 699 509 762 - Mari Carmen Álvarez González, hija de Manuela. Reside en Zafra. Teléfono de contacto: 606 044 448. Cuando Mª Antonia entró en nuestro centro ocupacional, Mari Carmen, vivía con su madre (Manuela), y fue ella la que empezó a hacerse cargo de Mª Antonia, recibiendo, en un primer momento, la cantidad mensual de 600€, por gastos de “manutención” de Mª Antonia. Posteriormente y tras intervenir la comisión Tutelar (creo recordar que Amalia) la cantidad se redujo a 500€. En varias ocasiones, Mari Carmen ha manifestado su rechazo a ocuparse de temas , principalmente médicos, de Mª Antonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2020-01-17','TERESA: ENVIO FAX AL JUZGADO FACILITANDO LOS CONTACTOS QUE NOS HA SOLICITADO EL JUZAGADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-01-17','TERESA:HABLO CON LA HERMANA DE BEATRIZ. ESTA INGRESADA EN UHB DEBIDO A QUE HA SUFRIDO UNA CRISIS. LA HERMANA ES LA QUE SE ENCARGA DE LLEVARLE TABACO Y LO QUE NECESITE POR LO TANTO ESTABLECEMOS UNA TRANSFERENCIA A SU HERMANA YA QUE BEATRIZ NO PUEDE SACASR SU ASIGANAICON SEMANAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2020-01-23','(Pedro)Llamada de Reme, T.Soc. del SSB de los Colorines. +++La hermana de Jesús ha perdido el número de teléfono del Juzgado que lleva el procedimiento tras su fallecimiento para dárselo y quew vuelva a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-01-23','Isabel Nájera, Abogada (najerasalas@yahoo.es 927574765-600682804), se pone en contacto con nosotros porque está tramitando una herencia en la que se ven afectados los hermanos de Pablo. Enviamos un correo electrónico a su cuenta, a los efectos nos remita toda la documentación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-01-23','TERESA: Te escribo referente a Juana Nieto Labrador. Ella “tiene una curatela” y……... una gran adicción a las compras… que parecía más o menos controlada pero de nuevo hemos descubierto que está “haciendo de las suyas”. Teníamos ya sospechas desde antes de Navidades y descubrimos que la lotería, de Plena Inclusión Zafra, que se llevó para vender en su pueblo, por importe de 20€, la vendió pero no entregó dinero. Eso se solucionó “descontándole” esa cantidad del dinero que se iba a llevar a casa para Navidades (Nochebuena y Navidad hasta fin de año estuvo en La Parra, y fin de año y Reyes los pasó aquí) Casi inmediatamente después de eso…descubrimos, que una hoja de firmas para el sorteo de una cesta de ibéricos, en beneficio del club deportivo “El Bellotín” (de Plena Inclusión Zafra) al que ella pertenece, por valor de 50€ , también se los quedó. Aún no los ha devuelto. Durante las Navidades sabemos, por los compañeros de residencia (monitores y usuarios) que ha estado comprando cosas y manejando dinero cuya procedencia se desconocía, y una obsesión por salir a andar por las tardes por Zafra, pero con la intención de entrar en tiendas y ver escaparates. A la vuelta de las Navidades, la hemos visto especialmente nerviosa y con deseo de ir de nuevo a su casa a recoger regalos de reyes, decía ella. Fue a casa y a la vuelta de ese fin de semana…peor… hasta este pasado martes, día 21, que ella sola ha confesado, que le estaba robando dinero a su madre (un total de 70€ en tres ocasiones), un cordón que creía que era de oro (no lo es) de su hermano, para venderlo, ha dejado “a deber” una pulsera de actividad en una tienda de aquí de Zafra (después de comprar esta ha comprado otra), y más cosas que seguro que se nos escapan. Por qué te cuento esto??.....pues principalmente para justificarte, que a modo de consecuencia de estos actos, nos vemos obligados a decirle que al Circo del Sol no va a asistir porque esa es la cantidad justo que le ha robado a su madre, pensionista que tiene serias dificultades para pasar el mes, y debe hacerse responsable de devolverle esa cantidad. El resto no sé muy bien aún cómo vamos a hacerlo, pero otras medidas que hemos adoptado, son no salir sola por Zafra, no manejar dinero, una cita de revisión psiquiátrica lo más urgente posible, volver a avisar en tiendas que no le de nada sin pagar y sin supervisión de algún profesional, … y estamos valorando las visitas a su casa o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='ROMERO'and apellido2='RODRIGUEZ'),'2020-01-23','Ana: Recibo por correo postal certiticado original de Ingreso en Centro de María (Residencia de mayores Virgen de la Piedad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-01-23','Reunión Teresa/Pedro. +++valorar propuesta de Plena Inclusión de Llerena para las visitas de Beatriz a su hija.PROPUESTA: +++++de LLERENA a CÁCERES EN TREN (¿SOLA?) y en CÁCERES la recoge su PADRE en BUS. La VUELTA: con Futuex tras ver a su hija el lunes. SUPONDRÍA PASAR EL FIN DE SEMANA EN TRUJILLO. ++++++PRINCIPAL PROBLEMA: IR SOLA HASTA Cáceres. +++ALTERNATIVAS: +++++CAMBIO A UN CENTRO MÁS PRÓXIMO A TRUJILLO. +++++Estancias más prolongadas y con visitas menos espaciadas en el tiuempo durante esas estancias (hay que contar con la aceptación de la abuela). +++++¿?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-01-23','(Teresa, Ana y Pedro)Recibimos visita en la Comisión de Begoña y Mª Jésus, Técnicas de la DGIFamilia:Begoña quiere visitar este domingo a Andrés y quiere saber si cuenta con la aprobación de la Comisión. En pricipio no hay problema, quedando supeditada la visita a que Plena Inclusión de Cabeza del Buey la vea oportuna en función de la situación de Andrés en ese momento. +++++Llamamos a Lola, T. Soc. del centro para comunicarle la visita y la aceptación por parte de la Comisión de la misma salvo que el centro, llegado el moemtoi, considere que no sea aconsdejable. +++++Andrés está más tranquilo y agradeció la visita de la Fundación Triángulo para hablar tanto con él, como para orientar a los profesionales del Centro a la hora de enfocar su trabajo en esta dimensión de Andrés. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ (Teresa y Pedro) Conversación con Raúl Sánchez, Psicólogo del Instituto Psicopedagógico "Dulce Nombre de María", de Málaga (952-290499). +++Tras la conversación mantenida con las Begoña y Mª Jesus, nos enteramos de que ya en Málaga se le hizo un estudio de la UTIG en relación a la identidad sexual de Andrés. Solicitamos por ello a Raúl copia de ese Informe para valorar esta dimensión de la vida de Andrés, al ser una de sus principales demandas. +++Dejo teléfonos de Teres y mío, así como mi correo electrónico. +++Informamos a P. Inclusión de cabeza del Buey sobre estas gestiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2020-01-24','(Pedro)Llamada de José Tello, interesado en la finca olivar de Dª Sofía. +++Quiere retomar el tema y parce que podría ser viable el arrendamiento por aprovechamineto o con opción de compra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='RASTROLLO'and apellido2='BARRAGAN'),'2020-01-23','Ana: Recibimos llamada de Manuela, TS CSS-Mér. Comunica que Agustín se fugó la semana pasada del CSS y volvió ayer, comentando que había estado en su casa y tiene una fuga de agua que puede ocasionar problemas al vecino. /// Se lo comunicaré a Amalia, TS CTAEX.','2');
