insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-01-24','Ana: Llamo a Pilar, TS ESM-CC (54612): Está de vacaciones. //// Llamo a Rosario, enfermera (54609): No asistió a la cita programada de ayer para ponerse el inyectable. Llamó a su madre y ésta le informó de que está un poco alterado y que hacía unas semanas que se había ido a vivir a otro piso. Le preguntó si hacía falta que nos llamara y dijo que no. *La madre acudirá a comprar el inyectable e intentarán convencerlo para que acuda a ponérselo la semana que viene. **Pido que nos mantenga informados y si finalmente no acude que no remitan informe al respecto. **Gestionará la cita con la Psiquiatra, considera que debe ponerse el inyectable con máyor frecuencia ///// Al final de la mañana recibo llamada de la Enfermera, Rosario, dice que Saturnino se ha presentado preguntando cuándo tenía la cita. Ha acordado acudir el lunes a ponerse el inyectable.','2');
