insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-01-28','TERESA: RECIVO EMAIL DE MARI CIELO CRPS días Beatriz ha estado muy mal y que han tenido que contenerla en varias ocasiones, pero que hoy se encontraba un poco mejor. Me ha comentado que la noche previa al ingreso que estuvo sin dormir toda la noche se grabó en vídeo y los colgó en youtube; te mando el enlace https://www.youtube.com/channel/UC99jZDpmLnk4uZM0_g3lwyA Me pregunto si hubiese la posibilidad de poder retirarlos de allí por estar incapacitada, no se como lo veréis vosotros. Ella no sabe que los hemos visto, pero me parecen que pueden vulnerar su imagen. Estudiarlo y ver que os parece. Un saludo y Gracias. +++LO COMUNICAMOS A FISCALIA DE ZAFRA, por teléfono, al 924-551581 (contacto Ana) y por correo-e al correo siguiente: anamaria.medrano@justicia.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2020-01-28','Ana: Paula, T.O. del CRR-Plas., me comunica que a primeros de enero ya fueron a valorar a Guadalupe de Dependencia. Estamos a la espera de la resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-01-24','Llega a la Comisión Tutelar escrito remitido desde la Consejería de Sanidad y Servicios Sociales de la solicitud formulada y dirigida a la Consejería de los padres de D. Rubén por parte de su abogado D. Luis de Miguel Ortega.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-01-28','Hablamos con Inés María Talavero Pacheco (646098001), presidenta de la Comunidad de vecinos del inmueble sito en C/. General Margallo, 21, de Cáceres. Nos indica que en relación con la Propuesta de Ejecución dictada por el Ayuntamiento de Cáceres, en la que como propietaria también está obligada, al igual que Miguel, han realizado una valoración técnica del estado en el que se encuentra el edificio. Están a la espera de recibirlo. Posteriormente, hay que hacer un Proyecto de la obra a realizar. De todo nos irá informando enviándonos documentación, a los efectos de sufragar los importes correspondientes. Nos solicitan que vayamos informándonos de las posibles subvenciones que hayan para sufragar estas reparaciones. Sería conveniente una visita al inmueble de Miguel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-01-28','Ana: Icíar, admvo. secc.ecca., me comunica que ya se ha hecho efectiva la transferencia bancaria a la cuenta de la Abogada, con quién habló ayer por teléfono. //// Se lo comunico a Vanesa mediante conversación telefónica. *Ésta dice también que ayer acudió al Jdo. y que solicitó en persona la firmeza y se la dieron. Se la llevó a la T.S. para que nos la envíe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2020-01-28','Ana: Realizo llamada a los Pisos Tutelados de Villa del Rey (927 39 51 54) en relación al presuesto para ropa de Salvadora (se aprueba), Alicia, Directora, no se encuentra, le dejan nota para que me devuelva la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-01-28','Ana: Recibimos nueva Cédula de Citación para el reconocimiento del Médico Forense, lo adelantan al día 3 de febrero. //////////////////// Llamo de María Barrasa, TS CSS-Mérida (24005): Juan Ángel aún no ha regresado de su fuga. **Le han pedido Informe Social e Informe sobre el numero de fugas del Juan Ángel. ///// Remito por fax al Serv. de Admisión del CSS (924 38 80 83) la nueva cédula de citación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2020-01-28','(Pedro)Conversación con Sole, T. Soc. de "La Luz". +++La madre de Juana en alguna de las visitas que ha realizado al domicilio familiar, parece ser que le ha pedido ayuda para pagar ciertas deudas, al parecer, de la vivienda social en la que vive, por importe de 1000 euros. +++Cuando Sole ha hablado con ella al respecto lo ha desmentido. Se le indicó que el dinero de su hija era para atenderla a ella y que la Comisión solo se debía preocupar de Juana. +++PIDIÓ EL TELÉFONO DE LA COMISIÓN PARA LLAMARNOS, y Sole solo quería quye estuviésemos atentos por si efectuaba dicha llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2020-01-28','(Pedro) Conversación con Sole, T. Soc. de "La Luz". +++Envía presupuesto pra compra de ordenador para Soledad. +++Muestro nuestra preocupación por el uso que se pueda hacer de él pero comenta que han tenido formación con ella y alguna charla de la Guardia Civil al respecto. +++Imprimo y dejo en la mesa de Alberto para su estudio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-01-28','(Pedro)Remito escrito de los padres de Rubén a la Vicepresidencia de la CTAEx, por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MONROY'and apellido2='LLERA'),'2020-01-29','Se admite la demanda de desahucio en el asunto de Don José Luis Monroy LLera. Caso de oposición la vista es el dia 02.03.2020 a las 9,15 hora en el Juzgado de Primera Instancia Nº 2 de Badajoz, y el lanzamiento el día 14.04.2020 a las 9,15 horas. Para el día de la vista (02.03.20) ha de asistir a la vista el demandante, es decir, el Sr. Monroy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-28','Ana: Recibo llamada de José Manuel (667 384 817), preguna si ya se sabe algo de la plaza solicitada en CRR. Ha estado hoy con su psiquiatra, Dr. Juan Pedro Jiménez Cano, éste le ha preguntado si ya sabía algo de la plaza (curioso pues desde Salud Mental han enviado la solicitud e informe hace sólo unos días). Cuenta también que ayer tuvo que llamar a la policía por problemas con su hijo, dice que les tuvo que enseñar una foto del mismo y le pidieron también la dirección. Le recomendaron que pusiera una denuncia y orden de alejamiento, pero él de momento prefier no hacerlo. Virginia, Delegada Tutelar, ha estado con él esta mañana, nos va a enviar imagen de dos documentos del Jdo. que ha recibido. Por otra parte dice que la asignación que tiene es muy baja, que no le llega para comer, pero cuando vuelvo a hablarle del comedor social, dice que no quiere ir pues no le gusta la gente que acude al mismo. Comunica además que necesita un brasero y una máquina de afeitar y cortarse el pelo pues se le han estropeado, le digo que pida presupuestos y nos los haga llegar. Por último también tiene avería en el plato de ducha y calentador. Pediremos que Futuex le apoye en la búsqueda de profesionales y de pedir presupuestos también de estas reparaciones (No tiene seguro de hogar)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-01-29','Ana: Eva, Psicóloga de Secc. Salud Mental, me comunica que ya han recibido solicitud e informe de CRR remitido por Salud Mental. /////////// Toni-Futuex nos remite por email imagen de los docuemntos que ha recibido José Manuel: uno del Jdo.- Citación para mañana marte 30 para reconocimiento por el Médico Forense y otro del Colegio de Abogados de Badajoz. **Se lo paso a Ángel, Asesor Jurídico, llamará para informarse de ambos. ////////////////// Hablo con José Manuel, dice que no necesita que le acompañe nadie mañana al Forense. De todas formas Virgina le dijo ayer que ella no podría acompañarle mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO JESUS'and edp.apellido1='MORALES'and apellido2='ESQUIVEL'),'2020-01-29','TERESA: ENVIO AUTORIZACION JEDES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2020-01-29','TERESA: ENVIO AUTORIZACION JEDES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-01-29','Ana: Recibimos resolución del INSS, aprueban la PFHC solicitada para Desideria. Importe mensual: 395,60 €. Fecha de efecto 1/01/2020. // Se lo comunico a Toni-Futuex, para que puedan comunicárselo a ella y tranquilizar al matrimonio. /// Se lo comunico también a Mariví Clemente, TS CSS (24142). **Ella me comunica que Gloria de Futuex acudirá mañana a hacerles seguimiento al CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2020-01-24','Ana: Recibimos correo de Julián Álvarez, Gerente de COCENFE: "Buenos días. Os comunicamos que Tomás tiene revisión en Hospital Nacional de Parapléjicos de Toledo el día 5 de febrero de 2020. Nos han comunicado que tendrá que estar en revisión los días 5, 6 y 7 de febrero. Ya está gestionado el transporte por el SES. Como el año pasado debe ir acompañado con la cuidadora que ya el año pasado fue con él. Os informo del ingreso. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-01-29','Hablamos con Marisa Cantero, abogada del marido de Joaquina. Envían convenio regulador para liquidar la sociedad de gananciales del matrimonio y proceder a la separación y divorcio. Va a presentar la demanda contenciosa en el Juzgado. Posteriormente, nos darán traslado para que, una vez se le designe abogado a Joaquina, contestemos a la demanda. Según Marisa, nuestra tutelada en su día sacó todo el dinero de una cuenta que tenían en común, su marido y ella, y abrió una cuenta donde solo está ella y su hijo, que también está tutelado por nosotros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2020-01-29','Ana: Realizo llamada a los Pisos Tutelados de Villa del Rey (927 39 51 54) en relación al presuesto para ropa de Salvadora, Alicia, Directora, de nuevo no se encuentra, le dejan nota para que me devuelva la llamada. /// Como no está Alberto, Jefe del Área Ecca., la cuantía no es alta, tiene dinero y la ropa es necesaria, pido a las compañeras que hagan la transferencia. **Icíar se encarga de las gestiones. ///// Comunico a Toni-Futuex por mail que el presupuesto está aprobada y se hará la transferencia para que Salvadora pueda ir a recoger la ropa a partir de mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-01-29','Ana: Paso a Icíar, secc. ecca., nota de la Delegada Tutelar, que me facilitó ayer en persona Toni-Futuex, en relación a las deudas pendientes de Vanesa tanto del alquiler como de recibos de electricidada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2020-01-29','-Amalia , derivo a seccion juridica la peticion de aumentar su incapacidad : Buenos días , se envía este informe de J.Carlos para que solicitemos pasar a tutela con el fin de poder ingresarlo en Ctro. de discapacidad. Hay también un I. social del Serv. Social de Atención Social Básica en esta línea. Considero necesario aumentar su incapacidad , se hace inviable poder abordar su problemática social desde su domicilio . La casa no reúne condiciones de habitabilidad y él no tiene capacidades mínimas de autogobierno o autonomía para poder vivir sólo . Vivía con la madre , que sufrió un ictus y tuvo que ser ingresada por emergencia social en una residencia de mayores. Si pudiéramos , intentaría ingresarlos a los dos juntos en el mismo centro . La madre está en proceso de incapacitación .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-01-29','Ana: Recibo llamada de Carmen, EVD Plas. (24108). Quiere saber por qué se ha solictado Informe Social PIA, si Conchi, ya tiene su plaza en piso supervisado, asociado al CRR-Plas. /// Reviso la intrantet, desde aquí no lo hemos solicitado. Hablaré con el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2019-12-23','Recibimos Sentencia, NO FIRME, dictada por el Juzgado de lo Penal nº 2, de Badajoz, en relación con el PA 79/2019, por la que condenan a María, por un delito leve de hurto en grado de tentativa (Carrefour), al pago de una multa de 20 días con una cuota diaria de tres euros','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-01-30','Correo-e del Hogar San vicente de Paul (2º).. +++Buenos días, les informamos que la Policía se puso en contacto con nosotros sobre las 2,30 horas para decirnos que habían encontrado a Marga y la llevaban a la unidad de psiquiatría del hospital Virgen del Puerto. Un saludo Pilar Sánchez ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++ Correo-e del Hogar San vicente de Paul. +++Buenas noches, les informamos que a las 21,00 horas, Margarita Antich, sin ningún motivo aparente, se ha escapado del Hogar. Hemos salido a buscarla y no la hemos encontrado, así que hemos puesto la denuncia en la Policía Nacional. A esta hora, aún no ha aparecido. Si durante la noche tenemos alguna noticia nos pondremos mañana en contacto con ustedes. Un saludo Pilar Sánchez ///////////////////////////////////////////////////////////////////////////////////////////// Ana: Llamo a Fernando, TS, al Hptal. Virgen del Puerto de Plas., no obtengo respuesta. // Llamo a Centralita (78402) y pido que me pasen con la UHB. Control de Enfermería(78582), me piden que vuela a llamar en una hora. //////////////////////// Llamo más tarde, hablo con la Dra. Lorenzo. Expresa que Margarita "es terca como una mula, está enfadada, no es una descompensación como tal". Al parecer hizo un hurto que confesó y la "regañaron", ella esperaba que la reforzaran pues consideraba que hizo bien por reconocerlo. La encontraron a las 2:00 a.m. en la estación de autobuses. "No se siente mal ni culpable por lo que ha hecho". Presenta una actitud infantil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-01-30','Ana: Llamada de Mariví Clemente (24142): Ana, la psiquiatra de Ángel, marido de Desideria, quiere hablar con Gloria-Futuex para que intervengan con él, pues de nuevo presenta activo el discurso del dinero de la venta de la casa, que la mitad ha desaparecido... Mariví le ha explicado de nuevo que la tutelada es Desideria, y tanto la CTAEX como FUTUEX, sólo tienen que intervenir con ella. Y la cuestión monetaria ya se la ha explicado a ambos varias veces. ////// Llamo a Toni-Futuex para informale y que pueda avisar a Gloria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-01-23','-Amalia : Llamo a Laly , tia de Minerva y al resto de tfs de familiares que tenemos ,incluida la madre. Falta a CO desde el 8 de enero , no se ha incorporado desde Navidad. La tía va a llamar a la madre. Empiezo a mover el tema de ingreso involuntario en residencia . Lo trateremos en reunion el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2020-01-23','-Amalia : hablo con su tia Lali , me facilita el TF de su sobrino Jorge , llega a las 14.30 a casa y es el tf al que se puede llamar . Desde el C.O. se quejan de falta total de higiene y aseo y faltas de asistencia injustificadas.','2');
