insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-01-31','Ana: Acude Soraya Masa a hablar conmigo: La plaza de que iban a asignar a Pilar en la UHDAC tiene que volver a ser ocupada por la persona que se había ido de alta, debido a una incidencia. De modo que hasta marzo no habrá plazas libres en la UHDAC. *En la UHB quieren darle el alta, la han mantenido a la espera de la supuesta plaza en la UHDAC. Soraya se lo comunicará el lunes. //////////////////////////////////////// Llamo a la Casa de la Misericordia de Alcuescar (927 12 00 24). Julia me comunica que sólo atienden a hombres. ////////////////////// Llamo al Centro de Acogida Temporal "Centro Vida" - CC (927 23 50 82), Mamen, TS, me comunica que no tienen ninguna plaza libre en estos momentos. //////////////////////////////// Llamo al Hptal Santiago de Zafra (924 55 47 80) hablo con Tena, Responsable. Dice que en estos momentos disponen de alguna plaza, tienen en estos momentos "puerta de entrada única" por un acuerdo en la Junta de Extremadura. Me pide que hable con Toni Galán. ///// *Hablo con Toni Galán, me informa de que se le acreditaron 10 plazas por el MADEX pero que están todas cubiertas. En la institución podrían acogerla como venían haciendo siempre. // ****El lunes intentaremos solicitar plaza por emergencia social en algún centro. PEDIR INFORME DE PSIQUIATRÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2020-01-31','Ana: Ana Isabel Gil Domínguez, T.S. Ayto de Miajadas (agil@miajadas.org //927 901 215) nos remite por mail la Firmeza de la Sentencia de fecha de 5/07/19 "...constitución de curatela y nombramiento de curador..." *Se lo comunico a Juan Pedro e Icíar - CTAEX y lo guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-01-30','Ana: Fco. Javier Pecero, Director del CRR-Mér, comunica mediante mail (direccion.crrmerida@grupo5.net) que Emilia será trasladada hoy al CRR-Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-03','Ana: Llamo al HSPA-CC, Mª José ya no está. Hablo con Mamen, TS de UHB (56823), le explico la situación, pedirá informe al Psiquiatra. // Llamo al Hptal Santiago de Zafra (924 55 47 80) hablo con Tena, Responsable. **El único inconveniente sería que presentara AGRESIVIDAD, pues en ese caso TENDRÍA QUE ABANDONAR EL RECURSO. En cuanto a la cuestión económica, le recuerdo el único ingreso con el que cuenta y dice que eso no es problema, que ingresemos lo que se pueda y que ya lo hablaremos en otro momento, pues no es lo prioritario. *Acordamos que haré la solicitud de plaza temporal (2 meses) por escrito mediante correo-e (hospisantiago@yahoo.es) adjuntando copia DNI, Certificado y Dictamen CADEX, firmeza de sentencia tutela provisional e ingreso involuntario e Informe médico con pauta de medicación. *Envío todo tal y como acordamos excepto el informe médico que enviaré en cuanto nos lo remitan del hptal. **Le confirmaremos también el día de ingreso cuando nos confirmen la fecha de alta en el hptal. /////////// Soraya nos comunica a última hora que mañana mismo darán el alta a Pilar. La trasladarán al Hptal Santiago de Zafra en ambulancia, llevará informe, pauta de medicación y medicación para los primeros días. **Lo comunico mediante mail al Hptal. Santiago de Zafra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-02-03','TERESA: EMIAL DEL CENTRO Por contarte un poco la breve estancia de Josefa con nosotros y su regreso a UDHAC…durante la semana que ha estado aquí…pues buenooo…ha estado “contenida”… no ha habido incidentes con ella pero tampoco grandes cambios. Al principio parecía mejor pero con el avance de la semana íbamos viendo que seguía en su línea de no querer estar en talleres, no quería mucho o nada de contacto con sus compañeros, con sus peticiones de comprar, peluquería, bragas pañal… No quería volver…pero una vez allí, en Plasencia, con la trabajadora social, afirmó que el motivo de querer venir a nuestro centro, no era porque sienta que es su sitio y nos echase de menos, si no porque es mejor que estar en UDHAC, en UDHAC no quiere estar porque siente miedo de otros compañeros pero es justo lo que reproduce ella aquí con compañeros y profesionales. Una vez allí, hablando con Estrella, trabajadora social, volvió a surgir nuestra valoración de cambiar a Josefa de recurso : de discapacidad a salud mental; para que el recurso se adapte más a las necesidades de Josefa. Estrella a esto… nos afirmaba que Josefa estaba incapacitada…como posible inconveniente, a lo que le dijimos que esto lo valorábamos hace tiempo con vosotros y nos apoyabais en ese aspecto. Tomó nota y probablemente, deduzco, que se pondrán en contacto contigo. Ese día, el martes 28, cuando volvió, la psicologa no estaba y no concretamos nada más para su vuelta. Durante esta semana que viene, Eduardo (psicólogo de nuestro centro) y ella se pondrán en contacto y volverán a retomar esa reincorporación a nuestro centro…así que te seguiré informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-02-03','Ana: Recibo llamada de Rafa, Técnico de Control Económico (927 62 00 51), me comunica que hubo un problema/bloqueo por el que no pudo subsanar el problema de los recibos devueltos. Hay recibos pendientes de abono desde el 1 de agosto hasta el 31 de diciembre. **A partir del día 12 regularizarán todo y Antonio podrá cobrar los atrasos. *Corroboramos que el nº de cuenta que tiene anotado es el nuevo que se le abrió. /// Llamo a Paz- TS de la Cruz Blanca (927 24 68 52) y le transmito lo que me ha dicho Rafa.','2');
