insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-02-03','Ana: Conversación telefónica con Paula, TO del CRR-Plas.: Al preguntarle por la primera impresión sobre Emilia desde que ingresó la semana pasada en el CRR, dice que llega con un alto nivel de exigencias. Ya la conocen pues estuvo anteriormente en su centro. Al menos no ha habido ninguna incidencia con los residentes en estos primeros días.','2');
