insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESSA'and edp.apellido1='CARRERAS'and apellido2='PEREZ'),'2020-02-04','Ana: Puesto que Chema Tovar se negó a llevar a las tres tuteladas correspondientes al C.O.-Down, se le envió una carta firmada por el D.Gerente que tampoco surtión efecto. A posteriori el jueves 30, Virgina y Gloria, Delegadas Tutelares, fueron a realizar una visita a Nace para hablar con las propias tuteladas y con los responsables de la entidad y les dijeron que el lunes día 3 debía acudir al C.O. ////////////////////////// **Llamo a Elsa, Psicóloga de Down (927 227 435 // 652 48 55 12) y me confirma que CONTINÚA SIN LLEVARLAS AL CENTRO.','2');
