insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-04','Ana: Recibo llamada de Mamen, T.S. HSPA (56283), y me envía el informe de Psiquiatría por fax. **La vuelvo a llamar, porque en el informe que me remite pone fecha de alta del día 15/01/2020, cuando el alta se lo darán hoy. *Le pido que nos remita el informe que le faciliten cuando se marche hoy (alta real). Lo escaneo igualmente y lo guardo en su expte. /////////////////////////////// Envío a Toni-FUTUEX, email comunicando el traslado de Pilar y pidiendo que continúen haciéndole allí el seguimiento. /////////////////////////////////////// Llamo al Hptal Santiago de Zafra (924 55 47 80), hablo con Susana, T.S. Le explico la situación, pues estos días atrás ella no estaba y Tena no ha podido ponerla al corriente y le informo de los dos emails remitidos ayer. Le comunico que hoy a media mañana Pilar será trasladada. Seguiremos en contacto. /////////////////// En su cuenta a día de hoy tiene 269,76€, puesto que sólo percibe una LISMI= 149,86€ X 14. **Ahora que dejará de ser unidad de convivencia con su madre le solictaré PNC. /////////////////////////////// Pido a Alberto, Jefe Secc. Ecca. que anule las tarjetas bancarias que tenga y limite la cuenta para que no puedar retirar el dinero.','2');
