insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-02-04','TERESSA;: EMAIL DEL CENTRO Buenas tardes Teresa. Te comunico que el viernes se fue Libertad a su casa para pasar unos días con su familia. Os comunico que se han pautado salidas cada 3 fines de semana a su casa debido a la inestabilidad emocional y su conducta continuamente desafiante y disruptiva. Últimamente muestra un comportamiento agresivo y desmotivador que perturba la armonía del grupo de compañeros tanto de la Residencia como del Centro Ocupacional. Dado el efecto positivo que tiene en ella las visitas a su casa, se han pautado dichas salidas. Se trata de una chica que a pesar de poseer capacidad suficiente para desempeñar un trabajo correctamente muestra desmotivación absoluta hacia la formación y el empleo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2020-02-04','Ana: Llamada de Mariví Clemente, T.S. CSS-Plas, hace días me dijo que querían solicitar revisión del grado de Dependendencia. Aún siguen pendiete del informe médico necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2020-02-04','Ana: Recibo correo de Estrella, TS del CSS-Plas. :"Buenos días, Ana. Te comunico que Remedios Chaves Masero va a ser intervenida quirurgicamente esta misma mañana, al ingerir ayer cuerpo extraño. Saludos" *La Directora del CSS, Soraya, ha firmado como guardadora de hecho al ser una urgencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-04','Ana: Recibo llamada de José Luis, hermano de José Manuel (687 581 061), vuelve a preguntar si se sabe algo de la plaza en CRR solictada para su hermano. Le vuelvo a explicar que eso no depende de nosotros. Lo único que sé es que aún no se ha reunido el equipo valorador. Me pide que llame a su hermano. ////////////////////////// Llamo a José Manuel (667 384 817), dice que necesita dinero, quiere 40€, le digo que ayer lunes retiró los 60€ semanales habituales, pero dice que pagó en la multitienda y no le queda nada... se lo pasaré a Alberto, secc. ecca.','2');
