insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-05','Ana: Llamo al Hptal Santiago de Zafra (924 55 47 80), pregunto por Susana, T.S. y me dicen que llame al 607 33 19 63. Me comunica que las primeras horas de Pilar en el centro han ido muy bien. Estuvo con las auxiliares, que le ayudaron a asearse, mostró reticencia en desnudarse de cintura para abajo, así que no la obligaron. Después con el enfermero mejor, éste le cortó las uñas de los pies. Participó en actividades del centro. Está tranquila. //////////////////////Conversación con Toni-Futuex: El día 11 acudirán Gloria y Susana, Delegadas Tutelares, a visitar a Pilar. /////////////// Mamen, TS HSPA me remite por fax Informe de Alta de Psiquiatría. Lo escaneo y lo archivo.','2');
