insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-02-05','Ana: Llamo a Pilar Sánchez, Directora Hogar S. Vicente de Paúl (671 01 66 15), creen que darán el alta hoy a Margarita. En ppio, la Dra. Lorenzo les dijo que no fueran a verla hasta ayer. ////////////////////// Pilar considera que Marga necesita una terapia psicologógica continuada, no servicio de psiquiatría. Presenta una actitud inmadura (debido a su trastorno de desarrollo madurativo), el problema es que en el centro no tiene este recurso y Marga no tiene recursos económicos como para costearselo. *De momento pedirán cita con el Serv. de Psicología de Salud Mental. *Y dice hablará con Carmen Núñez, Directora Gral. para ver si puede pedir alguna subvención para que se cubra este servicio de alguna manera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2020-02-04','Ana: Recibo llamada de Jesús, pareja de Felisi (616 158 973). Pregunta en qué compañía tiene Felisi el Seguro de Hogar, pues tienen que dar parte de las averías de la vivienda. **Vuelve a insistir en que quieren retirar el efectivo en la sucursal bancaria de El Casar en lugar de en La Nava, como en ocasiones anteriores le digo que no es posible, que ya se les explicó los motivos, pide que volvamos a valorarlo, pues como él está trabajando no puede llevarla y a su padre no le viene bien ir todas las semanas. *En cuanto a la vivienda de protección quiere saber cuánto le queda a Felisi por pagar, le comunico que aún no hemos recibido respuesta al escrito que enviamos. Intentaré contactar con vivienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REMEDIOS'and edp.apellido1='CHAVES'and apellido2='MASERO'),'2020-02-05','Ana: Recibo correo de Estrella, TS del CSS-Plas. (estrella.duranc@salud-juntaex.es): "Buenos días, Ana. Te comunico que Remedios ya le dieron el alta del Hospital Virgen del Puerto y está de nuevo en la UDAC Saludos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2020-02-06','Ana: Llamada de Ángela, Directora PLACEAT (927 421 950), nos va a remitir por mail autorización para las ACTIVIDADES EN LA NATURALEZA de los JEDEX. Al preguntarle por Mª Rosa, dice que está bien, continúa bien adaptada y participando en todo. Lo único que hace unos días ha comenzado con algunas alteraciones de conducta, cómo las que tenía anteriormente cuando acudía sólo al C.O. *Lo abordan desde el centro. //////////////// Pongo la autorización para la firma del D.Gerente y hablo con los asesores jurídicos-CTAEX, harán la comunicación al Fiscal sobre la autorización de derechos de imagen y difusión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-06','Ana: Paso a Alberto, Jefe Secc. Ecca. los presupuestos de electrodomésticos para José Manuel remitidos por Toni-FUTUEX. El reintegro extra que pidió de 40 € no se le va a aprobar. Los auriculares que aparecen en el presupuesto tampoco. *La afeitadora y el brasero sí. //////// Me remiten también justificante bancario del abono para la emisión de la tarjeta de transporte subvencionado.','2');
