insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-06','De: MARIA MERCEDES CRUZ DUQUE Enviado: martes, 21 de enero de 2020 14:29 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: A/A Amalia Buenas tardes Amalia: Acabo de tener entrevista con Manuel Domínguez Martín y le he comunicado la decisión del equipo de trabajo de vivienda y ambulatorio, de la pasada semana. Al comienzo de la estancia de Manuel en la vivienda teníamos dudas de que fuera el recurso adecuado para él, hasta ahora hemos atendido a Manuel en todo lo que hemos podido, pero tanto a él como a tí, os comentamos que seríamos honestos y si no podíamos atenderle del modo que necesitaba o no veíamos mejoras y avances, pondríamos fecha para abandonar la vivienda, dándoos un tiempo prudencial para buscar otro recurso o solución. Se ha decidido poner fecha de fin de estancia, siendo la fecha límite para abandonar la vivienda el 21 de febrero del 2020. Los motivos que han provocado ésta decisión son: Incumplimiento de normas No ser honesto y quitar importancia a diversas actitudes y comportamientos. Consumo de cannabis (en una ocasión) y retomar hábito de juego con máquinas tragaperras. Lo hemos sabido a través de su padre, él no reconocía éste hábito o problema No seguir las indicaciones del equipo de trabajo (comprar tabaco de contrabando, no realizar sus tareas y/o responsabilidades en la vivienda, etc.) Descontrol económico: Ocultaba cuánto dinero cobraba y se abrió una cuenta en otra entidad bancaria. No cumplir con los tiempos para inyectarse la medicación mensual. Abandonar el gimnasio y mantener como ocio el tiempo en los distintos bares, pese al trabajo realizado con él para cambiar de hábitos a otros más saludables. La vivienda en la que está residiendo Manuel va a comenzar a acompañarla o realizar el seguimiento otra persona, te facilito sus datos por si tienes que contactar con ella: Rosa Garay Cano: 637353364, e-mail: rgaray.cdmeba@caritas.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-06','De: MARIA MERCEDES CRUZ DUQUE Enviado: martes, 21 de enero de 2020 14:29 Para: Comisión Tutelar de Adultos >ctutelar@salud-juntaex.es> Asunto: A/A Amalia Buenas tardes Amalia: Acabo de tener entrevista con Manuel Domínguez Martín y le he comunicado la decisión del equipo de trabajo de vivienda y ambulatorio, de la pasada semana. Al comienzo de la estancia de Manuel en la vivienda teníamos dudas de que fuera el recurso adecuado para él, hasta ahora hemos atendido a Manuel en todo lo que hemos podido, pero tanto a él como a tí, os comentamos que seríamos honestos y si no podíamos atenderle del modo que necesitaba o no veíamos mejoras y avances, pondríamos fecha para abandonar la vivienda, dándoos un tiempo prudencial para buscar otro recurso o solución. Se ha decidido poner fecha de fin de estancia, siendo la fecha límite para abandonar la vivienda el 21 de febrero del 2020. Los motivos que han provocado ésta decisión son: Incumplimiento de normas No ser honesto y quitar importancia a diversas actitudes y comportamientos. Consumo de cannabis (en una ocasión) y retomar hábito de juego con máquinas tragaperras. Lo hemos sabido a través de su padre, él no reconocía éste hábito o problema No seguir las indicaciones del equipo de trabajo (comprar tabaco de contrabando, no realizar sus tareas y/o responsabilidades en la vivienda, etc.) Descontrol económico: Ocultaba cuánto dinero cobraba y se abrió una cuenta en otra entidad bancaria. No cumplir con los tiempos para inyectarse la medicación mensual. Abandonar el gimnasio y mantener como ocio el tiempo en los distintos bares, pese al trabajo realizado con él para cambiar de hábitos a otros más saludables. La vivienda en la que está residiendo Manuel va a comenzar a acompañarla o realizar el seguimiento otra persona, te facilito sus datos por si tienes que contactar con ella: Rosa Garay Cano: 637353364, e-mail: rgaray.cdmeba@caritas.es','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-02-06','Ana: Recibimos por nota interior RESOLUCIÓN ADJUDICACIÓN DE PLAZA EN CRR-PLAS. POR TRASLADO (fecha 29/01/2020)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2020-02-06','Ana: Recibimos por nota interior RESOLUCIÓN de BAJA en el Serv. de Att. Residencia - CRR Cáceres por RENUNCIA VOLUNTARIA de fecha de 13/01/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AMALIA'and edp.apellido1='PEREZ'and apellido2='MARAGATO'),'2020-02-07','Ana: Correo de Estrella, TS de El Torno (ssbestrella@mancomunidadvalledeljerte.es), envía autorización para domiciliación bancaria de la mensualidad de la Residencia de Amalia. *Se lo paso a Alberto, Jefe de la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2020-02-06','Ana: Toni me remite por mail Informe de seguimiento del día 30, en dicho informe incluyen una tabla de gastos aprox. fijos mensuales del matrimonio y propuesta de aportación económica con la que consideran debe bolaborar Desideria. Se valorará con Pedro, Jefe de Secc. CTAEX, y Alberto, Jefe Secc. Ecca.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2019-12-27','CORREO DE LA LUZ : Buenos días, Pedro. Conseguí consultar el caso de Sol López por teléfono con Pensiones de Orfandad y es compatible la percepción de la pensión de orfandad con rentas de trabajo, sólo tendría una modificación la cuantía que percibe en concepto de Complemento por mínimos que en su caso asciende a 351,01€ , si en cómputo anual superaran sus rentas 7.569€ excepto la pensión a complementar (P. Orfandad). El resto de la cuantía (463-351,01€=111,99€), la seguiría percibiendo. Si superara ese límite de ingresos pero consiguiera el trabajo, sería un éxito para ella. Aportaría normalización en su vida, autoestima y una inclusión mayor en esta sociedad en la que vivimos. Cuando dejara de trabajar volvería a recuperar el complemento a mínimos. Aún así, para estar bien seguros, solicité cita en el CAISS y consulté el caso concreto solicitando por escrito la base legal que confirma esta información. La parte menos buena es que es un proceso selectivo, hay numerososos currículums y aunque desde Plena Inclusión se apuesta por ella , quien realmente tiene que apostar es la empresa que contrata. Os iré contando. Un saludo. Soledad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2020-02-07','Ana: Adelanto escaneado el CI debidamente firmado y sellado a Paula, T.O. CRR-Plas, por mail. Y paso el original a Juan Pedro, CTAEX, para que se lo remita por correo certificado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-02-07','Buenas Tardes, Amalia. Opino que habría que ir tramitándola ya, para que no den de baja el expediente y posteriormente adjuntamos la citación. Me personé en el CADEX y hablé con ellos. Tienen previsto citarlo en Febrero pero sabes que se tarda un tiempo desde que lo valoren hasta que recibamos el nuevo certificado de minusvalía aunque se podría solicitar un certificado provisional. Puedo ir cumplimentando la solicitud pero algunos de los apartados los tenéis que cumplimentar vosotros porque desconozco los datos. Es una solicitud específica para personas jurídicas. Te enviaré por correo ordinario la solicitud y la documentación. Por favor, cuando la entregues, dímelo para ir haciendo el seguimiento ¿O.K?. ¿Podrías enviarme una copia?. Nosotros ya tenemos una cuenta bancaria abierta a nombre de Brahim.En Diciembre de 2.019 os envíamos informe social , información sobre los datos bancarios, certificación de saldo y otros documentos que nos solicitásteis. Por cierto, aprovecho para decirte (olvidé informar de ello) que Brahim no tiene seguro de defunción para que se lo hagáis al igual que lo habéis hecho con el resto de los tutelados y curatelados del Centro. Supongo que en la nueva solicitud pondréis esos datos bancarios y José Vicente Granado se pondrá también en la cuenta. Si lo hacéis en otra cuenta, por favor,dímelo para que estemos al tanto. Muchas gracias por tu colaboración. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-06','Ana: Correo de Toni-Futuex: "Confirmarte que Juan Chamorro, está en una situación de descompensación, dice que si te toma la Olanzapina (5mg) y el rivotril (2mg) (que es la medicacion diaria) pero que el inyectable para nada... esta con su situación de delirio activo, no ha sido posible ni siquiera que Teresa le acompañara al centro de salud, lo más a tomar un café." ////////////////////////// *Hoy es cuando tenía cita con el Dr. Medina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-07','Ana: Llamo al C.Salud de Guadalupe (53107), varias veces pero no obtengo respuesta. //////////////////////// Llamo a Germán, Enfermero del ESM de Trujillo (54508), Comunica. //////////// Llamo al Dr. Miguel Medina, Psiquiatra ESM Trujillo (54507): no acudió ayer a la consulta, ni se puso el inyectable. Le van a dar plazo de una semana, si no acude a ponerse el inyectable le ingresarán, momento en que aprovecharán también para aumentarle la medicación oral.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2020-02-07','Ana: Recibo correo de Estrella, TS del CSS-Plas. (emilia.almodovar@salud-juntaex.es): Envía presupuesto de empresa de Att. a la Dependencia "Júbilo", para el acompañamiento hospitalario.//// **Se lo paso a Alberto, jefe de la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-07','María Dolores Fernández se encuentra en observación del Hospital de Mérida porque anoche afirmó haber tomado paracetamol y tramadol. Vino el 112 y la trasladaron. Acabamos de hablar con el Hospital para saber cómo se encuentra y nos dicen que está tranquila pero a la espera de ser valorada por Psiquiatra. Al parecer estando aquí los facultativos vomitó y no se observaron más que dos pastillas y bastante comida (pese a asegurar que no había comido nada)....... Creemos que puede deberse a una deuda telefónica con la compañía Orange que, al parecer, trajo ayer por la tarde de su casa (250 euros aproximadamente) con advertencia de recurrir a la vía judicial si no abona el importe. Pensaremos en equipo la forma de intervenir ante estas conductas al ser la segunda vez que ocurre en poco tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-07','Ana: Recibo llamada de Susana, TS del hptal. Santiago de Zafra, Pilar ya está empadronada en su centro. Aún tienen pendiente renovar el DNI y enviarnos el Cdo. de Ingreso en centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-07','María Dolores Fernández se encuentra en observación del Hospital de Mérida porque anoche afirmó haber tomado paracetamol y tramadol. Vino el 112 y la trasladaron. Acabamos de hablar con el Hospital para saber cómo se encuentra y nos dicen que está tranquila pero a la espera de ser valorada por Psiquiatra. Al parecer estando aquí los facultativos vomitó y no se observaron más que dos pastillas y bastante comida (pese a asegurar que no había comido nada)....... Creemos que puede deberse a una deuda telefónica con la compañía Orange que, al parecer, trajo ayer por la tarde de su casa (250 euros aproximadamente) con advertencia de recurrir a la vía judicial si no abona el importe. Pensaremos en equipo la forma de intervenir ante estas conductas al ser la segunda vez que ocurre en poco tiempo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-07','-Amalia: Buenos días, sólo por manteneros informados, Manuel ha sido derivado hoy al Centro Padre Cristobal , en Mérida , donde voluntariamente ha querido acceder a la Comunidad Terapéutica. El tiempo de estancia va a depender de la evolución en su tratamiento de deshabituación . A ver si para entonces tiene la opción de acceder a plaza en Piso Supervisado. Estoy en contacto directo y coordinando todo el traslado con el personal del piso de Cáritas. Su padre ha sido informado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-07','Ana: Llamo a José Manuel (667 384 817): Salta el buzón de voz. Dejo un mensaje comunicando que se le ha aprobado el presupuesto para el brasero y la afeitadcora, lo demás no. **Consigo hablar con él más tarde y le explico todo. *Quiere saber cuándo podrá pasar por la tienda a recoger ambas cosas, se le avisará, pues Coral-CTAEX no ha conseguido hablar con ellos. /// Por otra parte me comunica que le están devolviendo las transferencias de las pensiones de alimento que pasa a sus hijos/mujer. *Se lo comunico a Alberto, jefe de secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2020-02-07','-TF. ESPERANZA GRAO 629202607.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2020-02-04','Ana: Recibo llamada de Ángel, direcort del CAMP, comunca que Joaquina ha vuelto al centro con oxígeno y sondas para comer (le dieron el alta el 22/01/2020). En cuanto a su hermana Ángela, continúa ingresada, le han hecho un escaner y han detectado una masa. Posiblemente le darán en alta hoy o mañana. /////// *Por otra parte me comunica que se ha enviado otras facturas del acompañamiento hospitalario al ctutelar@ el día 27/01/2020, la localizaré y se la pasaré a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-02-04','Ana: Recibo llamada de la Dra. Isabel Álvarez, Psiquiatra de UME (24068), pregunta por qué hemos tutelado a este hombre, cómo hemos puesto un diagnóstico de esquizofrenia y qué por qué le hemos ingresado en UME. Le digo que nosotros ni podemos hacer diagnósticos psiquiátricos ni podemos derivar a ninguna unidad de salud mental. A la UME le derivaron desde la UHB y se convocó una Comisión de valoración en el CSS, Pedro y yo acudimos a la misma como cuando acuden los familiares y porque nos lo solicitaron (con voz pero sin voto). La sentencia de incapacitación la dictó el Jdo., desde la CTAEX se aceptó el cargo, como es nuestro deber. **No considera que deba estar incapacitado, "mantiene consumo activo de todo y no presenta ninguna intención de dejar las drogas". *Afirma que su madre "es una maleducada y hace mucha presión en todos sitios". Las fugas de Juan Ángel son contínuas y desde la unidad no se puede trabajar así con él. Indica que la próxima vez que se fugue llamará a Ana Delfa para convocar una comisión de valoración, pues no piensa darle más oportunidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-02-07','(Teresa/Pedro)Reunión en la UHB de Mérida con Virginia Gajardo, Psiquiatra de Rubén. +++Nos excplica el cambio de tratamineto con reducción progresiva de la medicación actual e instauración de la clozepina. +++Virginia considera que Rubén no debe volver a su domicilio y que debe estar mucho tiempo en centro: pasar de UME a URA y, siempre según evolución, plantear la posibilidad de acceso a piso supervisado. +++SE envía consentimiento informado por fax.924382466 +++Entrevista con Rubén: +++++Traslado de Barcelona a Sevilla con 6 años. +++++Plantea deseo de trasladarse a Sevilla porque allí pasó su infancia. +++++Inicio de consaumo de alcohol y porros a los 14 años. +++++Inicio de la enfermedad sobre los 25 años, tras pasar por el ejército profesional (1 año de contrato que dejó "porque era muy duro...") +++++Viaje a Ecuador donde le extirparon las glándulas suprarrenales: se suponía que ello acabaría con la esquizopfrenia: "...estando allí yo me negué a la intervención, pero mis padres degeron que, ya que estaban allí, cómo me iba a negar..." +++++Quire estudiar un módulo de mecánica. +++++AGRESIÓN A SU MADRE: en agosto pasado agrede a su madre con un cuchillo, sale a la calle y piden que llamen a una ambulancia. +++++ULTIMOS CONTACTOS CON SUS PADRES: le han ido a visitar varias veces a la UME. Preguntado sobre si dichas visitas son positivas para él el gesto inicial es más bien negativo, aunque enseguida corrige y dice que "...bien, porque me traen caramelos, dulces, etc..." +++++Se le explican ñlas funciones de la Comisión Tutelar, la responsabilidad que se tiene sobre él y de la que legalmente carecen sus padres y se le pide que no firme nada que se le ofrezca si no es con el consentimineto de la Coamisión Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-02-07','miguel, llega del jzdo 1º inst. e instrucc nº2 de Coria (vía lexnet) citación para inventario en fecha 11-3-2020. Comprobamos que efectivamente ya somos curadores con lo que asistiremos a la constitución del inventario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2020-02-07','Ana: Adelanto escaneado a Paula, TO del CRR-Plas.: Solicitud de Inclusión en Lista de Esepra Quirúgica y C.I. para Cirugía para la incontinencia urinaria de esfuerzo (Malla) debidamente firmadas y selladas. *Le paso a J.Pedro, originales para que los remita por correo certificado.','2');
