insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-02-07','miguel, nos llega dle jzdo 1ºinst e instrucc nº1 de Plasencia del procedimiento DPA Diligencias previas del pocedimiento abreviado 511/2018, auto de 3-2-2020 donde se decreta la apertura de juicio oral por Delito de Lesiones, y se pide la fianza al tutelado (y subsidiariamente a la Junta) 14.093€. Comprobamos que sólo cobra la PNC y en cuenta la parte económica nos aporta el saldo actual en Liberbank de 2.655,91€. ******************************************************** Hablo con su abogado de oficio D. Moisés Palacios Cotano (tlfno 927-678060; 927-678114 y 656-533967) quién me indica que efectivamente se trata de una garantía lo que requiere el Jzdo y ya se verá cuánto importe habrá de abonarse cuando haya sentencia condenatoria, si es que se le condenara. ******************************************************** Se lo remitimos vía email a Secretaría General (Mª Guerrero) para su constancia, quién me comenta que hablemos con Infancia para saber cómo proceden en estos casos. No obstante, tras comentarlo Angel, Pedro y yo concretamos que los pasos han de ser: 1.-Notificar al jzdo el importe de saldo en cuenta, justificarles que sólo cobra una PNC, justificar los gastos mensuales (para lo cual se lo comunico a la sección económica) 2.-Que sea el Jzdo quién notifique al Centro Socio Sanitario que han de ingresar el importe que entiendan que le corresponda ingresar como responsables subsidiarios a la Junta de Extremadura.','2');
