insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-02-11','TERESA: LLAMO A OLGA LA TS DE VALENCIA DEL VENTOSO PARA IFORMARME SOBRE LA SITUACION DE JOSE M. ME COMENTA QUE LA CASA ESTA MAS O MENOS MANTENIDA GRACIAS AL SAD. JOSE ES MUY DESCONFIADO. OLGA PLANTEA LA NECESIDAD DE EXPLICARLE QUE ESTA TUTELADO Y LO QUE ESO CONLLEVA POR ELLO PIDE QEUE LE HAGAMOS UNA VISITA. TAMBIEN ME COMENTA QUE NO ACUDE A LAS CONSULTAS DE SALUD MENTAL. EN LA CASA HAY NECESIDAD DE COMPRAR ALGUNAS CONSAS COMO POR EJEMPLO UN COLCHON Y EL NO CONSIENTE. QUEDO EN VOLVER A LLAMARLA MAÑANA Y COMENTARME MAS COSAS PUES VA A HABLAR CON LAS AUXILIA DEL SAD QUE LO CONOCE MEJOR.','2');
