insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-02-12','miguel, llama Mely (hermanastra del tutelado)para preguntar por la herencia firmada ya que hace falta que solicitemos autorización aprobando la herencia. Me pide que mande un email a la notaria solicitando lo que necesite y les remito email pidiendoles las escrituras originales firmadas escaneadas para poder solicitar dicha autorización judicial (para lo cual les indico que tendremos que pedir abogado de oficio y portanto tardará un tiempo) Una vez tengamos dicha autorización judicial de la herencia se la mandaré a Mely para puedan inscribir la herencia. *********************************************************** Una vez esté inscrita la herencia procederemos a solicitar autorización de venta para lo cual necesitaremos el borrador de la escritura de la notaria indicando precio de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2020-02-12','Con motivo de la venta de inmuebles de Andrea, solicitamos asistencia jurídica gratuita, requiriéndonos que aportemos documentación (Libro de Familia, certificado de matrimonio, certificado de defunción de Juan Cervera Díaz, exmarido). Esta documentación se la hemos solicitado al Juzgado de Paz de Fuente del Maestre (tfno924530003-fax924531938, Lucía,luciamarquez02@hotmail.com, Secretaria Judicial). También hablamos con su sobrina, Ángela Guerrero Enrique 643650084, que va a intentar conseguirla acudiendo al domicilio de Andrea. Por otra parte, Francisco Ramos (Paco Bolindre) (924094036-650895085), C/. Cura, 23, 06360 Fuente del Maestre, su mujer se llama Manuela Delgado Bautista, que explota las tierras de Andrea, es familia del Juez del Juzgado de Fuente del Maestre. La Secretaria Judicial va a intentar conseguirnos el teléfono para hablar con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-02-12','Ana: Llamo a Paco Ortés, Albañil (638712004): Entregaron el proyecto en el ayto., ya tienen la licencia de obras, pero no lo han hecho aún por el mal tiempo, pues tienen que "desmantelar todo el tejado" y porque ha tenido y tiene otros trabajos en curso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-12','Amalia: He hablado con Inmaculada Pulido, la trabajadora social que va a acompañar a Manuel en el Centro. Para contactar con ella hay que llamar al Centro (tf. 924 30 26 18) ó al número 607516031. Le he dicho lo de la autorización de los 100 euros para los gastos de Manuel. Lo de la aportación al Centro, dado que es muy poco tiempo, no lo ve necesario. De todas formas será bueno que te pongas en contacto con ella. Su correo electrónico es ipulido.cdmeba@caritas.es Bueno Amalia, aunque ya no siga yo el proceso de Manuel, quedo a tu disposición agradeciendo tu interés y disponibilidad. Un abrazo: Rosa Rosa Mª Garay Cano Área de Inclusión C/ Manuel Saavedra Martínez 2, 3ª planta 006006 – Badajoz 924.23.11.57 - 607.562.810 rgaray.cdmeba@caritas.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN'and edp.apellido1='MONTERO'and apellido2='SANCHEZ'),'2020-02-12','(Pedro) Llamada de Rubén desde la UHB de Mérida. Control (81616). +++¡¡¡¡¡¡¡¡CUIDADO!!!!!!!: SOLICITA EL NÚMERO DE CUENTA para dárselo a sus padres porque"...quieren ingresarle dinero". Se le informa de que esa información no está disponible y que si sus padres quieren ponerse en contacto con la Comisión lo pueden hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2020-02-12','Ana: Recibimos correo de Paula, T.O. del CRR-Plas.: "Te envío un consentimiento informado de dentista porque hemos iniciado un proceso de revisión dental con Mª Angeles Santos Urbano, pudiendo beneficiarse del programa de Salud dental de la Junta de Extremadura. Lo primero que deben hacer son extracciones de varias piezas dentales, que realizarán en tres fases. Por este motivo necesitaría tres autorizaciones firmadas del documento de consentimiento de Mª Ángeles con sus datos pero SIN fecha, puesto que se iría poniendo en función de cuándo nos fueran dando las citas. De este modo agilizaríamos el proceso. Si es posible os lo agradeceríamos." *Cumplimento los C.I. y los pongos para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-12','(Pedro) En la visita realizada por Gisela hoy nos informa de que Mariloli ya se encuentra en el CRR y que está muy arrepentida por lo ocurrido. Le dieron el alta este pasado lunes, 10 de febrero, por la tarde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2020-02-13','miguel, remito a liberbank de Trujillo, físicamente por carta certificada y por email la documentación necesaria para reparto de la herencia de la madre de nuestro tutelado (según me confirmó uno de los hermanos por tlfno, ellos ya han remitido al subdirector de la entidad su parte de documentación).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-12','Ana: A última hora recibo llamada del Dr. Miguel Medina, Psiquiatra (54507), comunica que ha hablado con la Dra. Consolación, que ésta está preocupada porque Juan continúa sin ponerse el inyectable. El Dr. Medina dice que habrá que volver a intentarlo y sino habrá que ingresar al paciente. Pide que acudamos mañana desde la Comisión a hablar de nuevo con él, pero que antes se pase por la USM para recoger su informe y el inyectable (Trevicta) y con esto se acuda con la Dra. Consolación y la enfermera para intentar ponérselo en su casa pues hay que darle una última oportunidad. ///////////////////////////////////////*Llamo a Toni-Futuex, expresa que es imposible que acuda mañana Teresa,Delegada Tutelar, que no puede cambiar la agenda y que además ya estuvo el jueves pasado allí, tienen más de 200 km de distancia y Juan está cerrado en banda, no se le va a convencer. ///////////////////////*Vuelvo a llamar al Dr. Medina, le transmito lo hablado con Toni y planteo que dada las circustancias quizá lo mejor es activar directamente el 112. Insiste en que hay que darle otra oportunidad y si no puede ser mañana, pues el lunes (el viernes él no está en Trujillo, le toca hptal.) Puede esperar unos días pues "aún tiene medicación en sangre" ///////////////////////////////// Toni-Futuex remite informe de la última visita de Teresa, Delegada Tutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='PINILLA'and apellido2='BAENA'),'2020-02-13','El Juzgado de Primera Instancia e Instrucción nº 2, de Montijo, dicta Sentencia nº 73/19, en el procedimiento LEV JUICIO SOBRE DELITOS LEVES 150/2019, condenando a Francisco como autor criminalmente responsable de un delito leve de amenazas, a la pena de un mes de multa/4 euros diarios, sujeta a responsabilidad personal en caso de impago de un día de privación de libertad por cada dos cuoas de multa insatisfechas. Se le prohibe a comunicarse con su padre por cualquier medio o procedimiento, así como aproximarse a su domicilio y a su lugar de trabajo a una distancia inferior a 100 metros por un periodo de 4 meses. SENTENCIA NO FIRME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-02-13','TERESA: HABLO DE NUEVO CON OLGA, ME COMENTA QUE HA ESTADO HABLANDO CON LA AUXILAR DEL SAD. LE COMENTA QUE SIGUE CON SU NEGATIVA AL CAMBIO DE SABANAS MANTAS ETC. QUEDO CON OLGA EN IR A VISITARLE EL PROXIMO DIA 26 A LA 11:30, IREMOS UNA VEZ SE HAYA IDO LA AUXILAR PARA QUE NO RELACIONES LA VISITA CON EL SERVICIO DE SAD YA QUE ES LA UNICA PERSONA QUE LE DEJA ENTRAR Y EN LA QUE CONFIA. EL OBJETIVO DE LA VISITA ES EXPLICAR QUE ESTA TUTELADO Y EN QUE COSISTE LA TUTELA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='REBOLLO'and apellido2='LAZARO'),'2020-02-13','BAJA DE EXPEDIENTE Mediante Auto 272/19, de 5 de diciembre, se desestima la remoción, del cargo de tutor, de D. Juan Carlos Rebollo Lázaro. Terminado el procedimiento se extingue la defensa judicial y se procede al archivo del expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-13','Pedro-Ana: Tras varias convesaciones con el manos libre con la Dra. Consolación y el Dr. Medina, finalmente se acuerda el Ingreso de Juan hoy en la UHB en CC. *La Dra. Consolación confirma que ya tiene en Jara la indicación de activación del 112 del Dr. Medina y procederá a ello en breve. Se le facilita el nº de contacto del Jefe de Sala del 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2020-02-13','Se inicia expediente en intranet como Defensor Judicial, tras petición formulada por el Letrado de la Junta D. Francisco M. Sanchez Calzado. Finalmente, en Pieza de Nombramiento de defensor judicial 001/2019, mediante Decreto de 30/01/2019 se designa a Plena Inclusón Montijo como defensora judicial de Dña . Sandra González Escaso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-02-13','(Alberto/Pedro). Visita de Jonathan con su madre, Dª Mª Carmen Juárez. Tengo que pedir a Jonathan que salga porque se pone muy irascible con su madre, a la que no deja hablar. +++"Mi hijo tiene que entrar en un centro porque si no algún día me lo voy a encontrar muerto...Además, él quiere entrar en un centro también...". Le explico las condiciones para acceder a CEDEx y C. Terapéutica, insitiendo en la voluntariedad imprescindible para inciar el proceso de desintoxicación. +++++Además, parece ser que Jonathan ha hecho un pedido de dos móbiles que van a intentar retirar. +++Cuando entra Jonathan dice ESTAR DISPUESTO A ENTRAR EN CEDEX, recordándole las innumerables ocasiones en las que, desde esta Comisión, hemos tratado de inciar este camino. Quedo en llamar a CEDEX para pedir cita y dársela a su madre con la cual "parece" que podemos contar en esta ocasión. +++CITA CEDEX: 19-02-2020 A LAS 10:00h. TIENE QUE CAMBIAR DE MÉDICO POR LUGAR DE RESIDENCIA... +++La madre también está interesada en asber si su hijo tiene un seguro de deceso, de lo que se le informa en sentido positivo. ++++++++++++++++++++++++++++++++++++++++++++++++++LLAMADA DE Dª Mª CARMEN (madre, 633-774980): +++Se le da la cita para CEDEX del 19 de febrero de 2020 a las 10:30h, indicando que le atenderá Marisa. +++Se le informa también (parece ser que ya lo tenía previsto) que Jonathan debe solicitar nueva asignación de Médico de Familia en Mérida (actualmente está viviendo con su padre en el PERI). +++++++++++++++++++++++++++++++++++++++++++++++++++CAMBIO DE CITA +++Llama Amalia para informarme de que, con la finalidad de que el día que vaya al CEDEX lo puedan atender tanto Marisa (T. Soc.) como Mª Ángeles (Médico), se CAMBIA LA CITA AL DÍA 6 DE MARZO A LAS 10:30h. +++Tras la conversación con Amalia, comunico a Dª Carmen el cambio de cita y el motivo del mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFINA'and edp.apellido1='MORA'and apellido2='ZABALA'),'2020-02-13','TERESA: ENVIO ALTA A TERCEROS PARA COMPRA SILLA GERIATRICA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2020-02-13','Ana: Recibo llamada de Maite Cañadas, le comunico que la cuanta de Luisa ya está bloqueada. *Me informa que la ingresan en el hptal y necesitará acompañamiento hospitalario. Le paso con Juana, secc. ecca, para que le diga cómo están las cuentas y el nº que tendría que facilitar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-13','Ana: Pongo para la firma del D.Gerente el C.I. para contraste de yodo, junto con el de sedación para endoscopia y el de colonoscopia (estos 2 último ya los tienen firmados y sellados de septiembre. Pedro, Jefe CTAEX le consulta por mail).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-13','-Amalia: email del CRR Buenos días, El lunes por la tarde le dieron el alta a María Dolores, en el informe médico de alta pone que la cantidad de fármaco era insignificante. Ayer elaboramos en equipo la intervención que vamos a llevar a cabo para tratar de revertir la situación. Muchas gracias por todo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2020-06-04','Ana: Correo de Miguel Ángel, Dtror. CRR-CC (residenciadir@feafescaceres.com):"Buenos días de nuevo Ana, te remito los informes de revisión de Traumatología de Juan Maria Blasco San Román. Debemos volver el miércoles día 10 de junio para volver a valorar el estado del pie. Un cordial saludo. PD: Te remito el segundo informe en jpg porque al convertirlo a pdf se da la vuelta…." ················· Guardo los documentos en el expte. digital. **En el informe de Traumatología exponen: "...retropié muy edematoso, que no permite realizar la cirugía por el momento...." ·········································· Nuevo correo de Miguel Ángel: "Buenas de nuevo Ana, lo que si especifica en el informe es que se debe de mandar la autorización/ consentimiento de los tutores legales para poder realizar la intervención quirúrgica. Le comentaron a la monitora que acompaño a Juan Mario que se le debía de mandar al Doctor José María Solís García. Un cordial saludo. PD: Con lo que nos informen el miércoles que viene te comento. Un cordial saludo." ························ Mi respuesta: "Hola de nuevo Miguel Ángel, Precisamente iba a escribirte sobre ese asunto. Como te comenté, no hay ningún problema en enviar ese consentimiento informado firmado, pero si no nos lo hacen llegar primero desde el hospital difícilmente podremos devolvérselo firmado… ¿Podríais por favor, cuando le acompañéis el día 10 decir que nos lo envíen bien al fax: 924 00 31 94 o bien a mi e-mail o el de la CTAEX? A mi atención o a la de Pedro Gracia, Jefe de Sección. Gracias y un saludo." ······································ Respuesta de Miguel Ángel: "Perfecto Ana, lo dejo registrado para que el monitor que acompañe a Juan Mario el miércoles se lo comenté al Traumatólogo. Un cordial saludo." ·························· Nuevo correo de Miguel Ángel: "Buenas de nuevo Ana, nos hemos puesto en contacto con el Hospital Universitario para informarles que necesitáis el documento de consentimiento informado para realizar la intervención quirúrgica tanto de Consuelo Nevado Pacheco como de Juan María San Román Blasco y nos han comentado que a lo largo de la mañana os lo remitirán vía mail, no irán con los nombres por la protección de datos pero si irán con esta información redactada… EXTRACCIÓN DE MATERIAL QUIRURGICO que ese consentimiento es de Consuelo Nevado Pacheco y en el otro documento aparecerá esta información redactada… IMPLANTACIÓN DE MATERIAL QUIRURGICO que ese consentimiento es de Juan Mario San Román Blasco. El miércoles en consulta si ya disponen del consentimiento le harán la prueba de la anestesia que es la única que le falta a Juan Mario y ya nos citarán para realizarle la intervención quirúrgica, no hemos podida hablar con el Traumatólogo que es recibió ayer en consulta debido a que solo pasa consultas los miércoles, así que debemos ser precavidos y pensar que seguramente la intervención sea el miércoles 17 de junio. Un cordial saludo." ·············································· Recibo del HUC, por @ C.I. para interveción quirúrgica. *Imprimo y pido a Pedro, jefe de secc., que lo ponga para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-02-13','-Amalia: email del CRR Buenos días, El lunes por la tarde le dieron el alta a María Dolores, en el informe médico de alta pone que la cantidad de fármaco era insignificante. Ayer elaboramos en equipo la intervención que vamos a llevar a cabo para tratar de revertir la situación. Muchas gracias por todo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-13','He hablado con Inmaculada Pulido, la trabajadora social que va a acompañar a Manuel en el Centro. Para contactar con ella hay que llamar al Centro (tf. 924 30 26 18) ó al número 607516031. Le he dicho lo de la autorización de los 100 euros para los gastos de Manuel. Lo de la aportación al Centro, dado que es muy poco tiempo, no lo ve necesario. De todas formas será bueno que te pongas en contacto con ella. Su correo electrónico es ipulido.cdmeba@caritas.es Bueno Amalia, aunque ya no siga yo el proceso de Manuel, quedo a tu disposición agradeciendo tu interés y disponibilidad. Un abrazo: Rosa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-13','Ana: Susana Cortés, TS del Hptal. Santiago de Zafra (hospisantiagots@gmail.com), me remite por mail, copia escaneada del DNI renovado de Pilar.','2');
