insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-14','Pedro y Ana: Conversación a 3 con la Dra. Consolación, C.S. Guadalupe: Ayer tras activar el 112 la ambulancia no tardó mucho en acudir, en 45 min. apróx. Juan estaba aún en el domicilio. Éste lo primero que hizo fue pedirle la orden judicial de ingreso... Le trasladaron a la UHB del HSPA-CC . /////////////////////////////////////////////////// Ana: Llamo a la UHB del HSPA-CC. El Dr. Medina ya ha finalizado la guardia. Me informan que según lo hablado en la Reunión Clínica esta mañana, Juan ingresó ayer "descompensado en su patología", "ha pasado bien la noche, no tiene problemas actuales de agresividad. Está abordable, es un paciente facilmente controlable". Al ser ingreso involuntario están pendientes de que acuda el Médico Forense a valorarle.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDORA'and edp.apellido1='LEAL'and apellido2='ROMAN'),'2020-02-14','Ana: Pilar Cerrillo, TS de la Res. Virgen de la Montaña, (calidad@grupociudadjardin.com) me remite por mail el Certificado de Prestaciones de 2019 remitido desde Suiza (Dpto. Federal de Finanzas).','2');
