insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2020-02-14','TERESA: Buenos días TEresa. Ayer no fue a casa de Beatriz, porque cuando me disponía a salir estaba ella en el Centro con la auxiliar de dependencia. Estuvimos hablando sobre las tareas y las funciones que tenia la auxiliar y como se iban a organizar. Beatriz no esta bien, esta verborreica y tiene muchos conflictos con su familia y pareja. Esperemos que podamos sujetarla un poco, si no va a ingresar de nuevo. Le di mi telefono a Isabel (auxiliar de dependencia) para que se pusiese en contacto conmigo para cualquier cosa.','2');
