insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2020-02-17','Ana: Recibimos escrito del INSS: han resuelo denegar la solicitus de PFHC. Causa: "PNC habiendo optado" //////////////////////////////// Llamo a PFHC (927 62 08 28), miran el expte., me comunican que el Sist. lo ha denegado automáticamente por haberse cumplido el plazo de presentación del modelo de opción. Como ahora estamos en plazo de reclaciones aún puedo presentar el modelo de opción. Si finalmente no concedieran la Orfandad, tendríamos que volver a presentar la solicitud de PNC **Pongo el modelo de opción para la firma del D.Gerente. ///////////////////////////////////////////////////// Llamo a P.Orfandad, hablo con Esther, (927 62 00 56): tras revisar el expte. me confirma que aún sigue pendiente de resolver. Le dieron cita con el EVI el día 11 y lo han pospuesto.','2');
