insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-02-18','TERESA: HABLO CON FELIX TS HOSPITAL ME COMENTA QUE ESTA TARDE HACEN EL TRALADO A LA RESIDENCIA. HABLO CON TERESA ADMI DE LA RESICENCIA, ME PREGUNTA QUIEN FIRMA EL CONTRARO, EL DIGO QUE ES UNA CURATELA ECONOMICA CON LO CUAL TIENE CAPACIDAD PARA FIRMAR, LE PASO EL TELFONO DE AGUDA PARA QUE GESTIONE EL TEMA DE ROPA Y DE ENSERES PERSONALES HABLO CON AGUEDA PARA COMENTARLE LA SITUACION PIDO A FUTUEX QUE LE HAGA UNA VISITA NO PODEMOS MANTENERLA EN ESTA PLAZA POR MOTIVOS ECONOMICOS YA QUE VALE 1190, LE PIDO A AGUEDA QUE LE GESTIONE UNA PLAZA PUBLICA MIENTRAS TANTO SOLICITAMOS AL JUZAGO LA AMPLIACION DE LA INCAPACIDAD E INRESO INVOLUNTARIO','2');
