insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='ESTEVEZ'and apellido2='RODRIGUEZ'),'2020-02-18','-Amalia : hablo con Nuria , quedo pte. del envio de los tf de los dos hnos para que futuex los avise para programar cita. Me va a enviar Cdo defuncion de la madre , se lo envió a Belen por email. Ella rellenará la solicitud de P. orf. Ab con la firma de los dos hnos y me la reenviará pq según sentencia , son los dos curatelas , solo asisitimos , tenemos que firmar junto a ellos pero no tenemos capacidad para solicitarlo nosotros solos. Yo adjuntaré toda la documentacion compulsada + registro+ envio al CAISS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-02-17','miguel, remito al jzdo de 1º instacia e inscrucción nº1 de villafranca fax indicando que nos aclare si aparte del tutelado es o no necesario nuestra asistencia, en cuyo caso nos autorice videoconferencia. Asimismo, al no tener representación procesal, le solicito que si es preciso soliciten ellos de oficio abogado y procurador','2');
