insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2020-02-18','-Amalia: Bueno, te digo las citas que tiene programadas Cris con el tema del tratamiento. La semana que viene vamos a que se haga las analíticas. El día 23 de marzo, a las 12.45 horas tiene endocrina. El 3 de abril, a las 8.30 tiene psiquiatra. con respecto a Joaquín estamos en contacto con la UFAT , para información sobre tratamiento y la firma de los consentimientos oficiales .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2020-02-18','Ana: Recibo llamada de Catalina Iglesias Mendoza (927 12 70 17), hermana de Mercedes, para interesarse por su hermana y el estado de sus cuentas. Se le transmite que está todo bien, que percibe su pensión de orfandad correspondiente y que en el centro está bien atendida y tiene todas sus necesidades cubiertas. *Dice que la semana pasada fue a visitarla al hptal., que no acude más por su estado de salud y la distancia de su pueblo, Torremocha (residencia actual) a Plasencia. Fue la anterior tutora de Mercedes, pero solicitó la remoción porque vivía en Cataluña en aquel momento. **Me informa que Mercedes tiene un NICHO EN PROPIEDAD en el CEMENTERIO DE TORREMOCHA. / Por último pregunta que ellos qué tienen que hacer cuando fallezca su hermana. Le explico que tendrán que acudir al Jdo. que la incapacitó.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-02-13','Ana: Conversación con Paula, TO CRR-Plas.: ellos ya conocían a Emilia pues ya estuvo hace años en su centro. Presenta trastorno límite y falta de control de impulsos, el tirar y romper cosas es parte de su transtorno. En relación a la dentadura nueva que tiró hace unos meses al contenedor, lo trabajarán "intensamente" con ella, pero no pueden garantizar que pueda volver a ocurrir. Me comunica que el día 26 tiene cita con el Podólogo, preoperatorio en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-18','Ana: Pongo para la firma del D.Gerente la Solicitud de PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2020-02-19','Ana: Recibo llamada de Juan Carlos Serrano, Director del C.R. Los Pinos (21911), nos ha enviado un correo: "Buenos días, ayer a las 21,15 fallece Dª Eduvigis Fuentes Tornero tutelada por la Comisión), se llama a la familia para comunicarle el fallecimiento y se hacen cargo de los gastos del sepelio. A las 23.50 horas llega la Funeraria a por Dª Eduvigis. Comunicarme si os tengo que enviar algún documento al respecto. Un saludo.". *Nos enviará escaneado por mail el documento que firmó anoche el médico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-19','Ana: Llamo al Dr. Miguel Medina, Psiquiatra (54507), dice que Juan "está delirante, no entiende por qué está allí, está peor de lo que pensaba", añade que el día del ingreso a él no lo quiso ni ver, dice que espera que se le deriven a Media Estancia. *Comunica que la próxima vez serán "más diligentes". Pregunta sobre el proceso de ampliación de incapacidad y le comunico que la última información de que disponemos al respecto es que el Fiscal ha desistido del procedimiento. Se muestra sorprendido y no entiende por qué, pues "ya son muchas veces".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-02-19','Ana: llamo a Chus, Directora de los Pisos de Miajadas (638 499 546): Dice que Steve está mucho mejor, le han reducido la medicación y va bien. En el C.O. no está muy contento, y al parecer siempre le acusan a él de robos y problemas aún de forma infundada. En relación al curso que realizó hace años, del que no se le solicitó Certificado de Profesionalidad, aún habiendo aprobado todos los módulos, dice que ya se pasó el plazo y no se puede pedir. Gloria, Delegada-Futuex, tiene los documentos escaneados. **En cuanto el certificado de discapacidad (el que tenemos en el expte. que es el mismo que tienen en el piso) es "PROVISIONAL, revisable en marzo de 2016" SOLICITAREMOS la REVISIÓN DEL CADEX. Nos harán llegar los informes médicos de que dispongan. *Yo solicitaré informes social al SSB. ///////////////////////////////////////// Llamo a Choni, TS del Miajadas (927 90 12 38), en relación a la revisión del CADEX me comunica que en su día ella lo intentó, pero Marisa, TS de CTAEX, le paró pues corría el riesgo de que no se le concediera ningún grado de discapacidad. /////////////////////////// Por otra parte tiene reconocido Grado I de Dependencia, pero ni ellos ni nosotros tenemos documento al respecto en el expte. *Lo pido a Clara, Jefa de Secc. Depend. por correo interior. *Cuando lo tenga se lo enviaré a Choni, TS, por mail: servicios.sociales@miajadas.org','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2020-02-19','-Amalia : Hablo con Tomás , he solicitado plaza en una habitacion individual , y que le compren ropa . Le aviso que la mantenemos en muface a su email : tmoreno@caseresidencial.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTEVE'and edp.apellido1='PASCUAL'and apellido2='RAMOS'),'2020-02-17','Ana: Recibo llamada de Soledad Cacho, orientadora laboral del una entidad colaboradora del SEXPE, de un programa al que ha comenzado a asisitir Esteve. Pregunta por qué no se le solicitó el Certificado de Profesionalidad de un curso que realizó el joven hace 5 años de Pinche de Cocina en Pinofranqueado. Nosotros no tenemos información al respecto. Por otra parte, pregunta sobre la tutela, la gestión de la misma y el seguimiento que se realiza. Realiza una crítica al funcionamiento del Sistema. Le explico a grosso modo la la estructura, las funciones y alcance de la Comisión Tutelar. *Ponemos el manos libre y participa también Pedro, Jefe de secc., en la conversación. Aunque se muestra agradecida por las aclaraciones, dice que pondrá una denuncia pues estas personas no pueden estar así.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-02-18','Ana: recibo mail de Amor López, TS de ASPACE CC, "...Ayer ... vinieron del SEPAD para valorar a Santi (revisión de la dependencia) no va a ver cambio al respecto. Me dijo que os enviarán la resolución de la valoración, ya nos envias copia para guardar en su expediente si puede ser..."','2');
