insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2020-02-19','-Amalia: envio email a Ctro residencial : Con respecto a Amelia , quedamos pendiente que me comentes si existe disponibilidad para pasarla a una habitación individual y cómo gestionamos el tema de la compra de ropa y demás enseres que necesite. Para el traslado de MUFACE a Seguridad Social , no estamos en plazo , abren dos al año , está todo al día ,con lo que se mantiene con MUFACE .L os problemas que teníamos sobre la información sanitaria se pueden subsanar presentando sentencia. Si necesitas que contacte con alguna clínica privada o demás me lo indicas , de todas formas , y como guardadores de hecho que sois actualmente , no hay inconveniente en facilitaros la sentencia por si tuvieras que presentarla a nivel sanitario. La llaves de la casa se la llevaron los familiares o la dejaron en la resi ¿? Vamos a proceder a una limpieza integral del domicilio. Con respecto a la deuda pendiente , ya te habrá escrito la sección económica para que enviéis la factura y se os haga el pago de inmediato. Un saludo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-19','-Amalia : 658229350 ( tf de Angelica TO del CSS de Mérida ) es su prima , quiere saber sobre la situación de Manuel . -tf de Manuel , me llama pq quiere que le autorice dinero 677716154 , para irse a montar un puesto al mercadillo. Denegado . -Dice que ha solicitado en el centro una semana más y que luego buscará algo por Plasencia . a casa no quiere volver pq al fallecer su abuela su padre ha vuelto a casa con la madre con la que no se habla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-02-19','Ana: Recibo llamada de Rosa, Admvo. CSS Plas., para hacerme consulta del alcance de la curaleta. En el Auto de nombramiento no especifica nada. Me lee la anterior sentencia, previa a la remoción, que nombraba a su hermana, tiene muchas especificidades. *Me enviará copia de la misma para que sepamos a qué atenernos, pues esa no nos la han enviado del Jdo. Yo le remito el testimonio del Auto de Nombramiento y el Acuerdo de Aceptación del Cargo para su expte.','2');
