insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-02-20','TERESA: Buenos días, os informo sobre vuestro tutelado Andrés Silva Bonifacio que el pasado día 14 de febrero sufrió un cólico nefrítico, le pautaron un antibiótico (monurol) 3 gramos (2 sobres) y analgésico (enantyum 25 mg cada 8 horas), además le pidieron una analítica que adjunto para que den su autorización puesto que le pidan una serología muy específica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-02-20','Ana: Llamo a la Residencia S.Pedro de Alcántara (927580624), me dicen que Ivonne, Directora, está hoy en la Res. Buenos Aires (927 58 24 22): Dice que Rosa tiene todas las necesidades cubiertas, no necesita dinero para nada en estos momentos, pues además tras la segunda operación está muy débil y no podrá salir. Ya es la segunda intervención por rotura de cadera. De todas formas, la idea de hacerles transferencia a la residencia para su gasto de bolsillo no es factible pues ellos NO gestionan dinero de los residentes nunca. El servicio de podólogo mensual se puede hacer mediante domiciliación bancaria (cada mes va uno de los 3 podólogos que hay en el pueblo), me remitirá por email la Autorización. El servicio de peluquería, que ella necesita cada 2 meses, en principio se abona en efectivo, pero preguntará si excepcionalmente se pudiera realizar por transferencia, y en ese caso nos facilitaría un nº de cuenta. *En cuanto a su recuperación sí que considera necesario ponerle un acompañamiento para que le ayude a levantarse y la saque a pasear, convendría 1 hora diaría. Le pregunto por Gema, persona que se quedó y cuida a su perrito pero dice no conocerla. No obstante si existe un buen vínculo le parece bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-02-20','En relación con la intervención quirúrgica, el Juzgado de Primera Instancia e Instrucción nº 4, de Plasencia, nos comentan, telefónicamente, que tiene que reconocerle el forense, después debe informar el Fiscal y posteriormente resolverá el Juez.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2020-02-20','TERESA: Te adjunto informe de alta e informo que ayer se le realizó un TAC con contraste programado previo a la consulta de oncología prevista para el 2 de marzo a las 15.00 horas ARCHIVO INFORME','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-02-17','(Pedro)Llamada de David, T. Soc. "Padre Cristóbal" (607-556002). +++Ildefonso y Josquina están el Centro "Padre Cristóbal". Comentan que están buscando alquiler pero no lo encuentran. +++Explico las circunstancias actuales de Ildefonso. Pueden permanecer unos días allí. +++Volvereé a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-02-20','(Pedro)Llamada de Paqui, de Gestión de Penas ( 924-266158). +++Ildefonso ha acudido muy pronto a la cita. Comenta que se quiere ir a Barcelona porque lo van a echar del Centro "Padre Cristóbal" y no tiene donde quedarse. +++Pueden tramitar el traslado del expediente a Barcelona, pero desconoce Paqui cómo se gestiona allí el cumplimineto de las penas. +++Tras hablar conmigo y como mañana va a venir a la Comisión para hablar del tema, Paqui lo vuelve a citar para el próximo jueves, 27 de febrero, a las 12:00h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2020-02-20','TERESA: RAMON 641420404 SOLICITA DINERO PARA PIENSO, HABLO CON EL MOLINO DE PIENSO PARA HACER EL PAGO POR TRANSFERENCIA 924731071','2');
