insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2020-02-20','Ana: Llamo al CSS-Mérida; Maribel, TS, me confirma que Juan Ángel regresó el día 11 a la UME.','2');
