insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-20','Ana: Mª del Carmen Alvarez (Mamen), TS del HSPA-CC, me remite por fax la ACEPTACIÓN DE LA DERIVACIÓN A LA UHDAC. En el punto 2 añaden: "Se informará en el momento de disponibilidad de camas." ////////////////////////// Llamo a Susana, TS del Hptal. Santiago de Zafra (607 33 19 63): Pilar está participando perfectamente en las actividades y talleres del centro, se puso muy contenta cuando fueron a visitarla Gloria y Susana de Futuex. Está estable, no ha presentado alteraciones de conducta. Tienen mejor color de piel y se le nota también en el cabello. Está comiendo bien y se le nota. Sale mucho al patio a pasear. **El problema principal sería la cuestión econóimca, ellos sólo tienen subvención por la 10 plazas de RAE por el MADEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-02-20','miguel, llega citación a través de email de examen judicial y reconocimiento forense para 17-3-2020 a 12:30h en jzdo nº1 de villanueva de la serena (no es necesario que acudamos)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2020-02-21','(Pedro)Llama Catalina. +++NO QUIERE CAMBIAR de PISO, pero no está cómoda porque al parecer hay mucho revuelo en el bloque y alrededores los fines de semana. No sabe qué hacer en esos días en los que "...vosotros no estáis...". SE le indica que en esos casos llame al 112 y cuente lo que sucede. +++No quiere cambiar de piso porque le gusta en el que está, además, "...si me fuera a otro pasaría lo mismo, porque la gente se mete en las casas, se oyen riñas..." pero en el suyo responde que nunca ha entrado nadie. +++Acudió al Psiquiatra el 18 de febrero y le mantuvo el tratamiento. Visitó a Asunción Cabrera sobre noviembre y tiene que volver en abril. +++Hablar con Sonia (FUTUEx) y Asun (CSS Mérida).La semana que viene la vuelve a visitar Sonia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-02-19','NUEVO DIRECTOR DEL CRR de CÁCERES:D. Miguel Ángel Rodríguez Félix (687-487908).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-02-21','TERESA: Buenas Tere, nos han comentado por teléfono desde el SEPAD, que José Lara Serrano, pierde la plaza T3· que tiene con nosotros. Nos llegará la carta avisandonos entre el 5 y 10 de marzo, y a partir de esa fecha, hay un mes para que pueda dejar la residencia. Ya me dices si le vas a gestionar algún recurso o se lo hacemos desde la residencia. Estamos en contacto .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-02-20','Ana: Recibo correo de Rosa, Admvo. CSS-Plas.: "Buenos días Ana: Te adjunto la Sentencia de Incapacidad de J.M. Moreno, donde se le declaró incapaz y se nombró CURADOR a su hermana. Buen día." //////////////// En dicha sentencia - FALLO: "...deberá prestar al demandado la asistencia que precise en el ámbito personal cuando el mismo se encuentre en fases agudas de su enfermedad, así como en la administración de su patrimonio de tal manera que el incapaz precisará autorización de su curadora para llevar a cabo todos los actos para los que los tutores precisan autorización judicial... debiendo autorizar en todo caso las posibles extracciones de dinero... cuya cuantía exceda de 150,00 €..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-02-18','Ana: En reunión mantenida con Toni-Futuex, se expone que desde que Rosa fue intervenida no ha podido acudir al banco a retirar la asignación económica. Plantearé a la Resid. el poder hacerles a ellos una transferencia para que puedan facilitarle el dinero y su gestión. Así mismo, se valora la necesidad de poner una persona que realice acompañamiento y le ayude en el proceso de rehabilitación, para levantarse y dar pequeños paseos. Gloria, delegada Futuex, plantea a Gema, persona que tiene y cuida el perrito de Rosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='GOMEZ'and apellido2='NEVADO'),'2020-02-21','Ana: Llamo a Toni-Futuex, quién demanda el tener dinero de bolsillo es la propia tutelada. *Intentaremos que de forma excepecional y puntual sea Gloria, Delegada, quién acuda sola a retirar el dinero de Rosa. **Lo pasaré a Alberto, jefe secc. ecca. // En cuanto al acompañamiento hablarán con Gema y me enviarán presupuesto. //*Toni me remite por email el presupuesto de acompañamiento de Rosa. //// Se podría asumir 5 días/semana de acompañiento, al menos al principio. Se lo comunico a Toni por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2020-02-21','miguel, remito email a la abogada de la junta como parte interesada (responsabilidad subsidiaria) con copia a Pedro y a Angel, conforme instrucciones con secretaria general (Maria Guerrero)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-02-21','Ana: Devuelvo llamada a Paz Boticario- TS de la Cruz Blanca (927 24 68 52), ayer cuando llamó yo estaba en una reunión y le atendió Coral, secc. ecca., al parecer vuelve a haber problemas con la pensión de Antonio. //////////////////////////////////////// Llamo al INSS - P.Orfandad (927 62 00 56), Toni dice es muy raro, pues aparece rehabilitado (Gestión realizada por Miguel, jefe secc. control de pensiones). Le aparece en alta tanto en PFHC como en P. Orfandad (desde el 1/2/20) 467,80 € con la subida actual. Cobrará el día 25.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-02-21','(Alberto/Pedro). Reunión mantenida con Ildefonso. +++Insiste en que se quiere ir con Joaquina a Barcelona, a compartir piso con una amiga de ella que está dispuesta a ello. Además, tienen planes para casarse. +++Se le trata de hacer ver los inconvenientes de esa decisión, dado que Ildefonso desconoce a esa persona, lo que va a tener que aportar al alquiler, etc. +++Además tiene pendiente el cumplimineto de las 112 jornadas de servicios a la comunidad, por lo que se le plantea que los cumpla en Extremadura y mientras se piense la decisión de marchars ea Barcelona. +++En cuanto a la "boda", se le trata de hacer ver el compromiso que ello implica, especialmente en caso de que la relación fallase y hubiese un posible divorcio (pensión, etc...). +++Tiene que ir el jueves que viene a Badajoz a Gestión de Penas para traslado de expediente (tampoco sabe qué sistema de gestión tendrán en Barcelona) y se le pide que se paase de nuevo por la Comisión para darnos la dirección en la que se van a quedar en Barcelona. +++Reintegros autorizados de 150 euros/semana, a partir de primeros de marzo, y siempre que esté claro el cumplimiento de la medida, sea aquí o en Bracelona. +++TELÉFONO: dice haber dado el suyo de tarjeta a una amigo. Solo disponemos en este momento del de JOAQUINA: 665-940924.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUVIGIS'and edp.apellido1='FUENTES'and apellido2='TORNERO'),'2020-02-18','EXITUS. Comunican desde el Centro su fallecimiento el 18/02/20.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='GORDILLO'and apellido2='PINTO'),'2020-02-20','EXITUS. Comunican desde el Centro su fallecimiento el 20/02/2020','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-02-21','(Pedro) Conversación con Cristina, Psicóloga del CRR de Cáceres. +++Tras su última alta de la UHB se encuentra más tranquila pero todavía inestable: con sensaciones de miedo y recuerdos recurrentes de su intento de suicidio. +++Respecto a José Manuel R.M. saben que se estuvieron viendo antes de Navidad, y que unas veces era él el que se acercaba y en otras ocasiones era ella la que lo buscaba, a pesar de tener una nueva relación en el CRR. +++En estos momentos, comenta Cristina que NO HAY MOTIVOS PARA DENUNCIAR. No obstante, lo han puesto en conocimeinto de la Unidad de Policía (UFAM) que eatiende estos casos y van a estar pendientes de ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-02-24','TERESA: RECIBO LLAMADA DE LA RESIDENCIA ME COMENTA QUE EL MES DE FEBRERO PAGARA LA MITAD, ME FACILITA NUMEROS DE CUENTA PARA EL PAGO TANTO DE LA RESIDENCIA COMO DE LA FARMACIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-24','Ana: Recibo llamada de José Manuel (667 384 817), pregunta "que pasa con el centro", le recuerdo que esto no depende de mí, que está solicitado y que aunque no hay resolución oficial ya sabe lo que le dijo Pilar, TS ESM, que han valorado y no da perfil. Hay que esperar a que convoquen la Subcomisión Sociosanitaria. Por otra parte, pregunta si se le va aumentar la asignación semanal, le digo que aún no ha hecho cuentas el jefe de la secc. ecca. Pregunta si al menos se le podría dar dinero para el bonobús mensual = 29€. Lo hablaré con Alberto, secc. ecca.,y le diré algo. ////////////////////////////////// Vuelve a llamarme José Manuel más tarde, dice que ha hablado con Pilar Martín (TS ESM) y le ha dicho que para poder acceder a CRR primero tendría que pasar por el CSS de Plasencia para estabilizarse, que tendría que ir primero al HSPA, ingresar en UHB y de ahí le derivarían a UME. Como él no quiere ingresar primero en UHB, y el miércoles 26 tiene cita con su Psiquiatra, le planteará el ingreso directo en UME.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-24','Ana: Recibo llamada de Mamen, TS del HSPA (56283), le ha comentado el Pisquiatra que Juan pide hablar conmigo. Le digo que sin problema, que le facilite mi número y me llamen cuando consideren. Si prefieren que llame yo, que me digan qué día y a qué hora apróx. //////////// Llama de nuevo Mamen, me comunica que el Psiquiatra que lleva a Juan es el Dr. Molina (56832), pide que llame el miércoles 26.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-02-24','TERESA: Como acordamos, os adjunto copia del número de cuenta en el que habría que hacer el ingreso del mes de Josefa, en el caso de febrero será medio mes, siendo 595 Euros. A partir de marzo, el ingreso serían 1190. Para medicamentos y acompañamiento a médicos, os doy otro número de cuenta. Sería de IBERCAJA: ES58 2085 4514 2103 3022 6738','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2020-02-24','Ana: Llamo a Paz Boticario- TS de la Cruz Blanca (927 24 68 52), le transmito lo que me dijeron en el INSS, que está todo bien, aparece en alta en ambas prestaciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='MUÑOZ'and apellido2='REJA NIETO'),'2020-02-24','TERESA: Os informo que el pasado viernes se tuvo que acompañar a Josefa al hospital, se fueron a las 11:45 y llegaron a la residencia a las 16:45, siendo el acompañamiento médico de 5 horas. En este caso el abono de los 50 Euros sería en Ibercaja. Si os parece bien hacéis ese abono y ya más adelante os adjuntamos el gasto en medicamentos. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='HURTADO'),'2020-02-24','(Pedro)Llamada de la Directora del CR "El Cuartillo", para ver cómo va el procedimiento. +++Somos Defensores Judiciales. Al parecer, según la Directora, la hermana de Dª Rosa a pedido ser su tutora.','2');
