insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-02-26','(Pedro) Llamo al Dr. Urbina pero no se encuentra disponible en estos momentos. También llamé la pasada semana sin conseguirlo. +++Volver a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-26','Ana: Llamo al Dr. Molina, UHB HSPA (56832), refiere que e un paciente que conocen de hace años, "está como siempre, es un señor muy delirante al que le pongas la medicación que le pongas no cesa en los delirios." Ha hablado con el Dr. Medina - ESM, "como en el pueblo no acepta el tto. ni asiste a seguimiento,es conveniente derivarlo a UME". Dada la demanda de Juan de que le llame, acuerdo llamarlo en horario de 10:00 a 12:00 a la UHB (56826). Se lo comunicará a la celadora para que esté pendiente. /////////////////////////////////////////////////////////// Llamo a Juan a la UHB, nada más comenzar la convesación se muestra muy alterado, dice que él no tiene que estar ingresado ahí y que tampoco quiere ir a Plasencia, que él no tienen ninguna patología. Le digo que nosotros desde la CTAEX no somos quines decidimos si permanece más o menos tiempo en la UHB o si le derivan al CSS, que son los Psiquiatras los que toman esas decisiones y quienes emiten los diagnósticos. Añade que "los psiquiatras no son dios y no tienen ni idea, que quién mejor sabe si está enfermo es el propio enfermo". *Que le han retirado el Xeplión, y ahora con la otra medicación se encuentra mejor. Que llame a la Jueza de Instrucción de Logrosán para que le saquen de allí que él no piensa ir de ninguna de la maneras a Plasencia. Que si nosotros somos lo que tenemos que velar por sus derechos llamemos a la Jueza y le informemos de toda la situación. Le recuerdo que la Jueza ya sabe que está ahí ingresado, que el médico forense ha ido ya a valorarlo. Pero insiste que a quien hay que informar es la "Jueza de Instrucción". *Durante la conversación es necesario decirle en varias ocasiones que se calme y no de voces, pues a él nadie le ha hablado mal, una de la veces dice que no piensa hablar en otros términos, hasta que se le dice que en ese caso se terminará la conversación y es cuando rebaja un poco el tono y el volumen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2020-02-26','En relaciòn con el procedimiento de separación contenciosa, hemos enviado fax al Juzgado de Primera Instancia e Instrucción, nº 1, de Plasencia, solicitando se le designe abogado de oficio para contestar a la demanda, así como que a la comparecencia del día 9/3, asistamos a través de videoconferencia en los Juzgados de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-02-26','Ana: Me devuelven de registro copia de la SOLICITUD de PNC con REGISTRO DE ENTRADA de 24/02/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-02-26','TERESA: Buenos días, informaros que en el día de ayer se tuvo que activar el 112 dos veces. La primera vez por la mañana, agredió a 5 cuidadores (a uno de ellos le ha causada baja laboral), cuando vino el 112 le pusieron el rescate pautado (media ampolla de Abilify). Por la tarde, insistía en fugarse del centro y según se iba fugando iba dando patadas y tirando todo el mobiliario, cuando salió intentó quitar un tapón de una rueda de un coche y salió corriendo. Lo trajo la policía local, intervino también el médico de urgencias, 112 y guardia civil (le pusieron una ampolla de Haloperidol) y pautaron su trastalo a Mérida. Hoy se encuentra todavía en Mérida y no tenemos noticias ningunas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2020-02-26','Buenas tardes, Os hago llegar la demanda del paciente Bartolomé Alba Gragera, de 55 años de edad, que ha acudido al hospital reclamando ayuda por su situación de "desamparo", según sus propias palabras, que se encuentra incapacitado legalmente y según manifiesta tiene una Curatela a vuestro cargo. Reclama un aumento de su asignación semanal de 10 euros para sus gastos. Refiere que ha intentando solicitar un abogado de oficio pero que le que se lo han denegado. Dice encontrarse indefenso y dispuesto a hacer una locura, que lleva 5 años en esta situación y que puede gobernarse por sí mismo. Os escribo este correo simplemente para haceros saber estra demanda a petición del paciente, que manifiesta vehementemente que esta cantidad es insuficiente y que ni siquiera puede comprarse ropa, que lo que lleva encima, explica, le ha sido donado por la caridad. Gracias. Un saludo Juan José Marín Trabajador Social Hospital Universitario de Badajoz 924218100 (Ext. 48330/ 31806','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-02-26','Buena tarde y feliiz celebracion de carnaval. Por medio de la presente le informo que el día martes llegó mi hijo menor desde Nueva York a visitarme en consecuencia necesito tiempo disponible para compartir con el. Ya Inmaculada está al tanto y a través de la señora Juana, les hice saber de esta situación tan inesperada y por demás grata para mí. Siendo un asunto tan personal y familiar comprendo que los días que necesito tomar los pagaré yo. Agote todas las instancias para buscar una persona de confianza y no fue posible. Para resolver de que Rosario se quede con alguien responsable, los días de este fin de semana los cubre la señora Yaneth que es de Colombia y los días entre semana mi sobrina Anaybeth quien estuvo en mis vacaciones de diciembre. Será hasta el 5 o 6 de marzo que ya mi hijo retorna a los estados Unidos. El fin de semana del 29 y 1 de marzo estará Aixa Do como cualquier fin de semana al mes. Espero comprenda que es una circunstancia en la cual requiero estar con mi hijo después de más de 2 años sin verle personalmente. Les agradezco su receptividad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-02-26','TERESA: ENVIO ACTUALIZACION DE PENSIONES A PETICION DEL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2020-02-28','ME LLAMA MERCEDES PARA GESTIONAR VISITA DE BEA PARA EL PROXIMO VIERNES DIA 6 DE MARZO A LAS 16.00 ME COMENTA QUE LA UTLIMA VISITA FUE BIEN SOLO QUE LA NIÑA PUES LLORA BASTANTE. COMENTA QUE ES MUY MALA HORA PUESTO QUE LA NIÑA VIENE DE LA GUARDE Y TIENE SUEÑO. A LA VUELTA PRESENCIARON UN ACCIDENTE DE TRAFICO LO CUAL HIZO QUE EL VIAJE FUERA DESAGRADABLE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-26','Ana: Recibo llamada de José Luis, hermano de José Manuel, ha remitido al ctutelar@ factura de electricidad que acaba de abonar, para que le hagamos transferencia. Se lo pasaré al jefe de la secc. ecca. Por otra parte, pregunta de nuevo por el centro para su hermano y se le vuelve a explicar lo que se le ha explicado ya en diversas ocasiones. /////////////////// Recibo llamada de Pilar, Martín (54612), José Manuel ha acudido a su consulta más temprano de lo acordado, aún no ha llegado Gloria, Delegada Tutelar. *Ha recibido ya la Resolución denegatoria de plaza para CRR. *Me volverán a llamar tras la consulta con el psiquiatra. /////////////////////////////////////// Al final de la mañana llamo yo a Pilar, pero no obtengo respuesta. *Le envío un mail solicitando me remitan por mail la resolución denengatoria de CRR y preguntando si hay alguna novedad tras la consulta de Psiquiatría. //////////////////////////////// Llamo a José Manuel (667 384 817), pero salta el buzón de voz. Le dejo mensaje, volveré a llamar mañana. //////////////////// Recibo correo de Toni-Futuex, me remite ACUERDO DE LA COMISIÓN DE VALORACIÓN DE EXPTE: NO aceptan la solicitud de valoración a CRR "...puesto que los informes evidencian presencia de conductas autolíticas, con recientes ingresos en la UHB... Se orienta a que convoquen SUBCOMISIÓN DE GESTIÓN DE CASOS..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-02-26','miguel, remito al Juzgado Decano de Zafra la solicitud de aprobación de la herencia de la madre (notaria de Villajoyosa)que ya ratificamos en diciembre 2019. Y la solicito también Autorización de Venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-02-19','(Teresa y Pedro) Visita domiciliaria de la CTAEx a D. José Mª, acompañados por Olga, T. Soc. del SSB de Valencia del Ventoso. +++D. José Mª se encontraba en casa. Tras explicarle cuál era su situación a nivel jurídico y las competencias de la CTAEx le pedimos que si nos quería enseñar su casa, a lo cual no puso reparos en cuanto a la mayoría de estancias (entrada, cocina, salón y dormitorio) y sí tuvimos que insistir algo más para que nos permitiera ver dos de las habitaciones que tenía cerradas con llave y el doblado, que como pudimos observar tenía el tejado en muy malas concidiones (ver fotografías en expediente digital). Estas estancias no las había podido ver la T. Soc. hsata este momento. +++La vivienda estaba en condiciones "aceptables" en cuanto a orden y limpieza (de las zonas que permitía atender a la Aux. del SAD). Las habitaciones cerradas estaban llenas de trastos, muebles y ropa, sin ventilación y con signos de humedad en paredes y techos. +++PENDIENTE: convencer a D. josé Mª de que permita limpiar las habitaciones mencionadas a la Auxiliar de Hogar y que lleve el dinero que dice tener en casa al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2020-02-27','TERESA: ENVIO FICHA SOLICITUD ACTUACIONES DE TURISMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-02-27','TERESA: ENVIO FICHA SOLICITUD ACTUACIONES DE TURISMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2020-02-27','TERESA: ENVIO FICHA SOLICITUD ACTUACIONES DE TURISMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANO'and edp.apellido1='CALVO'and apellido2='MARTIN'),'2020-02-27','Ana: Correo de ayer a final de la mañana de Pilar Cerrillo (calidad@grupociudadjardin.com): "Buenos días Ana, ponte en contacto conmigo lo antes posible, ha fallecido emiliano Calvo, es tutelado vuestro, no sabemos si tiene póliza. La familia que tiene quiere llevarlo a Montehermoso. Un saludo. Pilar" /////////////////////////////////// Pregunto a Coral, secc. ecca, ya habló ella ayer con Pilar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-02-27','Ana: Recibo llamada de Pilar Martín, TS ESM-CC (54612), va a convocar ella la subcomisión de gestión de casos. ***Me comunica también que el Psiquiatra emitió ayer informe en que expresa que tras no haber sido tenido en cuenta su criterio, se autoexime de la responsabilidad de derivar a ningún otro recurso a José Manuel. *Pedir informe a Carmen Ferrer. ///////////////////////////////////////////////////// Llamo a José Manuel (667 384 817), dice que él no está para crónicos, qué el quiere ir a URA o a otro centro. *No está bien en su casa y dice que ha tendio amenazas de los vecinos. Dice que necesita dinero, que ya no tiene "ni leche ni nada". *Tengo pendiente hablar con Alberto. ////////////////////////////////// Alberto dice que se le subirá los 29€/mes para el abono mensual del bus. Podrá retirarlo el lunes 02/03 acompañado de Virginia-Futuex, quien le acompañará también a realizar las gestiones de bonobús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-02-26','Ana: Pedro, Jefe de Secc. CTAEX, ha hablado con Asunción Cabrera, Psicóloga y coord. de los pisos supervisados en Mérida, al parecer José Manuel tiene solicitada plaza en el CRR de Mérida. Renunció a pisos voluntariamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANO'and edp.apellido1='CALVO'and apellido2='MARTIN'),'2020-02-27','EXITUS El centro informa de su óbito, acaecido el 26/02/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GOMEZ'and apellido2='GALLARDO'),'2020-02-27','Ana: Recibo llamada de Secretaría HVP-Plas. (78017) de parte del Dr. Urbina - Urólogo. Han intentado contactar con Pedro, jefe de secc. Comunican que aún están pendientes de recibir respuesta en relación a la intervención o no de Pablo. La demanda proviene de él y del Dr. Molina, Jefe de Servicio. ///// *Se lo comunico a Pedro cuando regresa de la visita de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2020-02-27','-Amalia : pregunto a la residencia por el estado de Amelia. Según me informan las enfermeras se cayó el domingo, suponen que al levantarse ella sola se tropezó y se dio un golpe en la cabeza, fue derivada a Clideba, pero ya está en la Residencia. Tiene una brecha en la cabeza, le dieron puntos y le hicieron un TAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2020-02-27','Ana: Recibo llamada de Cristina Castro, Ed. Asoc.Vera (681 143 911), me informa de que llamó alguien diciendo que era abogado y pidiendo explicaciones de por qué tenía la tutela de Adrián la Junta y no la familia. Le dijeron que no podían facilitar ninguna información. En teoría se pondrá en contacto con la CTAEX. // En cuanto a Adrián, dice que se le ve contento. En carnavales desfiló con mucho ritmo y muy alegre. *Lo único es que le dejaron salir por la noche con un compañero y tenía que volver a las 00:00h y llegado el momento no quería volver al centro. Lo encontró Cristina a las 02:00 h y le costó convencerlo para que volviera. A la mañana siguiente se mostraba arrepentido y pidió disculpas. *Por otra parte hubo un incidente en el centro entre otros dos compañeros y él actuó muy bien, los separó y medió. Esta conducta ha sido reforzada al igual que la otra tuvo su reprimenda. /// Al margen de esto Cristina dice que no tienen en el expte. el Certificado de Dependencia de Adrián, miro en el PC y escaneado al menos no lo tenemos, miraré en el expte. papel y si no lo tenemos solicitaré una copia del mismo. /////////////////////////// Solicito mediante nota interior a Clara Gómez, Jefa de secc. dependencia, Certificado de Dependencia de Adrián.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2020-02-27','-Amalia : pregunto a la residencia por el estado de Amelia. Según me informan las enfermeras se cayó el domingo, suponen que al levantarse ella sola se tropezó y se dio un golpe en la cabeza, fue derivada a Clideba, pero ya está en la Residencia. Tiene una brecha en la cabeza, le dieron puntos y le hicieron un TAC.','1');
