insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2020-02-27','Ana: Nos remiten desde el CAM Isabel de Mostezuma de Caminomorisco, Certificado de Revalorización de Pensiones: Orfandad Absoluta. Líquido a percibir = 467,80 € /////////////// Cumplimento modelo de Comunicación de variaciones al INSS (domicilio *a efecto de comunicaciones) y lo pongo para la firma del D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='GUILLEN'and apellido2='ROMAN'),'2019-12-19','miguel, tras conversación con Belén Camisón (cuñada del tutelado) Hablo con la notaria Ana (quién dejará la escritura a Jose Luis) para sea firmada el día 2 de enero por los interesados y el 3 ratificaremos nosotros, así se lo hago saber a Ana y Jose Luis. No obstante Ana me pide le envíe email para recordarselo, y así lo haré. Por otra parte al día siguiente Belén Camisón me llama para ratificar que se pueda firmar y me confirma que harán transferencia el 26 o 27 de diciembre, lo cual se lo comunico a la parte económica para tengamos cuidado de que el tutelado no disponga de ese dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AIDA MARIA'and edp.apellido1='MARTIN'and apellido2='DE PIÑOL'),'2020-02-27','Ana: Pongo para REGISTRO DE ENTRADA Comunicación de variaciones al INSS (*Domicilio a efecto de comunicaciones).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='ANTUNEZ'and apellido2='SANZ'),'2019-12-04','miguel, envío fax al Jzdo 1º instancia e instrucción nº2 de Don Benito solicitando nos comuniquen por escrito el problema de la dilación en la resolución. ****************************************************** Adjunto les remito la reclamación de cantidad dineraria y facturas que envía el perito que ha arreglado la vivienda Camilo. ******************************************************** Paralelamente resuelvo negativamente el escrito de reclamación de cantidad hasta que el juzgado resuelva, y que le enviaremos en próximos días. ********************************************************* Hablo con la persona del Jzdo de Don Benito que lleva el procedimiento y me confirma que el motivo es porque todavía el Colegio de Abogados no ha nombrado un abogado de oficio. Me dice que remitirá el expediente al Ministerio Fiscal y paralelamente enviará un nuevo oficio al colegio de abogados solicitandole abogado de oficio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-02-27','Ana: Recibo correo de Toni-Futuex con presupuesto de Limpieza de la empresa Tomás Manuel Refolio y otro del Hostal Nairobi. Tras revisarlo, como no hace mención a tareas de desinfección y sólo constan 8 horas de trabajo, llamo a la Empresa (648 019 498), Tomás dice que ha hecho un presupuesto sin haber visto la casa, y si está tan sucia posiblemente las 8 horas resulten insuficientes. Ellos no realizan tareas de desinfección como tal, limpian con lejía, desengrasante y productos que suele haber en los hogares, pero dice que hay otra empresa en el pueblo que sí la hace. Acordamos que Gloria, Educadora Futuex, volverá a llamarle para que acuda con ella a visitar la vivienda y valorar las horas de trabajo necesaria, para hacer un presupuesto más acertado, y si fuera necesaria una desinfección. Podría facilitarnos el contacto de la otra empresa. **Envío correo a Toni-Futuex informándole al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-02-27','(Teresa y Pedro). Visita a Plena Inclusión Zafra. Reunión con el Equipo: Ana (Taller), Charo (Dirección), Eduardo (Psicólogo), Ana (Educadora) y Miguel (Monitor). También entrevista con Natalia. +++EXposición de la situación: las estrategias terapéuticas segidas hasta ahora no han dado el resultado esperado. +++Nuevas estrategias: denuncias a la Policía ante posibles comportamientos delictivos y apercibimiento de posible cambio de centro (Natalia teme que tenga que marcharse de allí). +++Según compoortamiento de Natalia: mantenimiento de visitas a su abuela o disminución de las mismas hasta su desaparición llegado el caso (es otro de los temores que más presocupan, o lo parece, a Natalia. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Entrevista con Natalia, junto con el Equipo del centro y posteriormente a solas con ella. +++SE explica el papel de la CTAEx en cuanto a su tutela. Se refuerza el papel del centro en relación con la actitud que demuestra Natalia. +++Se le hace ver que la Comisión apoyará cualquier decsión que se tome desde el centro, así como las denuncias que su comportamioneto pueda ocasionar, al margen de que "existan o no pruebas del mismo, ya que ello depende de la valoración que se haga desde el juzgado..." +++Se le trata de hacer entender que las traumáticas experiencias que ha vivido en la infancia nos pueden permitir entender, a quienes tratamos de ayudarla, sus comportamientos actuales, pero que en ningún caso esas experiencias los justifican, por lo que los mismos son de su responsabilidad y, ante un juzgado, puede tener que responder de los mismos si se le considera imputable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-02-27','(Pedro)Llamada de Paqui (Gestión de Penas de Badajoz) al móvil de la Comisión (en viaje a Zafra a visitar centro y tuetelado). +++"Ildefonso está aquí y dice que mañana se va a Barcelona...Traslado entonces el expediente?" +++Se le explica a Patricia que su decisión es contraria a la de la Comisión, que se lo ha desaconsejado en todos los sentidos, pero dada la curatela que tiene no le podemos obligar en forma alguna. +++Le pido que nos envíe documentación en la que se refleje el trasladode expedeinte y comunicaremos al juzgado su marcha a Barcelona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='JIMENEZ'and apellido2='NAVARRO'),'2020-02-28','Fax del CSS-Mér. Felisa ingresó ayer día 27 en el Serv. de Urgencias del Hptal. de Mérida.','2');
