insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2020-02-28','(Pedro)En el teléfono aparcece lladada del CAMP Don Benito de las 00:02 del día de hoy. +++Llamo al CAMP y hablo con Miriam (supervisora): Hermenegildo se ha escapado esta noche. A la 1:30 de la madrugada ha llamado su madre para decir que estaba en su casa y que dispusieramos los medio para que regresara en el día de hopy al CAMP. Previamente se había dado aviso a la Policía Nacional sobre esta incidencia. Pido que nos comuniquen el retorno por fax o cualquier otra incidfencia.','2');
