insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-02-28','Ana: Recibo llamada de Raquel, TS del SSAB de Guadalupe (927 36 70 06), preguntando por Juan. Le explico cómo está la situación hasta el momento. Ella expresa que lo ideal es que vaya al CSS-Plas. y que ya no salga de allí, según habló con Pilar Bueno - TS CSS (ya jubilada) en su momento, si volvía a ingresar allí, ya no le darían el alta. *Pide que llamemos al CSS y para recordarlo.','2');
