insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-02-28','-Amalia: email de SS , para tramitar PFHC ANTES DEL 30 DE MARZO , CUANDO TENGA RESOLUCION CADEX O SIN ELLA . Buenas tardes, te envío el certificado que me has solicitado. Actualmente se encuentra de baja por caducidad del certificado de discapacidad. Una vez lo tengáis, debéis solicitar nuevo expediente, al pasar la tutela con vosotros. Cuando lo presentéis, hacer constar en la solicitud nueva que en Enero presentasteis un certificado con la cita en el Cadex, para que no pierda efectos económicos. Por último decirte que en la nómina que se abonará en Julio, se le pagará 250 euros del primer trimestre. Si tienes alguna duda mi teléfono es 924-216141. Gracias y un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-02-28','miguel, tras consulta del CSS (Rosa) sobre la vivienda de Santos Cordero, le indica Angel que estamos pendiente de que nos remitan el proyecto para el arreglo y ver cuáles son los gastos. Mientras que sobre el tema del embargo, el tutelado no sabe si le han o no embargado la cuenta a fecha actual, por lo que actualizará el fin de semana las cuentas y dependiendo de si se lo han o no cargado, procederemos o no a pedir al Oar de Cáceres Carta de Pago de dicho embargo. El lunes nos llamará Rosa y nos confirmará si finalmente hay o no que pagar dicho embargo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2020-03-02','TERESA: Buenos días, informaros que el viernes (28/02) por la tarde volvió Andrés al centro y en el día de ayer sábado 29 de febrero por la tarde tuvo que intervenir el 112 de nuevo y lo trasladaron a Mérida UHB. Agredió a cuidadora, estuvo bastante agresivo con el mobiliario de su habitación y muy alterado.','2');
