insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AURORA'and edp.apellido1='PAREJO'and apellido2='MORENO'),'2020-03-02','TERESA: PIDO A FUTUEX QUE ACOMPAÑE A AURORA AL JUZGADO EL PROCXIMO 17 DE MARZO A LAS 12:30 HORAS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-03-02','(Pedro) Llamada de Manuel (677-716154) +++Quiere dinero, 300 euros, para ropa y dentista. +++ME PONE CON SU PADRE, D. Manuel (657-656184). +++++Al parecer tuvo que ir a recogerlo el viernes a Badajoz y pregunta si la Comisión Tutelar no se ocupa de mantenerlo en Mérida. Quedo pendiente de consultar la situación para dar una respuesta. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Amalia/Pedro). Conversación con D. Manuel, padre de Manuel. +++Se le explica que lo ocurrido es que se ha expulsado a su hijo de la c.T. de"Padre Cristóbal" por incumplimiento de las normas. +++Se le informa de que se va a llevar a cabo una subcomsión de casos lo antes posible para buscar el recurso más adecuado a su hijo. DE momento dice que se quedará en su casa hasta que le encontremos el recurso. +++Comprende o parece comprender nuestras explicaciones, y nos osfrece su apoyo para tratar de convencer a su hijo de que debe aceptar y cumplir las normas del lugar en el que resida. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Amalia /Pedro). Llamada de Manuel (hijo). +++Tratamos de que copmprenda el motivo de su "expulsión" y reconoce que son cosas que pasan en la convicencia. +++Marchó a Badajoz para buscar un piso compartido con estudiantes que no ha llegado a encontrar. Le explicamos quesin su colaboración ningún recurso va a aceptarlo y que finalmente terminará viviendo en la calle. Le comentamos que hemos estado hablando con su padre y que se ha ofrecido a acogerlo en su casa hasta que podamos encontrar un lugar adecuado para él, pero él dice que "...YO NO QUIERO ESTAR EN MI CASA..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2020-03-02','Ana: Comprobamos en SIDEX: Félix se encuentra pendiente de gestión de cita de valoración de dependencia. //// *Se lo comuncio a Paula, T.O. CRR-Plas., mediante email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2020-02-20','Ana: Reunión en Mérida con Paula, Javier y Blanca del CRR-Plas. Preguntan por la valoración de dependencia de Félix. Él querría irse a una Residencia de Mayores en la zona de Plasencia y alrededores. *Preguntan tambien por la Herencia de Félix, pues es una demanda suya. **SE lo comentaré a Ángel, asesor jurídico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-03-02','Buenos días Amalia. Soy Angélica( T.O. CSS MERIDA ) Te informo de que el jueves expulsaron a mi primo del centro de Mérida y se fue a Badajoz, de donde le expulsaron también. Me he enterado porque el sábado por la mañana me llamó la trabajadora social del Padre Cristobal para decirme que allí ya no estaba y no sabían donde se localizaba. El caso es que estaba en la calle en Badajoz desde el viernes. Me puse en contacto con mi tio y le dije que fuese a recogerle, que la calle no es un sitio para que esté. Creo que no tener un lugar donde estar, un vinculo, le está poniendo fatal. Si quieres comentamos luego por teléfono. Me gustaría saber si la gestión de emergencia social se ha efectuado y que posibilidades hay ahora mismo para conseguir que se encuentre abstinente, ya que sin ayuda y en esta situación no lo va a hacer. Necesita apoyo especializado. Le dije a mi tio que os llamase esta mañana para comunicar que está con él. Te dejo mi teléfono 658229350 Chao...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-03-02','-Amalia: llama Manuel para decir que está en Moraleja 677716154','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-02-29','Buenos días Amalia Te informo que Manuel Domínguez Martín ya no se encuentra alojado en nuestro centro residencial. Se acordó mantenerlo un tiempo más a partir de que su compromiso con vivienda era hasta el día 21 pero tras un reiterado incumplimiento de normas y además mantener una actitud desafiante ante los compañeros, el Equipo valoró que con esa actitud no podía permanecer. Se marchó el jueves 27 pero desconocemos donde, se le ofreció las alternativas de otros centros pero no las aceptó. Para cualquier duda, puedes llamarme. Un abrazo. Inma Pulido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2020-03-02','-Amalia : Escribo a Inma Pulido , TS del CTro . Padre Cristobal : Buenos días , Te he llamado pero me indican que hoy no estabas . Entiendo la situación , sin su voluntariedad no podemos ayudarlo. Necesito que me envíes un informe indicando fecha de entrada y salida de vuestro recurso y brevemente cómo ha evolucionado su situación en el mismo . Tenemos que informar al Juzgado y nos lo piden también desde el SEPAD para valorar el caso a posible ingreso de piso supervisado. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2020-02-20','Ana: Reunión con Paula, Javier y Blanca del CRR-Plas.: Nos comunican que Emi tiene pendiente una intervención quirúrgica en Ba. Sería conveniente ponerle unas horas de acompañamiento hospitalario. Plantean, en el caso de que no se le pudiera poner, que al menos se le supervisara por parte de Futuex.','2');
