insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2020-03-02','TEREESA: Buenos días. Me pongo en contacto para comunicarles la salida de Libertad García a su domicilio este fin de semana. Se fue el viernes dia 28 y volverá hoy o mañana martes. Como les comenté en su día Libertad sigue mostrándose continuamente desafiante y sus conductas disruptivas alteran el desarrollo y funcionamiento del Centro y se han establecido salidas a su casa puesto que dichas salidas resultan beneficiosas para Libertad','2');
