insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='SANTOS'and apellido2='CORDERO'),'2020-03-02','miguel,tras hablar a primera hora con Rosa del Css de Plasencia, quién me comenta que irá finalmente el tutelado a actualizar la cartilla del banco, me llama Mariví, quién no entiende todo lo comentado estos días con Rosa. Me pone al tlfno al tutelado a quién le explico la situación actual: -Casa cuesta de la reina de Cáceres: entregada en Dación en Pago a Liberbank junto con las deudas que quedaron compensadas. -Casa calle General Margallo de Cáceres: comprada por el tutelado poco antes de asumir esta Comisión Tutelar el cargo de tutores. Le han girado una complementaria que nos remite Rosa del Css y que recibió un familiar el 19/2/2020 donde no se le reconoce lo abonado en concepto de ITP cuando compró la casa y por la que pagó 3.115€(compró por 35.000€). Ahora en la complementaria la Junta indica que el valor de mercado es de 77.292,95€, sin embargo no le han descontado lo que pagó y le reclaman 7.022,89€ (dicha complementaria me llega el 28-2-2020). Tras preguntarle a Miguel Santos si tiene mas cuentas me dice que no y que no ha abonado dicho embargo. Asimismo le comento que estamos pendientes de que la presidenta Ines le remita a Angel el proyecto de arreglos de la vivienda para ver cúal es la parte a abonar por él y al tiempo comenzar la reparación de la vivienda y elementos comunes. ********************************************************** Pido y me envían desde el Oar de Cáceres la Carta de Pago de la deuda actualizada del embargo que imprimo y doy a Juana (Alberto no ha venido hoy lunes. Una vez que me la de la sección económica la adjuntaré al modelo de pago de ITP que pagó en su día y contestaremos a modo de alegaciones (aunque fuera de plazo) *********************************************************','2');
