insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE PEDRO'and edp.apellido1='VILLEGAS'and apellido2='SERRANO'),'2020-02-28','miguel, tras la consulta de la sección económica sobre si sería o no posible la venta de la vivienda sita en c/ Sor Valentina Mirón 3, 2º B. Le comento que es la que esta alquilada y con una hipoteca que aparece en la nota simple por principal de 81.000€ por lo que no sabemos si está o no vinculada con la finca de su hermana fallecida Mª Cristina de la c/ zapateria 38, 2ªA. Es la inquilina (sobrina del curatelado) quién está interesada en la compra del inmueble. Compruebo el valor de mercado de aproximadamente 65.000€ según la página de la junta de valores fiscales, y por la zona hay precios de unos 59.000€ por lo que teniendo en cuenta los problemas económicos del curatelado, entiendo que deberíamos ahorrarnos hacer una tasación. ****************************************************** Por otro lado, Alberto y yo comprobamos online la oficina a que pertenece el ptmo (antiguo Banco de Castilla, después Banco Popular, ahora Banco Santander)y comprobamos que hay un único ptmo de 166.000€ de principal, por lo que hablaremos con la sucursal para intentar desvincular y cancelar el ptmo que afecta a la parte de la vivienda que se intenta vender de c/ Sor Valentina Mirón 3, 2º B, Plasencia','2');
