insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2020-03-03','(Pedro). Llamada de D. MARCELO ROMERO PÉREZ, primo 2º de Mercedes. Teléfono de CONTACTO: 686-415179 (trabaja en la Deleg. de Juventud del Ayto. de Lucena). Vive en Aguilar de la Frontera (Córdoba). Teléfono domicilio: 957-689012 (USAR SIEMPRE EL DEL MÓVIL, SALVO CASOS EXCEPCIONALES). +++Mercedes está llamándolo constatemente, porque "...soy la única persona de la familia que le hace un cierto seguimeinto de su situación.Jesús, su primo abogado, está ya quemado por ella y el resto de la familia no quiere saber nada. +++Desde hace 2-3 semanas le está diciendo que SE QUIERE IR A VIVIR A MÁLAGA: "...Mé ha pedido el teléfono de una antigua amiga de juventud, a la que no ve desde hace años, y que vive en Fuengirola para llamarla...No le he dado ningún teléfono porque yo sé que tiene una curatela económica y no sé si ella puede tomar decisiones como ésta, más allá de lo puramente económico..." +++Hbalaremos con Mercedes y le planteo la posibilidad de contactar con él en caso de que lo considermeos necesario. Está de acuerdo con ello.','2');
