insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='MORATO'and apellido2='PICADO'),'2020-03-03','Ana: Recibimos Informe Urbanístico de los Servicios Técnicos Municipales del Ayto. de Valencia de Alcántara, referente al estado de la vivienda de Manueal: "...se hace necesaria una intervención en la cubierta y en los falsos techos, con el fin de mejorar las condiciones de salubridad de la vivienda y que con las lluvias de este próximo invierno, podrían agravarse." /////////////////////////////////////////////// Envío un correo a Toni-Futuex, solicitando nos hagan llegar al menos 2 presupuestos de obra. Le envío adjunto el informe técnico municipal, para que los presupuestos los elaboren en base al mismo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-02-27','TERESA: REUNION PI ZAFRA EL EQUIPO QUE TRABAJA CON NATALIA FORMADO POR M0NITORES EUDCADORA Y DIRECTORA DEL CENTRO NOS TRALADA- - NATALIA TIENE UNA CODUCTA DELICTIVA ADQUIRIDA EN SU INFANCIA POR LA FAMILIA QUE HA TENIDO SIENDO ESTA MUY DIFICIL DE MODIFIVAR -TIENE MUCHAS HABILIDADES Y ES INTELIGENTE CON LO CUAL MIENTE Y MANIPULA MUY BIEN LAS SITUACIONES- -HA SUFRIDO MALTRATO TANTO FISICO COMO PSICOLOGICO -DESDE EL EQUPO SE HACEN REUNIONES SEMANALES PARA INTERVERNIR Y PONER REFUERZOS POSTIVOS PARA MEJORAR LA CONDUCTA DE NATALIA LOS CUALES NO HAN DADO RESULTADO -EN EL CENTRO SUFREN ROBOS, AGRESIONES Y DISCRIMIZACION POR PARTE DE NATALIA -HACE MAL SIN NINGÚN FIN NI BENEFICIO -LA ABUELA PATERNA ES UN PUNTO DE APOYO AUNQUE A VECES NO COLABORA . SIENTE DESCONFIANZA DE LOS PROFESIONALES QUE HAN TRABAJADO CON NATALIA ANTERORMENTE -EL CENTRO NO POSEE LOS MEDIOS PARA CONTROLAR LAS CONDUCTAS DE NATALIA. LAS QUE LLEVAN TRABAJANDO ESTOS 5 AÑOS NO DAN RESULTADOS -PEDRO PLANTEA: -DENUNCIAR SUS ACTOS -PLANTEAR LOS PROBLEMAS DEL CENTRO A DISCAPACIDAD -REUNION CON LA ABUELA PARA EXPLICARLE LAS FUNCIONES DE LA CTAEX, SALIDAS DEL CENTRO, COORDINACIO DEL CENTRO CON LA ABUELA. -HACER SALIDAS SIEMPRE SUPERVISADA -RESTRINGIR LAS LLAMADAS PARA EVIAR LOS CONTACTOS CON LA MADRE ----------------------------------------------------------- MANTENEMOS UNA ENTREVISTA CON NATALIA A SOLAS LE EXPLICAMOS QUE ES LA CTAEX Y LE TRASLADAMOS LA PREOCUPACION POR SU COMPORTAMIENTO. ELLA NOS CUENTA QUE LE HA ROBADO ROPA A UN COMPAÑERO PORQUE ESE COMPAÑERO LE HABIA AMENAZADO, QUE SE BAJO EN SANTA MAARTA PARA VER A SU MADRE PORQUE ELLA QUIERE VER A SU MADRE. - LE COMENTAMOS LAS CONSECUENCIAS QUE PUEDEN TENER SUS COMPORTAMIENTOS .CAMBIAR DE CENTRO .DEJAR DE VISITAR A SU ABUELA .DENUNCIAR A LA POLICIA .DEJAR DE REALIZAR LLAMADAS ACORDAMOS REUNIRNOS CON LA ABUELA EL PROXIMO 6 DE MARZO NOS COMENTA QUE ESTA ESCRIBIENDO UN LIBRO SOBRE SU VIDA Y QUE ESTA SEMANA HA ESTADO MAL PORQUE NO HA PODIDO VER A SU ABUELA. NOS DICE QUE NO LE DEJAN HABLAR CON LA COMISION TUTELAR Y QUE QUIERE MANTENER CONTACTO CON SU PADRE. C0NFIESA QUE SU MADRE LE PIDE DINERO Y ELLA LO ROBA PARA DARSELO. NOS DESPEDIMOS DE ELLA Y QUEDAMOS PENDIETE LA REUNION CON LA ABUELA PARA CERRAR ACUERDOS','2');
