insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-02','Ana: Llamo a Susana, TS del Centro Residencial Hptal. Santiago de Zafra (607 33 19 63): Dado que la plaza en UHDAC va a tardar más de lo que no dijeron en un primer momento y más importante *Pilar se está adaptando bien al centro, no ha manifestado ninguna alteración de conducta desde que ingresó, nos proponemos comenzar a tratimar; Solicitud de Valoración de Dependencia, Revisión del Grado de Discapacidad y Solicitud de plaza en centro por Decreto. *Susana pedirá informe a la Psicóloga del centro y al médico de atención primaria los Informes correspondientes. **En cuanto al tipo de plaza, Susana opina que a día de hoy, ve más a Pilar para RAE, que para RAL, pues ha estado usando pañales por las noches y la tienen que guiar en todo. ////////////////////////////////////////////// En conversaciones mantenidas con Soraya Masa, Jefa de Ud. de Programas Asistenciales, así como con Maite y Maribel (Secc. Acceso a Recursos de Discapacidad) se acuerda proceder de la misma manera.','2');
