insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-04','Ana: Cumplimento y pongo para firma del D.Gerente, la Solicitud de Valoración de la Ley de Dependencia. ///////////////////////////////// Llamo a Javier Monago, PNC (927 00 43 42), acordamos que le comunicaré por mail (javier.monago@salud-juntaex.es) los cambios en la situación de Pilar (tutela provisional, residencia actual y solictud de PNC) y le pediré nos envíe el Certificado Telemático del Subsidio de Garantía de Ingresos Mínimos (SGIM) de la LISMI que viene percibiendo. /////////////////////////////////// Recibo correo de Susana, TS del Hptal. Santiago, me solicita que le envíe el modelo de informe médico que hay que adjuntar a la solicitud de plaza en centro, pues no lo tiene y quiere llevarlo al médico por si acaso. *Lo escaneo y se lo envío.','2');
