insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-03-04','(Amalia/Pedro). Reunión en la CTAEx con Javier Pecero y Cristina, Director y Psicóloga del CRR de Mérida. +++La Comisión se va a presentar como parte en el procedimiento abierto por un presunto delito de abusos. CITACIÓN: 31 DE MARZO A LAS 10:00H Juzgado de 1ª Instancia nº 1 de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-03-04','(Amalia/Pedro). Reunión en la CTAEx con Javier Pecero y Cristina, Director y Psicóloga del CRR de Mérida. +++Se plantea la posibilidad de solicitar nueva subcomisión de casos.En caso necesario, llamar al 112 y denunciar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-03-04','Se comunica al Juzgado de 1ª instrucción nº 2 de Zafra el traslado de Ildefonso a Cataluña y se remite cambio de expedeinte a esta comunidad para el cumplimiento de la medida de trabajos a la comunidad. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamada de Ildefonso desde Blanes. +++"...Hola, Pedro. Tenemos un problema y necesitamos que liberéis una partida presupuestaria para poder alquilar un piso por aquí, porque no tenemos donde quedarnos...-le planteo que busquen un hostal o un albergue-De momento tenemos dinero para unos días..." +++Preguntado por la amiga de Joaquina con la que se iban a quedar según nos dijo a Alberto y a mí comenta: "...Nos ha fallado. No tiene problema en acoger a Joaquina pero a mí sí..." +++"Queremos alquilar un piso pero necesitamos dinero para ello...." Al respecto le comento que si quieren buscar alquiler lo haga, pero que no se le ocurra firmar nada sin antes haber revisado la Comisión el contrato...". En cualquier caso, he de hablar con Alberto al respecto. +++Le recurdo que se tiene que presentar para iniciar los trabajos en beneficio de la comunidad el próximo día 20 de marzo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2020-03-04','TERESA ayer fue imposible que Adolfo fuera visitado por el forense como se detalla a continuación: el pasado 3 de Marzo se visita a Adolfo en su domicilio y se le recuerda que tiene cita en los juzgados a las 13:15h. Después de media hora de preparación, se sale de la casa y se le lleva a los juzgados en coche. Una vez que entra en el edificio, se empieza a poner nervioso y se pone a hablar con el guardia de seguridad porque le conoce, le pregunta que por qué tiene que estar él allí y que no entiende por qué le han citado. Él le comenta que no se ponga nervioso y que suba a la primera planta para hablar con la forense. Se sube a la primera planta con él y se intenta charla de otros temas para que se relaje, pero se va de una habitación a otra hablando y preguntando a todo el que se encuentra por los pasillos, hasta que sube el guardia de seguridad para intentar relajarle. Hablamos con él otro rato pero Adolfo empieza a decir que se va, que no quiere estar allí porque no es ningún delincuente y porque le da vergüenza que le vean en esas dependencias. Aunque se intenta razonar con él y comentarle que él no ha hecho nada malo y está allí por un mero trámite, no quiere escuchar y se dirige a la puerta de la calle. Se va detrás de él hasta la misma y se le comenta que puede quedarse un rato fuera tomando el aire para tranquilizarse, a lo que contesta que él se va a su casa y que le dejemos tranquilo y no le hablemos más del tema. Seguidamente se habla con la forense y con la juez, para comentar lo sucedido y la forense pregunta el estado generalizado del tutelado estos dos últimos años. Se le cuenta el estado tan grave en el que se encuentra y que puede verse agravado por la reciente muerte de su madre. La forense, Ana, sale a hablar con la juez y pide que se la espere un momento. Cuando regresa comenta que para el proceso de internamiento involuntario es necesario que la juez lo vea, por lo que comenta que volvamos el martes día 17 de Marzo, para hablar con ellas dos. Se le comenta que va a ser difícil llevarle de nuevo porque se va a negar, pero intentaremos disuadirle de algún modo. La forense incluso facilita su teléfono para que se la llame en el momento en el que se esté cerca de los juzgados, el martes 17, para bajarse abajo con la jueza y aunque sea hablar con Adolfo en el vestíbulo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2020-03-04','TERESA SE ESTABLECE CUOTA DE BOLSILLO 225€ QUINCENALES ACOMPAÑADA DELEGADA TUTELAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2020-03-04','Ana: Recibo correo de ASPACE (maria.gonzalez@aspacecaceres.es): "Estimada Ana, Soy María González, trabajadora social de ASPACE Cáceres (junto con mi compañera Amor). Ella ha estado gestionando el caso de Eduardo Santiago, pero me lo han derivado. Quería aprovechar este correo electrónico para presentarme y ponerme a su disposición. El motivo concreto de este email es que la silla de Eduardo Santiago se ha estropeado y el arreglo cuesta 120€. Necesitaría autorización para que puedan arreglársela. Quedo a la espera de su respuesta Un cordial saludo -- María González Barroso" ////////////////////////////////////////////////////// Se lo paso a Alberto, secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-03-04','Ana: Saturnino Miguel ha llamado a Pedro, Jefe de Secc. Éste le ha notado un tanto alterado, enfadado, exigente y con elebada verborrea. Llamo a Pilar, TS ESM-CC (54612): Está liada con otra cuestión, me llamará mañana. //// Llamo a Rosario, enfermera (54609): dice que Saturnino tiene cita con el psiquiatra el día 6 a las 10:10 h. *Finalmente sí se puso el inyetable (27/01/2020). *Le va a llamar para recordarle la cita que tiene pasado mañana. ////////////////// Vuelve a llamar pasados unos minutos, con el manos libre hablamos Pedro, Jefe de secc. y yo con ella. No ha conseguido hablar con Saturnino, le ha comunicado a la madre la cita del viernes. No sabe si acudirá. Rosario dice que Saturnino no está en condiciones de vivir solo, que tendría que estar en algún recurso residencial. La CTAEX debería hacer algo. Y no está de acuerdo en que si él no quiere que no pueda acceder a CRR ni a Pisos Supervisados, pues está tutelado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-03-04','Ana: Juan Pedro, Director del C.A.M. Francisco Pizarro de Trujillo, acude a la CTAEX, a preguntar "cómo va la adjudicación de plaza de Aitor". Le comunico que precisamente hoy se ha puesto para la firma del D.Gerente el Acuerdo de Aceptación del Cargo de Tutor. De las plazas nosotros no sabemos nada pues ni lo hemos solicitado ni las gestionamos. Le acompaño a hablar con Maite, Secc. acceso a recursos de Discapacidad. Maite nos informa de que ya tienen perfil del CADEX, pero aún está pendiente la adjudicación de plaza. *Llamaré a Juan Pedro si hay alguna novedad al respecto. Él se lleva anotado mi teléfono también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-04','TERESA LLAMAMOS AL CENTRO PARA PREGUNTAR QUE TAL HA IDO LA SEMANA DE NATALIA CHARO LA DIRECTORA DEL CENTRO NOS COMENTA UN INCIDENTE OCURRIDO EN LA TARDE NOCHE DEL DOMINGO: CITO A UN USUARIO CON UNA GRAN DISCAPACIDAD A ENCONTRARSE CON ELLA EN EL BAÑO, UNA VEZ ALLI LE OBLIGO A DARLE DINERO Y ACTO SEGUIDO TRAS HACER SUS NECESIDADES NATALI LE OBLIGO A UNTARSE EL CUERPO CON SUS HECES. HIZO JURAR A LA CUIDADORA QUE NO LE IBA A DECIR NADA A LA DIRECTORA NATALIA CONTINUA CON LA LLAMADAS TELEFONICAS A ESCONDIDAS UTILIZANDO MOVILES DE LOS USUARIOS CONTINUA UTILIZANDO SU TECNICAS Y HABILIDADES HASTA TAL PUENTO QUE HA CONSEGUIDO DIVIDIR AL EQUIPO DE CUIDADORES AMPARANDOSE EN SU VICTIMISMO Y EN LA PENA CHARO PONE DE MANIFIESTO QUE HAN SIDO DEBILES ANTE LAS CONDCUTAS DELICITIVAS DE NATALIA UTLIZANDO SIEMPRE EL REFUERZO POSITIVO PARA RECONDUCIRLAS NO CONSIGUIENDO QUE LA ACTIUTD DE NATALIA CAMBIE ANTES ESTOS HECHOS TIENA UNA GRAN CAPACIDAD PARA MANIPULAR A TODOS LOS USUARIOS INCLUSO AL PERSONARL DEL CENTRO PARA CONSEGUIR SUS PROPOSITOS A TODA COSTA.','2');
