insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-03-04','Ana: Correo de Toni-Futuex: "Buenos dias, te cuento en la hoja de incidencia adjunta, nueva situacicón de Desideria Barbero de la que fuimos conocedoras ayer, y que trataremos de obtener mas información, pero que implica una recontextualización de la intervención que estabamos planteando con ella... hoy ibamos a quedar para ir a intentar reitar la asignación mensual, ya que estaba en vias de realizarse y de paso hacerles un seguimiento, cuya sorpresa la nuestra al comunicarnos que hoy no podia ser, pq se ibaan a comprar un piso.... bueno se lo va a compar Angel, ya que ella es consciente (o eso parece) que no puede... todo esto lo han hecho por su cuenta, en el sociosanitario, Mariví se enteró tambien ayer,... si lo conocian otros profesionales que intervengan con Angel, lo desconocemos.. asique parece que esta actuacion de producirse está enmarcada en la linea que viene marcando desde hace tiempo su patología respecto a cambiar sistematicamente de casas, comprar, vender, alquilar.. y en esa linea trataremos de ir la semana que viene y obtener mas información y te voy contando!" ///////////////////////////////////////////////// Unos días antes habíamos recibido un escrito de Desi pidiendo que se le deje usar su dinero para la compra de un piso en Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PAREDES'and apellido2='HERNANDEZ'),'2020-03-05','Te adjunto los documentos en nuestro poder de Antonio Paredes Hernández. El informe social lo registro junto con esto cuando me llegue el requerimiento, ¿te parece, o te lo adelanto? Por otro lado, te confirmo que es beneficiario de plaza T3 y su precio público es de 427,19 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-03-05','Ana: Correo de Estrella, TS CSS (estrella.duranc@salud-juntaex.es): "...Con respecto a Juan, solo lo he visto un momento en el pasillo de la unidad, que quería verme por tema de la ropa y el dinero. Se mostraba afable con el resto de profesionales que ya conocía de otras ocasiones en que ha estado ingresado. Conmigo correcto. Se quejaba de la C.T.A, de que le robaban su dinero...." ***Me remite también escaneados el informes de alta de la UHB por traslado a centro y de Derivación a UME. *Guardo en el expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2020-03-05','miguel, se suspende la vista del día 31/3/2020 que nos habían citado desde el Jzdo nº1 de Mérida hasta que nombren abogado y procurador de oficio (tal como les solicitamos por fax)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-05','TERESA:RECIBO LLAMADA DEL ABUELO DE NATALIA, MARIDO DE PILAR ABUELA PARTERNA (642 1010 15) COMIENZA HABLANDO DE LOS PROBLEMAS DE CONDUCTA DE SU NIETA Y LA EXCUSA DICIENDO QUE TIENE UNA ENFERMEDAD. COMENTA QUE LA DIRECTORA LE HA DICHO QUE TIRA LA TOALLA Y ELLA SE MUESTRA ENFADADA POR ESE COMENTARIO COMENTA QUE HACE CUATRO SEMANAS QUE NO VE A SU NIETA PORQUE HA ROBADO ROPA A UN COMPAÑERO Y HA TENIDO DISCUSIONES Y POR ELLO NO LE HAND DEJADO SALIR EL FIN DE SEMANA. LA ABUELA AFIRMA QUE EN SU CASA SE PORTA BIEN NORMALMENTE¡¡¡¡ NO PRESENTANDO AGRESIVIDAD ADEMAS COMENTA QUE NOTA QUE DESDE EL CENTRO NO QUIEREN QUE NATALIA HABLER CON SU ABUELA NI LE CUENTE LAS COSAS QUE PASAN EN EL CENTRO. DICE QUE NATALIA LE CONTO A LA ABUELA QUE UNA COMPAÑERA LE QUISO AGREDIR Y ELLA SOLO PUSO LAS MANOS PARA DEFENDERSE. INSISTE QUE NO SABE EL MOTIVO POR EL CUAL LLEVA VARIAS SEMANAS SIN VERLA QUE DESDE EL CENTRO NO LE HAN COMUNICADO NADA. NOS HABLA DEL DIA QUE SE BAJO EN SANTA MARTA, INSITE QUE SOLO SE BAJO PARA ORINAR Y QUE DESDE ESE DIA VIENEN LOS PROBLEMAS Y NO HABLAN CON ELLA. LA ABUELA NO CREE QUE HAYA ESTADO CON LA MADRE Y AFIRMA QUE NO TEINEN RELACION CON LA MADRE NATALIA EN LAS SALIDAS VA A VER A FAMILIARES PERO SIEMPRE ACOMPAÑADA POR LA ABUELA Y NO VE A LA MADRE HACE MUCHO TIEMPO. LA ABUELA AFIRMA QEU NATALAIA SIEMPRE ESTA CON "LA COSA" DE VER A SU MADRE A PESAR DEL DAÑO QUE LE HA HECHO PERO WUE A ELLA NO LE PIDE QUE QUIERA VER A SU MADRE COMENTA QUE LA LLEVA A VER AL ABULEO MATERNO A SU CASA Y ELLA LA ESPERA ABAJO MIENTRAS HACE LA VISITA (NOS QUEDA LA DUDA SI EN ESA VISITAS PUEDE ESTAR LA MADRE Y NO SABERLO)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALVARO'and edp.apellido1='GONZALEZ'and apellido2='ALVAREZ'),'2020-03-05','Ana: Recibimos escrito de la Subdirección de Salud Mental solicitanto INFORME COMPLEMENTARIO que justifique la inclusión en el programa para pacientes con necesidades asistenciales especiales. //////////////////////////////////////////// Llamo a Teresa, Novaforma (662 337 460); también han recibido la carta. Pero no saben muy bien qué informe es que se requiere. /////////////////////////// Llamo a la Subdirección de Salud Mental (22944), Maribel, Psiquiatra, no está. Marian, la compañera que me atiende intentará averiguar qué tipo de informe es el que se necesita y me devolverán la llamada. ///// Marian me llama y comunica que en la solicitud presentada sólo han adjntado una historia clínica resumida del médico de atendción primaria, en el que no aparece claramente el retraso mental. *Pueden solicitar un informe al medico de att. primaria que lo aclare y/o un informe del especialista de la última consulta a la que haya acudido. //////////////////// Vuelvo a llamar a Teresa-Novaforma, como no está le dejarán nota para que me devuelva la llamada.','2');
