insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2020-03-06','Ana: Llamo al CRR-CC (927 18 11 09), Pedro, T.O., dice que Consuelo parece estar algo más tranquila, pero continúa con altibajos, dependiendo del estado anímico del día, vuelven o no sus delirios y referencias al suceso, por ejemplo, si tiene alguna desavenencia con algún/a compañero/a o se siente mal, reaparece. No obstante consideran que a día de hoy NO haya riesgo de nueo intento autolítico. /////////////// En cuando al informe pendiente para la rendición anual, no está seguro si se envío, lo hablará luego con Cristina, Psicóloga, y nos enviarán informe.','2');
