insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-06','Ana: Recibo llamada de José Luis (687 581 061), hermano de José Manuel, solicitando que llame a su hermano a demanda de éste. //////////////// Llamo a José Manuel (667 384 817), vuelve a preguntar la manutención de sus hijos, por el acceso a centro (dice que aunque sea le "envíen a Plasencia" y añade que hoy ya no tiene para comer. *Vuelvo a decirle que acuda al comedor social, se lo va a pesnar e igual hoy pasa por allí. ////////////////////////////////////////////// Pregunto a Ángel-CTAEX, por la solicitud de modificación de la medidad (pensión de alimentos): Le reclamaron al Colegio de Abogados, porque el Abogado que designaron de oficio no ha hecho nada. Llamará al Colegio de abogados. //////////////////////////////////////////// Llamo a Pilar, TS ESM-CC (54612): el Dr. Juan Pedro Jiménez Cano, Psiquiatra, no quiere hacer ninguna otra derivación de José Manuel. Pilar dice que si queremos que le llamemos al él directamente. (Nº del centro: 927 21 37 30)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2020-03-06','miguel, hablo por tlfno con el Juzgado nº1 de Zafra y me comentan que el procedimiento 475/2019 sigue en instrucción, donde el forense había pedido dar traslado al Fiscal y ahora se dará traslado de nuevo al forense. Nuestra tutelada es parte acusada, siendo el denunciante su padre. Se le irá nombrando abogado de oficio conforme vaya necesitandolo en caso de que no se archive el procedimiento (no se sabe si el juez lo archivará en base a su inimputabilidad)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-03-06','Ana: Llamo a Pilar, TS ESM-CC (54612), ha hablado con la Dra. Guadalupe Espárrago. Saturnino ha acudido hoy a la consulta y sí que lo ha notado más alterado, pero le ha dado una nueva cita de seguimiento. Pilar le ha facilitado mi número para que nos llame ella directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-06','(Teresa/Pedro)Reunión con el Equipo Técnico de Plena Inclusión Zafra y los abuelos paternos de Natalia, Dª Pilar y D. Juan.CONCLUSIONES. +++SALIDAS al domicilio de los abuelos paternos: dadas las circusntancias ocurridas hace algunos días (se bajó del autobús en Santa Marta de los Barros cuando volvía a Zafra, no sabemos cual de las razones esgrimidas para ello son las verdaderas o si lo son alguna de ellas), se decide permitir la salida estre fin de semna con la condición de que el domingo vuelva al centro acompañada por los abuelos. Esto se repetirá de la misma forma durante una temporada, ya sean semnales o quincenales dichas visitas (siempre que los abuelos se comprometan a ello) y con la condición inexcusable de que durante la semana el comportamiento de Natalia, a juicio de los profesionales del centro, sea merecedor de ello. +++La desconsfianza existente por parte de los abuelos paternos hacia el centro creeemos se ha visto cuestionada por la propia Natalia, cuando ella misma ha reconocido que su comportamiento no siempre es el que ella expresa +++Esta desconfianza también es manifiesta debido a ello del centro hacia los abuelos. +++A pesar de dicha desconfianza por parte de los abuelos, ni Natalia ni ellos quieren que se traslade a otro centro, reconociendo por su parte que simpre la comunicación con P.I. ha sido fluida y han respondido a su petición de ayuda cuando así lo han requerido del centro. +++Por otro lado, el Equipo de P.I reconoce no saber ya qué estrategias aplicar en el caso de Natalia, reconociemdo haber tirado la toalla en este caso. Son conscientes de que la falta de consecuencias ante el comportamiento de Natalia ha contribuido al mantenimeinto de su comportamninento y que en ocasiones el mismo hubiera sido motivo de denuncia para protegerla no solo a ella sino al resto de ususarios. +++El centro plantea la posibilidad de derivar a Natalia a una vivienda tutelada donde pueda convivir con otros usuarios de capacidades similares, lo cual podría contribuir a un cambio de su conducta (deseable pero ¿posible?).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-06','Ana: Envío por email CI para GASTROSTOMÍA ENDOSCÓPICA PERCUTÁNEA debidamente firmado y sellado a Victoria, TS del Hptal. Don Benito-Vva. tal y cómo lo han solicitado.','2');
