insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2020-03-09','miguel, hablo con el Jzdo para el procedimiento del lunes 16 y me indican que han aceptado la videoconferencia pero no tienen aún confirmación de jzdos de Mérida, les doy tlfno de Scace para que confirmen con ellos. Por otro lado consultaran con su letrado la solicitud que les hacemos de que nombren abogado y procurador de oficio por cuanto su letrado lo ha denegado (le explico que por conflicto de intereses la abogacía de la Junta no puede ser parte demandante, en nombre del CSS de Plasencia y demandada en representación del tutelado). Lo hablará con el Letrado y nos dirán','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2020-03-09','miguel, llamo al jzdo nº2 de Coria para confirmar si tienen nombrado o no abogado de oficio, me comentan que no, y les indicó que será necesario sea nombrado de oficio abogado. *************************** De todas formas han suspendido el procedimiento hasta el 8/4/2020. Me indica que nos notificarán en un rato dicha suspensión y consultará lo del nombramiento de oficio de abogado.','2');
