insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2020-03-09','Ana: Nuevo correo de Mª Jesús Gómez, TS - SSAB Mancomunidad Comarca de Trujillo: El certificado de pensiones que le envié es el de 2019. Tras revisar compruebo que es el único que teníamos, no hemos recibido el actual. Se lo comunico por mail y aprovecho para recordarle que no hemos recibido Informe Social para la Rendición Anual. ///////////////////////////////////////////////////////////// Recibo llamada de Mª Jesús Gómez, TS (927 31 50 82), cree que ya solicitaron cambio de centro por la Ley de Dependencia. Me pide que averigüe yo cómo está la situación. /////////////////////////////// Compruebo en SIDEX con Julio-CTAEX, la solicitud de cambio de centro por PIA se realizó en abril de 2016, no hay nada más a posteriori.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-03-09','(Pedro)conversación con Marisa, T. Soc. del CEDEx de Mérida (924-300862///84792///84772). +++Jonathan acudió el pasado viernes al CEDEx si se le puso tratamiento con metadona. Tiene que acudir tres días en semana. +++Pido a Marisa que nos comunique cualquier incidencia en el tratamiento. Dejo mi téléfono y el de Amalia, además del correo de ctutelar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-02-20','Ana: Realizo llamada a Ivonne, Directora del C. Día de Valencia de Alcántara (Residencia C. Día San Pedro de Alcántara: 927580624 // Res. Buenos Aires: 927 58 24 22). Ivonne expresa que no es posible realizarle el aseo en C. Día, no pueden hacer ninguna excepción. Plantea la opción de que fuera al centro en el segundo turno de la mañana (Hay dos turnos de transporte, a las 8:30 comienza una ruta y a las 9:15 la segunda) de modo que a través de SAD se le pudiera realizar el aseo antes de que le recogieran en su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-09','Ana: Recibo llamada de Pilar Sánchez, Hogar San Vicente de Paúl (671 016 615). Necesitan un C.I. para realizar a Margarita un Resonancia Magnética. Se la van a realizar en la Clínica Privada San Miguel de CC. Les pido que nos lo hagan llegar por fax o correo electrónico para que lo suba a la firma. Se la devolveré por el mismo medio. //////////////////// **La prueba se la van a realizar porque desde la consulta del oftalmólogo, viendo que no mejoraba la visión con ningún cristal (modificando la graduación) le derivaron al Neurólogo. Éste a priori no cree que tenga ningún problema de tipo neurológico, pero por descartar ha decidido hacerle la resonancia. //////////////////////////// Tras recibir el CI, lo subo a la firma del D.Gerente y lo devuelvo por fax. *A posteriori se lo paso a los compañeros admvos. CTAEX, para que remita los originales al Hogar San Vicente de Paúl, tal y como me ha solictado Pilar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2020-03-09','miguel,ha habido una equivocación por parte del jzdo de lo penal nº2 de Mérida (que actúa por exhorto del jzdo de lo penal nº1 de Plasencia), ya que a quién querían citar es al tutelado. Al encontrarse en el centro penitenciario módulo de psiquiatría de Sevilla, doy al jzdo de lo penal nº2 de Mérida dichas indicaciones para que citen a este tutelado a efectos de que lo citen para conocer su opinión sobre las medidas de internamiento adoptadas en ejecución nº 643/2018 del procedimiento penal por delito de abusos sexuales.','2');
