insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2020-03-09','Ana: Recibo llamada de Reme, de Menores CC (927 004 362). Pregunta si ya hemos aceptado la Tutela y pregunta por el acceso de Aitor a centro de discapacidad. Le informo que ya hemos aceptado el cargo y que los compañeros que se encargan de ello han comenzado a solicitar a los distintos recursos competentes la documentación para realizar el inventario y poder comenzar a intervenir. *En cuanto a la plaza en el centro, le comunico que desde la Secc. de Discapacidad me han traído el modelo de solicitud de centro, pero aún no tengo ni siquiera el DNI. En cuanto lo tengamos lo cumplimentaré y lo pondré para la firma del D.Gerente. *Dice si desde aquí no podemos hacer "presión" para darle prioridad, pues ya ha cumplido la mayoría de edad. Le explico el funcionamiento. Dice que con respecto al Centro de Menores, no saben bien cómo actuar pues ya no tienen la tutela. Le explico que a efectos prácticos es lo mismo, la Tutela la sigue teniendo la Junta de Extremadura, ahora el Sistema de Protección de Adultos en lungar del de menores. En el Centro, a día de hoy, siguen siendo Guardadores de hecho. **Plantea una reunión en la CTAEX a la que vendría ella, una educadora del CAM y el propio Aitor. Acordamos que para la última semana de marzo. Se pondrán en contacto para confirmar. ///// Aitor presnta 67% de discapacidad reconocida por el CADEX.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-03-09','Ana: Llamo a la Dra. Guadalupe Espárrago (54605) a distintas horas a lo largo de la mañana sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SOLEDAD'and edp.apellido1='ACEVEDO'and apellido2='GALLEGO'),'2020-03-10','TERESA SE AUTORIZA ACOMPAÑAMIETO HOSPITALARIO CON LA EMPRESA FIXET DE 8 A 22 HORAS, INGRESO EL MARTES 3 DE MARZO, 10 ERUOS LA HORA SALVO EL FIN DE SEMANA QUE ES A 12 EUROS. TOTAL SEMANA 1036 EUROS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2020-03-10','Ana: Llamada de Estrella, TS CSS-Plas. (24146), a lo largo de la mañana intentarán llamarme para que hable con Juan. /////////////////////////////////////////////////// Más tarde recibo llamada del CSS, me pasan con Juan, está más tranquilo que la última vez que hablamos. Dice que ha dado con un buen médico, el Dr. Pizarro, que le han retirado el inyectable, que a él le hacía mucho daño y le han reajustado la medicación oral. Continúa sin conciencia de la enfermedad, dice que él no tiene que estar allí y que le han dicho que en cuanto esté bien del todo podrá volver a su casa. Mantiene su delirio sobre el complot de la Dr. Consolación y el Dr. Medina y las medicamentos nazis.','2');
