insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2019-12-18','Ana: Informe de seguimiento de FUTUEX, fechas: 4, 13 y 16 de diciembre, recoge las quejas constantes por la asignación económica, dice que "se ve obligado a pedir como un mendigo", acude a las citas médicas y a ponerse el inyectable que tiene pautado, pero se niega a acudir acompañado. Higiene personal y del hogar: aseado, bien vestido, piso limpio y ordenado, fuerte olor a tabaco. Pasa el día tocando la guitarra en la zona turística de la ciudad pidiendo limosna. Valoración: personas conflictiva y exigente en general, no aceptan su situación, presenta alta resistencia al control o supervisión. El casero ha recibido quejas por parte de los vecinos por los ruídos que provoca Jesús por la noche con la guitarra. Jesús expresa contínuas quejas de las CTAEX y del ESM, según él es "víctima de una conspiración que inició su padre"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2020-03-02','-Amalia: ya he registrado solicitud cambio PIA para pasar a R.Mayores , ya tenemos autorizacion judicial de ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2020-03-10','TERESA RECIBO COMUNICACION DE PERDIDA DE CONDICION DE RESIDENTE CON FECHA 5/3/20, QUEDO PENDITE DE QUE SE CELEBRE EL JUICO DE REMOCION CON FECHA 17/3/20 PARA SOLICITAR PLAZA RESIDENCIAL EN EL CASO DE QUE SIGAMOS SIENDO TUTORES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2019-09-18','miguel, tras conversación con el Juzgado de 1º instancia e instrucción nº2 de Plasencia y tal como me confirmó Matilde, indicandome que el registro civil, donde debemos aparecer esta Comisión Tutelar de Adultos como tutores, es Albacete. Me confirma que ya ha comprobado ella que le han inscrito nuestra tutoria y portanto que ya podemos solicitar Certificado literal de nacimiento. ******************************************************** Remito al Registro Civil de Albacete Certificado literal de nacimiento. Cuando me llegue hay que remitirlo a la notaria de Villajososa, ya que es el último trámite para que se pueda firmar la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2020-02-13','Ana: Recibimos escrito de Ventura, pidiendo un extra de 200€ para comprar un traje de nazareno para salir en procesión en Semana Santa. Dado que lo acordado con él y el Juez, fue que se ampliaba la asignación pero que no se le darían más extras, no se le aprobará. //////// En el escrito comunica también que ha cambiado de compañía de teléfono y de nº: 682 483 126','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PAREDES'and apellido2='HERNANDEZ'),'2020-03-11','-Amalia : Me reuno con Tomás , Dtor. de Caser Olivenza , ocupa plaza T3 , abona 427€. Quedo pte. que podamos intervenir en sus cuentas , para pasar dinero a su mujer que reside en plaza residencial en El Torno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-10','Ana: Recibo llamada de Susana, TS del Centro Residencial Hptal. Santiago de Zafra (607 33 19 63): ayer estuvo en el médico, a priori éste no se mostraba proclive a realizar el informe, pues dice que no la conoce como para ello. Basándose en el informe del enfermero del centro residencial, finalmente accede a rellenarlo. La semana que viene podrán pasar a recogerlo. // Mañana tiene cita con la T.S. del SSAB, me pide el contacto de la TS del IMAS, por si le ocurre lo mismo que con el médico. No obstante ella le informará sobre la situación actual.','2');
