insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2020-03-10','Ana: Llamo a Mª Ángeles, Empresa de SAD Depend.ex. (927 22 15 02). Revisará el presupuesto y me enviará uno actualizado. Le informo de la necesidad de instar y supervisar a Julián en su aseo diario, la necesidad de poner lavadora una vez a la senana y del mantenimiento del hogar. Estamos a la espera de la previa limpieza exahustiva del domicilio. Le informo que la idea es que acuda a centro de día. Me enviará propuesta, en principio valoramos 1 h u hora y cuarto, y en función de las necesidades vamos viendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2020-03-10','miguel, me llama David (tlfno 626214908) vecino de Monroy interesado en la compra de la vivienda de la interesada. En tiempos llamó Jacinto Periañez (tlfo 654-486482) que es el vecino de Monroy que explota desde hace años las tierras de la tutelada. El único familiar que le queda es un primo de Madrid que es quién se puso en contacto en su día para que tramitaramos la herencia familiar y nos mandó libro de familia, varias cartillas, certificado de bienes firmado por el interventor del Ayto de Monroy del 2011, certificado de nacimiento de la tutelada... ********************************* La familia estaba compuesta por los padres y 3 hermanos a parte de la tutelada, y donde uno de ellos (Miguel) compró varios bienes. Al ser imposible de localizar certificados de defunción, y recabar todos los bienes de la familia, y teniendo encuenta que en el inventario aparecen varias cuentas de la tutelada con suficiente dinero, procederemos a delegar la realización de esta herencia a una gestoría del pueblo. ********************************** Pregunto al vecino que ha llamado (David) y éste hablará con la unica gestoría del pueblo para que se ponga en contacto con nosotros para darnos presupuesto. Una vez esté hecha la herencia intentaremos facilitar las ventas (previas autorizaciones judiciales)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-10','(Pedro)Conversación con Charo, Directora de Plena Inclusión Zafra (924-563092). +++El domingo volvió Natalia y salvo un pequeño roce con un compañero, al que no le han dado mayor importancia, no ha sucedido nada relevante. +++Comenta Charo que los problemas son más serios con los compañeros de residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2020-03-10','Viene Jonathan a la CTAEX, a traernos un aviso urgente del SCACE de Mérida, para que acuda a las dependencias judiciales a que comparezca para practicar diligencias de su interés. Le indicamos que vaya al Juzgado. Hablo con el SCACE y me indican que se trata de un procedimiento por delitos leves nº 189/19, seguido en el Juzgado de Instrucción nº 3, de Badajoz, en calidad de denunciado, junto con otras dos personas. El juicio está previsto para celebrarse el día 1/6/2020. Envío fax al Juzgado 924284334, solicitando nos informen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2020-03-10','miguel, llega el ministerio del interior que a petición del penado y curatelado por esta Comisión, se procede al traslado de su expediente de trabajos en beneficio de la comunidad al Servicio de Gestion de Penas y Medias Alternativas de Girona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILUMINADA'and edp.apellido1='DONCEL'and apellido2='LUCAS'),'2020-03-10','miguel, pendientes de firmar herencia en la notaria de Badajoz de Don Juan Manuel Angel Avila. Firmaremos como mandatarios verbales y posteriormente habremos de firmar en Mérida la ratificación. Los originales de todo junto con el certificado bancario de cuentas es lo único que le falta a la notaria y que se lo hará llegar la abogada Doña Inmaculada Nuñez Amigo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='PINILLA'and apellido2='CABALLERO'),'2020-03-10','Buenos días, Finalmente tras la salida de ángel a Badajoz, regresó como estaba previsto sobre las 6 de la tarde del pasado martes. El miércoles por la mañana mantiene un comportamiento muy maniaco y acelerado, por lo que nos vemos obligados a llamar al 112. Ante su intención de no colaboración se requieren los servicios de la policía, aunque tras mucho mediar con estos, acepta ir voluntariamente. Este mismo día se ingresa hasta la actualidad. Sabemos que ha pasado unos días regulares, ha habido cambio de medicación y parece que actualmente está un poco más tranquilo. El Psiquiatra que le está atendiendo es D. Alfredo De La Rubia. Seria importante que por parte de todos podamos hacer presión para que puedan valorar un posible traslado a UME y que logre estabilizarse. Para cualquier novedad seguimos en contacto. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-02-14','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es):"Buenos días, Ana. Paso a explicarte lo que se acordó ayer en reunión de UDAC, donde está Josefa ingresada. El 21 de enero vinieros de su centro de Zafra a recogerla para llevársela una semana, con objeto de ir viniendo la posibilidad del alta, ya que en la UDAC Josefa no presenta ningún tipo de alteración conductual. El día 28 de enero volvió del centro y se puso de manifiesto que Josefa no quería volver a la UDAC, pero tampoco a su centro de Zafra. Es por esto que nos planteamos ayer en la citada reunión, la posibilidad de darle el alta y que se vaya a casa con su hermano Rafael. Durante las vacaciones de Navidad estuvo en casa y realizó visita domiciliaria la Trabajadora Social del pueblo y vio que estaba bien, la casa limpia, ella estaba sola barriendo, ya que su hermano estaba en el campo. He hablado con su hermano y le parece bien probar a ver qué tal le va y si se descontrolara, según él se descontrola por la convivencia con la gente del pueblo que le dan consejos no siempre buenos, la traería otra vez aquí. Como ves no hay nada decidido, pero quería comentartelo porque la CTA también conociera y opinara al respecto." ///// Respondo que lo valoraremos en equipo y le diremos algo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2020-03-10','Ana: Correo de Estrella Durán, TS CSS-Plas. (estrella.duranc@salud-juntaex.es): "Ana, seguimos con el planteamiento de que se vaya de alta a casa, el último pase ha ido bien, según ella y su hermano. Así que, nos gustaría que nos dijeras cómo debemos proceder. Gracias. Saludos" //////////////////////////////////////////// Tras hablar con Amalia y Teresa, llamo a Estrella, TS, no le viene bien hablar en este momento. Me llamará mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2020-03-10','Buenos días, os informamos que la semana pasada nos llamaron desde el Sepad para comunicar que había una posible permuta de plaza del piso de Cáceres, y que Juan José Bergantiño había solicitado reiteradamente. Tras hablar con él y su evidente alegría, hemos trasladado al Sepad la aceptación. Por lo que en breve, se procederá al traslado de Juanjo a dicho recurso. Desconozco se desde el Sepad, al ser un tutelado vuestro os lo han comunicado y si tendréis que firmar algún documento. Os comunicaremos en cuanto tengamos la fecha exacta. Un saludo, Leonor Chamorro (Terapeuta ocupacional CRR Badajoz) -Habla con Carmen Ferrer por el coronavirus , no se permite hacer traslados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FERNANDEZ'and apellido2='BERMEJO'),'2020-03-10','Ana: Maribel, TS Residencia Parque del Príncipe (Grupo Ciudad Jardín), me remite por mail Informe de Alta del Serv. de Urología, ha estado ingresado por Hematuria que no cede. *Tienen que hacerle una BIOPSIA PROSTÁTICA, para confirmar o descartar cáncer. Me envía el C.I. *Guardo informe en el expte. Subo el CI a la firma del D.Gerente y se lo envío escaneado por email a ella y al H.U.C.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2020-03-10','Hablo con Francisca, hermana de Lázaro (674586675), en relación con la intención de vender un inmueble de su madre. No han hecho la herencia previa. Me facilita el teléfon del abogado, Juan José Iglesias (679466386). Tras hablar con él, quedamos en que va a hablar con José Luis, de la Notaría de Virgen de Guadalupe, en Cáceres, para plantearle las opciones de aceptación de la herencia y venta de inmueble. Le envío un correo electrónico de prueba, a los efectos de mantenernos en contacto también por este medio (jmorenoiglesias@icac.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2020-03-10','Ana: Clara Gomez Nestares, me entrega Cdo. de Dependencia de Eduardo. Escaneo y guardo en expte. ////////////// Adjunto una copia del Cdo a la solicitud de complemento ATP (Comunicación de variaciones) y lo pongo para registro de entrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2020-03-11','Ana: Correo de ayer por la tarde del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "Buenas tardes, les informamos de que Margarita Antich Arroyo se encuentra ingresada, nuevamente, en la Unidad de Psiquiatría del Hospital Virgen del Puerto. Un saludo. Pilar Sánchez" /////////////////////////////////////////////////////////////////////// Conversación telefónica con Pilar - Hogar San Vicente de Paúl (671 016 615). Expresa que la reacción de ayer-tarde fue algo repentino, durante el día estuvo bien. Supuesta ideación autolítica. *Considera que Marga necesita un tratamiento psicológico continuado pues no sabe manejar sus emociones. No cuenta con recursos económicos para asumir una terapia privada. Están a la espera de la cita en el Servicio de Psicología del ESM. Han consultado en el CRPS, pero como no presenta enfermedad mental no pueden atenderla. Ha llegado incluso a prenguntar a la Psicóloga del CSS, pero tampoco es viable la atención allí. **En cuanto a su orientación sexual dice Pilar que también prestenta dificultades, no la tiene clara y lo pasa mal al respecto y aunque han intentado trabajarlo en el centro no ha dado resultado y no saben como aborarlo. Ante esto propongo que llamen a la Fundación Triángulo, por si le pueden atender o asesorar desde dicha entidad. *Pensaremos en alternativas para la terapia psicológica. ////////////////////////////////////////////////////////////////////////////////// Nueva llamada de Pilar: Ha hablado con la Dra. Lorenzo, Psiquiatra de la UHB, dice que son sólo llamadas de atención, le ha dicho que no quiere volver al centro. NO cree que en ningún momento vaya a intentar suicidarse. *Marga, incluso le ha reconocido a la Dra. Lorenzo que la vez que dijo que había tomado lejía no era verdad, no se lo había bebido. **La solución no es ingresarla en la UHB, no es el recurso adecuado, de momento la van a dejar unos días, pero no le van a cambiar la medicación ni nada. El primer año y pico que ha pasado en el Cento, ella era la novedad y ahora ya es una más y necesita llamar la atención. **Pilar expresa, que a pesar de que considera que son el recurso ideal para ella, dado que no cuentan con los medios para atender su necesidad actual, piden que, en el peor de los casos, valoremos el cambio de recurso en el que pueda tener la atención que precisa para estar bien.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2020-03-06','PEDRO/TERESA VISITA AL CENTRO PARA REUNION CON ABUELOS PATERNOS DE NATALIA COMENZAMOS LA REUNION EXPLICANDOLES QUE ES LA CTAEX, LO QUE CONSISTE SU INCAPACITACION Y LA TOMA DE DECISIONES. EL ABUELO NOS PREGUNTA QUE COMO VEMOS A NATALIA Y QUE SI HEMOS HABLADO A SOLAS CON ELLA YA QUE INSISTE EN QUE LA NIÑA TIENE MIEDO, QUE NO LA DEJAN HABLAR CON ELLOS Y QUE NO ACUDE A LAS REVISIONES DE SALUD MENTAL. ESTO LO UTILIZA COMO JUSTIFICANTE DE LAS CONDUCTAS DE NATALIA LA CUAL DICE QUE EL AL VE NERVIOSA LE PREGUNTMOS POR LAS AGRESIONES QUE SE ESTAN PRODUCIENDO EN EL CENTRO Y LA ABUELA DICE QUE NO TIENE CONOCIMIENTO DE ESTO, EN ESE MOMENTO EL ABULEO NOS ENSEÑA UNA FOTO DE HACE TRES AÑOS EN LA QUE NATALIA MUESTRA UN BRAZO CON MORETONES. SE HABLA DE UNA DENUNCIA QUE HUBO CON UN CUIDADOR, SE PUSO UNA DENUNCIA Y SE RETIRO POR PETICION DE LA ABUELA, HECHO QUE LA ABUELA NIEGA EN ESE MOMENTO. LA ABUELA INSISTE QEU ELLA NO ES DENUNCIAR QUE PREFIERE HABLAR Y QUE ELLA NUNCA HA TENIDO PROBLEMAS EN SU CASA PEDRO LE PREGUNTA QUE CREE QUE SE DEBE HACER PARA QUE NATALIA MEJORE EL ABUELO RESPONDE QUE HABRIA QUE TRASLADARLA YA QUE EL CENTRO NO PUEDE CON ELLA PORQUE ES MUY LISTA PEOR A PESAR DE ELLO ELLA ESTA BIEN AQUI SOLO QUE HAY ALGO QUE LE HACE SER AGRESIVA. PILAR LA ABUELA ROMPE A LLORAR AL HABLAR DEL VERANO PASADO QUE NO PUEDO ESATR CON ELLA TODAS LA VACACIONES PORQUE ESTABA ATRAVESANDO UNA DEPRESION EL PSICOLO EDU LE COMENTA QUE SE LE OFREICIO AYUDA Y ELL LO RECONOCE LA ABUELA RECONOCE QUE LA MADRE ES PERJUDICIAL PARA ELLA PEDRO LE PREGUNTA QUE COMO PÙEDE ESTAR SEGURA QUE NATALIA NO VE A LA MADRE EN LAS VISITAS QUE HACE AL ABUELO MATERNO Y COMENTA QUE EL ABUELO VIVE CON UNA HIJA LA CUAL NO SE HABLA CON LA MADRE DE NATALIA. MIGUEL LE COMENTA A LOS ABUELOS LOS INCIDENTES OCURRIDOS ESTA SEMANA A LO QUE LA ABUELA RESPONDE QUE ESO NO PUEDE SER PORQUE NATALIA ES MUY ESCRUPULOSA. LE COMENTA TAMBIEN EL INCIDENTE DEL COMEDOR. EDUARDO CUENTA LO QUE LE HA COMENTADO NATALIA SOBRE ESOS INCIDENTES SOBRE EL PRIMER QUE HA SIDO EL USUARIO EL QUE LO HA HECHO QUE ELLA NO HA TENIDO NADA QUE VER SOBRE EL SEGUNDO ECHA LA CULPA A LA CUIDADORA POR NO HACERLE CASO A SUS PETICIONES Y HABERLA INSULTADO INVITAMOS A NATALIA QUE PASE Y NOS QUEDAMOS A SOLAS CON ELLA Y SUS ABUELOS SEGUN ENTRA NATALIA LA ABUELA SE ABRAZA A ELLA Y LA BESA EL ABUELO SE QUEDA SENTADO MIRANDO SE SIENTA Y NATALIA NO DEJA DE MIRAR A SU ABUELO, LE PIDE QUE QUIERE DARLE UN BESO, EL ABUELO SE LEVANTA Y LA BESA. PEDRO LE PREGUNTA QUE TAL LA SEMANA, ELLA RESPONDE QEU BIEN. LE INVITA QUE LES EXPLIQUE A LOS ABUELOS PORQUE NO HA PODIDO IR A CASA ESTAS SEMANAS Y NATALIA RESPONDE QUE POR LO DE SU MADRE, LE PEDIMOS QUE SE EXPLIQUE MEJOR Y ELLA SE QUEDA CALLADA. PEDRO LE PREGUNTA SI ESTA SEMANA HA HABIDO ALGUN PROBLEMA Y ELLA DICE QUE NINGUNO, LUEGO DICE QUE LE ABREN LA DUCHA Y SE ENFADA PEDRO INSISTE Y ELLA COMENTA QUE UN COMPAÑERO LE DEJO DINERO EN EL BAÑO ENCIMA DE UN MUEBLE DONDE ESTAN LOS ROYOS DE PAPEL. DICE QUE UN COMPAÑERO SE HA METIDO CON ELLA Y NOS COMENTA QUE QUERIA UNA MANTA Y NO SE LA DABAN Y QEU SE ENFADO PORQUE TENIA FRIO PEDRO INSISTE NATALIA CONFIESA QEU HIZO CACA Y EL COMPAÑERO SE LA REFREGO QUE ESE COMPAÑERO HACE ESO MUHCAS VECES (NOTO A NATALIA A LA DEFENSIVA LA CONVSERSACION NO ES TAN DIRECTA COMO LA DE LA ANTERIOR VISITA) NATALIA CUENTA LO SUCESIDO EN EL BUS Y CAMBIA SU ULTIMA VERSION, AHORA DICE QUE SOLO FUE A ORINAR QUE NO HABIA QUEADO CON SU MADRE LE PREGUNTO QEU SI SIGUE QUERIENDO ESTAR EN EL CENTRO Y AFIRMA QUE SI QUE NO SE QUIERE IR PORQEU AQUI HAY GENTE QUE LE QUIERE, QUE LE LLEVAN DE EXCURSION, Y QUE TIENE AMIGAS. PEDRO LE PREGUNTA POR LAS COSAS BUENAS QUE HA HECHO HA DADO LA CENA A UNA COMPAÑERA HA DEJADO EL SECADOR A UNA RESIDENTE HA MEDIADO EN UNA PELEA HA AYUDADO A LEVANTARSE A UNA COMPALERA QUE SE CALLO HA LIMPIADO LAS MESAS DE FORMA VOLUNTARIA HA MANEJADO UNA GRUA COMENTA HABERSE SENTIDO MUY BIEN HACIENDO TODAS ESTAS COSAS NOS REUNIMOS DE NUEVO CON EL EQUIPO PARA DECIR SI LE DAMOS PERMISO PARA IRSE CON LA ABUELA ESTE FIN DE SEMAN MIGUEL COMENTA QUE TDOSA ESAS BUENAS ACCIONES LAS HA LLEVADO A CABO SOLO LOS ULTIMOS DIAS DE LA SEMANA. DECIMOS DEJARLA IRSE PERO CON SUPERVISION DE LOS ABUELOS EN LA IDA Y VENIDA DE MOMENTO NO VA A SALIR SOLA. SE DEJA IRSE PARA ALIVIAR LA PRESION QUE TIENE EL CENTRO CON LAS CONDUCTAS DE NATALIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='AMAYA'and apellido2='LOBATO'),'2020-03-11','TERESA LLAMO A OLGA PARA PREGUNTAR POR JM, ME COMENTA QUE HA VUELTO A VISITARLO Y QUE LE COMENTO QUE SI QUE LE TIENE QUE DECIR DONDE ESTA EL DINERO PERO QUE OTRO DIA LE COMENTO EL TEMA DE LIMPIAR ESAS HABITACIONES Y LE DIJO QEU MAS ALANTE. AL MENOS NO SE HA NEGADO Y MUESTRA UNA ACTITUD MAS ABIERTA. LE PASO LA INFORMCIN A TONI PARA QUE FUTUEX COMIENCE LAS VISITAS Y ACOMPAÑAMIENTOS A MEDICO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-11','En relación con el PA 64/2018, seguido en el Juzgado de Primera Instancia e Instruccón nº 4, de Mérida, la Comisión de Asistencia Jurídica Gratuita reconoce el derecho a la asistencia jurídica gratuita de José Manuel en este procedimiento. El abogado designado es Pedro Acedo Cañamero (924315112- pedroacedo@abogados-merida.es). Tras hablar con él, nos dice que no tiene conocimiento de documentación alguna de este procedimiento, debido a que está pendiente de designarse procurador. Va a ponerse en contacto con Rocío, del Colegio de Abogados. En cuanto sepa algo nos dice.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='NIETO'and apellido2='LABRADOR'),'2020-03-11','TERESA: ARCHIVO NOTIFICACION DE MEDINA CUADROS SOBRE UNA DEUDA CON TELEFONICA MOVILES YA ESTA ANGEL EN CONOCIENTO DEL CASO','2');
