insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2020-03-11','Ana: Solicitud de ATP (modelo de comunicación de variaciones) REGISTRADO DE ENTRADA: 11/03/2020.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='SAEZ'and apellido2='BERMEJO'),'2020-03-11','Ana: Recibimos escrito del Serv. de Prestaciones Sociales (Serv. Territorial de Ba): informan que la solicitud de PNC ha tenido entrada con fecha 24/02/2020. /////////////////////////////////////////////////////////// Correo de Susana, TS Hpal. Santiago de Zafra: "Buenas tardes Ana, ahora mismo vengo de la cita con la trabajadora social para el tema de los informes de Pilar Saez, le he contado un poco por encima y me dice que ellas no hacen el informe a no ser que desde la Comisión Tutelar se lo soliciten por escrito y con su debido registro de salida.... me he puesto un poco seria y ha llamado a la coordinadora y me dice que ellas no se niegan a hacer el informe pero previa solicitud vuestra... así que siento decirte que no puedo hacer más en este sentido, incluso al principio me decían que ellas no eran las que tenían que hacer ese informe, que se lo solicitara a la trabajadora social de cáceres... y al insistirle que ella vive ya aquí y está empadronada aquí es cuando me da la opción de que se lo solicites por escrito y entonces nos darán respuesta...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-11','Ana: Llamo a José Manuel (667 384 817), al parecer la Subcomisión de casos está convocada para la semana que viene, se lo ha comentado Pilar Martín a su hermano. Expresa que no quiere ir al CSS, le pregunto por el cambio de opinión, pues la última vez que hablamos manifestó que sí quería ir, aunque sea allí pues necesitaba estar en un centro. Finalmente acepta ir siempre que sea a UME, a Crónicos no quiere. *No obstante le recuero habrá que esperar a la Subcomisión, a ver qué ocurre. // Por otra parte dice que está sin saldo en el móvil, pide un extra de 10 € para recargárlo. *Se lo paso a Alberto, jefe secc. ecca. **Mañana podrá retirlo, le llamo y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2020-03-11','(Pedro). Se presenta en la Comisión José Mª Valle. +++"El calentador de casa lleva 15 días soltandom agua y ya ha pasado al psio de abajo..." +++Se le recrimina que no haya avisado antes. +++Me pongo en contacto con el propietario de la vivienda, a quien ya había llamado el vecino afectado y protesta por no haberle avisado antes "...es que este señor esun despreocupado..." Llamará al seguro de la vivienda para que valoren y reparen los daños, que dada la tardanza en avisar no sabemos a quién correponderá su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BRAHIM'and edp.apellido1='EL KINTY'and apellido2='SNEIBA'),'2020-03-11','(Pedro)Llamada de Mª Ángeles (CADEx). +++Brahim no ha sido valorado todavía porque desde el Cadex se ha solicitado un Informe previo a Educación y hasta que no se lo remitan no se procederá a dicha valoración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2020-03-11','En relación con el procedimiento de modificación de medidas, llamamos al SOJ de Cáceres y hablamos con Elena (927245184 - elenamendo@icac.es), para preguntar por la queja presentada por la no atención al procedimiento por parte del abogado de oficio que se designó. Nos comenta que le han dado traslado para que alegue lo que estime conveniente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2020-03-11','En relación con el procedimiento Jucio Verbal 242/2020, seguido en el Juzgado de Primera Instancia nº 2, de Badajoz, por el que reclaman en concepto de falta de pago del alquiler de la vivienda donde vivía, una mensualidad y la fianza, puestos en contacto con el arrendador nos comenta que ya le han pagado las cantidades debidas y que va a comunicarlo al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2020-03-11','Ana y Pedro: Conversación a tres con la Dra. Guadalupe Espárrago, ESM CC. Expresa que en la última consulta con Saturnino tuvo dudas sobre ingreso involuntario en UHB. Hace meses que no se toma el Litio. Lo notó "hipomaníaco y un tanto descompensado", "psicótico no lo ví en ningún momento" añade. Dijo que quiere que le quiten la tutela, a lo que le respondió que eso no es posible. Continúa bebiendo cerveza y reconoce que de vez en cuando cannabis. No tiene conciencia de la enfermedad. Se está manteniendo gracias al antipsicótico inyectable. Le dijo que estaba arreglando el piso, pero en ningún momento le dijo que se trataba del piso de la C/ General Margallo al que se ha ido a vivir solo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2020-03-11','Ana: Recibo llamada de Mariví Clemente, TS CSS-Plas (24142). En relación a la vivienda que ha adquirido Ángel, marido de Desideria, cree que puede ser una infravivienda en un barrio humilde de Plasencia. Ahora presentan constantes y exigentes demandadas de grandes cantidades de dinero. *Por otra parte, en su opinión utilizan el centro como un comedor social, no realizan un adecuado uso terapéutico para el que está concebido la unidad. Pero desde Psiquiatría se les da los pases y se les está consintiendo las faltas de asistencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2020-03-11','TERESA: RECIBO EMAIL DEL PISO Javier quiere solicitar si se le pudiera ingresar dinero para comprar una bicicleta de calidad ya que quiere empezar a hacer un poco de ciclismo con algunos compañeros del centro. Refiere haber estado comparado en varios negocios deportivos y que el precio oscila entre 300 y 350 euros. Quedo a la espera. Un saludo. SE AUTORIZA LA COMPRA','2');
